// api/chatbot.js — Vercel serverless function para Groq API
// SLOT: 7/12 apos criacao

import Groq from 'groq-sdk'
import { z } from 'zod'
import {
  CHATBOT_MAX_TOKENS,
  CHATBOT_TEMPERATURE,
  CHATBOT_TOP_P,
  CHATBOT_MAX_HISTORY,
} from '../src/features/chatbot/config/chatbotConfig.js'

const MODEL = process.env.GROQ_MODEL || 'groq/compound'

const chatbotRequestSchema = z.object({
  message: z
    .string()
    .min(1, { message: 'Mensagem obrigatória' })
    .max(500, { message: 'Mensagem muito longa (max 500 caracteres)' }),
  history: z
    .array(z.object({ role: z.enum(['user', 'assistant']), content: z.string() }))
    .optional()
    .default([]),
  systemPrompt: z.string().optional(),
})

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' })
  }

  // Validar API key
  if (!process.env.GROQ_API_KEY) {
    console.error('[chatbot] GROQ_API_KEY nao configurada')
    return res.status(500).json({ error: 'Chatbot não configurado' })
  }

  const groq = new Groq({ apiKey: process.env.GROQ_API_KEY })

  try {
    const parseResult = chatbotRequestSchema.safeParse(req.body)
    if (!parseResult.success) {
      return res.status(400).json({ error: parseResult.error.errors[0].message })
    }

    const { message, history, systemPrompt } = parseResult.data

    // Montar mensagens para Groq
    const messages = [
      { role: 'system', content: systemPrompt || 'Você é um assistente de medicamentos.' },
      ...history.slice(-CHATBOT_MAX_HISTORY).map(h => ({
        role: h.role === 'user' ? 'user' : 'assistant',
        content: h.content,
      })),
      { role: 'user', content: message },
    ]

    const completion = await groq.chat.completions.create({
      model: MODEL,
      messages,
      max_tokens: CHATBOT_MAX_TOKENS,
      temperature: CHATBOT_TEMPERATURE,
      top_p: CHATBOT_TOP_P,
    })

    const response =
      completion.choices[0]?.message?.content || 'Desculpe, não consegui responder.'

    // Log cache hit metrics (Groq Prompt Caching)
    const promptTokens = completion.usage?.prompt_tokens || 0
    const cachedTokens = completion.usage?.cached_prompt_tokens || 0
    const cacheHitRate = promptTokens > 0 ? Math.round((cachedTokens / promptTokens) * 100) : 0
    const estimatedSavings = Math.round(cachedTokens * 0.5) // 50% desconto em cached_tokens

    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      service: 'chatbot-api',
      level: 'info',
      message: 'Groq response received',
      model: MODEL,
      promptTokens,
      cachedTokens,
      cacheHitRate: `${cacheHitRate}%`,
      estimatedTokenSavings: estimatedSavings,
      completionTokens: completion.usage?.completion_tokens,
      totalTokens: completion.usage?.total_tokens,
    }))

    return res.status(200).json({
      response,
      model: MODEL,
      usage: completion.usage,
    })
  } catch (error) {
    console.error('[chatbot] Erro Groq:', error.message)

    if (error.status === 429) {
      return res.status(429).json({
        error: 'Limite de requisicoes atingido. Tente novamente em alguns segundos.',
      })
    }

    return res.status(500).json({ error: 'Erro ao processar mensagem' })
  }
}

// api/dlq.js
// Dead Letter Queue Admin API - Router consolidado
// Rotas: GET /api/dlq (list) | POST /api/dlq?action=retry&id=:id | POST /api/dlq?action=discard&id=:id
import { createClient } from '@supabase/supabase-js';
import { DLQStatus } from '../server/services/deadLetterQueue.js';
import { verifyAdminAccess } from '../server/utils/auth.js';
import { handleRetry } from './dlq/_handlers/retry.js';
import { handleDiscard } from './dlq/_handlers/discard.js';

const supabaseUrl = process.env.VITE_SUPABASE_URL || process.env.SUPABASE_URL;
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
const supabaseAnonKey = process.env.VITE_SUPABASE_ANON_KEY || process.env.SUPABASE_ANON_KEY;
const adminChatId = process.env.ADMIN_CHAT_ID;

/**
 * Handler: list (GET /api/dlq)
 * Lista notificações falhas com paginação
 */
async function handleList(req, res) {
  // Create Supabase client with service role key (bypasses RLS for admin access)
  const supabase = createClient(supabaseUrl, supabaseServiceKey);

  try {
    // Parse query parameters
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const offset = Math.max(parseInt(req.query.offset) || 0, 0);
    const status = req.query.status || null;

    // Validate status if provided
    const validStatuses = Object.values(DLQStatus);
    if (status && !validStatuses.includes(status)) {
      return res.status(400).json({
        error: `Invalid status. Valid values: ${validStatuses.join(', ')}`
      });
    }

    // Build query
    let query = supabase
      .from('failed_notification_queue')
      .select('*', { count: 'exact' })
      .order('created_at', { ascending: false })
      .range(offset, offset + limit - 1);

    // Apply status filter if provided
    if (status) {
      query = query.eq('status', status);
    }

    const { data, error, count } = await query;

    if (error) {
      console.error('[DLQ API] Database error:', error);
      return res.status(500).json({ error: 'Failed to fetch DLQ entries' });
    }

    // Return paginated response
    return res.status(200).json({
      data: data || [],
      total: count || 0,
      page: Math.floor(offset / limit) + 1,
      pageSize: limit,
      totalPages: Math.ceil((count || 0) / limit)
    });

  } catch (err) {
    console.error('[DLQ API] Unexpected error:', err);
    return res.status(500).json({
      error: 'Internal server error',
      details: process.env.NODE_ENV === 'development' ? err.message : undefined
    });
  }
}

/**
 * DLQ Router Handler
 * GET /api/dlq - List failed notifications with pagination
 * POST /api/dlq?action=retry&id=:id - Retry a specific notification
 * POST /api/dlq?action=discard&id=:id - Mark a notification as discarded
 *
 * Query params:
 * - limit: number of items per page (default: 20, max: 100)
 * - offset: offset for pagination (default: 0)
 * - status: filter by status (pending, retrying, resolved, discarded)
 * - action: 'retry' or 'discard' (POST only)
 * - id: UUID of the failed notification (POST only)
 *
 * Authentication:
 * - Requires Supabase Auth session token in Authorization header
 * - User must have telegram_chat_id matching ADMIN_CHAT_ID
 */
export default async function handler(req, res) {
  // Validate environment variables
  if (!supabaseUrl || !supabaseServiceKey || !supabaseAnonKey || !adminChatId) {
    console.error('[DLQ API] Missing configuration');
    return res.status(500).json({ error: 'Server configuration error' });
  }

  // Verify admin access (compartilhada entre todos os endpoints)
  const authResult = await verifyAdminAccess(req.headers['authorization']);
  if (!authResult.authorized) {
    console.error('[DLQ API] Unauthorized access attempt:', authResult.error);
    return res.status(401).json({ error: authResult.error });
  }

  const { action } = req.query;

  // Roteamento baseado em método e action (padrao router map)
  if (req.method === 'GET' && !action) {
    return handleList(req, res);
  }

  if (req.method === 'POST') {
    const postRoutes = {
      'retry': handleRetry,
      'discard': handleDiscard,
    };
    const routeHandler = postRoutes[action];
    if (routeHandler) {
      return routeHandler(req, res);
    }
  }

  return res.status(405).json({ error: 'Method not allowed' });
}

// api/dlq/_handlers/discard.js
// Dead Letter Queue Handler - Discard a failed notification
// NOTA: Este handler é chamado pelo router api/dlq.js, que já faz a autenticação
import { createClient } from '@supabase/supabase-js';
import { createLogger } from '../../../server/bot/logger.js';

const logger = createLogger('DLQDiscard');

const supabaseUrl = process.env.VITE_SUPABASE_URL || process.env.SUPABASE_URL;
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

/**
 * Handler para descartar notificação da DLQ
 * @param {object} req - Request object (Vercel)
 * @param {object} res - Response object (Vercel)
 */
export async function handleDiscard(req, res) {
  // Get notification ID from query (router passa via req.query.id)
  const { id } = req.query;

  if (!id) {
    return res.status(400).json({ error: 'Missing notification ID' });
  }

  // Validate UUID format
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  if (!uuidRegex.test(id)) {
    return res.status(400).json({ error: 'Invalid notification ID format' });
  }

  // Create Supabase client with service role key
  const supabase = createClient(supabaseUrl, supabaseServiceKey);

  try {
    // Fetch the failed notification
    const { data: notification, error: fetchError } = await supabase
      .from('failed_notification_queue')
      .select('*')
      .eq('id', id)
      .single();

    if (fetchError || !notification) {
      logger.error('Notification not found', fetchError, { id });
      return res.status(404).json({ error: 'Notification not found' });
    }

    // Check if notification can be discarded
    if (notification.status === 'resolved') {
      return res.status(400).json({ error: 'Notification already resolved' });
    }

    if (notification.status === 'discarded') {
      return res.status(400).json({ error: 'Notification already discarded' });
    }

    // Get reason from request body (optional)
    const reason = req.body?.reason || 'Discarded via admin interface';

    // Mark as discarded
    const { error: updateError } = await supabase
      .from('failed_notification_queue')
      .update({
        status: 'discarded',
        resolved_at: new Date().toISOString(),
        resolution_notes: reason
      })
      .eq('id', id);

    if (updateError) {
      logger.error('Failed to discard notification', updateError, { id });
      return res.status(500).json({ error: 'Failed to discard notification' });
    }

    logger.info('Notification discarded', {
      id,
      reason,
      previousStatus: notification.status
    });

    return res.status(200).json({
      success: true,
      message: 'Notification discarded successfully'
    });

  } catch (err) {
    logger.error('Unexpected error during discard', err, { id });
    return res.status(500).json({
      error: 'Internal server error',
      details: process.env.NODE_ENV === 'development' ? err.message : undefined
    });
  }
}

// api/dlq/_handlers/retry.js
// Dead Letter Queue Handler - Retry a failed notification via Dispatcher (ADR-030)
import { createClient } from '@supabase/supabase-js';
import { createLogger } from '../../../server/bot/logger.js';
import { dispatchNotification } from '../../../server/notifications/dispatcher/dispatchNotification.js';
import { Expo } from 'expo-server-sdk';

const logger = createLogger('DLQRetry');

const supabaseUrl = process.env.VITE_SUPABASE_URL || process.env.SUPABASE_URL;
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
const botToken = process.env.TELEGRAM_BOT_TOKEN;

/**
 * Handler para retry de notificação da DLQ
 */
export async function handleRetry(req, res) {
  const { id } = req.query;

  if (!id) return res.status(400).json({ error: 'Missing notification ID' });

  const supabase = createClient(supabaseUrl, supabaseServiceKey);
  const expoClient = new Expo({ accessToken: process.env.EXPO_ACCESS_TOKEN });

  try {
    // 1. Fetch the failed notification
    const { data: notification, error: fetchError } = await supabase
      .from('failed_notification_queue')
      .select('*')
      .eq('id', id)
      .single();

    if (fetchError || !notification) {
      return res.status(404).json({ error: 'Notification not found' });
    }

    // 2. Setup Dispatcher Dependencies (Minimal L1 Setup)
    const preferencesRepo = {
      async getByUserId(userId) {
        const { data } = await supabase.from('user_settings').select('notification_preference').eq('user_id', userId).single();
        return data?.notification_preference || 'telegram';
      },
      async hasTelegramChat(userId) {
        const { data } = await supabase.from('user_settings').select('telegram_chat_id').eq('user_id', userId).single();
        return !!data?.telegram_chat_id;
      },
      async getSettingsByUserId(userId) {
        const { data } = await supabase.from('user_settings').select('*').eq('user_id', userId).single();
        return data || {};
      }
    };

    const devicesRepo = {
      async listActiveByUser(userId, provider) {
        const { data } = await supabase.from('notification_devices').select('*').eq('user_id', userId).eq('provider', provider).eq('is_active', true);
        return data || [];
      }
    };

    const dlqRepo = {
      async enqueue(notificationData, error, retryCount, correlationId) {
        await supabase
          .from('failed_notification_queue')
          .upsert({
            user_id: notificationData.userId,
            protocol_id: notificationData.protocolId,
            notification_type: notificationData.type,
            notification_payload: notificationData,
            error_code: error?.code || error?.error_code,
            error_message: error?.message || 'Unknown error',
            retry_count: retryCount,
            correlation_id: correlationId,
            status: 'pending'
          }, { onConflict: 'correlation_id', ignoreDuplicates: false });
      }
    };

    const bot = {
      sendMessage: async (chatId, text, options) => {
        const response = await fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ chat_id: chatId, text, ...options })
        });
        const result = await response.json();
        if (!result.ok) throw new Error(result.description);
        return { success: true, messageId: result.result.message_id };
      }
    };

    // 3. Dispatch via 3-layer architecture
    const dispatchResult = await dispatchNotification({
      userId: notification.user_id,
      kind: notification.notification_type,
      data: {
        ...(notification.notification_payload || {}),
        isRetry: true // Ativa decoração "(Reenvio)" na L2
      },
      context: { 
        correlationId: notification.correlation_id || `retry_${id}`,
        isRetry: true
      },
      repositories: { preferences: preferencesRepo, devices: devicesRepo, dlq: dlqRepo },
      bot,
      expoClient
    });

    if (dispatchResult.success) {
      // Mark as resolved
      await supabase
        .from('failed_notification_queue')
        .update({
          status: 'resolved',
          resolved_at: new Date().toISOString(),
          resolution_notes: 'Manually retried via admin interface'
        })
        .eq('id', id);

      return res.status(200).json({
        success: true,
        message: 'Notification sent successfully',
        channels: dispatchResult.channels
      });
    } else {
      // Update retry count
      await supabase
        .from('failed_notification_queue')
        .update({
          retry_count: (notification.retry_count || 0) + 1,
          updated_at: new Date().toISOString(),
          error_message: dispatchResult.errors?.[0]?.message || 'Unknown error'
        })
        .eq('id', id);

      return res.status(500).json({
        success: false,
        error: dispatchResult.errors?.[0]?.message || 'Failed to send notification'
      });
    }

  } catch (err) {
    logger.error('Unexpected error during retry', err, { id });
    return res.status(500).json({ error: 'Internal server error', details: err.message });
  }
}

/**
 * Handler para atualização em batch de reviews do Gemini
 *
 * Permite que agents externos atualizem o status de múltiplas reviews
 * de uma única requisição. Usa autenticação via token webhook.
 *
 * @module api/gemini-reviews/_handlers/batch-update
 * @version 1.0.0
 */

import { createClient } from '@supabase/supabase-js'
import { z } from 'zod'
import crypto from 'crypto'

// ============================================================================
// CONFIGURAÇÃO
// ============================================================================

// Fallback para VITE_SUPABASE_URL caso SUPABASE_URL não esteja definida
// (Vercel pode ter apenas VITE_SUPABASE_URL configurada)
const SUPABASE_URL = process.env.SUPABASE_URL || process.env.VITE_SUPABASE_URL
const SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY
const AGENT_WEBHOOK_SECRET = process.env.AGENT_WEBHOOK_SECRET

// ============================================================================
// SCHEMAS ZOD
// ============================================================================

/**
 * Status possíveis das reviews
 * @readonly
 */
const REVIEW_STATUSES = [
  'detected',
  'reported',
  'assigned',
  'resolved',
  'partial',
  'wontfix',
  'duplicate',
  'pendente',
  'em_progresso',
  'corrigido',
  'descartado',
]

/**
 * Tipos de resolução possíveis
 * @readonly
 */
const RESOLUTION_TYPES = ['fixed', 'rejected', 'partial']

/**
 * Schema para item de atualização individual
 */
const batchUpdateItemSchema = z.object({
  review_id: z.string().uuid('ID da review deve ser um UUID válido'),
  status: z.enum(REVIEW_STATUSES, {
    errorMap: () => ({ message: 'Status inválido' }),
  }),
  resolution_type: z.enum(RESOLUTION_TYPES).nullable().optional(),
  commit_sha: z.string().min(1).optional(),
  resolved_by: z.string().uuid().nullable().optional(),
})

/**
 * Schema para o body da requisição
 */
const batchUpdateSchema = z.object({
  updates: z
    .array(batchUpdateItemSchema)
    .min(1, 'Deve haver pelo menos uma atualização')
    .max(100, 'Máximo de 100 atualizações por requisição'),
})

// ============================================================================
// FUNÇÕES AUXILIARES
// ============================================================================

/**
 * Verifica se a requisição está autenticada usando timing-safe comparison
 * @param {Object} req - Requisição HTTP
 * @returns {boolean} true se autenticado
 */
function isAuthenticated(req) {
  const authHeader = req.headers.authorization || ''
  const token = authHeader.replace(/^Bearer\s+/i, '')

  if (!token || !AGENT_WEBHOOK_SECRET) {
    return false
  }

  // Timing-safe comparison para prevenir timing attacks
  try {
    const tokenBuffer = Buffer.from(token)
    const secretBuffer = Buffer.from(AGENT_WEBHOOK_SECRET)

    if (tokenBuffer.length !== secretBuffer.length) {
      return false
    }

    return crypto.timingSafeEqual(tokenBuffer, secretBuffer)
  } catch {
    return false
  }
}

/**
 * Atualiza uma única review no Supabase
 * @param {Object} supabase - Cliente Supabase
 * @param {Object} update - Dados da atualização
 * @returns {Promise<Object>} Resultado da atualização
 */
async function updateReview(supabase, update) {
  const { review_id, status, resolution_type, commit_sha, resolved_by } = update

  // Construir objeto de atualização
  const updateData = {
    status,
    updated_at: new Date().toISOString(),
  }

  if (resolution_type !== undefined) {
    updateData.resolution_type = resolution_type
  }

  if (commit_sha !== undefined) {
    updateData.commit_sha = commit_sha
  }

  if (resolved_by !== undefined) {
    updateData.resolved_by = resolved_by
  }

  // Se status é resolved/partial/wontfix, adicionar resolved_at
  if (['resolved', 'partial', 'wontfix', 'corrigido', 'descartado'].includes(status)) {
    updateData.resolved_at = new Date().toISOString()
  }

  const { data, error } = await supabase
    .from('gemini_reviews')
    .update(updateData)
    .eq('id', review_id)
    .select('id, status')
    .single()

  if (error) {
    throw new Error(`Erro ao atualizar review ${review_id}: ${error.message}`)
  }

  return data
}

/**
 * Processa atualizações em batch com tratamento de erro individual
 * @param {Object} supabase - Cliente Supabase
 * @param {Array<Object>} updates - Lista de atualizações
 * @returns {Promise<Object>} Resultado do processamento
 */
async function processBatchUpdates(supabase, updates) {
  const results = {
    success: [],
    errors: [],
  }

  for (const update of updates) {
    try {
      const updated = await updateReview(supabase, update)
      results.success.push({
        review_id: update.review_id,
        status: updated.status,
      })
    } catch (error) {
      results.errors.push({
        review_id: update.review_id,
        error: error.message,
      })
    }
  }

  return results
}

// ============================================================================
// HANDLER PRINCIPAL
// ============================================================================

/**
 * Handler para requisições HTTP
 * @param {Object} req - Requisição HTTP
 * @param {Object} res - Resposta HTTP
 */
export async function handleBatchUpdate(req, res) {
  // Verificar método HTTP
  if (req.method !== 'POST') {
    return res.status(405).json({
      success: false,
      error: 'Método não permitido. Use POST.',
    })
  }

  // Verificar variáveis de ambiente PRIMEIRO (antes da autenticação)
  if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY) {
    return res.status(500).json({
      success: false,
      error: 'Configuração do servidor incompleta.',
    })
  }

  // Verificar autenticação
  if (!isAuthenticated(req)) {
    return res.status(401).json({
      success: false,
      error: 'Não autorizado. Token inválido ou ausente.',
    })
  }

  try {
    // Validar body da requisição
    const validation = batchUpdateSchema.safeParse(req.body)

    if (!validation.success) {
      return res.status(400).json({
        success: false,
        error: 'Dados inválidos',
        details: validation.error.issues.map((issue) => ({
          field: issue.path.join('.'),
          message: issue.message,
        })),
      })
    }

    const { updates } = validation.data

    // Criar cliente Supabase
    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY)

    // Processar atualizações
    const results = await processBatchUpdates(supabase, updates)

    // Retornar resultado
    const hasErrors = results.errors.length > 0
    const allFailed = results.success.length === 0

    return res.status(hasErrors ? (allFailed ? 500 : 207) : 200).json({
      success: !allFailed,
      updated: results.success.length,
      errors: results.errors,
      ...(hasErrors && { partial: !allFailed }),
    })
  } catch (error) {
    console.error('Erro no batch-update:', error)

    return res.status(500).json({
      success: false,
      error: 'Erro interno do servidor',
      message: error.message,
    })
  }
}

/**
 * Handler para criar GitHub Issues a partir de reviews do Gemini
 *
 * Recebe dados do review, busca issues pendentes no Supabase
 * (status='detected', priority='media'), cria issues no GitHub via API
 * e atualiza o Supabase com github_issue_number.
 *
 * @module api/gemini-reviews/_handlers/create-issues
 * @version 1.1.0
 */

import { createClient } from '@supabase/supabase-js'
import { z } from 'zod'
import jwt from 'jsonwebtoken'
import {
  checkRateLimit,
  getRateLimitHeaders,
  getClientIP,
  rateLimitResponse,
  internalErrorResponse,
  fetchWithRetry,
  MAX_RETRIES,
} from '../_shared/security.js'
import {
  logRequest,
  logAuth,
  logSupabase,
  logGitHub,
  logBlobDownload,
  logResult,
  logError,
  logInfo,
} from '../_shared/logger.js'

const ENDPOINT = 'create-issues'

// ============================================================================
// CONFIGURAÇÃO
// ============================================================================

// Fallback para VITE_SUPABASE_URL caso SUPABASE_URL não esteja definida
// (Vercel pode ter apenas VITE_SUPABASE_URL configurada)
const SUPABASE_URL = process.env.SUPABASE_URL || process.env.VITE_SUPABASE_URL
const SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY
const VERCEL_GITHUB_ACTIONS_SECRET = process.env.VERCEL_GITHUB_ACTIONS_SECRET
const GITHUB_TOKEN = process.env.GITHUB_TOKEN
// Token para acessar blobs privados do Vercel Blob Storage
const BLOB_READ_WRITE_TOKEN = process.env.BLOB_READ_WRITE_TOKEN || process.env.VERCEL_BLOB_TOKEN

// Labels para issues de refactoring
const REFACTOR_LABELS = {
  GEMINI_REFACTOR: '🤖 gemini-refactor',
  REFACTORING: 'refactoring',
  TECH_DEBT: 'tech-debt',
}

