/**
 * Busca issues pendentes no Supabase
 * Critérios: status='detected', priority='media', sem github_issue_number
 * @param {Object} supabase - Cliente Supabase
 * @param {number} prNumber - Número do PR
 * @returns {Promise<Array<Object>>} Lista de issues pendentes
 */
async function fetchPendingIssues(supabase, prNumber) {
  logSupabase(ENDPOINT, 'select', 'gemini_reviews', {
    operation: 'fetchPendingIssues',
    prNumber,
    filters: { status: 'detected', priority: ['media', 'alta', 'critica'], github_issue_number: null },
  })

  const { data, error } = await supabase
    .from('gemini_reviews')
    .select('*')
    .eq('pr_number', prNumber)
    .eq('status', 'detected')
    .in('priority', ['media', 'alta', 'critica'])
    .is('github_issue_number', null)
    .limit(10)

  if (error) {
    logError(ENDPOINT, 'Error fetching pending issues', error, {
      prNumber,
      errorMessage: error.message,
    })
    throw new Error(`Falha ao buscar issues pendentes: ${error.message}`)
  }

  logInfo(ENDPOINT, 'Pending issues fetched', {
    prNumber,
    count: data?.length || 0,
  })

  return data || []
}

/**
 * Atualiza o status da review no Supabase após criar issue
 * @param {Object} supabase - Cliente Supabase
 * @param {string} id - UUID da review
 * @param {number} issueNumber - Número da issue no GitHub
 */
async function updateReviewStatus(supabase, id, issueNumber) {
  logSupabase(ENDPOINT, 'update', 'gemini_reviews', {
    operation: 'updateReviewStatus',
    id,
    issueNumber,
    newStatus: 'reported',
  })

  const { error } = await supabase
    .from('gemini_reviews')
    .update({
      status: 'reported',
      github_issue_number: issueNumber,
      updated_at: new Date().toISOString(),
    })
    .eq('id', id)

  if (error) {
    logError(ENDPOINT, 'Error updating review status', error, {
      id,
      issueNumber,
      errorMessage: error.message,
    })
    throw new Error(`Falha ao atualizar review ${id}: ${error.message}`)
  }

  logInfo(ENDPOINT, 'Review status updated', { id, issueNumber, status: 'reported' })
}

/**
 * Baixa dados do review do Vercel Blob usando fetch com retry
 * @param {string} blobUrl - URL do blob
 * @returns {Promise<Object>} Dados do review
 */
async function downloadFromBlob(blobUrl) {
  logBlobDownload(ENDPOINT, blobUrl, { status: 'starting' })

  // Para blobs privados, precisamos do token de autenticação
  const headers = {}
  if (BLOB_READ_WRITE_TOKEN) {
    headers['Authorization'] = `Bearer ${BLOB_READ_WRITE_TOKEN}`
    logInfo(ENDPOINT, 'Using BLOB_READ_WRITE_TOKEN for authentication')
  } else {
    logInfo(ENDPOINT, 'No BLOB_READ_WRITE_TOKEN found, attempting public access')
  }

  const response = await fetchWithRetry(blobUrl, { headers }, MAX_RETRIES)

  if (!response.ok) {
    logError(ENDPOINT, 'Blob download failed', new Error(`HTTP ${response.status}`), {
      status: response.status,
      statusText: response.statusText,
    })
    throw new Error(`Falha ao baixar do Blob: ${response.status} ${response.statusText}`)
  }

  const data = await response.json()
  logBlobDownload(ENDPOINT, blobUrl, {
    status: 'success',
    dataSize: JSON.stringify(data).length,
  })

  return data
}

// ============================================================================
// FUNÇÃO PRINCIPAL
// ============================================================================

/**
 * Cria GitHub Issues para reviews MEDIUM
 * @param {Object} supabase - Cliente Supabase
 * @param {Object} reviewData - Dados do review
 * @param {string} githubToken - Token GitHub
 * @returns {Promise<Object>} Resultado da criação
 */
async function createIssuesFromReview(supabase, reviewData, githubToken) {
  const { pr_number, owner, repo } = reviewData

  logInfo(ENDPOINT, 'createIssuesFromReview started', {
    pr_number,
    owner,
    repo,
  })

  const results = {
    created: 0,
    issues: [],
    errors: [],
  }

  // Buscar issues pendentes
  const pendingIssues = await fetchPendingIssues(supabase, pr_number)

  if (pendingIssues.length === 0) {
    logInfo(ENDPOINT, 'No pending issues found', { pr_number })
    return results
  }

  logInfo(ENDPOINT, 'Processing pending issues', {
    pr_number,
    count: pendingIssues.length,
  })

  // Criar issues no GitHub
  for (const [index, issue] of pendingIssues.entries()) {
    try {
      logInfo(ENDPOINT, `Processing issue ${index + 1}/${pendingIssues.length}`, {
        reviewId: issue.id,
        title: issue.title?.substring(0, 50),
      })

      // Validar issue do Supabase
      const issueValidation = pendingIssueSchema.safeParse(issue)
      if (!issueValidation.success) {
        logError(ENDPOINT, 'Issue validation failed', new Error('Validation error'), {
          reviewId: issue.id,
          errors: issueValidation.error.issues,
        })
        results.errors.push({
          review_id: issue.id,
          error: 'Dados inválidos',
        })
        continue
      }

      // Criar issue no GitHub
      const githubIssue = await createGitHubIssue(
        issue,
        pr_number,
        owner,
        repo,
        githubToken
      )

      // Atualizar Supabase com referência
      await updateReviewStatus(supabase, issue.id, githubIssue.number)

      // Comentar no PR
      await commentOnPR(pr_number, githubIssue.number, owner, repo, githubToken)

      results.created++
      results.issues.push({
        review_id: issue.id,
        github_issue_number: githubIssue.number,
        title: githubIssue.title,
        url: githubIssue.html_url,
      })

      logInfo(ENDPOINT, 'Issue created successfully', {
        reviewId: issue.id,
        issueNumber: githubIssue.number,
      })
    } catch (error) {
      logError(ENDPOINT, 'Failed to create issue', error, {
        reviewId: issue.id,
        title: issue.title,
      })
      results.errors.push({
        review_id: issue.id,
        title: issue.title,
        error: 'Falha ao criar issue',
      })
    }
  }

  logResult(ENDPOINT, 'createIssuesFromReview', {
    created: results.created,
    errorsCount: results.errors.length,
  })

  return results
}

// ============================================================================
// HANDLER PRINCIPAL
// ============================================================================

/**
 * Handler para requisições HTTP
 * @param {Object} req - Requisição HTTP
 * @param {Object} res - Resposta HTTP
 */
export async function handleCreateIssues(req, res) {
  // Log inicial da requisição
  logRequest(ENDPOINT, req)

  // Rate limiting
  const clientIP = getClientIP(req)
  if (!checkRateLimit(clientIP)) {
    logInfo(ENDPOINT, 'Rate limit exceeded', { clientIP: clientIP.substring(0, 3) + '***' })
    return rateLimitResponse(res, getRateLimitHeaders(clientIP))
  }

  // Verificar método HTTP
  if (req.method !== 'POST') {
    logInfo(ENDPOINT, 'Method not allowed', { method: req.method })
    return res.status(405).json({
      success: false,
      error: 'Método não permitido. Use POST.',
    })
  }

  // Verificar variáveis de ambiente
  if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY) {
    logError(ENDPOINT, 'Missing environment variables', new Error('SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY not set'))
    return res.status(500).json({
      success: false,
      error: 'Configuração do servidor incompleta.',
    })
  }

  // Verificar autenticação
  const authResult = verifyAuth(req)
  logAuth(ENDPOINT, authResult.success, authResult.reason)

  if (!authResult.success) {
    return res.status(401).json({
      success: false,
      error: 'Não autorizado. Token inválido ou expirado.',
    })
  }

  try {
    let requestData

    // Se blob_url fornecida, baixar dados do Blob
    if (req.body.blob_url) {
      logInfo(ENDPOINT, 'Blob URL provided, downloading...', {
        blobUrl: req.body.blob_url.split('?')[0],
      })
      try {
        const blobData = await downloadFromBlob(req.body.blob_url)
        requestData = { ...blobData, ...req.body }
      } catch (error) {
        logError(ENDPOINT, 'Failed to download from Blob', error, {
          blobUrl: req.body.blob_url.split('?')[0],
        })
        return res.status(400).json({
          success: false,
          error: 'Erro ao baixar dados do Blob',
        })
      }
    } else {
      logInfo(ENDPOINT, 'Using body directly (no blob URL)')
      requestData = req.body
    }

    // Validar body da requisição
    logInfo(ENDPOINT, 'Validating request data', {
      pr_number: requestData?.pr_number,
      owner: requestData?.owner,
      repo: requestData?.repo,
      commit_sha: requestData?.commit_sha?.substring(0, 8),
      issuesCount: requestData?.issues?.length || 0,
    })

    const validation = createIssuesRequestSchema.safeParse(requestData)

    if (!validation.success) {
      logInfo(ENDPOINT, 'Validation failed', {
        errors: validation.error.issues.map((i) => ({
          field: i.path.join('.'),
          message: i.message,
        })),
      })
      return res.status(400).json({
        success: false,
        error: 'Dados inválidos',
        details: validation.error.issues.map((issue) => ({
          field: issue.path.join('.'),
          message: issue.message,
        })),
      })
    }

    const validatedData = validation.data
    logInfo(ENDPOINT, 'Validation successful', {
      pr_number: validatedData.pr_number,
      owner: validatedData.owner,
      repo: validatedData.repo,
    })

    // Usar GITHUB_TOKEN do ambiente apenas (não aceita do body por segurança)
    const githubToken = GITHUB_TOKEN

    if (!githubToken) {
      logError(ENDPOINT, 'GitHub token not configured', new Error('GITHUB_TOKEN not set'))
      return res.status(500).json({
        success: false,
        error: 'Token GitHub não configurado.',
      })
    }

    // Criar cliente Supabase
    logSupabase(ENDPOINT, 'connect', 'gemini_reviews', { operation: 'createClient' })
    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY)

    // Criar issues
    const results = await createIssuesFromReview(supabase, validatedData, githubToken)

    // Retornar resultado
    const hasErrors = results.errors.length > 0
    const allFailed = results.created === 0 && hasErrors

    const responseHeaders = getRateLimitHeaders(clientIP)

    logResult(ENDPOINT, 'handler', {
      created: results.created,
      errorsCount: results.errors.length,
      allFailed,
    })

    // Set headers individually (Vercel serverless doesn't support .set() chain)
    Object.entries(responseHeaders).forEach(([key, value]) => {
      res.setHeader(key, value)
    })

    return res
      .status(hasErrors ? (allFailed ? 500 : 207) : 200)
      .json({
        success: !allFailed,
        data: results,
        ...(hasErrors && { partial: !allFailed }),
      })
  } catch (error) {
    logError(ENDPOINT, 'Unhandled error in handler', error, {
      errorMessage: error.message,
      errorStack: error.stack,
    })
    return internalErrorResponse(res, error, 'create-issues')
  }
}

/**
 * Handler para persistir reviews do Gemini no Supabase
 *
 * Recebe dados de review via POST (ou baixa do Vercel Blob se blob_url fornecida),
 * valida autenticação JWT, calcula hash SHA-256 dos issues e persiste com
 * deduplicação por hash na tabela gemini_reviews.
 *
 * @module api/gemini-reviews/_handlers/persist
 * @version 1.1.0
 */

import { createClient } from '@supabase/supabase-js'
import { z } from 'zod'
import jwt from 'jsonwebtoken'
import crypto from 'crypto'
import {
  checkRateLimit,
  getRateLimitHeaders,
  getClientIP,
  rateLimitResponse,
  internalErrorResponse,
  fetchWithRetry,
} from '../_shared/security.js'
import {
  logRequest,
  logAuth,
  logSupabase,
  logBlobDownload,
  logResult,
  logError,
  logInfo,
} from '../_shared/logger.js'

const ENDPOINT = 'persist'

// ============================================================================
// CONFIGURAÇÃO
// ============================================================================

// Fallback para VITE_SUPABASE_URL caso SUPABASE_URL não esteja definida
// (Vercel pode ter apenas VITE_SUPABASE_URL configurada)
const SUPABASE_URL = process.env.SUPABASE_URL || process.env.VITE_SUPABASE_URL
const SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY
const VERCEL_GITHUB_ACTIONS_SECRET = process.env.VERCEL_GITHUB_ACTIONS_SECRET
// Token para acessar blobs privados do Vercel Blob Storage
const BLOB_READ_WRITE_TOKEN = process.env.BLOB_READ_WRITE_TOKEN || process.env.VERCEL_BLOB_TOKEN

/**
 * UUID do usuário sistema para reviews do Gemini.
 * Este UUID representa o agente automatizado do Gemini Code Assist.
 * Nota: Este usuário deve existir em auth.users ou a constraint de FK falhará.
 * Alternativa: tornar user_id nullable via migração se necessário.
 */
const GEMINI_SYSTEM_USER_ID = '00000000-0000-0000-0000-000000000000'

// ============================================================================
// SCHEMAS ZOD
// ============================================================================

/**
 * Schema para um issue individual do review
 */
const issueSchema = z.object({
  file_path: z.string().optional(),
  file: z.string().optional(),
  line_start: z.number().int().optional(),
  line: z.number().int().optional(),
  line_end: z.number().int().optional(),
  title: z.string().optional(),
  issue: z.string().optional(),
  description: z.string().optional(),
  suggestion: z.string().nullable().optional(), // Allow both null and undefined
  priority: z.enum(['CRITICAL', 'HIGH', 'MEDIUM', 'LOW']).optional(),
  severity: z.enum(['CRITICAL', 'HIGH', 'MEDIUM', 'LOW']).optional(),
  category: z.string().optional(),
})

/**
 * Schema para o body da requisição
 */
const persistRequestSchema = z.object({
  pr_number: z.number().int().positive('Número do PR deve ser positivo'),
  commit_sha: z.string().min(1, 'Commit SHA é obrigatório'),
  issues: z.array(issueSchema),
  blob_url: z.string().url().optional(),
})

// ============================================================================
// FUNÇÕES DE AUTENTICAÇÃO
// ============================================================================

/**
 * Verifica autenticação JWT
 * @param {Object} req - Requisição HTTP
 * @returns {Object} Resultado com success e reason
 */
function verifyAuth(req) {
  const authHeader = req.headers.authorization || ''
  const token = authHeader.replace(/^Bearer\s+/i, '')

  if (!token) {
    return { success: false, reason: 'No token provided' }
  }

  if (!VERCEL_GITHUB_ACTIONS_SECRET) {
    return { success: false, reason: 'Secret not configured' }
  }

  try {
    jwt.verify(token, VERCEL_GITHUB_ACTIONS_SECRET, {
      issuer: 'github-actions',
      audience: 'vercel-api',
    })
    return { success: true }
  } catch (error) {
    return { success: false, reason: error.message }
  }
}

// ============================================================================
// FUNÇÕES DE HASH E DEDUPLICAÇÃO
// ============================================================================

/**
 * Calcula hash SHA-256 para uma issue
 * @param {Object} issue - Dados da issue
 * @returns {string} Hash SHA-256 (64 caracteres hexadecimais)
 */
function calculateIssueHash(issue) {
  const dataToHash = {
    file_path: issue.file_path || issue.file,
    line_start: issue.line_start || issue.line,
    line_end: issue.line_end || issue.line,
    title: issue.title || issue.issue?.substring(0, 100) || 'Untitled',
    description: issue.description || issue.issue || '',
    suggestion: issue.suggestion?.trim() || null,
  }
  const content = JSON.stringify(dataToHash, Object.keys(dataToHash).sort())

  return crypto.createHash('sha256').update(content).digest('hex')
}

/**
 * Verifica se uma issue já existe no banco
 * @param {Object} supabase - Cliente Supabase
 * @param {string} issueHash - Hash SHA-256
 * @returns {Promise<Object|null>} Registro existente ou null
 */
async function checkExistingHash(supabase, issueHash) {
  logSupabase(ENDPOINT, 'select', 'gemini_reviews', {
    operation: 'checkExistingHash',
    hashPrefix: issueHash.substring(0, 16),
  })

  const { data, error } = await supabase
    .from('gemini_reviews')
    .select('id, status, github_issue_number, created_at, updated_at')
    .eq('issue_hash', issueHash)
    .maybeSingle()

  if (error) {
    logError(ENDPOINT, 'Error checking existing hash', error, {
      hashPrefix: issueHash.substring(0, 16),
    })
    throw new Error(`Erro ao verificar hash: ${error.message}`)
  }

  logInfo(ENDPOINT, 'Hash check result', {
    hashPrefix: issueHash.substring(0, 16),
    exists: !!data,
    status: data?.status,
  })

  return data
}

// ============================================================================
// FUNÇÕES DE MAPEAMENTO
// ============================================================================

/**
 * Mapeia prioridade do Gemini para formato do banco
 * @param {string} priority - Prioridade do Gemini
 * @returns {string} Prioridade mapeada
 */
function mapPriority(priority) {
  const map = {
    CRITICAL: 'critica',
    HIGH: 'alta',
    MEDIUM: 'media',
    LOW: 'baixa',
    critical: 'critica',
    high: 'alta',
    medium: 'media',
    low: 'baixa',
  }
  return map[priority] || 'media'
}

/**
 * Mapeia categoria do Gemini para formato do banco
 * @param {string} category - Categoria do Gemini
 * @returns {string} Categoria mapeada
 */
function mapCategory(category) {
  const map = {
    style: 'estilo',
    bug: 'bug',
    security: 'seguranca',
    performance: 'performance',
    maintainability: 'manutenibilidade',
    refactoring: 'manutenibilidade',
    'best-practice': 'manutenibilidade',
  }
  // Default para 'manutenibilidade' pois 'geral' não é válido no CHECK constraint
  return map[category?.toLowerCase()] || 'manutenibilidade'
}

// ============================================================================
// FUNÇÕES DE PERSISTÊNCIA
// ============================================================================

/**
 * Decide ação para issue existente
 * @param {Object} supabase - Cliente Supabase
 * @param {Object} existing - Registro existente
 * @param {Object} newIssue - Nova issue detectada
 * @param {number} prNumber - Número do PR
 * @param {string} commitSha - SHA do commit
 * @returns {Promise<string>} Ação: 'skipped', 'updated', 'reactivated'
 */
async function handleExistingIssue(supabase, existing, newIssue, prNumber, commitSha) {
  const { id, status } = existing

  logInfo(ENDPOINT, 'handleExistingIssue', {
    id,
    currentStatus: status,
    prNumber,
    commitSha: commitSha.substring(0, 8),
  })

  // Estados finais - ignorar
  const finalStatuses = ['wontfix', 'duplicate']
  if (finalStatuses.includes(status)) {
    logInfo(ENDPOINT, 'Issue in final status, skipping', { id, status })
    return 'skipped'
  }

  // Resolvida - reativar (re-introdução)
  if (status === 'resolved') {
    logSupabase(ENDPOINT, 'update', 'gemini_reviews', {
      operation: 'reactivateResolved',
      id,
      fromStatus: 'resolved',
      toStatus: 'detected',
    })
    await supabase
      .from('gemini_reviews')
      .update({
        status: 'detected',
        pr_number: prNumber,
        commit_sha: commitSha,
        updated_at: new Date().toISOString(),
        resolution_type: null,
        resolved_by: null,
        resolved_at: null,
      })
      .eq('id', id)
    return 'reactivated'
  }

  // Parcial - reativar para reported
  if (status === 'partial') {
    logSupabase(ENDPOINT, 'update', 'gemini_reviews', {
      operation: 'reactivatePartial',
      id,
      fromStatus: 'partial',
      toStatus: 'reported',
    })
    await supabase
      .from('gemini_reviews')
      .update({
        status: 'reported',
        pr_number: prNumber,
        commit_sha: commitSha,
        updated_at: new Date().toISOString(),
      })
      .eq('id', id)
    return 'reactivated'
  }

  // Detected/reported/assigned - atualizar referências
  logSupabase(ENDPOINT, 'update', 'gemini_reviews', {
    operation: 'updateReferences',
    id,
    status,
  })
  await supabase
    .from('gemini_reviews')
    .update({
      pr_number: prNumber,
      commit_sha: commitSha,
      updated_at: new Date().toISOString(),
    })
    .eq('id', id)
  return 'updated'
}

/**
 * Cria nova issue no Supabase
 * @param {Object} supabase - Cliente Supabase
 * @param {Object} issue - Dados da issue
 * @param {string} issueHash - Hash SHA-256
 * @param {number} prNumber - Número do PR
 * @param {string} commitSha - SHA do commit
 * @returns {Promise<Object>} Issue criada
 */
async function createNewIssue(supabase, issue, issueHash, prNumber, commitSha) {
  const insertData = {
    user_id: GEMINI_SYSTEM_USER_ID,
    pr_number: prNumber,
    commit_sha: commitSha,
    file_path: issue.file_path || issue.file,
    line_start: issue.line_start || issue.line || null,
    line_end: issue.line_end || issue.line || null,
    issue_hash: issueHash,
    status: 'detected',
    priority: mapPriority(issue.priority || issue.severity),
    category: mapCategory(issue.category),
    title: issue.title || issue.issue?.substring(0, 200) || 'Sem título',
    description: issue.description || issue.issue || '',
    suggestion: issue.suggestion || null,
  }

  logSupabase(ENDPOINT, 'insert', 'gemini_reviews', {
    operation: 'createNewIssue',
    hashPrefix: issueHash.substring(0, 16),
    filePath: insertData.file_path,
    priority: insertData.priority,
    category: insertData.category,
  })

  const { data, error } = await supabase.from('gemini_reviews').insert(insertData).select().single()

  if (error) {
    logError(ENDPOINT, 'Error creating new issue', error, {
      errorCode: error.code,
      errorMessage: error.message,
      hashPrefix: issueHash.substring(0, 16),
    })
    // Tratar violação de UNIQUE constraint
    if (error.code === '23505') {
      throw new Error(`Hash collision detectado`)
    }
    throw new Error('Falha ao criar registro')
  }

  logInfo(ENDPOINT, 'Issue created successfully', {
    id: data.id,
    hashPrefix: issueHash.substring(0, 16),
  })

  return data
}

/**
 * Persiste reviews com deduplicação por hash
 * @param {Object} supabase - Cliente Supabase
 * @param {Object} reviewData - Dados do review
 * @returns {Promise<Object>} Resultado da persistência
 */
async function persistReviews(supabase, reviewData) {
  const { pr_number, commit_sha, issues } = reviewData

  logInfo(ENDPOINT, 'persistReviews started', {
    pr_number,
    commit_sha: commit_sha.substring(0, 8),
    issuesCount: issues.length,
  })

  const results = {
    created: 0,
    updated: 0,
    skipped: 0,
    reactivated: 0,
    errors: [],
    createdIssues: [],
  }

  for (const [index, issue] of issues.entries()) {
    try {
      const issueHash = calculateIssueHash(issue)
      logInfo(ENDPOINT, `Processing issue ${index + 1}/${issues.length}`, {
        hashPrefix: issueHash.substring(0, 16),
        title: issue.title || issue.issue?.substring(0, 50) || 'Untitled',
      })

      const existing = await checkExistingHash(supabase, issueHash)

      if (existing) {
        const action = await handleExistingIssue(supabase, existing, issue, pr_number, commit_sha)
        logInfo(ENDPOINT, 'Existing issue handled', {
          hashPrefix: issueHash.substring(0, 16),
          action,
          existingStatus: existing.status,
        })

        switch (action) {
          case 'skipped':
            results.skipped++
            break
          case 'updated':
            results.updated++
            break
          case 'reactivated':
            results.reactivated++
            break
        }
        continue
      }

      // Criar nova issue
      const newIssue = await createNewIssue(supabase, issue, issueHash, pr_number, commit_sha)
      results.created++
      results.createdIssues.push({
        id: newIssue.id,
        hash: issueHash,
        status: newIssue.status,
      })
    } catch (error) {
      logError(ENDPOINT, 'Error processing issue', error, {
        issueIndex: index,
        issueTitle: issue.title || 'Sem título',
      })
      results.errors.push({
        issue: issue.title || 'Sem título',
        error: 'Falha ao processar',
      })
    }
  }

  logInfo(ENDPOINT, 'persistReviews completed', {
    created: results.created,
    updated: results.updated,
    skipped: results.skipped,
    reactivated: results.reactivated,
    errorsCount: results.errors.length,
  })

  return results
}

/**
 * Baixa dados do review do Vercel Blob usando fetch com retry
 * @param {string} blobUrl - URL do blob
 * @returns {Promise<Object>} Dados do review
 */
async function downloadFromBlob(blobUrl) {
  logBlobDownload(ENDPOINT, blobUrl, { status: 'starting' })

  // Para blobs privados, precisamos do token de autenticação
  const headers = {}
  if (BLOB_READ_WRITE_TOKEN) {
    headers['Authorization'] = `Bearer ${BLOB_READ_WRITE_TOKEN}`
    logInfo(ENDPOINT, 'Using BLOB_READ_WRITE_TOKEN for authentication')
  } else {
    logInfo(ENDPOINT, 'No BLOB_READ_WRITE_TOKEN found, attempting public access')
  }

  const response = await fetchWithRetry(blobUrl, { headers }, 3)

  if (!response.ok) {
    logError(ENDPOINT, 'Blob download failed', new Error(`HTTP ${response.status}`), {
      status: response.status,
      statusText: response.statusText,
    })
    throw new Error(`Falha ao baixar do Blob: ${response.status} ${response.statusText}`)
  }

  const data = await response.json()
  logBlobDownload(ENDPOINT, blobUrl, {
    status: 'success',
    dataSize: JSON.stringify(data).length,
    issuesCount: data?.issues?.length || 0,
  })

  return data
}

// ============================================================================
// HANDLER PRINCIPAL
// ============================================================================

/**
 * Handler para requisições HTTP
 * @param {Object} req - Requisição HTTP
 * @param {Object} res - Resposta HTTP
 */
export async function handlePersist(req, res) {
  // Log inicial da requisição
  logRequest(ENDPOINT, req)

  // Rate limiting
  const clientIP = getClientIP(req)
  if (!checkRateLimit(clientIP)) {
    logInfo(ENDPOINT, 'Rate limit exceeded', { clientIP: clientIP.substring(0, 3) + '***' })
    return rateLimitResponse(res, getRateLimitHeaders(clientIP))
  }

  // Verificar método HTTP
  if (req.method !== 'POST') {
    logInfo(ENDPOINT, 'Method not allowed', { method: req.method })
    return res.status(405).json({
      success: false,
      error: 'Método não permitido. Use POST.',
    })
  }

  // Verificar variáveis de ambiente
  if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY) {
    logError(ENDPOINT, 'Missing environment variables', new Error('SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY not set'))
    return res.status(500).json({
      success: false,
      error: 'Configuração do servidor incompleta.',
    })
  }

  // Verificar autenticação
  const authResult = verifyAuth(req)
  logAuth(ENDPOINT, authResult.success, authResult.reason)

  if (!authResult.success) {
    return res.status(401).json({
      success: false,
      error: 'Não autorizado. Token inválido ou expirado.',
    })
  }

  try {
    let reviewData

    // Se blob_url fornecida, baixar dados do Blob
    if (req.body.blob_url) {
      logInfo(ENDPOINT, 'Blob URL provided, downloading...', {
        blobUrl: req.body.blob_url.split('?')[0],
      })
      try {
        const blobData = await downloadFromBlob(req.body.blob_url)
        // Mescla os dados do blob com os do corpo da requisição, dando prioridade aos valores do corpo.
        reviewData = { ...blobData, ...req.body }
      } catch (error) {
        logError(ENDPOINT, 'Failed to download from Blob', error, {
          blobUrl: req.body.blob_url.split('?')[0],
        })
        return res.status(400).json({
          success: false,
          error: 'Erro ao baixar dados do Blob',
        })
      }
    } else {
      logInfo(ENDPOINT, 'Using body directly (no blob URL)')
      reviewData = req.body
    }

    // Validar body da requisição
    logInfo(ENDPOINT, 'Validating request data', {
      pr_number: reviewData?.pr_number,
      commit_sha: reviewData?.commit_sha?.substring(0, 8),
      issuesCount: reviewData?.issues?.length || 0,
    })

    const validation = persistRequestSchema.safeParse(reviewData)

    if (!validation.success) {
      logInfo(ENDPOINT, 'Validation failed', {
        errors: validation.error.issues.map((i) => ({
          field: i.path.join('.'),
          message: i.message,
        })),
      })
      return res.status(400).json({
        success: false,
        error: 'Dados inválidos',
        details: validation.error.issues.map((issue) => ({
          field: issue.path.join('.'),
          message: issue.message,
        })),
      })
    }

    const validatedData = validation.data
    logInfo(ENDPOINT, 'Validation successful', {
      pr_number: validatedData.pr_number,
      commit_sha: validatedData.commit_sha.substring(0, 8),
      issuesCount: validatedData.issues.length,
    })

    // Criar cliente Supabase
    logSupabase(ENDPOINT, 'connect', 'gemini_reviews', {
      operation: 'createClient',
    })
    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY)

    // Persistir reviews
    logInfo(ENDPOINT, 'Starting persistReviews', {
      issuesCount: validatedData.issues.length,
    })
    const results = await persistReviews(supabase, validatedData)

    // Retornar resultado
    const responseHeaders = getRateLimitHeaders(clientIP)

    logResult(ENDPOINT, 'persistReviews', {
      created: results.created,
      updated: results.updated,
      skipped: results.skipped,
      reactivated: results.reactivated,
      errorsCount: results.errors.length,
    })

    // Set headers individually (Vercel serverless doesn't support .set() chain)
    Object.entries(responseHeaders).forEach(([key, value]) => {
      res.setHeader(key, value)
    })

    return res.status(200).json({
      success: true,
      data: results,
    })
  } catch (error) {
    logError(ENDPOINT, 'Unhandled error in handler', error, {
      errorMessage: error.message,
      errorStack: error.stack,
    })
    return internalErrorResponse(res, error, 'persist')
  }
}

/**
 * Handler para atualizar status de resolução de reviews do Gemini
 *
 * Recebe atualização de status (resolved, partial, wontfix, duplicate),
 * valida autenticação JWT e atualiza o registro no Supabase.
 *
 * @module api/gemini-reviews/_handlers/update-status
 * @version 1.1.0
 */

import { createClient } from '@supabase/supabase-js'
import { z } from 'zod'
import jwt from 'jsonwebtoken'
import {
  checkRateLimit,
  getRateLimitHeaders,
  getClientIP,
  rateLimitResponse,
  internalErrorResponse,
} from '../_shared/security.js'
import {
  logRequest,
  logAuth,
  logSupabase,
  logResult,
  logError,
  logInfo,
} from '../_shared/logger.js'

const ENDPOINT = 'update-status'

// ============================================================================
// CONFIGURAÇÃO
// ============================================================================

// Fallback para VITE_SUPABASE_URL caso SUPABASE_URL não esteja definida
// (Vercel pode ter apenas VITE_SUPABASE_URL configurada)
const SUPABASE_URL = process.env.SUPABASE_URL || process.env.VITE_SUPABASE_URL
const SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY
const VERCEL_GITHUB_ACTIONS_SECRET = process.env.VERCEL_GITHUB_ACTIONS_SECRET

// ============================================================================
// CONSTANTES
// ============================================================================

/**
 * Status possíveis das reviews
 * @readonly
 */
const REVIEW_STATUSES = [
  'detected',
  'reported',
  'assigned',
  'resolved',
  'partial',
  'wontfix',
  'duplicate',
]

/**
 * Tipos de resolução possíveis
 * @readonly
 */
const RESOLUTION_TYPES = ['fixed', 'rejected', 'partial']

// ============================================================================
// SCHEMAS ZOD
// ============================================================================

/**
 * Schema para o body da requisição
 */
const updateStatusSchema = z.object({
  review_id: z.string().uuid('ID da review deve ser um UUID válido'),
  status: z.enum(REVIEW_STATUSES, {
    errorMap: () => ({ message: 'Status inválido' }),
  }),
  resolution_type: z.enum(RESOLUTION_TYPES).nullable().optional(),
  commit_sha: z.string().min(1).optional(),
  resolved_by: z.string().uuid().nullable().optional(),
})

/**
 * Schema para atualização em batch (múltiplas reviews)
 */
const batchUpdateSchema = z.object({
  updates: z
    .array(updateStatusSchema)
    .min(1, 'Deve haver pelo menos uma atualização')
    .max(100, 'Máximo de 100 atualizações por requisição'),
})

// ============================================================================
// FUNÇÕES DE AUTENTICAÇÃO
// ============================================================================

/**
 * Verifica autenticação JWT
 * @param {Object} req - Requisição HTTP
 * @returns {Object} Resultado com success e reason
 */
function verifyAuth(req) {
  const authHeader = req.headers.authorization || ''
  const token = authHeader.replace(/^Bearer\s+/i, '')

  if (!token) {
    return { success: false, reason: 'No token provided' }
  }

  if (!VERCEL_GITHUB_ACTIONS_SECRET) {
    return { success: false, reason: 'Secret not configured' }
  }

  try {
    jwt.verify(token, VERCEL_GITHUB_ACTIONS_SECRET, {
      issuer: 'github-actions',
      audience: 'vercel-api',
    })
    return { success: true }
  } catch (error) {
    return { success: false, reason: error.message }
  }
}

// ============================================================================
// FUNÇÕES DE ATUALIZAÇÃO
// ============================================================================

/**
 * Atualiza o status de uma review no Supabase
 * @param {Object} supabase - Cliente Supabase
 * @param {Object} update - Dados da atualização
 * @returns {Promise<Object>} Resultado da atualização
 */
async function updateReviewStatus(supabase, update) {
  const { review_id, status, resolution_type, commit_sha, resolved_by } = update

  logSupabase(ENDPOINT, 'update', 'gemini_reviews', {
    operation: 'updateReviewStatus',
    review_id,
    newStatus: status,
    resolution_type,
  })

  // Construir objeto de atualização
  const updateData = {
    status,
    updated_at: new Date().toISOString(),
  }

  if (resolution_type !== undefined) {
    updateData.resolution_type = resolution_type
  }

  if (commit_sha !== undefined) {
    updateData.commit_sha = commit_sha
  }

  if (resolved_by !== undefined) {
    updateData.resolved_by = resolved_by
  }

  // Se status é resolved/partial/wontfix, adicionar resolved_at
  if (['resolved', 'partial', 'wontfix'].includes(status)) {
    updateData.resolved_at = new Date().toISOString()
  }

  const { data, error } = await supabase
    .from('gemini_reviews')
    .update(updateData)
    .eq('id', review_id)
    .select('id, status, github_issue_number')
    .single()

  if (error) {
    logError(ENDPOINT, 'Error updating review status', error, {
      review_id,
      status,
      errorMessage: error.message,
      errorCode: error.code,
    })
    throw new Error('Erro ao atualizar review')
  }

  logInfo(ENDPOINT, 'Review status updated', {
    review_id,
    status: data.status,
    github_issue_number: data.github_issue_number,
  })

  return data
}

/**
 * Processa atualização de uma única review
 * @param {Object} supabase - Cliente Supabase
 * @param {Object} update - Dados da atualização
 * @returns {Promise<Object>} Resultado da atualização
 */
async function processSingleUpdate(supabase, update) {
  logInfo(ENDPOINT, 'Processing single update', {
    review_id: update.review_id,
    status: update.status,
  })

  try {
    const updated = await updateReviewStatus(supabase, update)
    return {
      review_id: update.review_id,
      status: updated.status,
      github_issue_number: updated.github_issue_number,
      success: true,
    }
  } catch (error) {
    logError(ENDPOINT, 'Failed to process single update', error, {
      review_id: update.review_id,
    })
    return {
      review_id: update.review_id,
      success: false,
      error: 'Falha ao atualizar',
    }
  }
}

/**
 * Processa atualizações em batch
 * @param {Object} supabase - Cliente Supabase
 * @param {Array<Object>} updates - Lista de atualizações
 * @returns {Promise<Object>} Resultado do processamento
 */
async function processBatchUpdates(supabase, updates) {
  logInfo(ENDPOINT, 'Processing batch updates', {
    count: updates.length,
  })

  const results = {
    success: [],
    errors: [],
  }

  for (const [index, update] of updates.entries()) {
    logInfo(ENDPOINT, `Processing update ${index + 1}/${updates.length}`, {
      review_id: update.review_id,
    })

    const result = await processSingleUpdate(supabase, update)

    if (result.success) {
      results.success.push({
        review_id: result.review_id,
        status: result.status,
        github_issue_number: result.github_issue_number,
      })
    } else {
      results.errors.push({
        review_id: result.review_id,
        error: result.error,
      })
    }
  }

  logResult(ENDPOINT, 'batchUpdates', {
    successCount: results.success.length,
    errorsCount: results.errors.length,
  })

  return results
}

// ============================================================================
// HANDLER PRINCIPAL
// ============================================================================

/**
 * Handler para requisições HTTP
 * @param {Object} req - Requisição HTTP
 * @param {Object} res - Resposta HTTP
 */
export async function handleUpdateStatus(req, res) {
  // Log inicial da requisição
  logRequest(ENDPOINT, req)

  // Rate limiting
  const clientIP = getClientIP(req)
  if (!checkRateLimit(clientIP)) {
    logInfo(ENDPOINT, 'Rate limit exceeded', { clientIP: clientIP.substring(0, 3) + '***' })
    return rateLimitResponse(res, getRateLimitHeaders(clientIP))
  }

  // Verificar método HTTP
  if (req.method !== 'POST') {
    logInfo(ENDPOINT, 'Method not allowed', { method: req.method })
    return res.status(405).json({
      success: false,
      error: 'Método não permitido. Use POST.',
    })
  }

  // Verificar variáveis de ambiente
  if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY) {
    logError(ENDPOINT, 'Missing environment variables', new Error('SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY not set'))
    return res.status(500).json({
      success: false,
      error: 'Configuração do servidor incompleta.',
    })
  }

  // Verificar autenticação
  const authResult = verifyAuth(req)
  logAuth(ENDPOINT, authResult.success, authResult.reason)

  if (!authResult.success) {
    return res.status(401).json({
      success: false,
      error: 'Não autorizado. Token inválido ou expirado.',
    })
  }

  try {
    // Detectar se é batch ou single update
    const isBatch = Array.isArray(req.body.updates)

    logInfo(ENDPOINT, 'Request type detected', {
      isBatch,
      bodyKeys: Object.keys(req.body || {}),
    })

    if (isBatch) {
      logInfo(ENDPOINT, 'Processing batch update', {
        updatesCount: req.body.updates?.length,
      })

      // Validação batch
      const validation = batchUpdateSchema.safeParse(req.body)

      if (!validation.success) {
        logInfo(ENDPOINT, 'Batch validation failed', {
          errors: validation.error.issues.map((i) => ({
            field: i.path.join('.'),
            message: i.message,
          })),
        })
        return res.status(400).json({
          success: false,
          error: 'Dados inválidos',
          details: validation.error.issues.map((issue) => ({
            field: issue.path.join('.'),
            message: issue.message,
          })),
        })
      }

      const { updates } = validation.data

      logInfo(ENDPOINT, 'Batch validation successful', {
        updatesCount: updates.length,
      })

      // Criar cliente Supabase
      logSupabase(ENDPOINT, 'connect', 'gemini_reviews', { operation: 'createClient' })
      const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY)

      // Processar atualizações em batch
      const results = await processBatchUpdates(supabase, updates)

      // Retornar resultado
      const hasErrors = results.errors.length > 0
      const allFailed = results.success.length === 0

      const responseHeaders = getRateLimitHeaders(clientIP)

      logResult(ENDPOINT, 'batchUpdate', {
        successCount: results.success.length,
        errorsCount: results.errors.length,
        allFailed,
      })

      // Set headers individually (Vercel serverless doesn't support .set() chain)
      Object.entries(responseHeaders).forEach(([key, value]) => {
        res.setHeader(key, value)
      })

      return res
        .status(hasErrors ? (allFailed ? 500 : 207) : 200)
        .json({
          success: !allFailed,
          updated: results.success.length,
          errors: results.errors,
          ...(hasErrors && { partial: !allFailed }),
        })
    } else {
      logInfo(ENDPOINT, 'Processing single update', {
        review_id: req.body.review_id,
        status: req.body.status,
      })

      // Validação single
      const validation = updateStatusSchema.safeParse(req.body)

      if (!validation.success) {
        logInfo(ENDPOINT, 'Single validation failed', {
          errors: validation.error.issues.map((i) => ({
            field: i.path.join('.'),
            message: i.message,
          })),
        })
        return res.status(400).json({
          success: false,
          error: 'Dados inválidos',
          details: validation.error.issues.map((issue) => ({
            field: issue.path.join('.'),
            message: issue.message,
          })),
        })
      }

      const update = validation.data

      logInfo(ENDPOINT, 'Single validation successful', {
        review_id: update.review_id,
        status: update.status,
      })

      // Criar cliente Supabase
      logSupabase(ENDPOINT, 'connect', 'gemini_reviews', { operation: 'createClient' })
      const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY)

      // Processar atualização única
      const result = await processSingleUpdate(supabase, update)

      if (!result.success) {
        logError(ENDPOINT, 'Single update failed', new Error(result.error), {
          review_id: result.review_id,
        })
        return res.status(500).json({
          success: false,
          error: 'Falha ao atualizar status',
          review_id: result.review_id,
        })
      }

      const responseHeaders = getRateLimitHeaders(clientIP)

      logResult(ENDPOINT, 'singleUpdate', {
        review_id: result.review_id,
        status: result.status,
      })

      // Set headers individually (Vercel serverless doesn't support .set() chain)
      Object.entries(responseHeaders).forEach(([key, value]) => {
        res.setHeader(key, value)
      })

      return res.status(200).json({
        success: true,
        data: {
          review_id: result.review_id,
          status: result.status,
          github_issue_number: result.github_issue_number,
        },
      })
    }
  } catch (error) {
    logError(ENDPOINT, 'Unhandled error in handler', error, {
      errorMessage: error.message,
      errorStack: error.stack,
    })
    return internalErrorResponse(res, error, 'update-status')
  }
}

/**
 * Logger estruturado para endpoints da API Gemini Reviews
 *
 * Fornece logging consistente com níveis e formatação JSON
 * para fácil parsing nos logs da Vercel.
 *
 * @module api/gemini-reviews/shared/logger
 * @version 1.0.0
 */

// ============================================================================
// CONSTANTES
// ============================================================================

/**
 * Níveis de log disponíveis
 * @readonly
 */
export const LOG_LEVELS = {
  DEBUG: 'debug',
  INFO: 'info',
  WARN: 'warn',
  ERROR: 'error',
}

/**
 * Prefixo para identificar logs nos endpoints Gemini
 */
const LOG_PREFIX = '[gemini-api]'

// ============================================================================
// FUNÇÕES DE LOG
// ============================================================================

/**
 * Log estruturado com timestamp e contexto
 * @param {string} endpoint - Nome do endpoint (persist, create-issues, etc.)
 * @param {string} level - Nível do log (debug, info, warn, error)
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais para o log
 */
export function log(endpoint, level, message, data = {}) {
  const timestamp = new Date().toISOString()
  const logEntry = {
    timestamp,
    endpoint,
    level,
    message,
    ...data,
  }

  const formattedMessage = `${LOG_PREFIX}[${endpoint}] ${message}`

  if (level === LOG_LEVELS.ERROR) {
    console.error(formattedMessage, JSON.stringify(logEntry, null, 2))
  } else if (level === LOG_LEVELS.WARN) {
    console.warn(formattedMessage, JSON.stringify(logEntry, null, 2))
  } else {
    console.log(formattedMessage, JSON.stringify(logEntry, null, 2))
  }
}

/**
 * Log de debug (detalhes finos para troubleshooting)
 * @param {string} endpoint - Nome do endpoint
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
export function logDebug(endpoint, message, data = {}) {
  log(endpoint, LOG_LEVELS.DEBUG, message, data)
}

/**
 * Log de informação (eventos normais)
 * @param {string} endpoint - Nome do endpoint
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
export function logInfo(endpoint, message, data = {}) {
  log(endpoint, LOG_LEVELS.INFO, message, data)
}

/**
 * Log de aviso (situações anômalas mas não críticas)
 * @param {string} endpoint - Nome do endpoint
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
export function logWarn(endpoint, message, data = {}) {
  log(endpoint, LOG_LEVELS.WARN, message, data)
}

/**
 * Log de erro com detalhes completos do erro
 * @param {string} endpoint - Nome do endpoint
 * @param {string} message - Mensagem descritiva
 * @param {Error|Object} error - Erro ocorrido
 * @param {Object} additionalData - Dados adicionais de contexto
 */
export function logError(endpoint, message, error, additionalData = {}) {
  const errorDetails = error instanceof Error
    ? {
        name: error.name,
        message: error.message,
        stack: error.stack,
        cause: error.cause,
      }
    : {
        error: String(error),
      }

  log(endpoint, LOG_LEVELS.ERROR, message, {
    ...errorDetails,
    ...additionalData,
  })
}

// ============================================================================
// FUNÇÕES DE LOG ESPECÍFICAS
// ============================================================================

/**
 * Log de requisição recebida
 * @param {string} endpoint - Nome do endpoint
 * @param {Object} req - Requisição HTTP
 */
export function logRequest(endpoint, req) {
  const sanitizedHeaders = { ...req.headers }
  // Remover dados sensíveis
  if (sanitizedHeaders.authorization) {
    sanitizedHeaders.authorization = '[REDACTED]'
  }
  if (sanitizedHeaders.cookie) {
    sanitizedHeaders.cookie = '[REDACTED]'
  }

  logInfo(endpoint, 'Request received', {
    method: req.method,
    headers: sanitizedHeaders,
    bodyKeys: req.body ? Object.keys(req.body) : [],
    hasBody: !!req.body,
    bodyType: Array.isArray(req.body) ? 'array' : typeof req.body,
  })
}

/**
 * Log de validação JWT
 * @param {string} endpoint - Nome do endpoint
 * @param {boolean} success - Se a validação foi bem-sucedida
 * @param {string} [reason] - Razão da falha (se aplicável)
 */
export function logAuth(endpoint, success, reason = null) {
  if (success) {
    logInfo(endpoint, 'JWT validation successful')
  } else {
    logWarn(endpoint, 'JWT validation failed', { reason })
  }
}

/**
 * Log de operação com Supabase
 * @param {string} endpoint - Nome do endpoint
 * @param {string} operation - Nome da operação (select, insert, update)
 * @param {string} table - Nome da tabela
 * @param {Object} [details] - Detalhes adicionais
 */
export function logSupabase(endpoint, operation, table, details = {}) {
  logInfo(endpoint, `Supabase ${operation}`, {
    table,
    operation,
    ...details,
  })
}

/**
 * Log de operação com GitHub API
 * @param {string} endpoint - Nome do endpoint
 * @param {string} operation - Nome da operação
 * @param {Object} [details] - Detalhes adicionais
 */
export function logGitHub(endpoint, operation, details = {}) {
  logInfo(endpoint, `GitHub API ${operation}`, {
    operation,
    ...details,
  })
}

/**
 * Log de download do Vercel Blob
 * @param {string} endpoint - Nome do endpoint
 * @param {string} blobUrl - URL do blob (sanitizada)
 * @param {Object} [result] - Resultado do download
 */
export function logBlobDownload(endpoint, blobUrl, result = {}) {
  // Sanitizar URL para não expor tokens
  const sanitizedUrl = blobUrl.split('?')[0]

  logInfo(endpoint, 'Blob download', {
    url: sanitizedUrl,
    ...result,
  })
}

/**
 * Log de resultado de operação
 * @param {string} endpoint - Nome do endpoint
 * @param {string} operation - Nome da operação
 * @param {Object} result - Resultado da operação
 */
export function logResult(endpoint, operation, result) {
  logInfo(endpoint, `${operation} completed`, {
    success: result.success !== false,
    ...result,
  })
}

/**
 * Log de rate limiting
 * @param {string} endpoint - Nome do endpoint
 * @param {string} clientIP - IP do cliente
 * @param {boolean} allowed - Se a requisição foi permitida
 * @param {Object} [details] - Detalhes adicionais
 */
export function logRateLimit(endpoint, clientIP, allowed, details = {}) {
  if (allowed) {
    logDebug(endpoint, 'Rate limit check passed', {
      clientIP: clientIP.substring(0, 3) + '***', // Partially mask IP
      ...details,
    })
  } else {
    logWarn(endpoint, 'Rate limit exceeded', {
      clientIP: clientIP.substring(0, 3) + '***',
      ...details,
    })
  }
}

/**
 * Log de retry de fetch
 * @param {string} endpoint - Nome do endpoint
 * @param {number} attempt - Número da tentativa
 * @param {number} maxRetries - Máximo de tentativas
 * @param {string} [reason] - Razão do retry
 */
export function logRetry(endpoint, attempt, maxRetries, reason = '') {
  logWarn(endpoint, `Fetch retry ${attempt}/${maxRetries}`, {
    attempt,
    maxRetries,
    reason,
  })
}

export default {
  log,
  logDebug,
  logInfo,
  logWarn,
  logError,
  logRequest,
  logAuth,
  logSupabase,
  logGitHub,
  logBlobDownload,
  logResult,
  logRateLimit,
  logRetry,
  LOG_LEVELS,
}

// api/health/notifications.js
import { createLogger } from '../../server/bot/logger.js';
import { getMetrics } from '../../server/services/notificationMetrics.js';
import { getDLQStats } from '../../server/services/deadLetterQueue.js';

const logger = createLogger('HealthNotifications');

/**
 * Thresholds para health checks
 */
const HEALTH_THRESHOLDS = {
  maxErrorRate: 5,           // 5% erro máximo
  maxDlqSize: 100,           // 100 notificações na DLQ
  maxMinutesSinceSuccess: 10, // 10 minutos sem sucesso
  maxRateLimitHitsPerHour: 10 // 10 rate limits por hora
};

/**
 * Verifica a saúde do sistema de notificações
 * @returns {object} Status de saúde
 */
async function checkHealth() {
  const metrics = getMetrics(5); // Últimos 5 minutos
  const dlqStats = await getDLQStats();

  const now = new Date();
  const checks = {
    errorRate: {
      status: 'healthy',
      value: metrics.summary.errorRate,
      threshold: HEALTH_THRESHOLDS.maxErrorRate,
      message: 'Taxa de erro dentro do limite'
    },
    dlqSize: {
      status: 'healthy',
      value: dlqStats.pending + dlqStats.retrying,
      threshold: HEALTH_THRESHOLDS.maxDlqSize,
      message: 'DLQ com tamanho adequado'
    },
    lastSuccessfulSend: {
      status: 'healthy',
      value: metrics.timestamps.lastSuccessfulSend,
      threshold: HEALTH_THRESHOLDS.maxMinutesSinceSuccess,
      message: 'Envios recentes detectados'
    },
    rateLimitHits: {
      status: 'healthy',
      value: metrics.summary.rateLimitHits,
      threshold: HEALTH_THRESHOLDS.maxRateLimitHitsPerHour,
      message: 'Rate limits dentro do esperado'
    }
  };

  // Verificar taxa de erro
  if (metrics.summary.errorRate > HEALTH_THRESHOLDS.maxErrorRate) {
    checks.errorRate.status = 'warning';
    checks.errorRate.message = `Taxa de erro alta: ${metrics.summary.errorRate.toFixed(1)}%`;
  }

  // Verificar DLQ
  if (checks.dlqSize.value > HEALTH_THRESHOLDS.maxDlqSize) {
    checks.dlqSize.status = 'critical';
    checks.dlqSize.message = `DLQ com ${checks.dlqSize.value} notificações pendentes`;
  } else if (checks.dlqSize.value > HEALTH_THRESHOLDS.maxDlqSize / 2) {
    checks.dlqSize.status = 'warning';
    checks.dlqSize.message = `DLQ com ${checks.dlqSize.value} notificações`;
  }

  // Verificar último envio bem-sucedido
  if (metrics.timestamps.lastSuccessfulSend) {
    const lastSuccess = new Date(metrics.timestamps.lastSuccessfulSend);
    const minutesSinceSuccess = (now - lastSuccess) / (1000 * 60);

    if (minutesSinceSuccess > HEALTH_THRESHOLDS.maxMinutesSinceSuccess) {
      checks.lastSuccessfulSend.status = 'critical';
      checks.lastSuccessfulSend.message = `Sem envios há ${Math.round(minutesSinceSuccess)} minutos`;
    } else if (minutesSinceSuccess > HEALTH_THRESHOLDS.maxMinutesSinceSuccess / 2) {
      checks.lastSuccessfulSend.status = 'warning';
      checks.lastSuccessfulSend.message = `Último envio há ${Math.round(minutesSinceSuccess)} minutos`;
    }
    checks.lastSuccessfulSend.minutesSince = Math.round(minutesSinceSuccess);
  } else {
    checks.lastSuccessfulSend.status = 'unknown';
    checks.lastSuccessfulSend.message = 'Nenhum envio registrado no período';
  }

  // Verificar rate limits
  if (metrics.summary.rateLimitHits > HEALTH_THRESHOLDS.maxRateLimitHitsPerHour) {
    checks.rateLimitHits.status = 'warning';
    checks.rateLimitHits.message = `${metrics.summary.rateLimitHits} rate limits no período`;
  }

  // Determinar status geral
  const statuses = Object.values(checks).map(c => c.status);
  let overallStatus = 'healthy';

  if (statuses.includes('critical')) {
    overallStatus = 'critical';
  } else if (statuses.includes('warning')) {
    overallStatus = 'warning';
  }

  return {
    status: overallStatus,
    timestamp: now.toISOString(),
    checks,
    metrics: {
      totalAttempts: metrics.summary.totalAttempts,
      successful: metrics.summary.successful,
      failed: metrics.summary.failed,
      errorRate: metrics.summary.errorRate,
      avgDeliveryTime: metrics.deliveryTime.avg
    }
  };
}

/**
 * Handler da API de health check
 */
export default async function handler(req, res) {
  // Apenas GET permitido
  if (req.method !== 'GET') {
    return res.status(405).json({ 
      error: 'Method not allowed',
      allowed: ['GET']
    });
  }

  logger.debug('Health check request', {
    ip: req.headers['x-forwarded-for'] || req.socket.remoteAddress,
    userAgent: req.headers['user-agent']
  });

  try {
    const health = await checkHealth();

    // Status HTTP baseado no health
    const statusCode = health.status === 'critical' ? 503 
                     : health.status === 'warning' ? 200 
                     : 200;

    // Headers para monitoramento
    res.setHeader('X-Health-Status', health.status);
    res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate');

    res.status(statusCode).json(health);

  } catch (error) {
    logger.error('Health check failed', error);

    res.status(500).json({
      status: 'error',
      error: error.message,
      timestamp: new Date().toISOString()
    });
  }
}

