// --- Bot Adapter (Minimal for Notifications) ---
function createNotifyBotAdapter(token) {
  const telegramFetch = async (method, body) => {
    let res;
    try {
      res = await fetch(`https://api.telegram.org/bot${token}/${method}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      const data = await res.json();

      if (!data.ok) {
        logger.error(`Erro na API do Telegram (${method})`, null, { error: data });
        const error = new Error(`Erro Telegram API: ${data.error_code} - ${data.description}`);
        // Anexar status HTTP para detecção de erros retryable
        error.response = { status: res.status };
        error.statusCode = res.status;
        throw error;
      }

      return data.result;
    } catch (err) {
      // Se o erro não tem response, adicionar baseado no fetch response
      if (!err.response && res) {
        err.response = { status: res.status };
        err.statusCode = res.status;
      }
      logger.error(`Erro de fetch (${method})`, err);
      throw err;  // SEMPRE re-lançar o erro
    }
  };

  /**
   * Verifica se um erro é passível de retry (transitório)
   * @param {Error} error - Objeto de erro
   * @returns {boolean} true se o erro é transitório e pode ser retentado
   */
  function isRetryableError(error) {
    // Network errors (connection issues)
    const retryableCodes = [
      'ETIMEDOUT',
      'ECONNRESET',
      'ENOTFOUND',
      'ECONNREFUSED',
      'Socket hang up',
      'ECONNABORTED',
      'Network Error'
    ];

    if (retryableCodes.some(code =>
      error.message?.includes(code) ||
      error.code === code
    )) {
      return true;
    }

    // Telegram API rate limiting (429 Too Many Requests)
    if (error.response?.status === 429) {
      return true;
    }

    // Telegram API internal errors (5xx)
    if (error.response?.status >= 500) {
      return true;
    }

    return false;
  }

  return {
    sendMessage: async (chatId, text, options = {}) => {
      const maxAttempts = 2; // Simple: just 2 attempts
      let lastError;

      for (let attempt = 1; attempt <= maxAttempts; attempt++) {
        try {
          const result = await telegramFetch('sendMessage', { chat_id: chatId, text, ...options });

          logger.debug(`Mensagem Telegram enviada`, {
            chatId,
            messageId: result.message_id,
            attempt
          });

          return {
            success: true,
            messageId: result.message_id,
            timestamp: new Date().toISOString(),
            attempts: attempt
          };
        } catch (err) {
          lastError = err;

          // Only retry on network/retryable errors
          if (!isRetryableError(err) || attempt === maxAttempts) {
            break;
          }

          // Simple delay: 1 second
          await new Promise(resolve => setTimeout(resolve, 1000));
        }
      }

      logger.error(`Falha ao enviar mensagem Telegram após ${maxAttempts} tentativas`, lastError, { chatId });

      return {
        success: false,
        error: {
          code: lastError.name || 'SEND_FAILED',
          message: lastError.message,
          retryable: isRetryableError(lastError)
        },
        timestamp: new Date().toISOString(),
        attempts: maxAttempts
      };
    }
  };
}

export default async function handler(req, res) {
  // Gerar correlation ID para esta execução do cron
  const correlationId = generateCorrelationId();

  // Log de diagnóstico das variáveis de ambiente (apenas existência, não valores)
  logger.info('Ambiente de execução', {
    correlationId,
    nodeEnv: process.env.NODE_ENV,
    vercelEnv: process.env.VERCEL ? 'present' : 'absent',
    hasSupabaseUrl: !!process.env.VITE_SUPABASE_URL,
    hasSupabaseAnonKey: !!process.env.VITE_SUPABASE_ANON_KEY,
    hasSupabaseServiceKey: !!process.env.SUPABASE_SERVICE_ROLE_KEY,
    hasCronSecret: !!process.env.CRON_SECRET,
    hasBotToken: !!process.env.TELEGRAM_BOT_TOKEN
  });

  logger.info('Cron job triggered', {
    correlationId,
    method: req.method,
    url: req.url
  });

  // Accept both GET (from cron-job.org) and POST (for compatibility)
  if (req.method !== 'GET' && req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed. Use GET or POST.' });
  }

  // Protection against unauthorized calls
  const authHeader = req.headers['authorization'];
  if (authHeader !== `Bearer ${process.env.CRON_SECRET}`) {
    logger.warn('Unauthorized cron attempt', { correlationId, authHeader });
    return res.status(401).json({ error: 'Unauthorized' });
  }

  const token = process.env.TELEGRAM_BOT_TOKEN;
  if (!token) {
    logger.error('TELEGRAM_BOT_TOKEN not configured', null, { correlationId });
    return res.status(500).json({ error: 'Token missing' });
  }

  const bot = createNotifyBotAdapter(token);

  // --- Notification Dispatcher Setup (Sprint 6.4) ---
  const notificationDispatcher = {
    async dispatch({ userId, kind, data, context }) {
      try {
        const result = await dispatchNotification({
          userId,
          kind,
          data,
          context,
          repositories: { 
            preferences: preferencesRepo, 
            devices: devicesRepo,
            dlq: dlqRepo
          },
          bot,
          expoClient
        });

        logger.info('[notificationDispatcher] Resultado do envio', { 
          userId, 
          kind, 
          success: result.success,
          totalDelivered: result.totalDelivered,
          totalFailed: result.totalFailed,
          correlationId: context?.correlationId 
        });

        return result;
      } catch (error) {
        logger.error('[notificationDispatcher] Erro ao enviar notificação', error, { userId, kind, correlationId: context?.correlationId });
        return { success: false, channels: [], totalDelivered: 0, totalFailed: 1, deactivatedTokens: [], errors: [{ message: error.message }] };
      }
    }
  };

  // Get current time in Sao Paulo
  const now = new Date();
  const spDate = new Date(now.toLocaleString("en-US", { timeZone: "America/Sao_Paulo" }));

  const currentHour = spDate.getHours();
  const currentMinute = spDate.getMinutes();
  const currentDay = spDate.getDate();
  const currentWeekDay = spDate.getDay();

  const currentHHMM = spDate.toLocaleTimeString('pt-BR', {
    hour: '2-digit', minute: '2-digit', hour12: false
  });

  logger.info(`Executing cron jobs`, {
    correlationId,
    time: currentHHMM,
    hour: currentHour,
    minute: currentMinute,
    day: currentDay,
    weekday: currentWeekDay
  });

  const results = [];

  try {
    // 1. Always check dose reminders (Every minute)
    await withCorrelation(
      (context) => checkReminders(bot, { ...context, notificationDispatcher }),
      { correlationId, jobType: 'reminders' }
    );
    results.push('reminders');

    // 2. Daily Digest (Horário personalizado por usuário validado em tasks.js)
    await withCorrelation(
      (context) => runDailyDigest(bot, { ...context, notificationDispatcher }),
      { correlationId, jobType: 'daily_digest' }
    );
    results.push('daily_digest');

    // 2.1 Daily Adherence Report (Fase 12: Storytelling + Nudges)
    // Chamado a cada minuto; elegibilidade por usuário validada em tasks.js
    await withCorrelation(
      (context) => runDailyAdherenceReport(bot, { ...context, notificationDispatcher }),
      { correlationId, jobType: 'daily_adherence_report' }
    );
    results.push('daily_adherence_report');

    // 3. Tasks at 09:00: Stock Alerts + DLQ Digest
    if (currentHour === 9 && currentMinute === 0) {
      await withCorrelation(
        (context) => checkStockAlerts(bot, { ...context, notificationDispatcher }),
        { correlationId, jobType: 'stock_alerts' }
      );
      results.push('stock_alerts');

      await withCorrelation(
        (context) => sendDLQDigest(notificationDispatcher, context),
        { correlationId, jobType: 'dlq_digest' }
      );
      results.push('dlq_digest');
    }

    // 4. Titration Alerts: Daily at 08:00
    if (currentHour === 8 && currentMinute === 0) {
      await withCorrelation(
        (context) => checkTitrationAlerts(bot, { ...context, notificationDispatcher }),
        { correlationId, jobType: 'titration_alerts' }
      );
      results.push('titration_alerts');
    }

    // 5. Adherence Reports: Sunday at 23:00
    if (currentWeekDay === 0 && currentHour === 23 && currentMinute === 0) {
      await withCorrelation(
        (context) => checkAdherenceReports(bot, { ...context, notificationDispatcher }),
        { correlationId, jobType: 'adherence_reports' }
      );
      results.push('adherence_reports');
    }

    // 6. Monthly Report: 1st of month at 10:00
    if (currentDay === 1 && currentHour === 10 && currentMinute === 0) {
      await withCorrelation(
        (context) => checkMonthlyReport(bot, { ...context, notificationDispatcher }),
        { correlationId, jobType: 'monthly_report' }
      );
      results.push('monthly_report');
    }

    logger.info('Cron jobs completed', {
      correlationId,
      executed: results,
      duration: Date.now() - now.getTime()
    });

    res.status(200).json({
      status: 'ok',
      executed: results,
      time: currentHHMM,
      correlationId
    });

  } catch (error) {
    console.error('[CronNotify] Cron job failed with error:', {
      correlationId,
      message: error.message,
      stack: error.stack,
      name: error.name,
      code: error.code
    });
    logger.error('Cron job failed', error, { correlationId });
    res.status(500).json({
      error: error.message,
      correlationId,
      details: process.env.NODE_ENV === 'development' ? error.stack : undefined
    });
  }
}

import { createClient } from '@supabase/supabase-js'
import { notificationDeviceRepository } from '../server/notifications/repositories/notificationDeviceRepository.js'

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' })
  }

  try {
    const token = req.headers.authorization?.split(' ')[1]
    if (!token) return res.status(401).json({ error: 'Unauthorized' })

    const supabase = createClient(
      process.env.VITE_SUPABASE_URL || process.env.SUPABASE_URL,
      process.env.VITE_SUPABASE_ANON_KEY || process.env.SUPABASE_ANON_KEY
    )

    const { data: { user }, error: authError } = await supabase.auth.getUser(token)
    if (authError || !user) return res.status(401).json({ error: 'Unauthorized' })

    const { pushToken, provider, appKind, platform, deviceName } = req.body

    await notificationDeviceRepository.upsert({
      userId: user.id,
      appKind,
      platform,
      provider,
      pushToken,
      deviceName
    })

    res.status(200).json({ success: true })
  } catch (error) {
    console.error('Error registering webpush:', error)
    res.status(500).json({ error: 'Internal server error' })
  }
}

/**
 * Endpoint para compartilhamento de relatórios PDF
 *
 * Recebe arquivo PDF em base64, faz upload para Vercel Blob com TTL
 * e retorna URL compartilhável.
 *
 * @module api/share
 * @version 1.0.0
 */

import { z } from 'zod'
import { createClient } from '@supabase/supabase-js'
import { createHash } from 'crypto'

// ============================================================================
// CONFIGURAÇÃO
// ============================================================================

const ENDPOINT = 'share'

// Fallback para variáveis de ambiente (R-083, AP-S03)
const SUPABASE_URL = process.env.SUPABASE_URL || process.env.VITE_SUPABASE_URL
const SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY
const BLOB_READ_WRITE_TOKEN = process.env.BLOB_READ_WRITE_TOKEN || process.env.VERCEL_BLOB_TOKEN
const BLOB_BASE_URL = process.env.BLOB_BASE_URL || 'https://blob.vercel-storage.com'

/**
 * Valida variáveis de ambiente obrigatórias
 * @throws {Error} Se alguma variável estiver faltando
 */
function validateEnvironment() {
  const missing = []

  if (!SUPABASE_URL) missing.push('SUPABASE_URL ou VITE_SUPABASE_URL')
  if (!SUPABASE_SERVICE_ROLE_KEY) missing.push('SUPABASE_SERVICE_ROLE_KEY')
  if (!BLOB_READ_WRITE_TOKEN) missing.push('BLOB_READ_WRITE_TOKEN ou VERCEL_BLOB_TOKEN')

  if (missing.length > 0) {
    throw new Error(`Variáveis de ambiente obrigatórias faltando: ${missing.join(', ')}`)
  }
}

// Executar validação no startup
validateEnvironment()

// ============================================================================
// LOGGER ESTRUTURADO (R-087, AP-S06)
// ============================================================================

/**
 * Níveis de log disponíveis
 * @readonly
 */
const LOG_LEVELS = {
  DEBUG: 'debug',
  INFO: 'info',
  WARN: 'warn',
  ERROR: 'error',
}

/**
 * Log estruturado com timestamp e contexto
 * @param {string} level - Nível do log (debug, info, warn, error)
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais para o log
 */
function log(level, message, data = {}) {
  const timestamp = new Date().toISOString()
  const logEntry = {
    timestamp,
    endpoint: ENDPOINT,
    level,
    message,
    ...data,
  }

  if (level === LOG_LEVELS.ERROR) {
    console.error(JSON.stringify(logEntry))
  } else if (level === LOG_LEVELS.WARN) {
    console.warn(JSON.stringify(logEntry))
  } else {
    console.log(JSON.stringify(logEntry))
  }
}

/**
 * Log de informação
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
function logInfo(message, data = {}) {
  log(LOG_LEVELS.INFO, message, data)
}

/**
 * Log de erro
 * @param {string} message - Mensagem descritiva
 * @param {Error|Object} error - Erro ocorrido
 * @param {Object} additionalData - Dados adicionais de contexto
 */
function logError(message, error, additionalData = {}) {
  const errorDetails = error instanceof Error
    ? { name: error.name, message: error.message, stack: error.stack }
    : { error: String(error) }

  log(LOG_LEVELS.ERROR, message, { ...errorDetails, ...additionalData })
}

/**
 * Log de warning
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
function logWarn(message, data = {}) {
  log(LOG_LEVELS.WARN, message, data)
}

/**
 * Log de debug
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
// eslint-disable-next-line no-unused-vars
function logDebug(message, data = {}) {
  log(LOG_LEVELS.DEBUG, message, data)
}

/**
 * Log de requisição recebida (sanitizado)
 * @param {Object} req - Requisição HTTP
 */
function logRequest(req) {
  const sanitizedHeaders = { ...req.headers }
  // Remover dados sensíveis
  if (sanitizedHeaders.authorization) {
    sanitizedHeaders.authorization = '[REDACTED]'
  }
  if (sanitizedHeaders.cookie) {
    sanitizedHeaders.cookie = '[REDACTED]'
  }

  logInfo('Request received', {
    method: req.method,
    path: req.url,
    contentType: req.headers['content-type'],
    hasBody: !!req.body,
  })
}

// ============================================================================
// SCHEMAS ZOD (R-082)
// ============================================================================

/**
 * Schema de validação para o body da requisição
 * - blob: base64 do PDF (máximo 5MB = ~7MB em base64)
 * - filename: nome do arquivo
 * - expiresInHours: tempo de expiração em horas (default: 72, max: 168)
 */
const shareRequestSchema = z.object({
  blob: z.string()
    .min(1, 'Base64 do arquivo é obrigatório')
    .refine(
      (val) => {
        // Verificar tamanho aproximado em bytes (base64 ≈ 4/3 do tamanho original)
        const estimatedSize = (val.length * 3) / 4
        return estimatedSize <= 5 * 1024 * 1024 // 5MB máximo
      },
      { message: 'Arquivo muito grande. Máximo de 5MB.' }
    ),
  filename: z.string()
    .min(1, 'Nome do arquivo é obrigatório')
    .max(255, 'Nome do arquivo muito longo')
    .refine(
      (val) => /^[\w\-.\s]+\.pdf$/i.test(val),
      { message: 'Nome do arquivo deve terminar com .pdf' }
    ),
  expiresInHours: z.number()
    .int()
    .min(1, 'Tempo de expiração mínimo é 1 hora')
    .max(168, 'Tempo de expiração máximo é 168 horas (7 dias)')
    .default(72),
})

// ============================================================================
// FUNÇÕES DE AUTENTICAÇÃO (R-042, AP-016)
// ============================================================================

/**
 * Extrai token do header Authorization
 * @param {Object} req - Requisição HTTP
 * @returns {string|null} Token JWT ou null
 */
function extractToken(req) {
  const authHeader = req.headers.authorization || ''
  const match = authHeader.match(/^Bearer\s+(.+)$/i)
  return match ? match[1] : null
}

/**
 * Verifica autenticação JWT com Supabase
 * @param {string} token - Token JWT
 * @returns {Promise<Object>} Resultado com { success: boolean, userId?: string, error?: string }
 */
async function verifyAuth(token) {
  if (!token) {
    return { success: false, error: 'Token não fornecido' }
  }

  try {
    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY)
    const { data, error } = await supabase.auth.getUser(token)

    if (error || !data.user) {
      logWarn('JWT validation failed', { error: error?.message })
      return { success: false, error: 'Token inválido ou expirado' }
    }

    logInfo('JWT validation successful', { userId: data.user.id })
    return { success: true, userId: data.user.id }
  } catch (error) {
    logError('Erro ao verificar autenticação', error)
    return { success: false, error: 'Erro interno de autenticação' }
  }
}

// ============================================================================
// FUNÇÕES DE UPLOAD PARA BLOB
// ============================================================================

/**
 * Faz upload do arquivo para Vercel Blob com TTL
 *
 * @param {Buffer} buffer - Buffer do arquivo
 * @param {string} filename - Nome do arquivo
 * @param {number} expiresInHours - TTL do cache em horas (via x-vercel-cache-max-age)
 * @param {string} userId - ID do usuário (para namespace do path)
 * @returns {Promise<Object>} Resultado com { url, cacheExpiresAt }
 *   - url: URL pública compartilhável
 *   - cacheExpiresAt: Data de expiração do cache CDN (não data de deleção do arquivo)
 * @throws {Error} Se o upload falhar
 */
async function uploadToBlob(buffer, filename, expiresInHours, userId) {
  logInfo('Iniciando upload para Blob', { filename, size: buffer.length, expiresInHours })

  // Gerar path único baseado no usuário e timestamp
  const timestamp = Date.now()
  const fileHash = createHash('md5').update(buffer).digest('hex').substring(0, 8)
  const safeFilename = filename.replace(/[^\w\-.]/g, '_')
  const path = `reports/${userId}/${timestamp}-${fileHash}-${safeFilename}`

  // Calcular data de expiração do cache (usa x-vercel-cache-max-age header)
  const cacheExpiresAt = new Date(Date.now() + expiresInHours * 60 * 60 * 1000)

  // Preparar upload usando a API do Vercel Blob
  // Ref: https://vercel.com/docs/storage/vercel-blob/using-blob-sdk
  const uploadUrl = `${BLOB_BASE_URL}/${path}`

  try {
    const response = await fetch(uploadUrl, {
      method: 'PUT',
      headers: {
        'Authorization': `Bearer ${BLOB_READ_WRITE_TOKEN}`,
        'Content-Type': 'application/pdf',
        'x-access': 'public', // URL pública para compartilhamento
        'x-vercel-cache-max-age': String(expiresInHours * 60 * 60), // TTL em segundos
      },
      body: buffer,
    })

    if (!response.ok) {
      const errorText = await response.text()
      throw new Error(`Upload falhou: ${response.status} ${response.statusText} - ${errorText}`)
    }

    // Extrair URL pública da resposta
    const responseData = await response.json()
    const publicUrl = responseData.url || `${BLOB_BASE_URL}/${path}`

    logInfo('Upload para Blob concluído', {
      url: publicUrl.split('?')[0],
      cacheExpiresAt: cacheExpiresAt.toISOString(),
    })

    return {
      url: publicUrl,
      cacheExpiresAt: cacheExpiresAt.toISOString(),
    }
  } catch (error) {
    logError('Falha no upload para Blob', error)
    throw error
  }
}

/**
 * Decodifica base64 para Buffer
 * @param {string} base64 - String em base64
 * @returns {Buffer} Buffer do arquivo
 * @throws {Error} Se a decodificação falhar
 */
function decodeBase64(base64) {
  try {
    // Remover prefixo data:application/pdf;base64, se existir
    const cleanBase64 = base64.replace(/^data:.*?;base64,/, '')
    return Buffer.from(cleanBase64, 'base64')
  } catch {
    throw new Error('Base64 inválido')
  }
}

// ============================================================================
// HANDLER PRINCIPAL
// ============================================================================

/**
 * Handler para requisições HTTP
 * @param {Object} req - Requisição HTTP
 * @param {Object} res - Resposta HTTP
 */
export default async function handler(req, res) {
  // Log inicial da requisição
  logRequest(req)

  // Verificar método HTTP
  if (req.method !== 'POST') {
    logWarn('Método não permitido', { method: req.method })
    return res.status(405).json({
      success: false,
      error: 'Método não permitido. Use POST.',
    })
  }

  try {
    // Verificar autenticação (R-042, AP-016)
    const token = extractToken(req)
    const authResult = await verifyAuth(token)

    if (!authResult.success) {
      return res.status(401).json({
        success: false,
        error: authResult.error,
      })
    }

    const userId = authResult.userId

    // Validar body da requisição (R-082)
    logInfo('Validando dados da requisição')

    const validation = shareRequestSchema.safeParse(req.body)

    if (!validation.success) {
      const errors = validation.error.issues.map((issue) => ({
        field: issue.path.join('.'),
        message: issue.message,
      }))

      logWarn('Validação falhou', { errors })
      return res.status(400).json({
        success: false,
        error: 'Dados inválidos',
        details: errors,
      })
    }

    const { blob, filename, expiresInHours } = validation.data

    logInfo('Validação bem-sucedida', { filename, expiresInHours, userId })

    // Decodificar base64
    let buffer
    try {
      buffer = decodeBase64(blob)
      logInfo('Base64 decodificado', { size: buffer.length })
    } catch (error) {
      logError('Erro ao decodificar base64', error)
      return res.status(400).json({
        success: false,
        error: 'Base64 inválido',
      })
    }

    // Fazer upload para Vercel Blob (R-084, AP-S04)
    const { url, cacheExpiresAt } = await uploadToBlob(buffer, filename, expiresInHours, userId)

    // Retornar sucesso (R-086, AP-S05)
    logInfo('Operação concluída com sucesso', { url: url.split('?')[0] })

    return res.status(200).json({
      success: true,
      data: {
        url,
        cacheExpiresAt,
      },
    })
  } catch (error) {
    // Nunca usar process.exit() - sempre retornar resposta (R-041, AP-010)
    logError('Erro não tratado no handler', error)
    return res.status(500).json({
      success: false,
      error: 'Erro interno do servidor',
    })
  }
}

import { handleStart } from '../server/bot/commands/start.js';
import { handleStatus } from '../server/bot/commands/status.js';
import { handleEstoque } from '../server/bot/commands/estoque.js';
import { handleHoje } from '../server/bot/commands/hoje.js';
import { handleProxima } from '../server/bot/commands/proxima.js';
import { handleHistorico } from '../server/bot/commands/historico.js';
import { handleAjuda } from '../server/bot/commands/ajuda.js';
import { handleRegistrar } from '../server/bot/commands/registrar.js';
import { handleAdicionarEstoque, handleReporShortcut } from '../server/bot/commands/adicionar_estoque.js';
import { handlePausar, handleRetomar } from '../server/bot/commands/protocols.js';
import { handleCallbacks } from '../server/bot/callbacks/doseActions.js';
import { handleConversationalCallbacks } from '../server/bot/callbacks/conversational.js';
import { createLogger } from '../server/bot/logger.js';

// --- Configuration ---
const token = process.env.TELEGRAM_BOT_TOKEN;
const logger = createLogger('TelegramWebhook');
// Note: Supabase client in this file was unused in previous logic except for /start linking
// The imported commands use their own Supabase client from ../server/services/supabase.js
// which uses dotenv. We rely on process.env being available in Vercel.

// --- Bot Adapter ---
// Creates a mock Bot object that mimics node-telegram-bot-api but uses simple fetch for Vercel
function createBotAdapter(token) {
  const telegramFetch = async (method, body) => {
    try {
      const res = await fetch(`https://api.telegram.org/bot${token}/${method}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      const data = await res.json();
      if (!data.ok) {
        console.error(`Telegram API Error (${method}):`, data);
      }
      return data.result;
    } catch (err) {
      console.error(`Fetch Error (${method}):`, err);
    }
  };

  const listeners = {
    callback_query: [],
    message: [] // conversational callbacks listen to message
  };

  return {
    // Methods used by commands
    sendMessage: async (chatId, text, options = {}) => {
      return telegramFetch('sendMessage', { chat_id: chatId, text, ...options });
    },
    sendChatAction: async (chatId, action) => {
      return telegramFetch('sendChatAction', { chat_id: chatId, action });
    },
    editMessageText: async (text, options = {}) => {
      // Handle overload: (text, options) vs (msgId, text, options) - library has quirks,
      // but our code seems to usage object options with chat_id and message_id inside.
      // Let's check usages.
      // Usage 1: bot.editMessageText(newText, { chat_id, message_id, ... })
      return telegramFetch('editMessageText', { text, ...options });
    },
    answerCallbackQuery: async (callbackQueryId, options = {}) => {
      return telegramFetch('answerCallbackQuery', { callback_query_id: callbackQueryId, ...options });
    },
    deleteMessage: async (chatId, messageId) => {
      return telegramFetch('deleteMessage', { chat_id: chatId, message_id: messageId });
    },
    getMe: async () => {
      return telegramFetch('getMe', {});
    },

    // Event listener registration (used by conversational callbacks)
    on: (event, handler) => {
      if (listeners[event]) {
        listeners[event].push(handler);
      }
    },

    // Internal: Trigger event
    _emit: async (event, payload) => {
      if (listeners[event]) {
        await Promise.all(listeners[event].map(handler => handler(payload)));
      }
    }
  };
}

export default async function handler(req, res) {
  logger.info('📨 Webhook recebido', {
    method: req.method,
    updateType: req.body?.message ? 'message' : req.body?.callback_query ? 'callback_query' : 'unknown'
  });

  if (req.method !== 'POST') {
    logger.warn('❌ Método não permitido', { method: req.method });
    return res.status(405).json({ error: 'Method not allowed' });
  }

  if (!token) {
    logger.error('❌ TELEGRAM_BOT_TOKEN ausente');
    return res.status(200).json({ error: 'Bot token not configured' });
  }

  const update = req.body;
  const bot = createBotAdapter(token);

  // Initialize listeners (register callbacks)
  // Note: These functions act as "setup" functions returning nothing or promises
  handleCallbacks(bot);
  handleConversationalCallbacks(bot);

  try {
    // Dispatch based on update type
    if (update.message?.text) {
      const msg = update.message;
      const text = msg.text;
      const chatId = msg.chat.id;

      logger.info('💬 Mensagem de texto recebida', {
        chatId,
        textPreview: text.substring(0, 50),
        textLen: text.length,
        isCommand: text.startsWith('/')
      });

      // Command Routing
      if (text.startsWith('/start')) {
        logger.debug('🔧 Roteando: /start', { chatId });
        await handleStart(bot, msg);
      }
      else if (text.startsWith('/status')) {
        logger.debug('🔧 Roteando: /status', { chatId });
        await handleStatus(bot, msg);
      }
      else if (text.startsWith('/estoque')) {
        logger.debug('🔧 Roteando: /estoque', { chatId });
        await handleEstoque(bot, msg);
      }
      else if (text.startsWith('/hoje')) {
        logger.debug('🔧 Roteando: /hoje', { chatId });
        await handleHoje(bot, msg);
      }
      else if (text.startsWith('/proxima')) {
        logger.debug('🔧 Roteando: /proxima', { chatId });
        await handleProxima(bot, msg);
      }
      else if (text.startsWith('/historico')) {
        logger.debug('🔧 Roteando: /historico', { chatId });
        await handleHistorico(bot, msg);
      }
      else if (text.startsWith('/ajuda')) {
        logger.debug('🔧 Roteando: /ajuda', { chatId });
        await handleAjuda(bot, msg);
      }

      else if (text.startsWith('/registrar')) {
        logger.debug('🔧 Roteando: /registrar', { chatId });
        await handleRegistrar(bot, msg);
      }
      else if (text.startsWith('/adicionar_estoque')) {
        logger.debug('🔧 Roteando: /adicionar_estoque', { chatId });
        await handleAdicionarEstoque(bot, msg);
      }

      // Arguments regex commands
      else if (text.startsWith('/repor')) {
        const match = text.match(/\/repor\s+(.+)\s+(\d+[.,]?\d*)/);
        if (match) {
          logger.debug('🔧 Roteando: /repor', { chatId });
          await handleReporShortcut(bot, msg, match);
        }
        else {
          logger.warn('⚠️ Formato inválido /repor', { chatId, text });
          bot.sendMessage(msg.chat.id, 'Formato inválido. Use: /repor Nome Quantidade');
        }
      }
      else if (text.startsWith('/pausar')) {
        const match = text.match(/\/pausar(?:\s+(.+))?/);
        logger.debug('🔧 Roteando: /pausar', { chatId });
        await handlePausar(bot, msg, match || [text, undefined]);
      }
      else if (text.startsWith('/retomar')) {
        const match = text.match(/\/retomar(?:\s+(.+))?/);
        logger.debug('🔧 Roteando: /retomar', { chatId });
        await handleRetomar(bot, msg, match || [text, undefined]);
      }

      // Fallback: Emit 'message' event for conversational callback listeners (chatbot IA)
      else {
        logger.info('🤖 Emitindo evento "message" para listeners (chatbot IA)', {
          chatId,
          textPreview: text.substring(0, 50)
        });
        await bot._emit('message', msg);
      }
    }
    else if (update.callback_query) {
      const callbackData = update.callback_query.data;
      const chatId = update.callback_query.message?.chat?.id;
      logger.info('🔲 Callback query recebido', {
        chatId,
        callbackData: callbackData.substring(0, 50),
        callbackLen: callbackData.length
      });
      // Dispatch to listeners registered via bot.on('callback_query', ...)
      await bot._emit('callback_query', update.callback_query);
    }
    else {
      logger.warn('⚠️ Update sem tipo identificado', { updateKeys: Object.keys(update) });
    }

    logger.info('✅ Webhook processado com sucesso');
    res.status(200).json({ success: true });
  } catch (error) {
    logger.error('❌ Erro no webhook', error, {
      errorMessage: error.message,
      errorName: error.name,
      chatId: update.message?.chat?.id || update.callback_query?.message?.chat?.id
    });
    res.status(200).json({ error: 'Internal Error', details: error.message });
  }
}

