// useTodayData.js — hook para dados da tela Hoje
// Padrão: { data, loading, error, stale, refresh }
// R-010: ordem de declaração — states → effects → handlers
// stale=true quando há snapshot em cache mas a última refresh falhou (R5-008)

import { useState, useEffect, useCallback, useRef, useMemo } from 'react'
import { AppState } from 'react-native'
import AsyncStorage from '@react-native-async-storage/async-storage'
import { getTodayLocal, parseLocalDate, evaluateDoseTimelineState, isProtocolActiveOnDate } from '@dosiq/core'
import { calculateAdherenceStats, calculateDosesByDate } from '@dosiq/core'
import { supabase } from '../../../platform/supabase/nativeSupabaseClient'
import {
  getActiveProtocols,
  getLogsForPeriod,
  getMedicinesData,
  getUserSettings,
} from '../services/dashboardService'

const TODAY_CACHE_KEY = '@dosiq/today-snapshot'

/**
 * @typedef {{ 
 *   protocols: Array, 
 *   logs: Array, 
 *   medicines: Record<string,Object>,
 *   stats: Object,
 *   zones: Object,
 *   user: Object|null,
 *   capturedAt?: string
 * }} TodayData
 * @returns {{ data: TodayData|null, loading: boolean, error: string|null, stale: boolean, isDaySegregated: boolean, refresh: Function }}
 */
export function useTodayData() {
  // States primeiro (R-010)
  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [stale, setStale] = useState(false)
  const [isDaySegregated, setIsDaySegregated] = useState(false)

  // Ref para snapshot check sem entrar nos deps do useCallback
  const dataRef = useRef(null)

  const load = useCallback(async () => {
    setLoading(true)
    setError(null)

    try {
      if (__DEV__) console.log('[useTodayData] fetch start')

      const { data: { session: currentSession }, error: sessionError } = await supabase.auth.getSession()

      let user = currentSession?.user
      if (sessionError || !user) {
        const { data: { user: verifiedUser }, error: userError } = await supabase.auth.getUser()
        if (userError || !verifiedUser) throw new Error('Sessão expirada')
        user = verifiedUser
      }

      const today = getTodayLocal()

      // Fetch online (primary)
      const [protocols, logs, userSettings] = await Promise.all([
        getActiveProtocols(user.id, today),
        getLogsForPeriod(user.id, 14), // 14 dias de logs para tendências comparativas
        getUserSettings(user.id)
      ])

      const medicineIds = [...new Set(protocols.map((p) => p.medicine_id))]
      const medicines = await getMedicinesData(medicineIds)

      const enrichedProtocols = protocols.map(p => ({
        ...p,
        medicine: medicines[p.medicine_id] || null
      }))

      const newData = { 
        protocols: enrichedProtocols, 
        logs, 
        medicines,
        user: {
          id: user.id,
          email: user.email,
          name: userSettings?.display_name || null,
          complexity_override: userSettings?.complexity_override || null
        },
        capturedAt: new Date().toISOString(),
        localDay: today // R-114 fix: save explicit local day string
      }

      // Salvar em cache para uso offline posterior
      await AsyncStorage.setItem(TODAY_CACHE_KEY, JSON.stringify(newData))

      dataRef.current = newData
      setData(newData)
      setStale(false)
      setIsDaySegregated(false)
    } catch (err) {
      if (__DEV__) console.warn('[useTodayData] Fetch failed, trying cache:', err.message)

      try {
        const cached = await AsyncStorage.getItem(TODAY_CACHE_KEY)
        if (cached) {
          const parsed = JSON.parse(cached)
          const capturedAt = new Date(parsed.capturedAt)
          const now = new Date()
          const diffHours = (now - capturedAt) / (1000 * 60 * 60)

          // Regra: < 24h
          if (diffHours < 24) {
            const today = getTodayLocal()

            // R-114: Prefer explicit localDay from snapshot, fallback to ISO split
            const snapshotDay = parsed.localDay || (parsed.capturedAt ?? '').split('T')[0]

            // Regra H5.8: Se dia diferente (comparação local-local), limpar logs
            if (snapshotDay && snapshotDay !== today) {
              if (__DEV__) console.log('[useTodayData] Day mismatch, segregating logs')
              parsed.logs = Array.isArray(parsed.logs) ? [] : []
              setIsDaySegregated(true)
            } else {
              setIsDaySegregated(false)
            }

            // Safety gate: garantir que parsed tem o formato esperado
            const safeData = {
              protocols: Array.isArray(parsed.protocols) ? parsed.protocols : [],
              logs: Array.isArray(parsed.logs) ? parsed.logs : [],
              medicines: parsed.medicines || {},
              user: parsed.user || null,
              capturedAt: parsed.capturedAt
            }

            setData(safeData)
            dataRef.current = safeData
            setStale(true)
            setError(null) 
          } else {
            throw new Error('Cache expirado (> 24h)')
          }
        } else {
          throw err // Re-throw original se não houver cache
        }
      } catch (cacheErr) {
        setError(err.message ?? 'Erro ao carregar dados.')
      }
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    load()
  }, [load])

  // Lógica de Refresh de Meia-Noite e AppState (R5-008, R-020)
  useEffect(() => {
    let midnightTimer

    const scheduleMidnightRefresh = () => {
      const now = new Date()
      // Meia-noite local do dia seguinte
      const nextMidnight = new Date(now)
      nextMidnight.setDate(nextMidnight.getDate() + 1)
      nextMidnight.setHours(0, 0, 0, 0)

      const msUntilMidnight = nextMidnight.getTime() - now.getTime()

      clearTimeout(midnightTimer)
      midnightTimer = setTimeout(() => {
        if (__DEV__) console.log('[useTodayData] Meia-noite detectada: Refreshing...')
        load()
        scheduleMidnightRefresh() // Agendar próxima
      }, msUntilMidnight + 1000) // +1s para garantir que passou o boundary
    }

    scheduleMidnightRefresh()

    // Listener para quando o app volta do background (Device Lock ou App Switch)
    const handleStateChange = (nextState) => {
      if (nextState === 'active') {
        const today = getTodayLocal()
        // Se mudou o dia enquanto estava em background, forçar reload
        if (dataRef.current?.localDay && dataRef.current.localDay !== today) {
          if (__DEV__) console.log('[useTodayData] Dia alterado via background: Refreshing...')
          load()
        }
      }
    }

    const subscription = AppState.addEventListener('change', handleStateChange)

    return () => {
      subscription.remove()
      clearTimeout(midnightTimer)
    }
  }, [load])

  // Derivar estatísticas e zonas (Performance: memoized)
  const enhancedData = useMemo(() => {
    if (!data) return null

    const todayStr = getTodayLocal()

    // 0. Resiliência de Cache: Filtrar validade do protocolo para HOJE (GMT-3)
    // Isso protege a UI caso o snapshot no AsyncStorage tenha dados obsoletos.
    const validProtocols = data.protocols.filter(p => isProtocolActiveOnDate(p, todayStr))

    // 1. Filtrar logs de hoje para a Timeline
    const todayLogs = data.logs.filter(l => {
      const logDate = new Date(l.taken_at)
      const lYear = logDate.getFullYear()
      const lMonth = String(logDate.getMonth() + 1).padStart(2, '0')
      const lDay = String(logDate.getDate()).padStart(2, '0')
      return `${lYear}-${lMonth}-${lDay}` === todayStr
    })

    // 2. Classificar doses em zonas para o Dashboard
    const { takenDoses, missedDoses, scheduledDoses } = calculateDosesByDate(
      todayStr,
      todayLogs,
      validProtocols
    )

    // 3. Calcular estatísticas de adesão (Últimos 7 dias - Diluído conforme feedback H8.7)
    const stats = calculateAdherenceStats(
      data.logs,
      validProtocols,
      7,
      0 // Janela atual (D0 a D7)
    )

    // 4. Calcular estatísticas do período anterior para tendência (+5% vs semana passada)
    const statsPrevious = calculateAdherenceStats(
      data.logs,
      validProtocols,
      7,
      7 // Janela anterior (D7 a D14)
    )

    const scoreTrend = statsPrevious.expected > 0 ? (stats.score - statsPrevious.score) : 0

    const statsWithTrend = {
      ...stats,
      trend: scoreTrend,
      hasPreviousData: statsPrevious.expected > 0
    }

    // Ordenar listas cronologicamente (00:00 -> 23:59)
    const sortByTime = (a, b) => {
      const timeA = a.scheduledTime || (a.taken_at ? new Date(a.taken_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '00:00')
      const timeB = b.scheduledTime || (b.taken_at ? new Date(b.taken_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '00:00')
      return timeA.localeCompare(timeB)
    }

    const zones = {
      late: missedDoses.sort(sortByTime),
      now: scheduledDoses.filter(d => {
        const [h, m] = d.scheduledTime.split(':').map(Number)
        const scheduledDate = new Date()
        scheduledDate.setHours(h, m, 0, 0)
        const now = new Date()
        const diffHours = (now - scheduledDate) / (1000 * 60 * 60)
        return diffHours >= -0.5 && diffHours <= 2
      }).sort(sortByTime),
      upcoming: scheduledDoses.sort(sortByTime),
      done: takenDoses.sort(sortByTime)
    }

    // 4. Nova Timeline Tática (Epic 2 Fase 8)
    const timeline = evaluateDoseTimelineState(todayStr, {
      takenDoses,
      missedDoses,
      scheduledDoses
    })

    // 5. Calcular alertas de estoque
    const stockAlerts = Object.values(data.medicines || {})
      .filter(m => {
        const daysRemaining = m.daysRemaining ?? Infinity
        return daysRemaining <= 7 // Limiar para alerta no Dashboard
      })
      .map(m => ({
        medicineId: m.id,
        medicineName: m.name,
        daysRemaining: m.daysRemaining
      }))

    return {
      ...data,
      stats: statsWithTrend,
      zones,
      timeline,
      stockAlerts
    }
  }, [data])

  return { 
    data: enhancedData, 
    loading, 
    error, 
    stale, 
    isDaySegregated,
    refresh: load 
  }
}

import { useState, useMemo, useEffect, useCallback } from 'react'
import { 
  ScrollView, 
  View, 
  Text, 
  RefreshControl, 
  StyleSheet, 
  LayoutAnimation, 
  Platform, 
  UIManager 
} from 'react-native'
import { Pill } from 'lucide-react-native'
import { useTodayData } from '../hooks/useTodayData'
import ScreenContainer from '../../../shared/components/ui/ScreenContainer'
import LoadingState from '../../../shared/components/states/LoadingState'
import EmptyState from '../../../shared/components/states/EmptyState'
import ErrorState from '../../../shared/components/states/ErrorState'
import { getPeriodFromTime } from '@dosiq/core'
import AdherenceDayCard from '../components/AdherenceDayCard'
import TimeBlockSeparator from '../components/TimeBlockSeparator'
import DoseTimelineCard from '../components/DoseTimelineCard'
import HeroDoseCard from '../components/HeroDoseCard'
import StockAlertInline from '../components/StockAlertInline'
import DoseRegisterModal from '../../dose/components/DoseRegisterModal'
import BulkDoseRegisterModal from '../../dose/components/BulkDoseRegisterModal'
import StaleBanner from '../../../shared/components/feedback/StaleBanner'
import { colors, spacing, typography } from '../../../shared/styles/tokens'

// Habilitar animações no Android
if (Platform.OS === 'android' && UIManager.setLayoutAnimationEnabledExperimental) {
  UIManager.setLayoutAnimationEnabledExperimental(true)
}

export default function TodayScreen({ route, navigation }) {
  const [modalProtocol, setModalProtocol] = useState(null)
  const [modalScheduledTime, setModalScheduledTime] = useState(null)
  // null | { mode, planId?, protocolIds?, scheduledTime, treatmentPlanName? }
  const [bulkModal, setBulkModal] = useState(null)
  const [expandedShifts, setExpandedShifts] = useState({})
  const [lastHeuristicDay, setLastHeuristicDay] = useState(null)

  const { data, loading, error, stale, isDaySegregated, refresh } = useTodayData()

  const timeline = data?.timeline ?? []
  const stockAlerts = data?.stockAlerts ?? []
  const protocols = data?.protocols ?? []
  const medicines = data?.medicines ?? {}
  const stats = data?.stats ?? { expected: 0, taken: 0, score: 0 }

  // 1. Lógica de Persona: Threshold de complexidade adaptativa (Wave 10A)
  const isComplex = useMemo(() => {
    if (data?.user?.complexity_override) {
      return data.user.complexity_override === 'complex'
    }
    return Object.keys(medicines).length > 3
  }, [medicines, data?.user?.complexity_override])

  // Agrupamento da Timeline por Turnos (Epic 2) - Memoized
  const { groupedTimeline, shifts, countsByShift } = useMemo(() => {
    const counts = {}
    const grouped = timeline.reduce((acc, dose) => {
      const shift = getPeriodFromTime(dose.scheduledTime)
      if (!acc[shift]) {
        acc[shift] = []
        counts[shift] = { total: 0, taken: 0 }
      }
      acc[shift].push(dose)

      // Acumular contadores (Wave v0.1.5 Otimizada)
      counts[shift].total += 1
      if (dose.isRegistered) counts[shift].taken += 1

      return acc
    }, {})

    // Carlos (isComplex) vê todos os turnos principais. Dona Maria vê apenas onde há doses.
    const allShifts = ['Manhã', 'Tarde', 'Noite', 'Madrugada']
    const activeShifts = isComplex 
      ? allShifts 
      : allShifts.filter(s => grouped[s] && grouped[s].length > 0)

    return { groupedTimeline: grouped, shifts: activeShifts, countsByShift: counts }
  }, [timeline, isComplex])

  // 2. Deeplink params de push notification (N1.4 → N1.5)
  // Abre BulkDoseRegisterModal automaticamente quando a tela é navegada via push tap
  useEffect(() => {
    const params = route?.params
    if (!params?.screen) return
    if (params.screen === 'bulk-plan' && params.planId) {
      setBulkModal({
        mode: 'plan',
        planId: params.planId,
        scheduledTime: params.at ?? '',
        treatmentPlanName: params.treatmentPlanName,
      })
    } else if (params.screen === 'bulk-misc') {
      setBulkModal({
        mode: 'misc',
        protocolIds: params.protocolIds ?? [],
        scheduledTime: params.at ?? '',
      })
    } else if (params.screen === 'dose-individual' && params.protocolId) {
      const protocol = protocols.find(p => p.id === params.protocolId)
      if (protocol) {
        setModalProtocol(protocol)
        setModalScheduledTime(params.at ?? null)
      }
    }
    // Limpar params após consumo para evitar re-abertura em back-navigate
    navigation?.setParams({ screen: undefined, planId: undefined, protocolIds: undefined })
  }, [route?.params])

  // 3. Heurística de Expansão Inicial
  useEffect(() => {
    const currentDay = data?.localDay
    const dayChanged = lastHeuristicDay && currentDay && lastHeuristicDay !== currentDay
    const isFirstLoad = Object.keys(expandedShifts).length === 0

    if (shifts.length > 0 && (isFirstLoad || dayChanged)) {
      const now = new Date()
      const timeStr = `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`
      const currentShift = getPeriodFromTime(timeStr)

      const initial = {}
      shifts.forEach(shift => {
        const doses = groupedTimeline[shift] || []
        // Regra 1: Expandir se for o turno atual
        const isCurrent = shift === currentShift
        // Regra 2: Expandir se tiver dose urgente (Atrasada/Próxima)
        const hasUrgent = doses.some(d => d.timelineStatus === 'ATRASADA' || d.timelineStatus === 'PROXIMA')

        initial[shift] = isCurrent || hasUrgent
      })

      setExpandedShifts(initial)
      setLastHeuristicDay(currentDay)
    }
  }, [shifts, groupedTimeline, data?.localDay, lastHeuristicDay])

  const toggleShift = useCallback((shift) => {
    LayoutAnimation.configureNext(LayoutAnimation.Presets.easeInEaseOut)
    setExpandedShifts(prev => ({
      ...prev,
      [shift]: !prev[shift]
    }))
  }, [])

  if (loading && !data) return <LoadingState message="Carregando o seu dia..." />
  if (error && !data) return <ErrorState message={error} onRetry={refresh} />

  // Doses prioritárias (Hero)
  const priorityDoses = timeline
    .filter(d => d.timelineStatus === 'PROXIMA' || d.timelineStatus === 'ATRASADA')
    .slice(0, 3)

  // Dados do Cabeçalho (Personalização H8.7)
  const fullUserName = data?.user?.name || data?.user?.email?.split('@')[0] || 'Usuário'
  const firstName = fullUserName.trim().split(' ')[0]
  const todayFormatted = new Date().toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long' })
  const greeting = `Olá, ${firstName}`

  function handleOpenRegister(protocol, scheduledTime) {
    setModalProtocol(protocol)
    setModalScheduledTime(scheduledTime)
  }

  function handleRegisterSuccess() {
    setModalProtocol(null)
    setModalScheduledTime(null)
    refresh()
  }

  return (
    <ScreenContainer>
      {stale && <StaleBanner isDaySegregated={isDaySegregated} />}

      <ScrollView
        contentContainerStyle={styles.scroll}
        refreshControl={
          <RefreshControl
            refreshing={loading && !!data}
            onRefresh={refresh}
            tintColor={colors.status.success}
          />
        }
      >
        <View style={styles.header}>
          <Text style={styles.greeting}>{greeting}</Text>
          <Text style={styles.date}>{todayFormatted}</Text>
        </View>

        <AdherenceDayCard 
          score={stats.score} 
          trend={
            stats.hasPreviousData 
              ? `${stats.trend >= 0 ? '+' : ''}${stats.trend}% vs semana anterior`
              : "Mantendo a média"
          }
        />

        <StockAlertInline alerts={stockAlerts} />

        {priorityDoses.length > 0 && (
          <HeroDoseCard 
            doses={priorityDoses} 
            onPress={(d) => handleOpenRegister(d.protocol, d.scheduledTime)} 
          />
        )}

        <View style={styles.agendaHeader}>
          <Text style={styles.agendaTitle}>Agenda de Hoje</Text>
        </View>

        {protocols.length === 0 ? (
          <EmptyState
            icon={<Pill size={48} color={colors.status.success} />}
            message={'Sem tratamentos ativos.\nAdicione tratamentos na versão web.'}
          />
        ) : !isComplex ? (
          /* MODO SIMPLE: Dona Maria (Lista direta cronológica) */
          <View style={styles.simpleList}>
            {timeline.map((dose) => (
              <DoseTimelineCard 
                key={dose.id} 
                dose={dose} 
                onRegister={handleOpenRegister}
              />
            ))}
          </View>
        ) : (
          /* MODO COMPLEX: Carlos (Agrupado por turnos com Accordion) */
          shifts.map(shift => {
            const doses = groupedTimeline[shift] || []
            const isExpanded = expandedShifts[shift]
            const isEmpty = doses.length === 0
            const shiftCounts = countsByShift[shift] || { total: 0, taken: 0 }

            return (
              <View key={shift} style={styles.shiftContainer}>
                <TimeBlockSeparator 
                  type={shift} 
                  isExpanded={isExpanded}
                  onToggle={() => toggleShift(shift)}
                  isDisabled={isEmpty}
                  counts={shiftCounts.total > 0 ? shiftCounts : null}
                />

                {isExpanded && (
                  <View style={styles.dosesList}>
                    {isEmpty ? (
                      <View style={styles.emptyShiftContainer}>
                        <Text style={styles.emptyShiftText}>Nenhum medicamento para este turno</Text>
                      </View>
                    ) : (
                      doses.map((dose) => (
                        <DoseTimelineCard 
                          key={dose.id} 
                          dose={dose} 
                          onRegister={handleOpenRegister}
                        />
                      ))
                    )}
                  </View>
                )}
              </View>
            )
          })
        )}
      </ScrollView>

      <DoseRegisterModal
        visible={modalProtocol !== null}
        protocol={modalProtocol}
        scheduledTime={modalScheduledTime}
        medicineName={modalProtocol ? (medicines[modalProtocol.medicine_id]?.name ?? 'Medicamento') : ''}
        onClose={() => {
          setModalProtocol(null)
          setModalScheduledTime(null)
        }}
        onSuccess={handleRegisterSuccess}
      />

      <BulkDoseRegisterModal
        visible={bulkModal !== null}
        mode={bulkModal?.mode ?? 'plan'}
        planId={bulkModal?.planId}
        protocolIds={bulkModal?.protocolIds}
        scheduledTime={bulkModal?.scheduledTime ?? ''}
        treatmentPlanName={bulkModal?.treatmentPlanName}
        userId={data?.user?.id ?? ''}
        onClose={() => setBulkModal(null)}
        onSuccess={({ successCount }) => {
          setBulkModal(null)
          refresh()
          if (__DEV__) console.log('[TodayScreen] BulkDoseRegisterModal — sucesso:', successCount)
        }}
      />
    </ScreenContainer>
  )
}

