// dashboardService.js — serviço thin para dados do dashboard mobile
// ADR-029: thin local service — chama Supabase directamente via nativeSupabaseClient
// Schemas de domínio via @dosiq/core (nunca duplicar lógica de negócio)

import { z } from 'zod'
import { supabase } from '../../../platform/supabase/nativeSupabaseClient'
import { parseLocalDate } from '@dosiq/core'

/**
 * Busca protocolos ativos do utilizador.
 * Seleciona apenas colunas necessárias para o dashboard (R-127: slim select).
 *
 * @param {string} userId
 * @returns {Promise<Array>}
 */
export async function getActiveProtocols(userId, dateStr) {
  z.string().uuid().parse(userId)
  const { data, error } = await supabase
    .from('protocols')
    .select('id, name, medicine_id, active, frequency, time_schedule, dosage_per_intake, start_date, end_date, titration_status')
    .eq('user_id', userId)
    .eq('active', true)
    .lte('start_date', dateStr)
    .or(`end_date.is.null,end_date.gte.${dateStr}`)
    .order('name')

  if (error) throw error
  return data ?? []
}

/**
 * Busca os logs de medicação de um dia específico.
 * Boundaries em UTC derivadas da meia-noite local (parseLocalDate).
 * Padrão do projecto: todos os timestamps no DB são UTC (R-020).
 * parseLocalDate('2026-04-13') → new Date('2026-04-13T00:00:00') → meia-noite local
 * .toISOString() → '2026-04-13T03:00:00.000Z' (para UTC-3) — boundary correcta.
 *
 * @param {string} userId
 * @param {string} dateStr  — formato YYYY-MM-DD
 * @returns {Promise<Array>}
 */
export async function getTodayLogs(userId, dateStr) {
  z.string().uuid().parse(userId)
  z.string().regex(/^\d{4}-\d{2}-\d{2}$/).parse(dateStr)
  // Boundaries UTC derivadas da meia-noite local (R-020: nunca raw new Date('YYYY-MM-DDT...'))
  // startUTC = meia-noite local do dia → UTC
  const startLocal = parseLocalDate(dateStr)
  const startUTC = startLocal.toISOString()
  // endUTC = meia-noite local do dia seguinte → UTC (exclusive upper boundary)
  const endLocal = new Date(startLocal)
  endLocal.setDate(endLocal.getDate() + 1)
  const endUTC = endLocal.toISOString()
  if (__DEV__) console.log('[dashboardService] getTodayLogs boundaries — start:', startUTC, 'end:', endUTC)

  const { data, error } = await supabase
    .from('medicine_logs')
    .select('id, protocol_id, medicine_id, taken_at, quantity_taken')
    .eq('user_id', userId)
    .gte('taken_at', startUTC)
    .lt('taken_at', endUTC)

  if (error) throw error
  return data ?? []
}

/**
 * Busca os dados dos medicamentos referenciados pelos protocolos.
 * Usado para enriquecer a lista de doses na tela Hoje.
 *
 * @param {string[]} medicineIds
 * @returns {Promise<Record<string, Object>>} — map de id → { name, dosage_per_pill, dosage_unit }
 */
export async function getMedicinesData(medicineIds) {
  // Validação conforme regra de camada de serviço (R-125)
  z.array(z.string().uuid()).parse(medicineIds)

  if (!medicineIds.length) return {}

  const { data, error } = await supabase
    .from('medicines')
    .select('id, name, dosage_per_pill, dosage_unit')
    .in('id', medicineIds)

  if (error) throw error

  return (data ?? []).reduce((acc, m) => {
    acc[m.id] = {
      name: m.name,
      dosage_per_pill: m.dosage_per_pill,
      dosage_unit: m.dosage_unit
    }
    return acc
  }, {})
}

/**
 * Busca as configurações do usuário, incluindo o nome.
 * @param {string} userId
 * @returns {Promise<Object|null>}
 */
export async function getUserSettings(userId) {
  z.string().uuid().parse(userId)
  const { data, error } = await supabase
    .from('user_settings')
    .select('display_name, timezone, complexity_override')
    .eq('user_id', userId)
    .single()

  if (error && error.code !== 'PGRST116') return null
  if (error) throw error
  return data
}

/**
 * Busca logs para um período de dias (histórico).
 * @param {string} userId
 * @param {number} days
 * @returns {Promise<Array>}
 */
export async function getLogsForPeriod(userId, days = 7) {
  z.string().uuid().parse(userId)

  // boundaries UTC baseadas na meia-noite local
  const startLocal = parseLocalDate(new Date().toISOString().split('T')[0])
  startLocal.setDate(startLocal.getDate() - (days - 1))
  const startUTC = startLocal.toISOString()

  const endLocal = parseLocalDate(new Date().toISOString().split('T')[0])
  endLocal.setDate(endLocal.getDate() + 1)
  const endUTC = endLocal.toISOString()

  const { data, error } = await supabase
    .from('medicine_logs')
    .select('id, protocol_id, medicine_id, taken_at, quantity_taken')
    .eq('user_id', userId)
    .gte('taken_at', startUTC)
    .lt('taken_at', endUTC)

  if (error) throw error
  return data ?? []
}

// BulkDoseRegisterModal.jsx — modal para registro em batch de doses de um bloco semântico
// Usado após tap em push notification grouped (plan ou misc) via deeplink N1.4
// R-010: estados → effects → handlers

import { useState, useEffect } from 'react'
import {
  Modal,
  View,
  Text,
  Pressable,
  ScrollView,
  StyleSheet,
  ActivityIndicator,
} from 'react-native'
import { CheckCircle, Circle } from 'lucide-react-native'
import { usePlanProtocols } from '../hooks/usePlanProtocols'
import { registerDoseMany } from '../services/doseService'
import { colors, spacing, borderRadius } from '../../../shared/styles/tokens'

/**
 * @param {{
 *   visible: boolean,
 *   onClose: Function,
 *   onSuccess: Function,           — chamado com { successCount } após submit bem-sucedido
 *   mode: 'plan' | 'misc',
 *   planId?: string,
 *   protocolIds?: string[],
 *   scheduledTime: string,         — 'HH:MM'
 *   treatmentPlanName?: string,
 *   userId: string,
 * }} props
 */
export default function BulkDoseRegisterModal({
  visible,
  onClose,
  onSuccess,
  mode,
  planId,
  protocolIds,
  scheduledTime,
  treatmentPlanName,
  userId,
}) {
  // States (R-010: ordem obrigatória)
  const [selected, setSelected] = useState({})
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)

  const { protocols, loading: protocolsLoading, error: protocolsError } = usePlanProtocols({
    mode,
    planId,
    protocolIds,
    scheduledTime,
    userId,
  })

  // Pré-marcar todos quando protocolos carregam
  useEffect(() => {
    if (protocols.length === 0) return
    const initial = {}
    protocols.forEach(p => { initial[p.id] = true })
    setSelected(initial)
  }, [protocols])

  // Limpar estado ao fechar
  useEffect(() => {
    if (!visible) {
      setSelected({})
      setError(null)
      setLoading(false)
    }
  }, [visible])

  function toggleProtocol(id) {
    setSelected(prev => ({ ...prev, [id]: !prev[id] }))
  }

  async function handleConfirm() {
    const selectedIds = Object.keys(selected).filter(id => selected[id])
    if (selectedIds.length === 0) {
      setError('Selecione pelo menos um medicamento.')
      return
    }

    setLoading(true)
    setError(null)

    const logsData = selectedIds.map(id => {
      const p = protocols.find(p => p.id === id)
      return {
        protocol_id: p.id,
        medicine_id: p.medicine?.id ?? p.medicine_id,
        taken_at: new Date().toISOString(),
        quantity_taken: p.dosage_per_intake ?? 1,
      }
    })

    const result = await registerDoseMany(logsData)
    setLoading(false)

    if (!result.success && result.results.length === 0) {
      setError(result.error ?? 'Erro ao registrar doses.')
      return
    }

    const successCount = result.results.filter(r => r.success).length
    if (successCount > 0) {
      onSuccess({ successCount })
    } else {
      setError(result.error ?? 'Nenhuma dose foi registrada.')
    }
  }

  function handleClose() {
    if (loading) return
    onClose()
  }

  const selectedCount = Object.values(selected).filter(Boolean).length
  const header = mode === 'plan'
    ? (treatmentPlanName ?? 'Plano de tratamento')
    : `Doses agora — ${scheduledTime}`

  return (
    <Modal
      visible={visible}
      transparent
      animationType="slide"
      onRequestClose={handleClose}
    >
      <View style={styles.overlay}>
        <Pressable style={styles.backdrop} onPress={handleClose} />
        <View style={styles.sheet}>
          <View style={styles.handle} />

          <View style={styles.header}>
            <View style={styles.titleCol}>
              <Text style={styles.title}>{header}</Text>
              <Text style={styles.subtitle}>Selecione os medicamentos tomados</Text>
            </View>
            {scheduledTime ? (
              <View style={styles.timeBadge}>
                <Text style={styles.timeBadgeText}>{scheduledTime}</Text>
              </View>
            ) : null}
          </View>

          {protocolsLoading ? (
            <View style={styles.centerState}>
              <ActivityIndicator color={colors.primary[600]} />
            </View>
          ) : protocolsError ? (
            <View style={styles.centerState}>
              <Text style={styles.errorText}>{protocolsError}</Text>
            </View>
          ) : (
            <ScrollView style={styles.list} contentContainerStyle={styles.listContent}>
              {protocols.map(p => {
                const isChecked = !!selected[p.id]
                const medicineName = p.medicine?.name ?? p.name ?? 'Medicamento'
                const dose = `${p.dosage_per_intake ?? 1} cp`
                return (
                  <Pressable
                    key={p.id}
                    style={styles.item}
                    onPress={() => toggleProtocol(p.id)}
                    disabled={loading}
                  >
                    {isChecked
                      ? <CheckCircle size={22} color={colors.primary[600]} strokeWidth={2} />
                      : <Circle size={22} color={colors.neutral[300]} strokeWidth={2} />
                    }
                    <View style={styles.itemText}>
                      <Text style={[styles.medicineName, !isChecked && styles.unchecked]}>
                        {medicineName}
                      </Text>
                      <Text style={styles.doseInfo}>{dose}</Text>
                    </View>
                  </Pressable>
                )
              })}
            </ScrollView>
          )}

          {error ? <Text style={styles.errorText}>{error}</Text> : null}

          <View style={styles.actions}>
            <Pressable style={styles.cancelBtn} onPress={handleClose} disabled={loading}>
              <Text style={styles.cancelText}>Cancelar</Text>
            </Pressable>

            <Pressable
              style={[styles.confirmBtn, (loading || selectedCount === 0) && styles.btnDisabled]}
              onPress={handleConfirm}
              disabled={loading || selectedCount === 0}
            >
              {loading
                ? <ActivityIndicator color="#fff" size="small" />
                : <Text style={styles.confirmText}>
                    Registrar {selectedCount} {selectedCount === 1 ? 'dose' : 'doses'}
                  </Text>
              }
            </Pressable>
          </View>
        </View>
      </View>
    </Modal>
  )
}

