// useTreatments.js — hook para listagem de tratamentos
// Padrão: { data, loading, error, stale, refresh }

import { useState, useEffect, useCallback, useRef, useMemo } from 'react'
import { AppState } from 'react-native'
import AsyncStorage from '@react-native-async-storage/async-storage'
import { getTodayLocal, isProtocolActiveOnDate } from '@dosiq/core'
import { supabase } from '../../../platform/supabase/nativeSupabaseClient'
import { getActiveTreatments } from '../services/treatmentsService'

const TREATMENTS_CACHE_KEY = '@dosiq/treatments-snapshot'

/**
 * @typedef {{ id: string, name: string, frequency: string, time_schedule: string[], dosage_per_intake: number, titration_status: string, medicine: { name: string, type: string } }} Treatment
 * @returns {{ data: Treatment[]|null, loading: boolean, error: string|null, stale: boolean, refresh: Function }}
 */
export function useTreatments() {
  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [stale, setStale] = useState(false)
  const dataRef = useRef(null)

  const load = useCallback(async () => {
    // ... codigo de load ...
    setLoading(true)
    setError(null)

    try {
      const { data: authData, error: authError } = await supabase.auth.getUser()
      const user = authData?.user
      if (authError || !user) throw new Error('Sessão expirada.')

      const result = await getActiveTreatments(user.id)

      if (!result.success) throw new Error(result.error)

      const newData = result.data
      const today = getTodayLocal()
      const snapshot = {
        data: newData,
        capturedAt: new Date().toISOString(),
        localDay: today // R-114 fix
      }

      await AsyncStorage.setItem(TREATMENTS_CACHE_KEY, JSON.stringify(snapshot))

      dataRef.current = { data: newData, localDay: today }
      setData(newData)
      setStale(false)
    } catch (err) {
      if (__DEV__) console.warn('[useTreatments] Fetch failed, checking cache:', err.message)

      try {
        const cached = await AsyncStorage.getItem(TREATMENTS_CACHE_KEY)
        if (cached) {
          const parsed = JSON.parse(cached)
          const capturedAt = new Date(parsed.capturedAt)
          const now = new Date()
          const diffHours = (now - capturedAt) / (1000 * 60 * 60)

          if (diffHours < 24) {
            setData(parsed.data)
            dataRef.current = { data: parsed.data, localDay: parsed.localDay }
            setStale(true)
            setError(null)
          } else {
            throw new Error('Cache expirado')
          }
        } else {
          throw err
        }
      } catch (cacheErr) {
        setError(err.message ?? 'Erro ao carregar tratamentos.')
      }
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    load()
  }, [load])

  // Lógica de Refresh de Meia-Noite e AppState (R-184)
  useEffect(() => {
    let midnightTimer

    const scheduleMidnightRefresh = () => {
      const now = new Date()
      const nextMidnight = new Date(now)
      nextMidnight.setDate(nextMidnight.getDate() + 1)
      nextMidnight.setHours(0, 0, 0, 0)

      const msUntilMidnight = nextMidnight.getTime() - now.getTime()

      clearTimeout(midnightTimer)
      midnightTimer = setTimeout(() => {
        if (__DEV__) console.log('[useTreatments] Meia-noite detectada: Refreshing...')
        load()
        scheduleMidnightRefresh()
      }, msUntilMidnight + 1000)
    }

    scheduleMidnightRefresh()

    const handleStateChange = (nextState) => {
      if (nextState === 'active') {
        const today = getTodayLocal()
        if (dataRef.current?.localDay && dataRef.current.localDay !== today) {
          if (__DEV__) console.log('[useTreatments] Dia alterado via background: Refreshing...')
          load()
        }
      }
    }

    const subscription = AppState.addEventListener('change', handleStateChange)
    return () => {
      subscription.remove()
      clearTimeout(midnightTimer)
    }
  }, [load])

  // Resilience layer (Rule R-175): Filtrar validade para HOJE local.
  // Garante que mesmo que o snapshot no cache tenha dados de ontem, a UI oculte os expirados.
  // Resilience layer + Grouping (Rule R-175): Organizar por Planos/Classes
  const groupedData = useMemo(() => {
    if (!data) return null
    const today = getTodayLocal()

    // 1. Filtrar ativos para hoje e ordenar por horário da primeira dose
    const validProtocols = data
      .filter(p => isProtocolActiveOnDate(p, today))
      .sort((a, b) => {
        const timeA = (a.time_schedule && a.time_schedule[0]) || '99:99'
        const timeB = (b.time_schedule && b.time_schedule[0]) || '99:99'
        return timeA.localeCompare(timeB)
      })

    // 2. Agrupar
    const groupsMap = {}

    validProtocols.forEach(p => {
      let groupId, groupName, groupEmoji, groupColor

      if (p.treatment_plan) {
        // Via Plano de Tratamento (Prioridade 1)
        groupId = p.treatment_plan.id
        groupName = p.treatment_plan.name
        groupEmoji = p.treatment_plan.emoji
        groupColor = p.treatment_plan.color
      } else if (p.medicine?.therapeutic_class) {
        // Via Classe Terapêutica (Prioridade 2 - Fallback)
        groupId = `class-${p.medicine.therapeutic_class}`
        groupName = p.medicine.therapeutic_class
        groupEmoji = '🧪'
        groupColor = '#94a3b8' 
      } else {
        // Outros (Prioridade 3)
        groupId = 'general'
        groupName = 'Outros Tratamentos'
        groupEmoji = '💊'
        groupColor = '#cbd5e1'
      }

      if (!groupsMap[groupId]) {
        groupsMap[groupId] = {
          id: groupId,
          title: groupName,
          emoji: groupEmoji,
          color: groupColor,
          protocols: []
        }
      }
      groupsMap[groupId].protocols.push(p)
    })

    // Converter para array e ordenar grupos (Planos primeiro, depois alfabético)
    return Object.values(groupsMap).sort((a, b) => {
      if (a.id === 'general') return 1
      if (b.id === 'general') return -1
      return a.title.localeCompare(b.title)
    })
  }, [data]) // today é derivado de getTodayLocal() que é determinístico por dia

  const result = useMemo(() => ({ 
    data: groupedData, 
    loading, 
    error, 
    stale, 
    refresh: load 
  }), [groupedData, loading, error, stale, load])

  return result
}

import { useState, useCallback, useMemo } from 'react'
import { ScrollView, View, Text, StyleSheet, RefreshControl, LayoutAnimation, Platform, UIManager } from 'react-native'
import ScreenContainer from '../../../shared/components/ui/ScreenContainer'
import LoadingState from '../../../shared/components/states/LoadingState'
import ErrorState from '../../../shared/components/states/ErrorState'
import EmptyState from '../../../shared/components/states/EmptyState'
import TreatmentCard from '../components/TreatmentCard'
import TreatmentPlanHeader from '../components/TreatmentPlanHeader'
import { useTreatments } from '../hooks/useTreatments'
import { colors, spacing, typography } from '../../../shared/styles/tokens'
import StaleBanner from '../../../shared/components/feedback/StaleBanner'

// Habilitar animações no Android
if (Platform.OS === 'android' && UIManager.setLayoutAnimationEnabledExperimental) {
  UIManager.setLayoutAnimationEnabledExperimental(true)
}

const DEFAULT_COMPLEXITY = { isComplex: false, flatData: [] }

export default function TreatmentsScreen() {
  const { data: groups, loading, error, stale, refresh } = useTreatments()
  const [expandedGroups, setExpandedGroups] = useState({})

  // Heurística de Complexidade Adaptativa (Wave 10A)
  const { isComplex, flatData } = useMemo(() => {
    if (!groups) return DEFAULT_COMPLEXITY
    const total = groups.reduce((acc, g) => acc + g.protocols.length, 0)
    const flat = groups.flatMap(g => g.protocols)
    return { isComplex: total > 3, flatData: flat }
  }, [groups])

  const toggleGroup = useCallback((groupId) => {
    LayoutAnimation.configureNext(LayoutAnimation.Presets.easeInEaseOut)
    setExpandedGroups(prev => {
      // Se for undefined (estado inicial), tratamos como true (aberto), então o toggle inverte para false.
      const isCurrentlyExpanded = prev[groupId] !== false
      return {
        ...prev,
        [groupId]: !isCurrentlyExpanded
      }
    })
  }, [])

  if (loading && !groups) {
    return (
      <ScreenContainer>
        <LoadingState message="Carregando seus tratamentos..." />
      </ScreenContainer>
    )
  }

  if (error && !groups) {
    return (
      <ScreenContainer>
        <ErrorState message={error} onRetry={refresh} />
      </ScreenContainer>
    )
  }

  // Se não houver grupos, mostrar EmptyState
  const isEmpty = !groups || groups.length === 0

  return (
    <ScreenContainer>
      {stale && <StaleBanner />}

      <ScrollView
        contentContainerStyle={styles.scroll}
        refreshControl={
          <RefreshControl
            refreshing={loading && !!groups}
            onRefresh={refresh}
            tintColor={colors.status.success}
          />
        }
      >
        <View style={styles.header}>
          <Text style={styles.title}>Meus Tratamentos</Text>
          <Text style={styles.subtitle}>Acompanhe seus tratamentos ativos</Text>
        </View>

        {isEmpty ? (
          <EmptyState 
            title="Nenhum tratamento ativo"
            message={'Sem tratamentos ativos.\nAdicione tratamentos na versão web.'}
          />
        ) : !isComplex ? (
          /* MODO SIMPLE: Dona Maria (Lista direta sem accordions) */
          <View style={styles.simpleList}>
            {flatData.map(protocol => (
              <TreatmentCard 
                key={protocol.id} 
                treatment={protocol} 
              />
            ))}
          </View>
        ) : (
          /* MODO COMPLEX: Carlos (Agrupado por planos/classes) */
          groups.map(group => {
            const isExpanded = expandedGroups[group.id] !== false

            return (
              <View key={group.id} style={styles.groupContainer}>
                <TreatmentPlanHeader 
                  title={group.title}
                  emoji={group.emoji}
                  color={group.color}
                  isExpanded={isExpanded}
                  onToggle={() => toggleGroup(group.id)}
                  count={group.protocols.length}
                />

                {isExpanded && (
                  <View style={styles.protocolsList}>
                    {group.protocols.map(protocol => (
                      <TreatmentCard 
                        key={protocol.id} 
                        treatment={protocol} 
                      />
                    ))}
                  </View>
                )}
              </View>
            )
          })
        )}
      </ScrollView>
    </ScreenContainer>
  )
}

