import { useState } from 'react'
import { debugLog } from '@shared/utils/logger'
import './AdherenceHeatmap.css'

/**
 * Nomes dos dias da semana
 */
const DAY_NAMES = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado']

/**
 * Nomes dos períodos do dia
 */
const PERIOD_NAMES = ['Madrugada', 'Manhã', 'Tarde', 'Noite']

/**
 * Componente de heatmap de adesão por dia da semana e período do dia
 *
 * Props:
 * - pattern: { grid, worstCell, narrative, hasEnoughData } (saída de analyzeAdherencePatterns)
 *
 * Renderiza:
 * - Desktop (>= 380px): Grid 7x4 via CSS
 * - Mobile (< 380px): Stacked cards via CSS
 * (A responsividade é controlada por media queries no CSS, não por lógica JS)
 */
export default function AdherenceHeatmap({ pattern }) {
  // States
  const [hoveredCell, setHoveredCell] = useState(null)
  const [touchedCell, setTouchedCell] = useState(null)

  debugLog('AdherenceHeatmap', 'Pattern recebido:', pattern)

  // Guard clause: dados insuficientes
  if (!pattern || !pattern.hasEnoughData) {
    debugLog('AdherenceHeatmap', 'Dados insuficientes:', {
      hasPattern: !!pattern,
      hasEnoughData: pattern?.hasEnoughData,
      narrative: pattern?.narrative,
    })
    return (
      <div className="adherence-heatmap adherence-heatmap--empty" role="status">
        <p className="adherence-heatmap__empty-message">
          {pattern?.narrative || 'Registre pelo menos 21 dias de doses para análise de padrões.'}
        </p>
      </div>
    )
  }

  /**
   * Calcula opacidade baseada na adherência (0-100%)
   * 100% = 1.0 (verde opaco)
   * 50% = 0.5 (verde translúcido)
   * 0% = 0.1 (verde bem transparente)
   * null = N/D (cinza neutro)
   */
  const getOpacity = (adherence) => {
    if (adherence === null) return 1.0
    if (adherence >= 90) return 1.0
    if (adherence >= 75) return 0.8
    if (adherence >= 50) return 0.5
    if (adherence >= 25) return 0.25
    return 0.1
  }

  /**
   * Retorna cor CSS com opacidade adequada
   * null = cinza neutro (sem protocolo)
   */
  const getCellColor = (adherence) => {
    if (adherence === null) return 'rgba(120, 120, 140, 0.15)' // cinza neutro para N/D
    const opacity = getOpacity(adherence)
    return `rgba(34, 197, 94, ${opacity})` // green-500 com opacidade variável
  }

  /**
   * Constrói o texto do tooltip com informações corretas de adesão
   */
  const buildTooltip = (dayIndex, periodIndex) => {
    const cell = pattern.grid[dayIndex][periodIndex]
    const adherenceText = cell.adherence === null ? 'N/D' : `${cell.adherence}%`
    // totalExpected = doses esperadas por dia × quantas vezes esse dia ocorre nos logs
    const totalExpected = cell.expected * (pattern.dayOccurrences?.[dayIndex] || 1)
    return `${DAY_NAMES[dayIndex]} ${PERIOD_NAMES[periodIndex]}: ${adherenceText} (${cell.taken}/${totalExpected} doses)`
  }

  /**
   * Handler para tooltip ao passar mouse
   */
  const handleCellInteraction = (dayIndex, periodIndex) => {
    setHoveredCell(buildTooltip(dayIndex, periodIndex))
  }

  /**
   * Handler para tooltip ao tocar em mobile
   */
  const handleCellTouchEnd = (dayIndex, periodIndex) => {
    const tooltip = buildTooltip(dayIndex, periodIndex)
    setTouchedCell(tooltip === touchedCell ? null : tooltip)
  }

  const handleCellMouseLeave = () => {
    setHoveredCell(null)
  }

  // Renderização: Grid (visível em desktop via CSS) + Stacked (visível em mobile via CSS)
  return (
    <div
      className="adherence-heatmap"
      role="region"
      aria-label="Heatmap de adesão por dia e período"
    >
      {/* Grid: Desktop (>=380px) */}
      <div className="adherence-heatmap__grid-container">
        <div className="adherence-heatmap__container">
          {' '}
          {/* Inner container for grid styling */}
          {/* Cabeçalho com períodos */}
          <div className="adherence-heatmap__header">
            <div className="adherence-heatmap__corner" />
            {PERIOD_NAMES.map((period, idx) => (
              <div key={idx} className="adherence-heatmap__period-header">
                {period}
              </div>
            ))}
          </div>
          {/* Grid de células */}
          {pattern.grid.map((row, dayIndex) => (
            <div key={dayIndex} className="adherence-heatmap__row">
              {/* Label do dia */}
              <div className="adherence-heatmap__day-label">{DAY_NAMES[dayIndex]}</div>

              {/* Células do grid */}
              {row.map((cell, periodIndex) => {
                const cellKey = `${dayIndex}-${periodIndex}`
                const isActive =
                  hoveredCell !== null &&
                  hoveredCell.includes(`${DAY_NAMES[dayIndex]} ${PERIOD_NAMES[periodIndex]}`)

                return (
                  <div
                    key={cellKey}
                    className={`adherence-heatmap__cell ${isActive ? 'adherence-heatmap__cell--active' : ''} ${cell.adherence === null ? 'adherence-heatmap__cell--na' : ''}`}
                    style={{ backgroundColor: getCellColor(cell.adherence) }}
                    onMouseEnter={() => handleCellInteraction(dayIndex, periodIndex)}
                    onMouseLeave={handleCellMouseLeave}
                    onTouchEnd={() => handleCellTouchEnd(dayIndex, periodIndex)}
                    role="gridcell"
                    aria-label={`${DAY_NAMES[dayIndex]} ${PERIOD_NAMES[periodIndex]}: ${cell.adherence === null ? 'N/D' : `${cell.adherence}%`}`}
                    tabIndex={0}
                  >
                    <span className="adherence-heatmap__cell-text">
                      {cell.adherence === null ? '—' : `${cell.adherence}%`}
                    </span>
                  </div>
                )
              })}
            </div>
          ))}
          {/* Tooltip flutuante */}
          {hoveredCell && (
            <div className="adherence-heatmap__tooltip" role="tooltip">
              {hoveredCell}
            </div>
          )}
          {/* Tooltip para mobile (persistente) */}
          {touchedCell && (
            <div
              className="adherence-heatmap__tooltip adherence-heatmap__tooltip--mobile"
              role="status"
            >
              {touchedCell}
            </div>
          )}
        </div>
      </div>

      {/* Stacked: Mobile (<380px) */}
      <div className="adherence-heatmap__stacked-wrapper">
        <div className="adherence-heatmap__stacked-container">
          {pattern.grid.map((row, dayIndex) => (
            <div key={dayIndex} className="adherence-heatmap__day-card">
              <h4 className="adherence-heatmap__day-card-title">{DAY_NAMES[dayIndex]}</h4>
              <div className="adherence-heatmap__day-card-periods">
                {row.map((cell, periodIndex) => (
                  <div
                    key={periodIndex}
                    className={`adherence-heatmap__period-bar ${cell.adherence === null ? 'adherence-heatmap__period-bar--na' : ''}`}
                  >
                    <span className="adherence-heatmap__period-name">
                      {PERIOD_NAMES[periodIndex]}
                    </span>
                    <div className="adherence-heatmap__period-fill-bg">
                      <div
                        className="adherence-heatmap__period-fill"
                        style={{
                          width: `${cell.adherence === null ? 0 : cell.adherence}%`,
                          backgroundColor: getCellColor(cell.adherence),
                        }}
                      />
                    </div>
                    <span className="adherence-heatmap__period-percent">
                      {cell.adherence === null ? '—' : `${cell.adherence}%`}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Narrativa (única para ambos os layouts) */}
      {pattern.narrative && (
        <div className="adherence-heatmap__narrative" role="status">
          💡 {pattern.narrative}
        </div>
      )}
    </div>
  )
}

import { useState, useEffect, useCallback } from 'react'
import { adherenceService } from '@services/api/adherenceService'
import AdherenceProgress from './AdherenceProgress'
import StreakBadge from './StreakBadge'
import Loading from '@shared/components/ui/Loading'
import './AdherenceWidget.css'

/**
 * @typedef {Object} ProtocolScore
 * @property {string} protocolId - ID do protocolo
 * @property {string} name - Nome do protocolo
 * @property {string} [medicineName] - Nome do medicamento associado
 * @property {number} score - Porcentagem de adesão (0-100)
 */

/**
 * @typedef {Object} AdherenceData
 * @property {number} overallScore - Score geral de adesão (0-100)
 * @property {number} overallTaken - Total de doses tomadas
 * @property {number} overallExpected - Total de doses esperadas
 * @property {number} [currentStreak] - Dias consecutivos atual
 * @property {number} [longestStreak] - Recorde de dias consecutivos
 * @property {ProtocolScore[]} [protocolScores] - Scores por protocolo
 */

/**
 * @typedef {Object} AdherenceWidgetProps
 * @property {string} [defaultPeriod='30d'] - Período inicial: '7d' | '30d' | '90d'
 */

/**
 * AdherenceWidget - Widget completo de adesão ao tratamento
 *
 * **Propósito:**
 * Widget completo que carrega e exibe dados de adesão ao tratamento,
 * incluindo score geral, streak, adesão por protocolo e dicas personalizadas.
 * Este componente gerencia seu próprio estado de dados e chamadas à API.
 *
 * **Funcionalidades incluídas:**
 * - Score geral de adesão com indicador visual circular
 * - Seletor de período (7 dias, 30 dias, 90 dias)
 * - Streak atual e recorde de dias consecutivos
 * - Breakdown de adesão por protocolo
 * - Dicas contextualizadas baseadas no score
 * - Estados de loading e erro
 *
 * **Quando usar:**
 * - No dashboard para visão geral de adesão
 * - Quando você precisa que os dados sejam carregados automaticamente
 * - Para widgets completos com interatividade (mudança de período)
 *
 * **Quando NÃO usar (use AdherenceProgress em vez disso):**
 * - Quando você já tem o valor calculado e só precisa exibir
 * - Para indicadores visuais simples em cards ou listas
 * - Quando precisa de controle total sobre o layout e dados
 *
 * **Dependências de dados:**
 * Este componente usa {@link adherenceService} para carregar:
 * - Resumo de adesão via `adherenceService.getAdherenceSummary(period)`
 *
 * @param {AdherenceWidgetProps} props
 * @returns {JSX.Element}
 *
 * @example
 * // Uso padrão com período inicial de 30 dias
 * <AdherenceWidget />
 *
 * @example
 * // Período inicial customizado
 * <AdherenceWidget defaultPeriod="7d" />
 *
 * @see {@link AdherenceProgress} - Para componente visual puro sem dados
 * @see {@link StreakBadge} - Para exibir streak em outros contextos
 */
export default function AdherenceWidget({ defaultPeriod = '30d' }) {
  const [period, setPeriod] = useState(defaultPeriod)
  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  const loadAdherenceData = useCallback(async () => {
    try {
      setLoading(true)
      setError(null)
      const summary = await adherenceService.getAdherenceSummary(period)
      setData(summary)
    } catch (err) {
      console.error('Erro ao carregar adesão:', err)
      setError('Não foi possível carregar os dados de adesão')
    } finally {
      setLoading(false)
    }
  }, [period])

  useEffect(() => {
    loadAdherenceData()
  }, [loadAdherenceData])

  const getScoreLabel = (score) => {
    if (score >= 90) return 'Excelente'
    if (score >= 80) return 'Muito Bom'
    if (score >= 60) return 'Bom'
    if (score >= 40) return 'Regular'
    return 'Precisa de Atenção'
  }

  const getScoreStatus = (score) => {
    if (score >= 80) return 'good'
    if (score >= 60) return 'warning'
    return 'poor'
  }

  if (loading) {
    return (
      <div className="adherence-widget loading">
        <Loading text="Calculando adesão..." size="sm" />
      </div>
    )
  }

  if (error) {
    return (
      <div className="adherence-widget error">
        <p className="error-text">{error}</p>
        <button onClick={loadAdherenceData} className="retry-btn">
          Tentar novamente
        </button>
      </div>
    )
  }

  return (
    <div className="adherence-widget">
      {/* Header com período selector */}
      <div className="adherence-header">
        <h3 className="adherence-title">Score de Adesão</h3>
        <div className="period-selector">
          {['7d', '30d', '90d'].map((p) => (
            <button
              key={p}
              className={`period-btn ${period === p ? 'active' : ''}`}
              onClick={() => setPeriod(p)}
            >
              {p.replace('d', ' dias')}
            </button>
          ))}
        </div>
      </div>

      {/* Score principal e streak */}
      <div className="adherence-main">
        <div className="score-section">
          <AdherenceProgress score={data?.overallScore || 0} size={140} strokeWidth={12} />
          <div className="score-info">
            <span className={`score-label ${getScoreStatus(data?.overallScore || 0)}`}>
              {getScoreLabel(data?.overallScore || 0)}
            </span>
            <span className="score-detail">
              {data?.overallTaken || 0} de {data?.overallExpected || 0} doses
            </span>
          </div>
        </div>

        {/* Streak info */}
        {(data?.currentStreak > 0 || data?.longestStreak > 0) && (
          <div className="streak-section">
            {data?.currentStreak > 0 && (
              <div className="streak-item">
                <StreakBadge streak={data.currentStreak} size="lg" />
                <span className="streak-description">dias seguidos</span>
              </div>
            )}
            {data?.longestStreak > data?.currentStreak && (
              <div className="streak-item record">
                <span className="record-label">Recorde:</span>
                <span className="record-value">{data.longestStreak} dias</span>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Adesão por protocolo */}
      {data?.protocolScores?.length > 0 && (
        <div className="protocol-scores">
          <h4 className="protocols-title">Por Protocolo</h4>
          <div className="protocols-list">
            {data.protocolScores.map((protocol) => (
              <div key={protocol.protocolId} className="protocol-item">
                <div className="protocol-info">
                  <span className="protocol-name">{protocol.name}</span>
                  {protocol.medicineName && (
                    <span className="protocol-medicine">{protocol.medicineName}</span>
                  )}
                </div>
                <div className="protocol-score">
                  <div className="mini-progress">
                    <div
                      className="mini-progress-bar"
                      style={{
                        width: `${protocol.score}%`,
                        backgroundColor:
                          protocol.score >= 80
                            ? '#00ff88'
                            : protocol.score >= 60
                              ? '#ffd700'
                              : '#ff3366',
                      }}
                    />
                  </div>
                  <span className="protocol-score-value">{protocol.score}%</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Dicas baseadas no score */}
      <div className="adherence-tips">
        {(data?.overallScore || 0) < 60 && (
          <p className="tip-text">💡 Dica: Configure lembretes para não esquecer suas doses</p>
        )}
        {(data?.overallScore || 0) >= 90 && (
          <p className="tip-text success">🌟 Parabéns! Você está mantendo uma adesão excelente!</p>
        )}
      </div>
    </div>
  )
}

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest'
import { analyzeAdherencePatterns } from '../adherencePatternService'
import { randomUUID } from 'crypto'

describe('adherencePatternService', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  afterEach(() => {
    vi.clearAllMocks()
    vi.clearAllTimers()
  })

  describe('analyzeAdherencePatterns', () => {
    // Utilitários para testes
    const createLog = (medicineId, protocolId, quantityTaken, dateStr, hour = 10) => ({
      id: randomUUID(),
      medicine_id: medicineId,
      protocol_id: protocolId,
      quantity_taken: quantityTaken,
      taken_at: `${dateStr}T${String(hour).padStart(2, '0')}:00:00Z`,
    })

    const createProtocol = (
      id,
      medicineId,
      frequency = 'diário',
      timeSchedule = ['09:00', '21:00'],
      startDate = '2026-02-22'
    ) => ({
      id,
      medicine_id: medicineId,
      name: `Medicamento ${id}`,
      frequency,
      time_schedule: timeSchedule,
      dosage_per_intake: 1,
      start_date: startDate,
    })

    it('retorna hasEnoughData=false com < 21 dias de dados', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = [
        createLog(medicineId, protocolId, 1, '2026-02-24', 9),
        createLog(medicineId, protocolId, 1, '2026-02-25', 9),
        createLog(medicineId, protocolId, 1, '2026-02-26', 9),
        // Apenas 3 dias
      ]
      const protocols = [createProtocol(protocolId, medicineId)]

      const result = analyzeAdherencePatterns({ logs, protocols })

      expect(result.hasEnoughData).toBe(false)
      expect(result.worstCell).toBeNull()
      expect(result.narrative).toContain('21 dias')
    })

    it('retorna hasEnoughData=true com >= 21 dias de dados', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = []

      // Criar 21 dias de logs
      for (let i = 0; i < 21; i++) {
        const date = new Date(2026, 1, 24 + i) // Fevereiro 24 - março 16
        const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
        logs.push(createLog(medicineId, protocolId, 1, dateStr, 9))
      }

      const protocols = [createProtocol(protocolId, medicineId)]

      const result = analyzeAdherencePatterns({ logs, protocols })

      expect(result.hasEnoughData).toBe(true)
      expect(result.grid).toHaveLength(7) // 7 dias da semana
      expect(result.grid[0]).toHaveLength(4) // 4 períodos
    })

    it('calcula grid 7x4 com adherência correta', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = []

      // 21 dias: dia 24 (segunda) a 16 (terça)
      for (let i = 0; i < 21; i++) {
        const date = new Date(2026, 1, 24 + i)
        const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
        // Tomar medicamento sempre às 9 (manhã, período 1)
        logs.push(createLog(medicineId, protocolId, 1, dateStr, 9))
      }

      // Protocolo: diário, 09:00 e 21:00 (2 vezes/dia)
      const protocols = [createProtocol(protocolId, medicineId, 'diário', ['09:00', '21:00'])]

      const result = analyzeAdherencePatterns({ logs, protocols })

      // Expected é o padrão por dia da semana (1 dose às 09:00 em cada segunda)
      // Taken é o total de doses tomadas nas 3 segundas-feiras dos 21 dias
      // Há 3 Mondays nos 21 dias (Mar 02, 09, 16)
      expect(result.grid[1][1].adherence).toBe(100) // Segunda, Manhã: toma todos os dias esperados
      expect(result.grid[1][1].taken).toBe(3) // 3 doses em 3 segundas
      expect(result.grid[1][1].expected).toBe(1) // padrão: 1 dose por segunda-feira
      expect(result.grid[1][3].adherence).toBe(0) // Segunda, Noite: nunca toma
      expect(result.grid[1][3].taken).toBe(0)
      expect(result.grid[1][3].expected).toBe(1) // padrão: 1 dose por segunda-feira
    })

    it('identifica pior célula corretamente', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = []

      // 21 dias de logs, mas variando adherência por período
      for (let i = 0; i < 21; i++) {
        const date = new Date(2026, 1, 24 + i)
        const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`

        // Tomar manhã (09:00) sempre
        logs.push(createLog(medicineId, protocolId, 1, dateStr, 9))

        // Tomar à noite (21:00) apenas em 50% dos dias (i par)
        if (i % 2 === 0) {
          logs.push(createLog(medicineId, protocolId, 1, dateStr, 21))
        }
      }

      // Protocolo: diário, 3 vezes à noite (para expected >= 3)
      const protocols = [
        createProtocol(protocolId, medicineId, 'diário', ['21:00', '21:30', '22:00']),
      ]

      const result = analyzeAdherencePatterns({ logs, protocols })

      expect(result.worstCell).not.toBeNull()
      // Pior célula deve ser período noite com 50% de aderência
      // (toma em 11 dias de 21 = ~52%, arredondado pode ser 50%)
      expect(result.worstCell.periodName.toLowerCase()).toContain('noite')
      expect(result.worstCell.adherence).toBeLessThanOrEqual(60) // Entre 50-60%
    })

    it('gera narrativa com dia e período do pior horário', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = []

      // 21 dias, sempre tomar na quarta-feira à tarde (muito baixa adesão)
      for (let i = 0; i < 21; i++) {
        const date = new Date(2026, 1, 24 + i)
        const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`

        // Tomar sempre manhã
        logs.push(createLog(medicineId, protocolId, 1, dateStr, 9))

        // Tomar tarde (15:00) apenas se quarta-feira (dias 26, 5, 12, 19)
        const dayOfWeek = date.getDay()
        if (dayOfWeek === 3) {
          // Quarta = 3
          // Não tomar à tarde em quarta
        } else {
          logs.push(createLog(medicineId, protocolId, 1, dateStr, 15))
        }
      }

      // Protocolo: diário, 3 vezes à tarde (expected >= 3 para worst cell detection)
      const protocols = [
        createProtocol(protocolId, medicineId, 'diário', ['15:00', '15:30', '16:00']),
      ]

      const result = analyzeAdherencePatterns({ logs, protocols })

      // Se houver uma pior célula detectada (expected >= 3), deve estar na narrativa
      if (result.worstCell && result.narrative.includes('pior horário')) {
        expect(result.narrative).toContain(result.worstCell.dayName)
        expect(result.narrative).toContain(result.worstCell.periodName.toLowerCase())
      } else {
        // Se não houver worst cell (expected < 3 para todos), just check narrative exists
        expect(result.narrative).toBeDefined()
      }
    })

    it('marca períodos sem doses esperadas como N/D (adherência = null)', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = []

      // 21 dias, tomar apenas às 9 (manhã)
      for (let i = 0; i < 21; i++) {
        const date = new Date(2026, 1, 24 + i)
        const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
        logs.push(createLog(medicineId, protocolId, 1, dateStr, 9))
      }

      // Protocolo: apenas uma vez/dia às 9 (manhã)
      const protocols = [createProtocol(protocolId, medicineId, 'diário', ['09:00'])]

      const result = analyzeAdherencePatterns({ logs, protocols })

      // Períodos madrugada, tarde, noite não têm doses esperadas
      // Devem ter adherência = null (N/D)
      expect(result.grid[1][0].expected).toBe(0) // Madrugada
      expect(result.grid[1][0].adherence).toBe(null)
      expect(result.grid[1][3].expected).toBe(0) // Noite
      expect(result.grid[1][3].adherence).toBe(null)
    })

    it('cap adherência em 100% se há mais doses que esperado', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = []

      // 21 dias, mas tomar 2x na manhã quando esperado é 1x
      for (let i = 0; i < 21; i++) {
        const date = new Date(2026, 1, 24 + i)
        const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
        logs.push(createLog(medicineId, protocolId, 2, dateStr, 9)) // quantity_taken = 2
      }

      // Protocolo: 1 vez/dia às 9
      const protocols = [createProtocol(protocolId, medicineId, 'diário', ['09:00'])]

      const result = analyzeAdherencePatterns({ logs, protocols })

      // Manhã: 2/1 * 100 = 200%, mas deve ser capped em 100%
      expect(result.grid[1][1].adherence).toBe(100)
    })

    it('retorna pior célula = null quando todos os períodos têm adherência 100%', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = []

      // 21 dias perfeitos
      for (let i = 0; i < 21; i++) {
        const date = new Date(2026, 1, 24 + i)
        const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
        logs.push(createLog(medicineId, protocolId, 1, dateStr, 9))
      }

      // Protocolo: 1x/dia
      const protocols = [createProtocol(protocolId, medicineId, 'diário', ['09:00'])]

      const result = analyzeAdherencePatterns({ logs, protocols })

      // Sem pior célula (todos 100% ou 0 esperado)
      expect(result.worstCell).toBeNull()
      expect(result.narrative).toContain('excelente')
    })

    it('valida entrada com Zod e lança erro em dados inválidos', () => {
      const invalidLogs = [{ invalid: 'data' }]
      const protocols = []

      expect(() => {
        analyzeAdherencePatterns({ logs: invalidLogs, protocols })
      }).toThrow()
    })

    it('mapeia frequência diária para todos os 7 dias', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = []

      // 21 dias, sempre tomar às 9
      for (let i = 0; i < 21; i++) {
        const date = new Date(2026, 1, 24 + i)
        const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
        logs.push(createLog(medicineId, protocolId, 1, dateStr, 9))
      }

      // Protocolo: diário
      const protocols = [createProtocol(protocolId, medicineId, 'diário', ['09:00'])]

      const result = analyzeAdherencePatterns({ logs, protocols })

      // Todos os 7 dias devem ter expected=1 (uma vez/dia)
      for (let day = 0; day < 7; day++) {
        expect(result.grid[day][1].expected).toBe(1) // Manhã (período 1)
      }
    })

    it('mapeia frequência dias_alternados corretamente', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = []

      // 21 dias
      for (let i = 0; i < 21; i++) {
        const date = new Date(2026, 1, 24 + i)
        const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
        logs.push(createLog(medicineId, protocolId, 1, dateStr, 9))
      }

      // Protocolo: dias alternados (0, 2, 4, 6)
      const protocols = [createProtocol(protocolId, medicineId, 'dias_alternados', ['09:00'])]

      const result = analyzeAdherencePatterns({ logs, protocols })

      // Domingo (0), Terça (2), Quinta (4), Sábado (6) devem ter expected=1
      expect(result.grid[0][1].expected).toBe(1) // Domingo
      expect(result.grid[2][1].expected).toBe(1) // Terça
      expect(result.grid[4][1].expected).toBe(1) // Quinta
      expect(result.grid[6][1].expected).toBe(1) // Sábado

      // Segunda (1), Quarta (3), Sexta (5) devem ter expected=0
      expect(result.grid[1][1].expected).toBe(0) // Segunda
      expect(result.grid[3][1].expected).toBe(0) // Quarta
      expect(result.grid[5][1].expected).toBe(0) // Sexta
    })

    it('ignora quando_necessário e personalizado (expected=0)', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = []

      // 21 dias
      for (let i = 0; i < 21; i++) {
        const date = new Date(2026, 1, 24 + i)
        const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
        logs.push(createLog(medicineId, protocolId, 1, dateStr, 9))
      }

      // Protocolo: quando_necessário
      const protocols = [createProtocol(protocolId, medicineId, 'quando_necessário', ['09:00'])]

      const result = analyzeAdherencePatterns({ logs, protocols })

      // Todos os períodos devem ter expected=0
      for (let day = 0; day < 7; day++) {
        for (let period = 0; period < 4; period++) {
          expect(result.grid[day][period].expected).toBe(0)
        }
      }
    })

    it('mapeia horas para períodos corretos', () => {
      const medicineId = randomUUID()
      const protocolId = randomUUID()
      const logs = [
        // 21 dias com diferentes horários
        ...Array.from({ length: 21 }, (_, i) => {
          const date = new Date(2026, 1, 24 + i)
          const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
          return [
            createLog(medicineId, protocolId, 1, dateStr, 3), // Madrugada (0-6)
            createLog(medicineId, protocolId, 1, dateStr, 9), // Manhã (6-12)
            createLog(medicineId, protocolId, 1, dateStr, 15), // Tarde (12-18)
            createLog(medicineId, protocolId, 1, dateStr, 21), // Noite (18-24)
          ]
        }).flat(),
      ]

      const protocols = [
        createProtocol(protocolId, medicineId, 'diário', ['03:00', '09:00', '15:00', '21:00']),
      ]

      const result = analyzeAdherencePatterns({ logs, protocols })

      // Há 3 segundas-feiras nos 21 dias (Mar 02, 09, 16)
      // Cada log é criado 4 vezes por dia, uma para cada período
      expect(result.grid[1][0].taken).toBe(3) // Madrugada × 3 Mondays
      expect(result.grid[1][1].taken).toBe(3) // Manhã × 3 Mondays
      expect(result.grid[1][2].taken).toBe(3) // Tarde × 3 Mondays
      expect(result.grid[1][3].taken).toBe(3) // Noite × 3 Mondays
    })
  })
})

// src/features/adherence/services/__tests__/protocolRiskService.test.js

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest'
import {
  calculateProtocolRisk,
  calculateAllProtocolRisks,
  RISK_LEVELS,
} from '../protocolRiskService'

describe('protocolRiskService', () => {
  beforeEach(() => {
    // Usar data fixa para evitar flakiness perto de meia-noite (fix: Gemini issue #7)
    vi.useFakeTimers()
    vi.setSystemTime(new Date('2026-03-08T12:00:00Z'))
  })

  afterEach(() => {
    vi.clearAllMocks()
    vi.clearAllTimers()
    vi.useRealTimers()
  })

  describe('calculateProtocolRisk', () => {
    it('classifica como STABLE com adesao >=80% e trend >= -5%', () => {
      // 14/14 doses tomadas (100%), trend 0%
      // Result: adherence >= 80% AND trend >= -5% = STABLE

      const now = new Date()
      const logs = []

      // Days 1-14: 14 doses = 100% adherence
      for (let i = 1; i <= 14; i++) {
        const date = new Date(now)
        date.setDate(date.getDate() - i)
        date.setHours(10, 0, 0, 0)
        logs.push({
          protocol_id: 'proto-1',
          medicine_id: 'med-1',
          taken_at: date.toISOString(),
          quantity_taken: 1,
        })
      }

      const protocol = {
        id: 'proto-1',
        medicine_id: 'med-1',
        frequency: 'diário',
        time_schedule: ['08:00'],
        active: true,
      }

      const result = calculateProtocolRisk({ protocolId: 'proto-1', logs, protocol })

      expect(result.riskLevel).toBe(RISK_LEVELS.STABLE)
      expect(result.adherence14d).toBe(100)
      expect(result.trend7d).toBe(0)
    })

    it('classifica como ATTENTION com adesao 50-79%', () => {
      // 9/14 doses = 64% adherence = ATTENTION (not CRITICAL, not STABLE)

      const now = new Date()
      const logs = []
      // Create 9 doses spread across 14 days
      for (let i = 1; i <= 9; i++) {
        const date = new Date(now)
        date.setDate(date.getDate() - i)
        date.setHours(10, 0, 0, 0)
        logs.push({
          protocol_id: 'proto-1',
          medicine_id: 'med-1',
          taken_at: date.toISOString(),
          quantity_taken: 1,
        })
      }

      const protocol = {
        id: 'proto-1',
        medicine_id: 'med-1',
        frequency: 'diário',
        time_schedule: ['08:00'],
        active: true,
      }

      const result = calculateProtocolRisk({ protocolId: 'proto-1', logs, protocol })

      expect(result.riskLevel).toBe(RISK_LEVELS.ATTENTION)
      expect(result.adherence14d).toBe(64)
    })

    it('classifica como CRITICAL com adesao <50%', () => {
      // 5/14 doses = 36% adherence = CRITICAL

      const now = new Date()
      const logs = []
      // Create 5 doses spread across 14 days
      for (let i = 1; i <= 5; i++) {
        const date = new Date(now)
        date.setDate(date.getDate() - i)
        date.setHours(10, 0, 0, 0)
        logs.push({
          protocol_id: 'proto-1',
          medicine_id: 'med-1',
          taken_at: date.toISOString(),
          quantity_taken: 1,
        })
      }

      const protocol = {
        id: 'proto-1',
        medicine_id: 'med-1',
        frequency: 'diário',
        time_schedule: ['08:00'],
        active: true,
      }

      const result = calculateProtocolRisk({ protocolId: 'proto-1', logs, protocol })

      expect(result.riskLevel).toBe(RISK_LEVELS.CRITICAL)
      expect(result.adherence14d).toBe(36)
    })

    it('classifica como CRITICAL com trend < -15%', () => {
      // Week 1: 0 doses (0%), Week 2 (previous): 7 doses (100%) → trend = -100% = CRITICAL

      const now = new Date()
      const logs = []

