import { validateAnalyzeAdherencePatternsInput } from '@schemas/adherencePatternSchema'

/**
 * Nomes dos dias da semana
 */
const DAY_NAMES = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado']

/**
 * Nomes dos períodos do dia
 */
const PERIOD_NAMES = ['Madrugada', 'Manhã', 'Tarde', 'Noite']

/**
 * Períodos do dia em horas (0-6, 6-12, 12-18, 18-24)
 */
const PERIOD_HOURS = [
  { start: 0, end: 6 }, // 0: Madrugada
  { start: 6, end: 12 }, // 1: Manhã
  { start: 12, end: 18 }, // 2: Tarde
  { start: 18, end: 24 }, // 3: Noite
]

/**
 * Determina o índice do período baseado na hora
 * @param {number} hour - Hora (0-23)
 * @returns {number} Índice do período (0-3)
 */
function getPeriodIndex(hour) {
  if (hour < 6) return 0 // Madrugada
  if (hour < 12) return 1 // Manhã
  if (hour < 18) return 2 // Tarde
  return 3 // Noite
}

/**
 * Conta quantos dias únicos com dados existem nos logs
 * @param {Array} logs - Array de logs de doses
 * @returns {number} Quantidade de dias únicos com dados
 */
function countUniqueDaysWithLogs(logs) {
  const uniqueDays = new Set(
    logs.map((log) => {
      const date = new Date(log.taken_at)
      return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
    })
  )
  return uniqueDays.size
}

/**
 * Pré-processa protocolos para mapear time_schedule por dia da semana
 * Retorna um mapa: { dayIndex: { periodIndex: count } }
 * @param {Array} protocols - Array de protocolos com time_schedule
 * @returns {Object} Mapa de doses esperadas por dia/período
 */
function preprocessProtocolsExpected(protocols) {
  const expectedMap = {}

  // Inicializar grid vazio
  for (let day = 0; day < 7; day++) {
    expectedMap[day] = { 0: 0, 1: 0, 2: 0, 3: 0 }
  }

  // Para cada protocolo, mapear doses esperadas por dia da semana
  protocols.forEach((protocol) => {
    if (!protocol.time_schedule || protocol.time_schedule.length === 0) {
      return
    }

    const daysOfWeek = getDaysOfWeekForProtocol(protocol.frequency)

    daysOfWeek.forEach((dayIndex) => {
      protocol.time_schedule.forEach((timeStr) => {
        const [hour] = timeStr.split(':').map(Number)
        const periodIndex = getPeriodIndex(hour)
        expectedMap[dayIndex][periodIndex] += 1
      })
    })
  })

  return expectedMap
}

/**
 * Retorna dias da semana esperados para um protocolo baseado em frequência
 * @param {string} frequency - Frequência do protocolo
 * @returns {Array<number>} Array de índices de dias (0-6)
 */
function getDaysOfWeekForProtocol(frequency) {
  switch (frequency) {
    case 'diário':
      return [0, 1, 2, 3, 4, 5, 6] // Todos os dias
    case 'dias_alternados':
      return [0, 2, 4, 6] // Padrão: dias pares
    case 'semanal':
      return [0] // Uma vez por semana (domingo)
    case 'quando_necessário':
    case 'personalizado':
      return [] // Não contar doses esperadas para esses casos
    default:
      return []
  }
}

/**
 * Analisa padrões de adesão por dia da semana e período do dia.
 *
 * @param {Object} params
 * @param {Array} params.logs - Logs de doses (mínimo 21 dias recomendado)
 * @param {Array} params.protocols - Protocolos ativos com time_schedule
 * @returns {{
 *   grid: Array<Array<{adherence: number, taken: number, expected: number}>>,
 *   worstCell: { dayIndex: number, periodIndex: number, adherence: number, dayName: string, periodName: string } | null,
 *   narrative: string,
 *   hasEnoughData: boolean
 * }}
 */
export function analyzeAdherencePatterns({ logs, protocols }) {
  // Validar entrada com Zod
  const validation = validateAnalyzeAdherencePatternsInput({ logs, protocols })
  if (!validation.success) {
    throw new Error(`Validação falhou: ${validation.errors.map((e) => e.message).join(', ')}`)
  }

  // Inicializar grid 7x4 com zeros
  const grid = Array.from({ length: 7 }, () =>
    Array.from({ length: 4 }, () => ({ taken: 0, expected: 0, adherence: 0 }))
  )

  // Pré-processar protocolos para obter doses esperadas (por dia da semana)
  const expectedMap = preprocessProtocolsExpected(protocols)

  // Contar doses tomadas por célula (CONTAR REGISTROS, NÃO COMPRIMIDOS)
  // Cada registro = 1 dose tomada (independente de quantity_taken)
  logs.forEach((log) => {
    const logDate = new Date(log.taken_at)
    const dayIndex = logDate.getDay() // 0-6 (domingo-sábado)
    const hour = logDate.getHours()
    const periodIndex = getPeriodIndex(hour)

    // Incrementar 1 para cada dose registrada (não usar quantity_taken que mistura comprimidos com doses)
    grid[dayIndex][periodIndex].taken += 1
  })

  // Contar quantas vezes cada dia da semana ocorre nos logs
  const dayOccurrences = [0, 0, 0, 0, 0, 0, 0]
  const uniqueDates = new Set()
  logs.forEach((log) => {
    const logDate = new Date(log.taken_at)
    const dateStr = `${logDate.getFullYear()}-${String(logDate.getMonth() + 1).padStart(2, '0')}-${String(logDate.getDate()).padStart(2, '0')}`
    if (!uniqueDates.has(dateStr)) {
      uniqueDates.add(dateStr)
      const dayIndex = logDate.getDay()
      dayOccurrences[dayIndex] += 1
    }
  })

  // Preencher expected e calcular adherence (normalizado)
  for (let dayIndex = 0; dayIndex < 7; dayIndex++) {
    for (let periodIndex = 0; periodIndex < 4; periodIndex++) {
      const expectedPerDay = expectedMap[dayIndex][periodIndex]
      const occurrences = dayOccurrences[dayIndex]
      const totalExpected = expectedPerDay * occurrences
      const taken = grid[dayIndex][periodIndex].taken

      // Armazenar expected (por dia) no grid
      grid[dayIndex][periodIndex].expected = expectedPerDay

      if (totalExpected > 0) {
        // Calcular adherence normalizando: (taken / totalExpected) * 100
        grid[dayIndex][periodIndex].adherence = Math.min(
          100,
          Math.round((taken / totalExpected) * 100)
        )
      } else if (expectedPerDay === 0) {
        // Se não há doses esperadas neste período, marcar como N/D
        grid[dayIndex][periodIndex].adherence = null
      } else if (occurrences === 0) {
        // Se o dia não ocorre nos logs, não calcular adherence
        grid[dayIndex][periodIndex].adherence = null
      }
    }
  }

  // Contar dias únicos com dados
  const daysWithData = countUniqueDaysWithLogs(logs)
  const hasEnoughData = daysWithData >= 21

  // Encontrar pior célula (mínimo 3 doses esperadas)
  let worstCell = null
  if (hasEnoughData) {
    let worstAdherence = 100
    let worstDayIndex = null
    let worstPeriodIndex = null

    for (let dayIndex = 0; dayIndex < 7; dayIndex++) {
      for (let periodIndex = 0; periodIndex < 4; periodIndex++) {
        const cell = grid[dayIndex][periodIndex]
        if (cell.expected >= 3 && cell.adherence < worstAdherence) {
          worstAdherence = cell.adherence
          worstDayIndex = dayIndex
          worstPeriodIndex = periodIndex
        }
      }
    }

    if (worstDayIndex !== null && worstPeriodIndex !== null) {
      worstCell = {
        dayIndex: worstDayIndex,
        periodIndex: worstPeriodIndex,
        adherence: worstAdherence,
        dayName: DAY_NAMES[worstDayIndex],
        periodName: PERIOD_NAMES[worstPeriodIndex],
      }
    }
  }

  // Gerar narrativa
  let narrative = ''
  if (hasEnoughData && worstCell) {
    narrative = `Seu pior horário é ${worstCell.dayName} à ${worstCell.periodName.toLowerCase()}`
  } else if (!hasEnoughData) {
    narrative = `Dados insuficientes. Registre pelo menos 21 dias de doses para análise completa.`
  } else {
    narrative = 'Sua adesão está excelente em todos os períodos!'
  }

  return {
    grid,
    dayOccurrences,
    worstCell: hasEnoughData ? worstCell : null,
    narrative,
    hasEnoughData,
  }
}

export default analyzeAdherencePatterns

// src/features/adherence/services/protocolRiskService.js

import { calculateExpectedDoses } from '@utils/adherenceLogic'

/**
 * Niveis de risco para protocolos.
 */
export const RISK_LEVELS = {
  STABLE: 'stable',
  ATTENTION: 'attention',
  CRITICAL: 'critical',
}

export const RISK_COLORS = {
  stable: 'var(--color-success)', // #22c55e
  attention: 'var(--color-warning)', // #f59e0b
  critical: 'var(--color-error)', // #ef4444
}

export const RISK_LABELS = {
  stable: 'Estável',
  attention: 'Atenção',
  critical: 'Crítico',
}

/**
 * Calcula score de risco para um protocolo.
 *
 * @param {Object} params
 * @param {string} params.protocolId
 * @param {Array} params.logs - TODOS os logs do usuario (sera filtrado internamente)
 * @param {Object} params.protocol - Protocolo com time_schedule, frequency, dosage_per_intake
 * @returns {{
 *   protocolId: string,
 *   adherence14d: number,    // 0-100
 *   trend7d: number,         // delta percentual (-100 a +100)
 *   riskLevel: 'stable'|'attention'|'critical',
 *   riskColor: string,
 *   riskLabel: string,
 *   hasEnoughData: boolean
 * }}
 */
export function calculateProtocolRisk({ protocolId, logs, protocol }) {
  const now = new Date()
  const fourteenDaysAgo = new Date(now)
  fourteenDaysAgo.setDate(now.getDate() - 14)
  fourteenDaysAgo.setHours(0, 0, 0, 0) // Zerar horas para comparacao consistente (fix: Gemini issue #1)

  const sevenDaysAgo = new Date(now)
  sevenDaysAgo.setDate(now.getDate() - 7)
  sevenDaysAgo.setHours(0, 0, 0, 0) // Zerar horas

  // Filtrar logs APENAS deste protocolo (fix: Gemini issue #4, nao OR por medicine_id)
  const protocolLogs = logs.filter((log) => log.protocol_id === protocolId)

  // Adesao ultimos 14 dias - usar sum of quantity_taken, nao contagem de logs (fix: Gemini issue #2)
  const logs14d = protocolLogs.filter((log) => new Date(log.taken_at) >= fourteenDaysAgo)
  const expected14d = calculateExpectedDoses([protocol], 14)
  const totalTaken14d = logs14d.reduce((sum, log) => sum + (log.quantity_taken ?? 0), 0)
  const adherence14d =
    expected14d > 0 ? Math.min(100, Math.round((totalTaken14d / expected14d) * 100)) : 100

  // Adesao ultimos 7 dias vs 7 dias anteriores (trend) - fix: Gemini issue #3
  const logs7d = protocolLogs.filter((log) => new Date(log.taken_at) >= sevenDaysAgo)
  const logsPrev7d = protocolLogs.filter((log) => {
    const logDate = new Date(log.taken_at)
    return logDate >= fourteenDaysAgo && logDate < sevenDaysAgo
  })

  const expected7d = calculateExpectedDoses([protocol], 7)
  const totalTaken7d = logs7d.reduce((sum, log) => sum + (log.quantity_taken ?? 0), 0)
  const totalTakenPrev7d = logsPrev7d.reduce((sum, log) => sum + (log.quantity_taken ?? 0), 0)
  const adherence7d = expected7d > 0 ? (totalTaken7d / expected7d) * 100 : 100
  const adherencePrev7d = expected7d > 0 ? (totalTakenPrev7d / expected7d) * 100 : 100
  const trend7d = Math.round(adherence7d - adherencePrev7d)

  // Verificar dados suficientes
  const hasEnoughData = expected14d >= 4 // Pelo menos ~2 doses/semana

  // Classificar risco
  let riskLevel
  if (!hasEnoughData) {
    riskLevel = RISK_LEVELS.STABLE // Nao penalizar sem dados
  } else if (adherence14d < 50 || trend7d < -15) {
    riskLevel = RISK_LEVELS.CRITICAL
  } else if (adherence14d < 80 || (trend7d >= -15 && trend7d < -5)) {
    riskLevel = RISK_LEVELS.ATTENTION
  } else {
    riskLevel = RISK_LEVELS.STABLE
  }

  return {
    protocolId,
    adherence14d,
    trend7d,
    riskLevel,
    riskColor: RISK_COLORS[riskLevel],
    riskLabel: RISK_LABELS[riskLevel],
    hasEnoughData,
  }
}

/**
 * Calcula risco para TODOS os protocolos ativos.
 */
export function calculateAllProtocolRisks({ protocols, logs }) {
  return protocols
    .filter((p) => p.active)
    .map((protocol) =>
      calculateProtocolRisk({
        protocolId: protocol.id,
        logs,
        protocol,
      })
    )
}

/**
 * DoseCalendar - Calendário visual de doses com indicadores de status
 *
 * Componente que exibe um calendário mensal com indicadores coloridos
 * mostrando o status de adesão para cada dia.
 *
 * @module DoseCalendar
 */
import { useState, useMemo, useCallback, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { useDashboard } from '@dashboard/hooks/useDashboardContext'
import Calendar from '@shared/components/ui/Calendar'
import {
  calculateMonthlyDoseMap,
  calculateMonthlyStats,
} from '@calendar/services/doseCalendarService'
import { formatLocalDate, parseLocalDate } from '@utils/dateUtils'
import './DoseCalendar.css'

/**
 * Cores para cada status de dose.
 * @constant {Object.<string, string>}
 */
const STATUS_COLORS = {
  completo: '#10b981', // Verde
  parcial: '#f59e0b', // Âmbar
  perdido: '#ef4444', // Vermelho
  sem_doses: '#6b7280', // Cinza
  futuro: '#6b7280', // Cinza (mesma cor para dias futuros)
}

/**
 * Rótulos em português para cada status.
 * @constant {Object.<string, string>}
 */
const STATUS_LABELS = {
  completo: 'Completo',
  parcial: 'Parcial',
  perdido: 'Perdido',
  sem_doses: 'Sem doses',
  futuro: 'Futuro',
}

/**
 * DoseCalendar - Componente de calendário visual de doses
 *
 * @returns {JSX.Element} Calendário com indicadores de status de doses
 */
function DoseCalendar() {
  // 1. States first (R-010)
  const [selectedDate, setSelectedDate] = useState(null)
  const [isPanelOpen, setIsPanelOpen] = useState(false)
  const [viewDate, setViewDate] = useState(new Date())

  // 2. Context/Hooks
  const { logs, protocols } = useDashboard()

  // 3. Memos
  /**
   * Calcula o mapa de doses para o mês atual em exibição.
   */
  const doseMap = useMemo(() => {
    const year = viewDate.getFullYear()
    const month = viewDate.getMonth() + 1 // JavaScript months are 0-indexed

    return calculateMonthlyDoseMap(logs, protocols, year, month)
  }, [logs, protocols, viewDate])

  /**
   * Calcula estatísticas do mês atual.
   */
  const monthlyStats = useMemo(() => {
    return calculateMonthlyStats(doseMap)
  }, [doseMap])

  /**
   * Gera lista de datas marcadas com suas cores para o Calendar.
   * Formato esperado pelo Calendar: array de strings de data
   */
  const markedDates = useMemo(() => {
    return Object.keys(doseMap).filter((dateStr) => {
      const dayInfo = doseMap[dateStr]
      return dayInfo.expected > 0
    })
  }, [doseMap])

  /**
   * Detalhes do dia selecionado para exibir no painel.
   */
  const selectedDayDetails = useMemo(() => {
    if (!selectedDate) return null

    const dateStr = formatLocalDate(selectedDate)
    const dayInfo = doseMap[dateStr]

    if (!dayInfo) return null

    // Verificar se é um dia futuro
    const today = new Date()
    today.setHours(0, 0, 0, 0)
    const isSelectedFuture = selectedDate > today

    // Agrupar doses por protocolo
    const protocolDetails = protocols
      .filter((protocol) => {
        // Verificar se o protocolo estava ativo na data selecionada
        const protocolStart = protocol.start_date ? parseLocalDate(protocol.start_date) : null
        const protocolEnd = protocol.end_date ? parseLocalDate(protocol.end_date) : null

        if (protocolStart && selectedDate < protocolStart) return false
        if (protocolEnd && selectedDate > protocolEnd) return false

        return protocol.active
      })
      .map((protocol) => {
        // Contar doses esperadas e tomadas para este protocolo nesta data
        const logsForProtocol = logs.filter((log) => {
          if (log.protocol_id !== protocol.id) return false
          const logDate = parseLocalDate(log.taken_at)
          return formatLocalDate(logDate) === dateStr
        })

        const expectedDoses = protocol.time_schedule?.length || 0
        const takenDoses = logsForProtocol.length

        let status = 'sem_doses'
        if (expectedDoses > 0) {
          if (takenDoses === expectedDoses) status = 'completo'
          else if (takenDoses > 0) status = 'parcial'
          else status = isSelectedFuture ? 'futuro' : 'perdido'
        }

        return {
          id: protocol.id,
          name: protocol.medicines?.name || protocol.medicine_name || 'Medicamento',
          expected: expectedDoses,
          taken: takenDoses,
          status,
          color: STATUS_COLORS[status],
        }
      })

    return {
      date: selectedDate,
      dateStr,
      ...dayInfo,
      status: isSelectedFuture ? 'futuro' : dayInfo.status,
      color: STATUS_COLORS[isSelectedFuture ? 'futuro' : dayInfo.status],
      protocols: protocolDetails,
    }
  }, [selectedDate, doseMap, logs, protocols])

  // 4. Effects
  /**
   * Fecha o painel ao pressionar Escape.
   */
  useEffect(() => {
    const handleEscape = (e) => {
      if (e.key === 'Escape' && isPanelOpen) {
        setIsPanelOpen(false)
      }
    }

    document.addEventListener('keydown', handleEscape)
    return () => document.removeEventListener('keydown', handleEscape)
  }, [isPanelOpen])

  // 5. Handlers last (R-010)
  /**
   * Manipula clique em um dia do calendário.
   *
   * @param {Date} date - Data clicada
   */
  const handleDayClick = useCallback((date) => {
    setSelectedDate(date)
    setIsPanelOpen(true)
  }, [])

  /**
   * Fecha o painel de detalhes.
   */
  const handleClosePanel = useCallback(() => {
    setIsPanelOpen(false)
  }, [])

  /**
   * Callback para carregar dados do mês (lazy loading).
   * Como usamos useDashboard, os dados já estão disponíveis.
   *
   * @param {number} year - Ano
   * @param {number} month - Mês (0-indexed)
   * @returns {Promise<void>}
   */
  const handleLoadMonth = useCallback(async (year, month) => {
    // Atualiza viewDate para disparar recálculo do doseMap
    setViewDate(new Date(year, month, 1))
    return Promise.resolve()
  }, [])

  /**
   * Formata data para exibição no painel.
   *
   * @param {Date} date - Data a formatar
   * @returns {string} Data formatada
   */
  const formatDateDisplay = (date) => {
    const options = { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }
    return date.toLocaleDateString('pt-BR', options)
  }

  return (
    <div className="dose-calendar">
      <div className="dose-calendar__header">
        <h2 className="dose-calendar__title">Calendário de Doses</h2>
        {monthlyStats && (
          <div className="dose-calendar__stats">
            <span className="dose-calendar__stat">
              <span className="dose-calendar__stat-value">{monthlyStats.adherenceRate}%</span>
              <span className="dose-calendar__stat-label">Adesão</span>
            </span>
            <span className="dose-calendar__stat">
              <span className="dose-calendar__stat-value">{monthlyStats.completeDays}</span>
              <span className="dose-calendar__stat-label">Dias Completos</span>
            </span>
          </div>
        )}
      </div>

      <div className="dose-calendar__legend">
        {Object.entries(STATUS_LABELS).map(([status, label]) => (
          <div key={status} className="dose-calendar__legend-item">
            <span
              className="dose-calendar__legend-dot"
              style={{ backgroundColor: STATUS_COLORS[status] }}
            />
            <span className="dose-calendar__legend-label">{label}</span>
          </div>
        ))}
      </div>

      <Calendar
        markedDates={markedDates}
        selectedDate={selectedDate}
        onDayClick={handleDayClick}
        enableLazyLoad={false}
        onLoadMonth={handleLoadMonth}
        enableSwipe={true}
        enableMonthPicker={true}
      />

      {/* Painel de detalhes com animação */}
      <AnimatePresence>
        {isPanelOpen && selectedDayDetails && (
          <>
            {/* Overlay */}
            <motion.div
              className="dose-calendar__overlay"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={handleClosePanel}
            />

            {/* Painel */}
            <motion.div
              className="dose-calendar__panel"
              initial={{ x: '100%' }}
              animate={{ x: 0 }}
              exit={{ x: '100%' }}
              transition={{ type: 'spring', damping: 25, stiffness: 300 }}
            >
              <div className="dose-calendar__panel-header">
                <h3 className="dose-calendar__panel-title">
                  {formatDateDisplay(selectedDayDetails.date)}
                </h3>
                <button
                  className="dose-calendar__panel-close"
                  onClick={handleClosePanel}
                  aria-label="Fechar painel"
                >
                  ×
                </button>
              </div>

              <div className="dose-calendar__panel-summary">
                <div
                  className="dose-calendar__panel-status"
                  style={{ backgroundColor: selectedDayDetails.color }}
                >
                  <span className="dose-calendar__panel-status-label">
                    {STATUS_LABELS[selectedDayDetails.status]}
                  </span>
                  <span className="dose-calendar__panel-status-count">
                    {selectedDayDetails.taken}/{selectedDayDetails.expected} doses
                  </span>
                </div>
              </div>

              <div className="dose-calendar__panel-protocols">
                <h4 className="dose-calendar__panel-subtitle">Por Protocolo</h4>
                {selectedDayDetails.protocols.length === 0 ? (
                  <p className="dose-calendar__panel-empty">Nenhum protocolo ativo nesta data</p>
                ) : (
                  <ul className="dose-calendar__protocol-list">
                    {selectedDayDetails.protocols.map((protocol) => (
                      <li
                        key={protocol.id}
                        className="dose-calendar__protocol-item"
                        style={{ borderLeftColor: protocol.color }}
                      >
                        <span className="dose-calendar__protocol-name">{protocol.name}</span>
                        <span className="dose-calendar__protocol-status">
                          {protocol.taken}/{protocol.expected} - {STATUS_LABELS[protocol.status]}
                        </span>
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  )
}

