import { useState, useCallback, useRef, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Trash2, X } from 'lucide-react'
import {
  sendChatMessage,
  loadPersistedHistory,
  savePersistedHistory,
  clearPersistedHistory,
} from '../services/chatbotService'
import { createWelcomeMessage } from '../config/chatbotConfig'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import ConfirmDialog from '@shared/components/ui/ConfirmDialog'
import styles from './ChatWindow.module.css'

// Funções auxiliares puras (fora do componente para melhor performance e organização)

/**
 * Renderiza conteúdo com suporte básico a markdown inline:
 * _texto_ → <em>texto</em> (itálico para disclaimers e ênfase)
 * Quebras de linha \n → <br>
 */
function renderMessageContent(content) {
  return content.split('\n').map((line, lineIdx) => {
    const parts = line.split(/(_[^_]+_)/g)
    return (
      <span key={lineIdx}>
        {lineIdx > 0 && <br />}
        {parts.map((part, i) => {
          if (part.startsWith('_') && part.endsWith('_') && part.length > 2) {
            return <em key={i}>{part.slice(1, -1)}</em>
          }
          return <span key={i}>{part}</span>
        })}
      </span>
    )
  })
}

/**
 * Formata timestamp para exibição relativa (e.g., "às 14:30", "Ontem às 09:15").
 */
const formatMessageTime = (timestamp) => {
  const date = new Date(timestamp)
  const now = new Date()
  const isToday = date.toDateString() === now.toDateString()
  const yesterday = new Date(now)
  yesterday.setDate(now.getDate() - 1)
  const isYesterday = date.toDateString() === yesterday.toDateString()
  const timeStr = date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
  if (isToday) return `às ${timeStr}`
  if (isYesterday) return `Ontem às ${timeStr}`
  return `${date.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' })} às ${timeStr}`
}

/**
 * Verifica se deve exibir separador de data antes da mensagem atual.
 */
const shouldShowDateSeparator = (msgs, idx) => {
  if (idx === 0) return false
  const prev = new Date(msgs[idx - 1].timestamp).toDateString()
  const curr = new Date(msgs[idx].timestamp).toDateString()
  return prev !== curr
}

/**
 * Formata label do separador de data (e.g., "Hoje", "Ontem", "15/03").
 */
const formatDaySeparator = (timestamp) => {
  const date = new Date(timestamp)
  const now = new Date()
  const isToday = date.toDateString() === now.toDateString()
  const yesterday = new Date(now)
  yesterday.setDate(now.getDate() - 1)
  const isYesterday = date.toDateString() === yesterday.toDateString()
  if (isToday) return 'Hoje'
  if (isYesterday) return 'Ontem'
  return date.toLocaleDateString('pt-BR', {
    weekday: 'long',
    day: '2-digit',
    month: 'long',
  })
}

/**
 * Drawer lateral de chat com o assistente IA.
 * Lazy-loaded — nao impacta main bundle.
 * Acessa dados do DashboardContext diretamente para montar contexto do paciente.
 *
 * @param {Object} props
 * @param {boolean} props.isOpen
 * @param {Function} props.onClose
 */
export default function ChatWindow({ isOpen, onClose }) {
  const { medicines, protocols, logs, stockSummary, stats } = useDashboard()

  const [messages, setMessages] = useState(() => {
    const persisted = loadPersistedHistory()
    if (persisted.length > 0) return persisted
    return [createWelcomeMessage()]
  })
  const [input, setInput] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [showClearConfirm, setShowClearConfirm] = useState(false)
  const messagesEndRef = useRef(null)

  // Auto-scroll para ultima mensagem
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  // Adiciona mensagem ao estado e persiste histórico
  const addMessage = useCallback((message) => {
    setMessages((prev) => {
      const next = [...prev, message]
      savePersistedHistory(next)
      return next
    })
  }, [])

  const handleSend = useCallback(async () => {
    if (!input.trim() || isLoading) return

    const userMessage = input.trim()
    setInput('')
    addMessage({ role: 'user', content: userMessage, timestamp: Date.now() })
    setIsLoading(true)

    try {
      const result = await sendChatMessage({
        message: userMessage,
        history: messages,
        patientData: { medicines, protocols, logs, stockSummary, stats },
      })

      addMessage({
        role: 'assistant',
        content: result.response || result.reason || '',
        timestamp: Date.now(),
      })
    } finally {
      setIsLoading(false)
    }
  }, [input, isLoading, messages, addMessage, medicines, protocols, logs, stockSummary, stats])

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSend()
    }
  }

  const quickSuggestions = [
    'Tomei meu remédio hoje?',
    'Como está minha adesão?',
    'Quando preciso repor estoque?',
  ]

  const handleClearHistory = () => {
    setShowClearConfirm(true)
  }

  const handleConfirmClear = () => {
    clearPersistedHistory()
    setMessages([createWelcomeMessage()])
    setShowClearConfirm(false)
  }

  const handleCancelClear = () => {
    setShowClearConfirm(false)
  }

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Overlay */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className={styles.overlay}
            onClick={onClose}
          />

          {/* Drawer */}
          <motion.div
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className={styles.drawer}
          >
            {/* Header */}
            <div className={styles.header}>
              <span className={styles.headerTitle}>Assistente IA</span>
              <div className={styles.headerActions}>
                <button
                  onClick={handleClearHistory}
                  className={styles.clearButton}
                  title="Limpar histórico"
                  aria-label="Limpar histórico de conversa"
                >
                  <Trash2 size={16} aria-hidden="true" />
                </button>
                <button onClick={onClose} className={styles.closeButton} aria-label="Fechar chat">
                  <X size={18} aria-hidden="true" />
                </button>
              </div>
            </div>

            {/* Messages */}
            <div className={styles.messages}>
              {messages.map((msg, i) => (
                <div key={i}>
                  {shouldShowDateSeparator(messages, i) && (
                    <div className={styles.dateSeparator}>{formatDaySeparator(msg.timestamp)}</div>
                  )}
                  <div
                    className={`${styles.messageBubble} ${
                      msg.role === 'user' ? styles.messageBubbleUser : styles.messageBubbleAssistant
                    }`}
                  >
                    {renderMessageContent(msg.content)}
                    {msg.timestamp && (
                      <span className={styles.messageTime}>{formatMessageTime(msg.timestamp)}</span>
                    )}
                  </div>
                </div>
              ))}

              {isLoading && <div className={styles.thinkingBubble}>Pensando...</div>}

              <div ref={messagesEndRef} />
            </div>

            {/* Quick suggestions (quando poucas mensagens) */}
            {messages.length <= 2 && (
              <div className={styles.suggestions}>
                {quickSuggestions.map((suggestion, i) => (
                  <button
                    key={i}
                    onClick={() => setInput(suggestion)}
                    className={styles.suggestionButton}
                  >
                    {suggestion}
                  </button>
                ))}
              </div>
            )}

            {/* Input */}
            <div className={styles.inputRow}>
              <input
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Digite sua pergunta..."
                disabled={isLoading}
                className={styles.textInput}
              />
              <button
                onClick={handleSend}
                disabled={isLoading || !input.trim()}
                className={styles.sendButton}
              >
                Enviar
              </button>
            </div>
          </motion.div>
        </>
      )}

      {/* Modal de confirmação — limpar histórico */}
      <ConfirmDialog
        isOpen={showClearConfirm}
        title="Limpar histórico"
        message="Tem certeza que deseja limpar todo o histórico de conversa? Esta ação não pode ser desfeita."
        confirmLabel="Limpar"
        cancelLabel="Cancelar"
        onConfirm={handleConfirmClear}
        onCancel={handleCancelClear}
        variant="danger"
      />
    </AnimatePresence>
  )
}

import { validateUserMessage, addDisclaimerIfNeeded } from './safetyGuard'
import { buildPatientContext, buildSystemPrompt } from './contextBuilder'
import {
  CHATBOT_MAX_HISTORY,
  CHATBOT_RATE_LIMIT_WINDOW,
  CHATBOT_RATE_LIMIT_MAX,
  CHATBOT_HISTORY_STORAGE_KEY,
  CHATBOT_HISTORY_MAX_DISPLAY,
} from '../config/chatbotConfig'

const MAX_HISTORY = CHATBOT_MAX_HISTORY
const RATE_LIMIT_WINDOW = CHATBOT_RATE_LIMIT_WINDOW
const RATE_LIMIT_MAX = CHATBOT_RATE_LIMIT_MAX

/**
 * Envia mensagem ao chatbot e retorna resposta.
 *
 * @param {Object} params
 * @param {string} params.message - Mensagem do usuario
 * @param {Array} params.history - Historico de mensagens [{role, content}]
 * @param {Object} params.patientData - Dados do DashboardContext para contexto
 * @returns {Promise<{
 *   response: string,
 *   blocked: boolean,
 *   reason?: string,
 *   rateLimited: boolean
 * }>}
 */
export async function sendChatMessage({ message, history = [], patientData }) {
  // 1. Rate limiting (client-side)
  if (isRateLimited()) {
    return {
      response: '',
      blocked: false,
      rateLimited: true,
      reason: 'Limite de mensagens atingido. Tente novamente em alguns minutos.',
    }
  }

  // 2. Safety guard
  const validation = validateUserMessage(message)
  if (validation.blocked) {
    return {
      response: validation.reason,
      blocked: true,
      rateLimited: false,
    }
  }

  // 3. Build context
  const context = buildPatientContext(patientData)
  const systemPrompt = buildSystemPrompt(context)

  // 4. Enviar para serverless function
  try {
    const response = await fetch('/api/chatbot', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        message,
        history: history.slice(-MAX_HISTORY),
        systemPrompt,
      }),
    })

    if (!response.ok) {
      const error = await response.json().catch(() => ({}))
      throw new Error(error.message || `HTTP ${response.status}`)
    }

    const data = await response.json()
    const safeResponse = addDisclaimerIfNeeded(data.response)

    incrementRateCounter()

    return {
      response: safeResponse,
      blocked: false,
      rateLimited: false,
    }
  } catch (error) {
    console.error('[chatbot] Erro ao enviar mensagem:', error)
    return {
      response: 'Desculpe, estou com dificuldades técnicas. Tente novamente em instantes.',
      blocked: false,
      rateLimited: false,
    }
  }
}

// -- Rate limiting (localStorage) --

function isRateLimited() {
  if (typeof window === 'undefined') return false
  try {
    const data = JSON.parse(localStorage.getItem('mr_chat_rate') || '{}')
    if (Date.now() - (data.windowStart || 0) > RATE_LIMIT_WINDOW) return false
    return (data.count || 0) >= RATE_LIMIT_MAX
  } catch {
    return false
  }
}

function incrementRateCounter() {
  if (typeof window === 'undefined') return
  try {
    const data = JSON.parse(localStorage.getItem('mr_chat_rate') || '{}')
    const now = Date.now()
    if (now - (data.windowStart || 0) > RATE_LIMIT_WINDOW) {
      localStorage.setItem('mr_chat_rate', JSON.stringify({ windowStart: now, count: 1 }))
    } else {
      localStorage.setItem(
        'mr_chat_rate',
        JSON.stringify({ windowStart: data.windowStart, count: (data.count || 0) + 1 })
      )
    }
  } catch {
    // Silently fail
  }
}

// -- Persistência de histórico (localStorage) --

/**
 * Carrega histórico persistido de conversa do localStorage.
 * @returns {Array<{role: string, content: string, timestamp: number}>}
 */
export function loadPersistedHistory() {
  if (typeof window === 'undefined') return []
  try {
    const data = JSON.parse(localStorage.getItem(CHATBOT_HISTORY_STORAGE_KEY) || '[]')
    // Validar estrutura mínima: array de objetos com role, content, timestamp
    if (!Array.isArray(data)) return []
    return data.filter((msg) => msg.role && msg.content && typeof msg.timestamp === 'number')
  } catch {
    return []
  }
}

/**
 * Persiste histórico de conversa no localStorage.
 * Limita a CHATBOT_HISTORY_MAX_DISPLAY mensagens mais recentes.
 * @param {Array<{role: string, content: string, timestamp: number}>} messages
 */
export function savePersistedHistory(messages) {
  if (typeof window === 'undefined') return
  try {
    // Filtrar mensagem de boas-vindas (primeira mensagem do assistente sem outras mensagens)
    const filtered = messages.filter((msg) => {
      if (msg.role === 'assistant' && messages.length === 1) return false // Mensagem inicial
      return true
    })
    // Manter apenas as últimas N mensagens
    const trimmed = filtered.slice(-CHATBOT_HISTORY_MAX_DISPLAY)
    localStorage.setItem(CHATBOT_HISTORY_STORAGE_KEY, JSON.stringify(trimmed))
  } catch {
    // Silently fail
  }
}

/**
 * Limpa histórico persistido do localStorage.
 */
export function clearPersistedHistory() {
  if (typeof window === 'undefined') return
  try {
    localStorage.removeItem(CHATBOT_HISTORY_STORAGE_KEY)
  } catch {
    // Silently fail
  }
}

/**
 * Monta contexto compacto do paciente para enviar ao LLM.
 * Dados vem do DashboardContext (cache SWR) — ZERO chamadas ao Supabase.
 *
 * REGRAS:
 * - NUNCA incluir IDs, UUIDs, ou dados que identifiquem o usuario
 * - NUNCA incluir dados de outros usuarios
 * - Manter o contexto compacto (<2000 tokens) para nao estourar free tier
 *
 * @param {Object} params
 * @param {Array} params.medicines - Medicamentos (incluem .stock[] embedded)
 * @param {Array} params.protocols - Protocolos ativos
 * @param {Array} params.logs - Logs do dia
 * @param {Array} params.stockSummary - Resumo de estoque por medicamento
 * @param {Object} params.stats - Stats de adesao (adherence: 0-1, etc.)
 * @returns {string} - Contexto formatado para system prompt
 */
export function buildPatientContext({ medicines, protocols, logs, stockSummary, stats }) {
  const today = new Date()
  const todayStr = today.toLocaleDateString('pt-BR')

  const medsContext = (medicines || []).map((med) => {
    const protocol = (protocols || []).find((p) => p.medicine_id === med.id && p.active)
    // Estoque vem via stockSummary ou medicine.stock embedded
    const stockEntry = (stockSummary || []).find((s) => s.medicine_id === med.id)
    const totalStock =
      stockEntry?.quantity ??
      (med.stock || []).filter((s) => s.quantity > 0).reduce((sum, s) => sum + s.quantity, 0)

    return {
      nome: med.name,
      principioAtivo: med.active_ingredient,
      classeTerapeutica: med.therapeutic_class,
      dosagem: `${med.dosage_per_pill ?? ''}${med.dosage_unit ?? ''}`.trim(),
      frequencia: protocol?.frequency ?? 'sem protocolo',
      horarios: protocol?.time_schedule ?? [],
      estoque: totalStock,
    }
  })

  const todayLogs = (logs || []).filter((log) => {
    const logDate = new Date(log.taken_at)
    return (
      logDate.getFullYear() === today.getFullYear() &&
      logDate.getMonth() === today.getMonth() &&
      logDate.getDate() === today.getDate()
    )
  })

  const adherence7d = stats?.adherence != null ? Math.round(stats.adherence * 100) : null

  return [
    `Data: ${todayStr}`,
    `Medicamentos ativos: ${medsContext.length}`,
    ...medsContext.map((m) => {
      const infos = [m.principioAtivo, m.classeTerapeutica].filter(Boolean).join(', ')
      const detalhe = infos ? ` [${infos}]` : ''
      return `- ${m.nome}${detalhe} (${m.dosagem}): ${m.frequencia}, horarios ${m.horarios.join(', ') || 'nao definidos'}, estoque ${m.estoque} un.`
    }),
    `Doses registradas hoje: ${todayLogs.length}`,
    adherence7d != null ? `Adesão ultimos 7 dias: ${adherence7d}%` : '',
  ]
    .filter(Boolean)
    .join('\n')
}

/**
 * Constrói a PARTE ESTÁTICA do system prompt (regras, instruções).
 * Esta seção é cacheable porque não muda entre requisições.
 * Ref: Groq Prompt Caching docs — colocar conteúdo estático PRIMEIRO.
 *
 * @returns {string}
 */
export function buildStaticSystemRules() {
  return [
    'Você é um assistente virtual do app Dosiq.',
    'Você ajuda o paciente a gerenciar seus medicamentos de forma amigavel.',
    'REGRAS ABSOLUTAS:',
    '- NUNCA recomende dosagens, diagnosticos ou substituicoes de medicamentos.',
    '- NUNCA sugira parar ou alterar tratamento sem consultar o medico.',
    '- Se sua resposta menciona medicamentos ou saúde, SEMPRE termine com uma linha em branco seguida de: "Não substituo orientação médica."',
    '- Responda em portugues brasileiro, de forma concisa (max 3 frases), em texto puro sem markdown, asteriscos, hashtags ou listas.',
    '- Use os dados do paciente abaixo para contextualizar respostas.',
  ].join('\n')
}

/**
 * System prompt para o LLM.
 * Combina regras estáticas (cacheable) + contexto dinâmico do paciente.
 *
 * NOTA: Para otimizar Groq Prompt Caching:
 * - Conteúdo estático (buildStaticSystemRules) deve vir PRIMEIRO
 * - Conteúdo dinâmico (patientContext) vem DEPOIS
 * - Isso permite cache hit em conversas multi-turn onde o contexto é reutilizado
 *
 * @param {string} patientContext
 * @returns {string}
 */
export function buildSystemPrompt(patientContext) {
  const staticRules = buildStaticSystemRules()
  return [staticRules, '', 'DADOS DO PACIENTE:', patientContext].join('\n')
}

/**
 * Filtros de seguranca para mensagens do chatbot.
 * Bloqueia intencoes perigosas e adiciona disclaimer medico.
 */

import {
  CHATBOT_BLOCKED_PATTERNS,
  CHATBOT_DISCLAIMER,
  CHATBOT_HEALTH_KEYWORDS,
} from '../config/chatbotConfig'

export const DISCLAIMER = CHATBOT_DISCLAIMER

/**
 * Valida mensagem do usuario antes de enviar ao LLM.
 * @param {string} message
 * @returns {{ blocked: boolean, reason?: string }}
 */
export function validateUserMessage(message) {
  for (const pattern of CHATBOT_BLOCKED_PATTERNS) {
    if (pattern.test(message)) {
      return {
        blocked: true,
        reason:
          'Não posso recomendar dosagens, diagnósticos ou mudanças no tratamento. Consulte seu médico.',
      }
    }
  }

  if (message.length > 500) {
    return {
      blocked: true,
      reason: 'Mensagem muito longa. Tente ser mais conciso (máx 500 caracteres).',
    }
  }

  return { blocked: false }
}

/**
 * Adiciona disclaimer a resposta do LLM se necessario.
 * @param {string} response
 * @returns {string}
 */
export function addDisclaimerIfNeeded(response) {
  const hasHealthContent = CHATBOT_HEALTH_KEYWORDS.some((kw) => response.toLowerCase().includes(kw))

  if (hasHealthContent && !response.includes('Não substituo')) {
    return `${response}\n\n_${CHATBOT_DISCLAIMER}_`
  }

  return response
}

