import { AlertTriangle } from 'lucide-react'
import { parseLocalDate } from '@utils/dateUtils'

/**
 * StockAlertInline — Banner de alerta de estoque para o Dashboard redesenhado.
 *
 * @param {Array} criticalItems — items com stockStatus === 'critical' ou 'low'
 *   Shape: { medicineName: string, daysRemaining: number, stockStatus: 'critical'|'low', prediction?: { predictedStockoutDate: string } }
 * @param {Function} onNavigateToStock — Callback para navegar para Estoque
 */
export default function StockAlertInline({ criticalItems = [], onNavigateToStock }) {
  if (!criticalItems || criticalItems.length === 0) return null

  const PROGRESS_BAR_MAX_DAYS = 30

  const sorted = [...criticalItems].sort((a, b) => a.daysRemaining - b.daysRemaining)
  const mostCritical = sorted[0]
  const isCritical = mostCritical.stockStatus === 'critical'

  const accentColor = isCritical ? 'var(--color-error, #ba1a1a)' : 'var(--color-tertiary, #7b5700)'

  const progressPct = Math.max(
    0,
    Math.min((mostCritical.daysRemaining / PROGRESS_BAR_MAX_DAYS) * 100, 100)
  )

  return (
    <div
      role="alert"
      aria-live="polite"
      style={{
        borderLeft: `4px solid ${accentColor}`,
        borderRadius: 'var(--radius-lg, 1rem)',
        padding: '1rem 1.25rem',
        background: isCritical
          ? 'color-mix(in srgb, var(--color-error, #ba1a1a) 8%, transparent)'
          : 'color-mix(in srgb, var(--color-tertiary-fixed, #ffdea8) 40%, transparent)',
        display: 'flex',
        flexDirection: 'column',
        gap: '0.75rem',
      }}
    >
      {/* Título */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
        <AlertTriangle size={16} color={accentColor} aria-hidden="true" />
        <span
          style={{
            fontFamily: 'var(--font-body, Lexend, sans-serif)',
            fontWeight: 'var(--font-weight-semibold, 600)',
            fontSize: 'var(--text-body-lg, 1rem)',
            color: accentColor,
          }}
        >
          {isCritical ? 'Estoque Crítico' : 'Estoque Baixo'}
          {criticalItems.length > 1
            ? ` · ${criticalItems.length} itens`
            : ` · ${mostCritical.medicineName}`}
        </span>
      </div>

      {/* Barra de progresso */}
      <div>
        <div
          style={{
            fontFamily: 'var(--font-body, Lexend, sans-serif)',
            fontSize: 'var(--text-label-md, 0.75rem)',
            color: 'var(--color-on-surface-variant, #3e4946)',
            marginBottom: '0.375rem',
          }}
        >
          {mostCritical.prediction?.predictedStockoutDate
            ? `Acaba em ~${parseLocalDate(mostCritical.prediction.predictedStockoutDate).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' })}`
            : `${mostCritical.daysRemaining} dia${mostCritical.daysRemaining !== 1 ? 's' : ''} restante${mostCritical.daysRemaining !== 1 ? 's' : ''}`}
        </div>
        <div
          role="progressbar"
          aria-valuenow={mostCritical.daysRemaining}
          aria-valuemin={0}
          aria-valuemax={PROGRESS_BAR_MAX_DAYS}
          aria-label={`${mostCritical.medicineName}: ${mostCritical.daysRemaining} dias restantes`}
          style={{
            height: '8px',
            borderRadius: 'var(--radius-full, 9999px)',
            background: 'var(--color-surface-container-highest, #e1e3e4)',
            overflow: 'hidden',
          }}
        >
          <div
            style={{
              height: '100%',
              width: `${progressPct}%`,
              borderRadius: 'var(--radius-full, 9999px)',
              background: accentColor,
              transition: 'width 1s ease-out',
            }}
          />
        </div>
      </div>

      {/* CTA */}
      <button
        onClick={() => onNavigateToStock?.()}
        aria-label="Ir para controle de estoque"
        style={{
          alignSelf: 'flex-end',
          padding: '0.375rem 0.875rem',
          minHeight: '36px',
          background: 'transparent',
          color: accentColor,
          border: `1.5px solid ${accentColor}`,
          borderRadius: 'var(--radius-full, 9999px)',
          fontFamily: 'var(--font-body, Lexend, sans-serif)',
          fontSize: 'var(--text-label-md, 0.75rem)',
          fontWeight: 'var(--font-weight-semibold, 600)',
          cursor: 'pointer',
          whiteSpace: 'nowrap',
          transition: 'all 150ms ease-out',
        }}
      >
        Ver Estoque →
      </button>
    </div>
  )
}

import React, { useState } from 'react'
import {
  motion,
  useMotionValue,
  useTransform,
  AnimatePresence,
  useReducedMotion,
} from 'framer-motion'
import PulseEffect from '@shared/components/ui/animations/PulseEffect'
import { analyticsService } from '@dashboard/services/analyticsService'
import './SwipeRegisterItem.css'

/**
 * SwipeRegisterItem - Item de medicamento com gesto de deslizar para confirmar.
 *
 * @param {Object} props
 * @param {Object} props.medicine - Dados do medicamento
 * @param {number} props.dosagePerIntake - Quantidade de comprimidos por dose (do protocolo)
 * @param {string} props.time - Horário previsto
 * @param {boolean} props.isSelected - Estado de seleção para lote
 * @param {Function} props.onToggleSelection - Callback para alternar seleção
 * @param {Function} props.onRegister - Callback de sucesso (dose registrada)
 */
export default function SwipeRegisterItem({
  medicine,
  dosagePerIntake,
  time,
  isSelected = false,
  onToggleSelection,
  onRegister,
}) {
  const [isSuccess, setIsSuccess] = useState(false)
  const [showPulse, setShowPulse] = useState(false)
  const x = useMotionValue(0)
  const prefersReducedMotion = useReducedMotion()

  // Mapear o arraste para opacidade e cor do fundo de confirmação
  const background = useTransform(x, [0, 200], ['rgba(0, 229, 255, 0)', 'rgba(0, 229, 255, 0.2)'])

  const opacity = useTransform(x, [0, 150], [0, 1])

  const handleDragEnd = async (_, info) => {
    // Threshold de 70% da largura (assumindo largura aprox de 300-350 no mobile)
    // Usaremos um valor fixo de 150px para maior consistência tátil
    if (info.offset.x > 150) {
      setIsSuccess(true)
      try {
        await onRegister?.(medicine.id, dosagePerIntake)
        setShowPulse(true)
        analyticsService.track('swipe_used', { medicine: medicine.name })
      } catch (err) {
        console.error('Erro ao registrar via swipe:', err)
        setIsSuccess(false)
        // O Framer Motion vai resetar a posição automaticamente se não mudarmos o estado
      }
    }
  }

  return (
    <div className="swipe-item-container">
      {/* Camada de Fundo (Ação) */}
      <motion.div className="swipe-item-action" style={{ background, opacity }}>
        <span className="swipe-item-action__text">CONFIRMAR DOSE</span>
        <span className="swipe-item-action__icon">✓</span>
      </motion.div>

      {/* Camada do Card (Interativa) */}
      <motion.div
        className={`swipe-item-card ${isSuccess ? 'swipe-item-card--success' : ''} ${isSelected ? 'swipe-item-card--selected' : ''}`}
        drag="x"
        dragConstraints={{ left: 0, right: 300 }}
        dragElastic={0.1}
        style={{ x }}
        onDragEnd={handleDragEnd}
        animate={isSuccess ? { x: '100%', opacity: 0 } : { x: 0, opacity: 1 }}
      >
        <div
          className="swipe-item-card__checkbox-wrapper"
          onClick={(e) => {
            e.stopPropagation()
            onToggleSelection?.(medicine.id)
          }}
        >
          <div className={`swipe-item-card__checkbox ${isSelected ? 'checked' : ''}`}>
            {isSelected && '✓'}
          </div>
        </div>

        <div className="swipe-item-card__time">{time}</div>
        <div className="swipe-item-card__info">
          <h4 className="swipe-item-card__name">{medicine.name}</h4>
          <span className="swipe-item-card__dosage">
            {dosagePerIntake || 1} comprimido{dosagePerIntake > 1 ? 's' : ''}
          </span>
        </div>
        <div className="swipe-item-card__gesture-hint">
          <span>→</span>
        </div>
      </motion.div>

      {/* Check bounce ao confirmar swipe */}
      <AnimatePresence>
        {isSuccess && (
          <motion.div
            className="swipe-item__check"
            initial={{ scale: 0 }}
            animate={{ scale: [0, 1.3, 1] }}
            exit={{ scale: 0, opacity: 0 }}
            transition={{
              duration: prefersReducedMotion ? 0 : 0.4,
              ease: 'easeOut',
            }}
            aria-hidden="true"
          >
            ✓
          </motion.div>
        )}
      </AnimatePresence>

      <PulseEffect trigger={showPulse} onComplete={() => setShowPulse(false)} />
    </div>
  )
}

import React, { useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import './TreatmentAccordion.css'

/**
 * TreatmentAccordion - Card expansível para protocolos.
 *
 * @param {Object} props
 * @param {Object} props.protocol - Dados do protocolo
 * @param {React.ReactNode} props.children - Itens de medicamento (SwipeRegisterItem)
 * @param {Function} props.onBatchRegister - Callback para registro em lote
 * @param {string} [props.riskLevel] - Nível de risco ('stable'|'attention'|'critical')
 * @param {string} [props.riskColor] - Cor CSS para badge de risco
 * @param {string} [props.riskLabel] - Label a exibir no título do protocolo
 */
export default function TreatmentAccordion({
  protocol,
  children,
  onBatchRegister,
  selectedMedicines = [],
  riskLevel,
  riskColor,
  riskLabel,
}) {
  const [isExpanded, setIsExpanded] = useState(false)

  const selectedCount = selectedMedicines.length
  const totalCount = protocol.medicines_count || 0

  // Formata a exibição da próxima dose com janela de tolerância
  const formatNextDose = () => {
    const nextDose = protocol.next_dose
    if (!nextDose || nextDose === '--:--') {
      return 'Próxima: --:--'
    }

    const windowEnd = protocol.next_dose_window_end
    const isInWindow = protocol.is_in_tolerance_window

    if (windowEnd && isInWindow) {
      return `Próxima: ${nextDose} (até ${windowEnd})`
    }

    return `Próxima: ${nextDose}`
  }

  return (
    <div
      className={`treatment-accordion ${isExpanded ? 'treatment-accordion--expanded' : ''} ${protocol.is_in_tolerance_window ? 'treatment-accordion--urgent' : ''}`}
    >
      <div className="treatment-accordion__header" onClick={() => setIsExpanded(!isExpanded)}>
        <div className="treatment-accordion__info">
          <div className="treatment-accordion__title-row">
            <h3 className="treatment-accordion__title">{protocol.name}</h3>
            {riskLevel && (
              <span
                className="treatment-accordion__risk-badge"
                style={{ backgroundColor: riskColor }}
                title={riskLabel || riskLevel}
                aria-label={`Risco: ${riskLabel || riskLevel}`}
              />
            )}
          </div>
          <span className="treatment-accordion__meta">
            {protocol.medicines_count || 0} medicamentos • {formatNextDose()}
          </span>
        </div>
        <div className="treatment-accordion__controls">
          <button
            className="treatment-accordion__batch-btn"
            onClick={(e) => {
              e.stopPropagation()
              onBatchRegister?.(protocol, selectedMedicines)
            }}
          >
            {selectedCount > 0 && selectedCount < totalCount ? `LOTE (${selectedCount})` : 'LOTE'}
          </button>
          <motion.span
            className="treatment-accordion__icon"
            animate={{ rotate: isExpanded ? 180 : 0 }}
          >
            ▼
          </motion.span>
        </div>
      </div>

      <AnimatePresence>
        {isExpanded && (
          <motion.div
            className="treatment-accordion__content"
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.3, ease: 'easeInOut' }}
          >
            <div className="treatment-accordion__list">{children}</div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

