import { dismissSuggestion } from '@features/protocols/services/reminderOptimizerService'
import './ReminderSuggestion.css'

/**
 * Notificação in-app não-intrusiva para sugestão de ajuste de horário.
 *
 * Props:
 * - suggestion: { currentTime, suggestedTime, avgDeltaMinutes, sampleCount }
 * - protocolId: string
 * - protocolName: string
 * - onAccept: (newTime: string) => void  // Chama protocolService.update()
 * - onDismiss: () => void
 */
export default function ReminderSuggestion({
  suggestion,
  protocolId,
  protocolName,
  onAccept,
  onDismiss,
}) {
  // Guard clause: sugestão inválida
  if (!suggestion) {
    return null
  }

  const handleAccept = () => {
    onAccept(suggestion.suggestedTime)
  }

  const handleKeep = () => {
    console.log('[ReminderSuggestion] handleKeep clicked:', { protocolId, protocolName })
    dismissSuggestion(protocolId, false) // 30 dias
    onDismiss()
  }

  const handleNeverAsk = () => {
    console.log('[ReminderSuggestion] handleNeverAsk clicked:', { protocolId, protocolName })
    dismissSuggestion(protocolId, true) // Permanente
    onDismiss()
  }

  return (
    <div className="reminder-suggestion" role="alert">
      <div className="reminder-suggestion__content">
        <p className="reminder-suggestion__text">
          Você costuma tomar <strong>{protocolName}</strong> por volta das{' '}
          <strong>{suggestion.suggestedTime}</strong>. Quer ajustar o lembrete de{' '}
          {suggestion.currentTime} para {suggestion.suggestedTime}?
        </p>
        <p className="reminder-suggestion__sample">(baseado em {suggestion.sampleCount} doses)</p>
      </div>

      <div className="reminder-suggestion__actions">
        <button
          onClick={handleAccept}
          className="reminder-suggestion__button reminder-suggestion__button--primary"
          type="button"
        >
          Ajustar
        </button>
        <button
          onClick={handleKeep}
          className="reminder-suggestion__button reminder-suggestion__button--secondary"
          type="button"
        >
          Manter
        </button>
        <button
          onClick={handleNeverAsk}
          className="reminder-suggestion__button reminder-suggestion__button--tertiary"
          type="button"
        >
          Não perguntar mais
        </button>
      </div>
    </div>
  )
}

import './TitrationStep.css'

/**
 * Componente de etapa individual da timeline de titulação
 *
 * @param {Object} props
 * @param {number} props.stepNumber - Número da etapa
 * @param {number} props.dose - Dose da etapa
 * @param {string} props.unit - Unidade da dose (mg, ml, etc)
 * @param {number} props.durationDays - Duração em dias
 * @param {'completed'|'current'|'future'} props.status - Status da etapa
 * @param {Date} [props.startDate] - Data de início
 * @param {Date} [props.endDate] - Data de fim
 * @param {string} [props.description] - Descrição da etapa
 * @param {boolean} [props.isLast] - Se é a última etapa
 * @param {number} [props.daysRemaining] - Dias restantes (para etapa atual)
 */
export default function TitrationStep({
  stepNumber,
  dose,
  unit,
  durationDays,
  status,
  startDate,
  endDate,
  description,
  isLast = false,
  daysRemaining = 0,
}) {
  const formatDate = (date) => {
    if (!date) return ''
    return new Date(date).toLocaleDateString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
    })
  }

  const getStatusIcon = () => {
    switch (status) {
      case 'completed':
        return '✓'
      case 'current':
        return '●'
      default:
        return '○'
    }
  }

  const getStatusLabel = () => {
    switch (status) {
      case 'completed':
        return 'Concluído'
      case 'current':
        return 'Você está aqui'
      default:
        return 'Futuro'
    }
  }

  return (
    <div className={`titration-step ${status}`}>
      <div className="step-connector">
        {!isLast && <div className="connector-line" />}
        <div className={`step-indicator ${status}`}>
          <span className="step-icon">{getStatusIcon()}</span>
        </div>
      </div>

      <div className="step-content">
        <div className="step-header">
          <span className="step-number">Etapa {stepNumber}</span>
          {status === 'current' && <span className="step-badge current">{getStatusLabel()}</span>}
        </div>

        <div className="step-dose">
          <span className="dose-value">{dose}</span>
          <span className="dose-unit">{unit}</span>
          <span className="dose-divider">•</span>
          <span className="duration">{durationDays} dias</span>
        </div>

        {description && <p className="step-description">{description}</p>}

        <div className="step-dates">
          {startDate && <span className="date-start">{formatDate(startDate)}</span>}
          {startDate && endDate && <span className="date-separator">→</span>}
          {endDate && <span className="date-end">{formatDate(endDate)}</span>}
        </div>

        {status === 'current' && daysRemaining > 0 && (
          <div className="step-countdown">
            <span className="countdown-label">Próxima etapa em:</span>
            <span className="countdown-value">
              {daysRemaining === 1 ? '1 dia' : `${daysRemaining} dias`}
            </span>
          </div>
        )}
      </div>
    </div>
  )
}

import { useMemo } from 'react'
import TitrationStep from './TitrationStep'
import {
  calculateTitrationSteps,
  formatDaysRemaining,
  isTitrationActive,
  hasReachedTarget,
} from '@protocols/services/titrationService'
import './TitrationTimeline.css'

/**
 * Componente de timeline de titulação
 *
 * Exibe todas as etapas de um protocolo de titulação com:
 * - Etapas concluídas (verde)
 * - Etapa atual (azul com destaque)
 * - Etapas futuras (cinza)
 * - Dias restantes para próxima etapa
 *
 * @param {Object} props
 * @param {Object} props.protocol - Protocolo com dados de titulação
 * @param {boolean} [props.compact=false] - Modo compacto (para cards)
 * @param {function} [props.onStepClick] - Callback ao clicar em uma etapa
 */
export default function TitrationTimeline({ protocol, compact = false, onStepClick }) {
  const titrationData = useMemo(() => {
    if (!protocol?.titration_schedule?.length) {
      return null
    }
    return calculateTitrationSteps(protocol)
  }, [protocol])

  if (!titrationData) {
    return (
      <div className="titration-timeline empty">
        <p className="empty-message">Nenhum cronograma de titulação definido</p>
      </div>
    )
  }

  const { steps, currentStep, totalSteps, daysUntilNext, progressPercent } = titrationData

  const isActive = isTitrationActive(protocol)
  const isComplete = hasReachedTarget(protocol)

  const getStatusMessage = () => {
    if (isComplete) return '🎯 Alvo atingido!'
    if (isActive) return `📈 Em titulação • Etapa ${currentStep} de ${totalSteps}`
    return '⏸️ Titulação pausada'
  }

  const handleStepClick = (step) => {
    if (onStepClick) {
      onStepClick(step)
    }
  }

  // Modo compacto: apenas preview das etapas
  if (compact) {
    return (
      <div className="titration-timeline compact">
        <div className="timeline-preview">
          {steps.map((step) => (
            <div
              key={step.stepNumber}
              className={`preview-step ${step.status}`}
              onClick={() => handleStepClick(step)}
              title={`${step.description || `Etapa ${step.stepNumber}`}: ${step.dose}${step.unit}`}
            >
              <span className="preview-dose">{step.dose}</span>
              <span className="preview-unit">{step.unit}</span>
            </div>
          ))}
        </div>

        <div className="timeline-progress-mini">
          <div className="progress-bar-mini">
            <div className="progress-fill-mini" style={{ width: `${progressPercent}%` }} />
          </div>
          <span className="progress-text-mini">{formatDaysRemaining(daysUntilNext)}</span>
        </div>
      </div>
    )
  }

  return (
    <div className="titration-timeline">
      <div className="timeline-header">
        <div className="timeline-title">
          <h4>Cronograma de Titulação</h4>
          <span
            className={`timeline-status ${isActive ? 'active' : isComplete ? 'complete' : 'paused'}`}
          >
            {getStatusMessage()}
          </span>
        </div>

        <div className="timeline-progress">
          <div className="progress-info">
            <span className="progress-label">Progresso geral</span>
            <span className="progress-value">{progressPercent}%</span>
          </div>
          <div className="progress-bar">
            <div className="progress-fill" style={{ width: `${progressPercent}%` }} />
          </div>
          {daysUntilNext > 0 && (
            <span className="days-remaining">{formatDaysRemaining(daysUntilNext)}</span>
          )}
        </div>
      </div>

      <div className="timeline-steps">
        {steps.map((step, index) => (
          <div
            key={step.stepNumber}
            className="timeline-step-wrapper"
            onClick={() => handleStepClick(step)}
          >
            <TitrationStep
              stepNumber={step.stepNumber}
              dose={step.dose}
              unit={step.unit}
              durationDays={step.durationDays}
              status={step.status}
              startDate={step.startDate}
              endDate={step.endDate}
              description={step.description}
              isLast={index === steps.length - 1}
              daysRemaining={step.status === 'current' ? daysUntilNext : 0}
            />
          </div>
        ))}
      </div>

      <div className="timeline-footer">
        {isActive && daysUntilNext > 0 && (
          <div className="next-step-info">
            <span className="info-icon">⏰</span>
            <span className="info-text">
              Próxima mudança de dose em{' '}
              <strong>
                {daysUntilNext} {daysUntilNext === 1 ? 'dia' : 'dias'}
              </strong>
            </span>
          </div>
        )}

        {isComplete && (
          <div className="completion-message">
            <span className="info-icon">🎉</span>
            <span className="info-text">Você atingiu a dose de manutenção!</span>
          </div>
        )}
      </div>
    </div>
  )
}

import { useState } from 'react'
import Button from '@shared/components/ui/Button'
import './TreatmentPlanForm.css'

export default function TreatmentPlanForm({ plan, onSave, onCancel }) {
  const [formData, setFormData] = useState({
    name: plan?.name || '',
    description: plan?.description || '',
    objective: plan?.objective || '',
    emoji: plan?.emoji || '',
    color: plan?.color || '',
  })

  const [errors, setErrors] = useState({})
  const [isSubmitting, setIsSubmitting] = useState(false)

  const handleChange = (e) => {
    const { name, value } = e.target
    setFormData((prev) => ({ ...prev, [name]: value }))
    if (errors[name]) {
      setErrors((prev) => ({ ...prev, [name]: '' }))
    }
  }

  const validate = () => {
    const newErrors = {}
    if (!formData.name.trim()) {
      newErrors.name = 'Nome do plano é obrigatório'
    }
    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    if (!validate()) return

    setIsSubmitting(true)
    try {
      await onSave({
        ...formData,
        name: formData.name.trim(),
        description: formData.description.trim() || null,
        objective: formData.objective.trim() || null,
        emoji: formData.emoji.trim() || null,
        color: formData.color.trim() || null,
      })
    } catch (error) {
      console.error('Erro ao salvar plano de tratamento:', error)
      const errorMessage = error?.message || 'Erro desconhecido ao salvar plano'
      setErrors({ submit: errorMessage })
    } finally {
      setIsSubmitting(false)
    }
  }

  return (
    <form className="treatment-plan-form" onSubmit={handleSubmit}>
      <div className="treatment-plan-form__header">
        <h3>{plan ? 'Editar Plano de Tratamento' : 'Novo Plano de Tratamento'}</h3>
        <p className="treatment-plan-form__help">
          Use planos para agrupar medicamentos de um mesmo tratamento (ex: Insuficiência Cardíaca).
        </p>
      </div>

      <div className="form-row">
        <label className="form-label" htmlFor="name">
          Nome do Plano{' '}
          <span className="required" aria-hidden="true">
            *
          </span>
        </label>
        <input
          type="text"
          id="name"
          name="name"
          className={errors.name ? 'error' : ''}
          value={formData.name}
          onChange={handleChange}
          placeholder="Ex: Quarteto Fantástico (IC)"
          autoFocus
        />
        {errors.name && <span className="error-message">{errors.name}</span>}
      </div>

      <div className="form-row">
        <label className="form-label" htmlFor="description">
          Descrição
        </label>
        <textarea
          id="description"
          name="description"
          value={formData.description}
          onChange={handleChange}
          placeholder="Ex: Protocolo para controle de insuficiência cardíaca conforme prescrição do Dr. Silva."
          rows="3"
        />
      </div>

      <div className="form-row">
        <label className="form-label" htmlFor="objective">
          Objetivo do Tratamento
        </label>
        <input
          type="text"
          id="objective"
          name="objective"
          value={formData.objective}
          onChange={handleChange}
          placeholder="Ex: Titular Beta-bloqueador até 100mg"
        />
      </div>

      <div className="treatment-plan-form__visual">
        <div className="form-row">
          <label className="form-label" htmlFor="emoji">
            Emoji do Plano
          </label>
          <input
            type="text"
            id="emoji"
            name="emoji"
            className="treatment-plan-form__emoji-input"
            value={formData.emoji}
            onChange={handleChange}
            placeholder="💊"
            maxLength={10}
          />
        </div>

        <div className="form-row">
          <label className="form-label" htmlFor="color">
            Cor do Badge
          </label>
          <div className="treatment-plan-form__color-row">
            <input
              type="color"
              id="color"
              name="color"
              value={formData.color || '#3d6b5e'}
              onChange={handleChange}
              className="treatment-plan-form__color-picker"
            />
            <input
              type="text"
              name="color"
              className="treatment-plan-form__color-text"
              value={formData.color}
              onChange={handleChange}
              placeholder="#6366f1"
              maxLength={7}
            />
          </div>
        </div>
      </div>

      {errors.submit && (
        <div className="error-banner" role="alert">
          {errors.submit}
        </div>
      )}

      <div className="form-actions">
        <Button type="button" variant="ghost" onClick={onCancel} disabled={isSubmitting}>
          Cancelar
        </Button>
        <Button type="submit" variant="primary" disabled={isSubmitting}>
          {isSubmitting ? 'Salvando...' : plan ? 'Atualizar Plano' : 'Criar Plano'}
        </Button>
      </div>
    </form>
  )
}

import { useState, useCallback, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import { medicineService, protocolService, stockService } from '@shared/services'
import { treatmentPlanService } from '@protocols/services/treatmentPlanService'
import {
  DOSAGE_UNITS,
  REGULATORY_CATEGORIES,
  REGULATORY_CATEGORY_LABELS,
} from '@schemas/medicineSchema'
import { FREQUENCIES, FREQUENCY_LABELS } from '@schemas/protocolSchema'
import { formatLocalDate } from '@utils/dateUtils'
import { toTitleCase, toSentenceCase } from '@utils/stringUtils'
import Button from '@shared/components/ui/Button'
import MedicineAutocomplete from '@medications/components/MedicineAutocomplete'
import LaboratoryAutocomplete from '@medications/components/LaboratoryAutocomplete'
import './TreatmentWizard.css'

const slideVariants = {
  enter: (direction) => ({ x: direction > 0 ? 300 : -300, opacity: 0 }),
  center: { x: 0, opacity: 1 },
  exit: (direction) => ({ x: direction > 0 ? -300 : 300, opacity: 0 }),
}

export default function TreatmentWizard({
  onComplete,
  onCancel,
  preselectedMedicine,
  treatmentPlanId,
}) {
  // States
  const [step, setStep] = useState(preselectedMedicine ? 2 : 1)
  const [direction, setDirection] = useState(1)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [error, setError] = useState(null)
  const [result, setResult] = useState(null)
  // Modo do passo 1: 'new' cria novo, 'existing' usa medicamento já cadastrado
  const [medicineMode, setMedicineMode] = useState('new')
  // Medicamento existente selecionado (quando mode === 'existing')
  const [selectedExistingMedicine, setSelectedExistingMedicine] = useState(
    preselectedMedicine || null
  )

  const [medicineData, setMedicineData] = useState({
    name: preselectedMedicine?.name || '',
    type: preselectedMedicine?.type || 'medicamento',
    dosage_per_pill: preselectedMedicine?.dosage_per_pill || '',
    dosage_unit: preselectedMedicine?.dosage_unit || 'mg',
    laboratory: preselectedMedicine?.laboratory || '',
    active_ingredient: preselectedMedicine?.active_ingredient || '',
    therapeutic_class: preselectedMedicine?.therapeutic_class || null,
    regulatory_category: preselectedMedicine?.regulatory_category || null,
  })

  const [protocolData, setProtocolData] = useState({
    frequency: 'diário',
    time_schedule: ['08:00'],
    dosage_per_intake: 1,
    start_date: formatLocalDate(new Date()),
  })

  const [stockData, setStockData] = useState({
    quantity: '',
    purchase_date: formatLocalDate(new Date()),
    unit_price: '',
    expiration_date: '',
  })

  // Seleção de plano de tratamento
  const [availablePlans, setAvailablePlans] = useState([])
  const [planMode, setPlanMode] = useState(treatmentPlanId ? 'existing' : 'none')
  const [selectedPlanId, setSelectedPlanId] = useState(treatmentPlanId || '')
  const [newPlanName, setNewPlanName] = useState('')
  const [newPlanEmoji, setNewPlanEmoji] = useState('📋')

  const { refresh, medicines } = useDashboard()

  useEffect(() => {
    treatmentPlanService
      .getAll()
      .then((plans) => setAvailablePlans(plans || []))
      .catch(() => setAvailablePlans([]))
  }, [])

  // Navigation
  const goNext = useCallback(() => {
    setDirection(1)
    setStep((s) => s + 1)
  }, [])

  const goBack = useCallback(() => {
    setDirection(-1)
    setStep((s) => s - 1)
  }, [])

  // Medicine field handler
  const updateMedicine = useCallback((field, value) => {
    setMedicineData((prev) => ({ ...prev, [field]: value }))
  }, [])

  // Protocol field handler
  const updateProtocol = useCallback((field, value) => {
    setProtocolData((prev) => ({ ...prev, [field]: value }))
  }, [])

  const addTime = useCallback(() => {
    setProtocolData((prev) => ({
      ...prev,
      time_schedule: [...prev.time_schedule, '12:00'],
    }))
  }, [])

  const removeTime = useCallback((index) => {
    setProtocolData((prev) => ({
      ...prev,
      time_schedule: prev.time_schedule.filter((_, i) => i !== index),
    }))
  }, [])

  const updateTime = useCallback((index, value) => {
    setProtocolData((prev) => ({
      ...prev,
      time_schedule: prev.time_schedule.map((t, i) => (i === index ? value : t)),
    }))
  }, [])

  // Stock field handler
  const updateStock = useCallback((field, value) => {
    setStockData((prev) => ({ ...prev, [field]: value }))
  }, [])

  // Autocomplete handlers for ANVISA database
  const handleMedicineSelect = useCallback((medicine) => {
    setMedicineData((prev) => ({
      ...prev,
      name: medicine.name,
      active_ingredient: toTitleCase(medicine.activeIngredient) || '',
      therapeutic_class: toSentenceCase(medicine.therapeuticClass) || null,
      regulatory_category: medicine.regulatoryCategory || null,
      laboratory: medicine.laboratory || '',
    }))
  }, [])

  const handleLaboratorySelect = useCallback((laboratory) => {
    setMedicineData((prev) => ({
      ...prev,
      laboratory: laboratory.laboratory || '',
    }))
  }, [])

  // Submit
  const handleComplete = useCallback(
    async (skipStock) => {
      setIsSubmitting(true)
      setError(null)
      try {
        const medicine =
          selectedExistingMedicine ||
          (await medicineService.create({
            name: medicineData.name,
            type: medicineData.type,
            dosage_per_pill: Number(medicineData.dosage_per_pill),
            dosage_unit: medicineData.dosage_unit,
            laboratory: medicineData.laboratory || null,
            active_ingredient: medicineData.active_ingredient || null,
            therapeutic_class: medicineData.therapeutic_class || null,
            regulatory_category: medicineData.regulatory_category || null,
          }))

        // Resolver plan ID: pode vir de prop, seleção ou criação
        let resolvedPlanId = null
        if (planMode === 'existing' && selectedPlanId) {
          resolvedPlanId = selectedPlanId
        } else if (planMode === 'new' && newPlanName.trim()) {
          const newPlan = await treatmentPlanService.create({
            name: newPlanName.trim(),
            emoji: newPlanEmoji || '📋',
          })
          resolvedPlanId = newPlan.id
        }

        let protocol = null
        if (step >= 3 || (step === 2 && !skipStock)) {
          protocol = await protocolService.create({
            medicine_id: medicine.id,
            name: `${medicine.name} - ${FREQUENCY_LABELS[protocolData.frequency]}`,
            frequency: protocolData.frequency,
            time_schedule: protocolData.time_schedule,
            dosage_per_intake: Number(protocolData.dosage_per_intake),
            start_date: protocolData.start_date,
            treatment_plan_id: resolvedPlanId,
          })
        }

        if (!skipStock && stockData.quantity) {
          await stockService.add({
            medicine_id: medicine.id,
            quantity: Number(stockData.quantity),
            purchase_date: stockData.purchase_date,
            unit_price: Number(stockData.unit_price) || 0,
            expiration_date: stockData.expiration_date || null,
          })
        }

        refresh()
        setResult({ medicine, protocol })
        setDirection(1)
        setStep(4)
      } catch (err) {
        setError(err.message)
      } finally {
        setIsSubmitting(false)
      }
    },
    [
      medicineData,
      protocolData,
      stockData,
      selectedExistingMedicine,
      planMode,
      selectedPlanId,
      newPlanName,
      newPlanEmoji,
      refresh,
      step,
    ]
  )

  // Validation
  const isMedicineValid =
    medicineMode === 'existing'
      ? !!selectedExistingMedicine
      : medicineData.name.length >= 2 && medicineData.dosage_per_pill > 0
  const isProtocolValid =
    protocolData.time_schedule.length > 0 && protocolData.dosage_per_intake > 0

  return (
    <div className="wizard">
      {/* Progress dots */}
      {step < 4 && (
        <div className="wizard__progress">
          {[1, 2, 3].map((s) => (
            <div key={s} className={`wizard__dot ${s <= step ? 'wizard__dot--active' : ''}`} />
          ))}
          <span className="wizard__step-label">{step}/3</span>
        </div>
      )}

      {/* Content */}
      <AnimatePresence mode="wait" custom={direction}>
        <motion.div
          key={step}
          custom={direction}
          variants={slideVariants}
          initial="enter"
          animate="center"
          exit="exit"
          transition={{ duration: 0.25, ease: 'easeInOut' }}
          className="wizard__content"
        >
          {step === 1 && (
            <div className="wizard__step">
              <h3 className="wizard__title">Medicamento</h3>

              {/* Toggle: novo vs existente */}
              {medicines.length > 0 && (
                <div className="wizard__mode-toggle">
                  <button
                    type="button"
                    className={`wizard__mode-btn${medicineMode === 'existing' ? ' wizard__mode-btn--active' : ''}`}
                    onClick={() => {
                      setMedicineMode('existing')
                      setSelectedExistingMedicine(null)
                    }}
                  >
                    Já cadastrado
                  </button>
                  <button
                    type="button"
                    className={`wizard__mode-btn${medicineMode === 'new' ? ' wizard__mode-btn--active' : ''}`}
                    onClick={() => {
                      setMedicineMode('new')
                      setSelectedExistingMedicine(null)
                    }}
                  >
                    Novo medicamento
                  </button>
                </div>
              )}

              {medicineMode === 'existing' ? (
                <label className="wizard__label">
                  Selecionar medicamento
                  <select
                    className="wizard__select"
                    value={selectedExistingMedicine?.id || ''}
                    onChange={(e) => {
                      const med = medicines.find((m) => m.id === e.target.value)
                      setSelectedExistingMedicine(med || null)
                    }}
                  >
                    <option value="">-- Escolha um medicamento --</option>
                    {medicines.map((m) => (
                      <option key={m.id} value={m.id}>
                        {m.name}
                        {m.dosage_per_pill ? ` ${m.dosage_per_pill}${m.dosage_unit}` : ''}
                      </option>
                    ))}
                  </select>
                </label>
              ) : (
                <>
                  <label className="wizard__label">
                    Nome *
                    <MedicineAutocomplete
                      value={medicineData.name}
                      onChange={(value) => updateMedicine('name', value)}
                      onSelect={handleMedicineSelect}
                      placeholder="Ex: Losartana ou busque na base ANVISA..."
                    />
                  </label>

                  <label className="wizard__label">
                    Tipo
                    <select
                      className="wizard__select"
                      value={medicineData.type}
                      onChange={(e) => updateMedicine('type', e.target.value)}
                    >
                      <option value="medicamento">Medicamento</option>
                      <option value="suplemento">Suplemento</option>
                    </select>
                  </label>

                  <label className="wizard__label">
                    Marca / Laboratório
                    <LaboratoryAutocomplete
                      value={medicineData.laboratory}
                      onChange={(value) => updateMedicine('laboratory', value)}
                      onSelect={handleLaboratorySelect}
                      placeholder="Ex: EMS, Medley..."
                    />
                  </label>

                  {medicineData.active_ingredient && (
                    <label className="wizard__label">
                      Princípio Ativo
                      <input
                        type="text"
                        className="wizard__input"
                        value={medicineData.active_ingredient}
                        readOnly
                      />
                      <small className="wizard__label-note">
                        Preenchido automaticamente via ANVISA
                      </small>
                    </label>
                  )}

                  {medicineData.therapeutic_class && (
                    <label className="wizard__label">
                      Classe Terapêutica
                      <input
                        type="text"
                        className="wizard__input"
                        value={medicineData.therapeutic_class}
                        onChange={(e) => updateMedicine('therapeutic_class', e.target.value)}
                        maxLength={100}
                      />
                      <small className="wizard__label-note">
                        Preenchido automaticamente via ANVISA
                      </small>
                    </label>
                  )}

                  <label className="wizard__label">
                    Categoria Regulatória
                    <select
                      className="wizard__select"
                      value={medicineData.regulatory_category || ''}
                      onChange={(e) =>
                        updateMedicine('regulatory_category', e.target.value || null)
                      }
                    >
                      <option value="">Selecione (opcional)</option>
                      {REGULATORY_CATEGORIES.map((category) => (
                        <option key={category} value={category}>
                          {REGULATORY_CATEGORY_LABELS[category] || category}
                        </option>
                      ))}
                    </select>
                    <small className="wizard__label-note">
                      Preenchido automaticamente via ANVISA quando disponível.
                    </small>
                  </label>

                  <div className="wizard__row">
                    <label className="wizard__label" style={{ flex: 1 }}>
                      Dosagem *
                      <input
                        type="number"
                        className="wizard__input"
                        value={medicineData.dosage_per_pill}
                        onChange={(e) => updateMedicine('dosage_per_pill', e.target.value)}
                        placeholder="50"
                        min="0"
                        step="any"
                      />
                    </label>
                    <label className="wizard__label" style={{ width: 100 }}>
                      Unidade
                      <select
                        className="wizard__select"
                        value={medicineData.dosage_unit}
                        onChange={(e) => updateMedicine('dosage_unit', e.target.value)}
                      >
                        {DOSAGE_UNITS.map((u) => (
                          <option key={u} value={u}>
                            {u}
                          </option>
                        ))}
                      </select>
                    </label>
                  </div>
                </>
              )}

              <div className="wizard__actions">
                <Button variant="ghost" onClick={onCancel}>
                  Cancelar
                </Button>
                <Button variant="primary" onClick={goNext} disabled={!isMedicineValid}>
                  Próximo →
                </Button>
              </div>
            </div>
          )}

          {step === 2 && (
            <div className="wizard__step">
              <h3 className="wizard__title">Como Tomar</h3>

              <label className="wizard__label">
                Frequência
                <select
                  className="wizard__select"
                  value={protocolData.frequency}
                  onChange={(e) => updateProtocol('frequency', e.target.value)}
                >
                  {FREQUENCIES.map((f) => (
                    <option key={f} value={f}>
                      {FREQUENCY_LABELS[f] || f}
                    </option>
                  ))}
                </select>
              </label>

              <div className="wizard__label">
                Horários
                {protocolData.time_schedule.map((time, i) => (
                  <div key={i} className="wizard__time-row">
                    <input
                      type="time"
                      className="wizard__input"
                      value={time}
                      onChange={(e) => updateTime(i, e.target.value)}
                    />
                    {protocolData.time_schedule.length > 1 && (
                      <button className="wizard__remove-time" onClick={() => removeTime(i)}>
                        ✕
                      </button>
                    )}
                  </div>
                ))}
                <button className="wizard__add-time" onClick={addTime}>
                  + Adicionar horário
                </button>
              </div>

              <label className="wizard__label">
                Comprimidos por dose
                <input
                  type="number"
                  className="wizard__input"
                  value={protocolData.dosage_per_intake}
                  onChange={(e) => updateProtocol('dosage_per_intake', e.target.value)}
                  min="1"
                  max="100"
                />
              </label>

              <label className="wizard__label">
                Data de início
                <input
                  type="date"
                  className="wizard__input"
                  value={protocolData.start_date}
                  onChange={(e) => updateProtocol('start_date', e.target.value)}
                />
              </label>

              {/* Plano de tratamento */}
              <div className="wizard__label">
                Plano de tratamento (opcional)
                <div className="wizard__mode-toggle" style={{ marginTop: 6 }}>
                  <button
                    type="button"
                    className={`wizard__mode-btn${planMode === 'none' ? ' wizard__mode-btn--active' : ''}`}
                    onClick={() => setPlanMode('none')}
                  >
                    Nenhum
                  </button>
                  {availablePlans.length > 0 && (
                    <button
                      type="button"
                      className={`wizard__mode-btn${planMode === 'existing' ? ' wizard__mode-btn--active' : ''}`}
                      onClick={() => setPlanMode('existing')}
                    >
                      Plano existente
                    </button>
                  )}
                  <button
                    type="button"
                    className={`wizard__mode-btn${planMode === 'new' ? ' wizard__mode-btn--active' : ''}`}
                    onClick={() => setPlanMode('new')}
                  >
                    + Criar plano
                  </button>
                </div>
                {planMode === 'existing' && (
                  <select
                    className="wizard__select"
                    style={{ marginTop: 8 }}
                    value={selectedPlanId}
                    onChange={(e) => setSelectedPlanId(e.target.value)}
                  >
                    <option value="">-- Escolha um plano --</option>
                    {availablePlans.map((p) => (
                      <option key={p.id} value={p.id}>
                        {p.emoji || '📋'} {p.name}
                      </option>
                    ))}
                  </select>
                )}
                {planMode === 'new' && (
                  <div style={{ marginTop: 8, display: 'flex', gap: 8 }}>
                    <input
                      type="text"
                      className="wizard__input"
                      style={{ flex: '0 0 48px', textAlign: 'center' }}
                      value={newPlanEmoji}
                      onChange={(e) => setNewPlanEmoji(e.target.value)}
                      placeholder="📋"
                      maxLength={2}
                    />
                    <input
                      type="text"
                      className="wizard__input"
                      style={{ flex: 1 }}
                      value={newPlanName}
                      onChange={(e) => setNewPlanName(e.target.value)}
                      placeholder="Nome do plano (ex: Hipertensão)"
                    />
                  </div>
                )}
              </div>

              <div className="wizard__actions">
                <Button variant="ghost" onClick={goBack}>
                  ← Voltar
                </Button>
                <Button
                  variant="ghost"
                  onClick={() => {
                    handleComplete(true)
                  }}
                >
                  Pular
                </Button>
                <Button variant="primary" onClick={goNext} disabled={!isProtocolValid}>
                  Próximo →
                </Button>
              </div>
            </div>
          )}

          {step === 3 && (
            <div className="wizard__step">
              <h3 className="wizard__title">Estoque Atual</h3>

              <label className="wizard__label">
                Quantidade (comprimidos)
                <input
                  type="number"
                  className="wizard__input"
                  value={stockData.quantity}
                  onChange={(e) => updateStock('quantity', e.target.value)}
                  placeholder="60"
                  min="0"
                />
              </label>

              <label className="wizard__label">
                Data da compra
                <input
                  type="date"
                  className="wizard__input"
                  value={stockData.purchase_date}
                  onChange={(e) => updateStock('purchase_date', e.target.value)}
                />
              </label>

              <label className="wizard__label">
                Preço unitário (R$)
                <input
                  type="number"
                  className="wizard__input"
                  value={stockData.unit_price}
                  onChange={(e) => updateStock('unit_price', e.target.value)}
                  placeholder="0.75"
                  min="0"
                  step="0.01"
                />
              </label>

              <label className="wizard__label">
                Validade (opcional)
                <input
                  type="date"
                  className="wizard__input"
                  value={stockData.expiration_date}
                  onChange={(e) => updateStock('expiration_date', e.target.value)}
                />
              </label>

              {error && <div className="wizard__error">{error}</div>}

              <div className="wizard__actions">
                <Button variant="ghost" onClick={goBack}>
                  ← Voltar
                </Button>
                <Button
                  variant="ghost"
                  onClick={() => handleComplete(true)}
                  disabled={isSubmitting}
                >
                  Pular
                </Button>
                <Button
                  variant="primary"
                  onClick={() => handleComplete(false)}
                  disabled={isSubmitting}
                >
                  {isSubmitting ? 'Salvando...' : 'Concluir'}
                </Button>
              </div>
            </div>
          )}

          {step === 4 && result && (
            <div className="wizard__step wizard__step--complete">
              <div className="wizard__complete-icon">✅</div>
              <h3 className="wizard__title">Pronto!</h3>
              <p className="wizard__complete-summary">
                <strong>{result.medicine?.name || medicineData.name}</strong> cadastrado
                {result.protocol && ` com tratamento ${FREQUENCY_LABELS[protocolData.frequency]}`}
                {stockData.quantity && ` e ${stockData.quantity} comprimidos em estoque`}.
              </p>
              <div className="wizard__actions wizard__actions--center">
                <Button variant="primary" onClick={() => onComplete(result)}>
                  Ir para Hoje
                </Button>
                <Button
                  variant="ghost"
                  onClick={() => {
                    setStep(1)
                    setResult(null)
                    setMedicineData({
                      name: '',
                      type: 'medicamento',
                      dosage_per_pill: '',
                      dosage_unit: 'mg',
                      laboratory: '',
                      active_ingredient: '',
                      therapeutic_class: null,
                    })
                    setProtocolData({
                      frequency: 'diário',
                      time_schedule: ['08:00'],
                      dosage_per_intake: 1,
                      start_date: formatLocalDate(new Date()),
                    })
                    setStockData({
                      quantity: '',
                      purchase_date: formatLocalDate(new Date()),
                      unit_price: '',
                      expiration_date: '',
                    })
                  }}
                >
                  Cadastrar outro
                </Button>
              </div>
            </div>
          )}
        </motion.div>
      </AnimatePresence>
    </div>
  )
}

