describe('reminderOptimizerService', () => {
  afterEach(() => {
    vi.clearAllMocks()
    vi.clearAllTimers()
    localStorage.clear()
  })

  describe('analyzeReminderTiming', () => {
    const mockProtocol = {
      id: 'proto-1',
      medicine_id: 'med-1',
      frequency: 'diario',
      time_schedule: ['08:00'],
    }

    const createMockLog = (hour, minute, protocolId = 'proto-1') => ({
      id: `log-${Math.random()}`,
      protocol_id: protocolId,
      medicine_id: 'med-1',
      quantity_taken: 1,
      taken_at: new Date(2026, 2, 8, hour, minute).toISOString(),
    })

    it('retorna null quando time_schedule está vazio', () => {
      const protocol = { ...mockProtocol, time_schedule: [] }
      const logs = []
      const result = analyzeReminderTiming({ protocol, logs })
      expect(result).toBeNull()
    })

    it('retorna null quando time_schedule é null', () => {
      const protocol = { ...mockProtocol, time_schedule: null }
      const logs = []
      const result = analyzeReminderTiming({ protocol, logs })
      expect(result).toBeNull()
    })

    it('retorna null quando frequency é "quando_necessario"', () => {
      const protocol = { ...mockProtocol, frequency: 'quando_necessario' }
      const logs = [createMockLog(7, 45), createMockLog(8, 15), createMockLog(8, 10)]
      const result = analyzeReminderTiming({ protocol, logs })
      expect(result).toBeNull()
    })

    it('retorna null quando logs insuficientes (<10 amostras)', () => {
      const logs = [createMockLog(8, 5), createMockLog(8, 10), createMockLog(8, 0)]
      const result = analyzeReminderTiming({ protocol: mockProtocol, logs })
      expect(result).toBeNull()
    })

    it('retorna null quando delta é <= 30 minutos', () => {
      // Protocolo: 08:00, logs: 08:15 (delta = 15 min < 30)
      const logs = Array.from({ length: 10 }, (_, i) => createMockLog(8, 15 + (i % 5)))
      const result = analyzeReminderTiming({ protocol: mockProtocol, logs })
      expect(result).toBeNull()
    })

    it('sugere ajuste quando |avgDelta| > 30 minutos (caso 1: toma mais cedo)', () => {
      // Protocolo: 08:00, logs: 07:20 (delta = -40 min, direção 'earlier')
      // -40 / 15 = -2.67 → round = -3 → -3 * 15 = -45 → 08:00 - 45 min = 07:15
      const logs = Array.from({ length: 12 }, () => createMockLog(7, 20))
      const result = analyzeReminderTiming({ protocol: mockProtocol, logs })

      expect(result).not.toBeNull()
      expect(result.shouldSuggest).toBe(true)
      expect(result.currentTime).toBe('08:00')
      expect(result.suggestedTime).toBe('07:15') // Arredondado para 15 min
      expect(result.direction).toBe('earlier')
      expect(result.avgDeltaMinutes).toBe(-40)
      expect(result.sampleCount).toBe(12)
    })

    it('sugere ajuste quando |avgDelta| > 30 minutos (caso 2: toma mais tarde)', () => {
      // Protocolo: 08:00, logs: 08:45 (delta = +45 min, direção 'later')
      const logs = Array.from({ length: 15 }, () => createMockLog(8, 45))
      const result = analyzeReminderTiming({ protocol: mockProtocol, logs })

      expect(result).not.toBeNull()
      expect(result.shouldSuggest).toBe(true)
      expect(result.currentTime).toBe('08:00')
      expect(result.suggestedTime).toBe('08:45') // Arredondado para 15 min
      expect(result.direction).toBe('later')
      expect(result.avgDeltaMinutes).toBe(45)
      expect(result.sampleCount).toBe(15)
    })

    it('arredonda sugestão para 15 minutos (delta=-37)', () => {
      // -37 min / 15 = -2.46 → round = -2 → -2 * 15 = -30
      const logs = Array.from({ length: 10 }, () => createMockLog(7, 23)) // 08:00 - 37 min
      const result = analyzeReminderTiming({ protocol: mockProtocol, logs })

      expect(result).not.toBeNull()
      expect(result.suggestedTime).toBe('07:30') // 08:00 - 30 min
    })

    it('arredonda sugestão para 15 minutos (delta=+38)', () => {
      // +38 min / 15 = 2.53 → round = 3 → 3 * 15 = 45
      const logs = Array.from({ length: 10 }, () => createMockLog(8, 38))
      const result = analyzeReminderTiming({ protocol: mockProtocol, logs })

      expect(result).not.toBeNull()
      expect(result.suggestedTime).toBe('08:45') // 08:00 + 45 min
    })

    it('filtra apenas logs dentro da janela de 4 horas', () => {
      // Protocolo: 08:00
      // Logs dentro da janela 4h: todos tomados em 08:45 (delta +45 > 30)
      // Logs fora: 13:00+ (fora da janela, descartados)
      const logs = [
        // 10 logs dentro da janela 4h, tomados em 08:45
        createMockLog(8, 45),
        createMockLog(8, 45),
        createMockLog(8, 46),
        createMockLog(8, 44),
        createMockLog(8, 45),
        createMockLog(8, 45),
        createMockLog(8, 45),
        createMockLog(8, 47),
        createMockLog(8, 45),
        createMockLog(8, 43),
        // Logs fora da janela 4h (devem ser ignorados)
        createMockLog(13, 0), // 5h depois = 300 min, fora da janela
        createMockLog(3, 0), // 5h antes = -300 min, fora da janela
      ]

      const result = analyzeReminderTiming({ protocol: mockProtocol, logs })
      expect(result).not.toBeNull()
      // Média deve estar ~45 (logs em 08:45 vs programado 08:00)
      expect(Math.abs(result.avgDeltaMinutes)).toBeGreaterThan(40)
      expect(Math.abs(result.avgDeltaMinutes)).toBeLessThan(50)
    })

    it('retorna primeira sugestão quando multiple time_schedule', () => {
      // Protocolo com 2 horários: 08:00 e 14:00
      const protocol = {
        ...mockProtocol,
        time_schedule: ['08:00', '14:00'],
      }

      // Logs para 08:00: delta = +50 min (sugere 08:45)
      const logs1 = Array.from({ length: 10 }, () => createMockLog(8, 50))

      // Logs para 14:00: delta = +60 min (sugere 15:00)
      const logs2 = Array.from({ length: 10 }, () => createMockLog(15, 0))

      const allLogs = [...logs1, ...logs2]
      const result = analyzeReminderTiming({ protocol, logs: allLogs })

      // Retorna primeira sugestão
      expect(result).not.toBeNull()
      expect(result.shouldSuggest).toBe(true)
    })

    it('valida entrada com Zod safeParse', () => {
      // Entrada inválida (protocol.id faltando)
      const invalidProtocol = {
        medicine_id: 'med-1',
        frequency: 'diario',
        time_schedule: ['08:00'],
      }

      const result = analyzeReminderTiming({
        protocol: invalidProtocol,
        logs: [],
      })

      // Zod vai rejeitar, função retorna null
      expect(result).toBeNull()
    })

    it('lida com logs sem protocol_id (filtra por medicine_id)', () => {
      // Logs com protocol_id = null, apenas medicine_id deve ser usado para match
      // Protocolo: 08:00, logs: 07:20 (delta -40)
      const logs = Array.from({ length: 12 }, () => ({
        id: `log-${Math.random()}`,
        protocol_id: null, // Sem protocol_id, filtra por medicine_id
        medicine_id: 'med-1',
        quantity_taken: 1,
        taken_at: new Date(2026, 2, 8, 7, 20).toISOString(),
      }))

      const result = analyzeReminderTiming({ protocol: mockProtocol, logs })

      expect(result).not.toBeNull()
      expect(result.direction).toBe('earlier')
      expect(Math.abs(result.avgDeltaMinutes)).toBeGreaterThan(30)
    })

    it('trata JSON parsing error em timestamp', () => {
      // Este teste verifica robustez contra dados malformados
      const logs = [
        {
          id: 'log-1',
          protocol_id: 'proto-1',
          medicine_id: 'med-1',
          quantity_taken: 1,
          taken_at: 'invalid-date',
        },
      ]

      // Deve não lançar erro, apenas retornar null
      expect(() => {
        analyzeReminderTiming({ protocol: mockProtocol, logs })
      }).not.toThrow()
    })
  })

  describe('isSuggestionDismissed', () => {
    beforeEach(() => {
      localStorage.clear()
      vi.useFakeTimers()
    })

    afterEach(() => {
      vi.useRealTimers()
    })

    it('retorna false quando nada foi dispensado', () => {
      const result = isSuggestionDismissed('proto-1')
      expect(result).toBe(false)
    })

    it('retorna true quando dispensado permanentemente', () => {
      dismissSuggestion('proto-1', true)
      const result = isSuggestionDismissed('proto-1')
      expect(result).toBe(true)
    })

    it('retorna true quando dentro da janela de 30 dias', () => {
      vi.setSystemTime(new Date('2026-03-08'))
      dismissSuggestion('proto-1', false)

      vi.setSystemTime(new Date('2026-03-15')) // +7 dias
      const result = isSuggestionDismissed('proto-1')
      expect(result).toBe(true)
    })

    it('retorna false quando expirou a janela de 30 dias', () => {
      vi.setSystemTime(new Date('2026-03-08'))
      dismissSuggestion('proto-1', false)

      vi.setSystemTime(new Date('2026-04-10')) // +33 dias
      const result = isSuggestionDismissed('proto-1')
      expect(result).toBe(false)
    })

    it('retorna true em ambiente server-side (typeof window === "undefined")', () => {
      // Verificamos se o código cuida disso
      const originalWindow = global.window
      // @ts-ignore
      delete global.window

      try {
        const result = isSuggestionDismissed('proto-1')
        expect(result).toBe(true)
      } finally {
        global.window = originalWindow
      }
    })

    it('trata JSON inválido em localStorage', () => {
      localStorage.setItem('optimizer_dismissed_proto-1', 'invalid json')
      const result = isSuggestionDismissed('proto-1')
      expect(result).toBe(true) // Falha segura
    })
  })

  describe('dismissSuggestion', () => {
    afterEach(() => {
      localStorage.clear()
    })

    it('armazena dispensação em localStorage (impermanente)', () => {
      vi.useFakeTimers()
      vi.setSystemTime(new Date('2026-03-08'))

      dismissSuggestion('proto-1', false)

      const stored = localStorage.getItem('optimizer_dismissed_proto-1')
      expect(stored).not.toBeNull()

      const parsed = JSON.parse(stored)
      expect(parsed.timestamp).toBe(Date.now())
      expect(parsed.permanent).toBe(false)

      vi.useRealTimers()
    })

    it('armazena dispensação em localStorage (permanente)', () => {
      dismissSuggestion('proto-2', true)

      const stored = localStorage.getItem('optimizer_dismissed_proto-2')
      expect(stored).not.toBeNull()

      const parsed = JSON.parse(stored)
      expect(parsed.permanent).toBe(true)
    })

    it('sobrescreve dispensação anterior', () => {
      vi.useFakeTimers()

      vi.setSystemTime(new Date('2026-03-08'))
      dismissSuggestion('proto-1', false)
      const stored1 = localStorage.getItem('optimizer_dismissed_proto-1')

      vi.setSystemTime(new Date('2026-03-10'))
      dismissSuggestion('proto-1', true)
      const stored2 = localStorage.getItem('optimizer_dismissed_proto-1')

      expect(stored1).not.toBe(stored2)
      expect(JSON.parse(stored2).permanent).toBe(true)

      vi.useRealTimers()
    })

    it('não lança erro em ambiente server-side', () => {
      const originalWindow = global.window
      // @ts-ignore
      delete global.window

      try {
        expect(() => {
          dismissSuggestion('proto-1', false)
        }).not.toThrow()
      } finally {
        global.window = originalWindow
      }
    })
  })
})

import { describe, it, expect } from 'vitest'
import {
  calculateTitrationSteps,
  getDaysUntilNextStep,
  getStepProgress,
  formatDose,
  formatDaysRemaining,
  isTitrationActive,
  hasReachedTarget,
  getTitrationSummary,
} from '@protocols/services/titrationService'

describe('titrationService', () => {
  describe('calculateTitrationSteps', () => {
    it('should return empty result for protocol without titration schedule', () => {
      const result = calculateTitrationSteps({})
      expect(result.steps).toEqual([])
      expect(result.currentStep).toBe(0)
      expect(result.totalSteps).toBe(0)
    })

    it('should calculate steps for a protocol with titration schedule', () => {
      const protocol = {
        titration_schedule: [
          { dosage: 1, duration_days: 7, description: 'Etapa inicial' },
          { dosage: 2, duration_days: 7, description: 'Etapa intermediária' },
          { dosage: 3, duration_days: 7, description: 'Dose alvo' },
        ],
        current_stage_index: 0,
        stage_started_at: '2024-01-01T00:00:00Z',
        start_date: '2024-01-01',
        medicine: { dosage_unit: 'mg' },
      }

      const result = calculateTitrationSteps(protocol)
      expect(result.steps).toHaveLength(3)
      expect(result.totalSteps).toBe(3)
      expect(result.currentStep).toBe(1)
      expect(result.steps[0].status).toBe('current')
      expect(result.steps[1].status).toBe('future')
    })

    it('should mark completed stages correctly', () => {
      const protocol = {
        titration_schedule: [
          { dosage: 1, duration_days: 7, description: 'Etapa 1' },
          { dosage: 2, duration_days: 7, description: 'Etapa 2' },
          { dosage: 3, duration_days: 7, description: 'Etapa 3' },
        ],
        current_stage_index: 1,
        stage_started_at: '2024-01-08T00:00:00Z',
        start_date: '2024-01-01',
        medicine: { dosage_unit: 'mg' },
      }

      const result = calculateTitrationSteps(protocol)
      expect(result.steps[0].status).toBe('completed')
      expect(result.steps[1].status).toBe('current')
      expect(result.steps[2].status).toBe('future')
    })

    it('should calculate correct dates for each step', () => {
      const protocol = {
        titration_schedule: [
          { dosage: 1, duration_days: 7, description: 'Semana 1' },
          { dosage: 2, duration_days: 7, description: 'Semana 2' },
        ],
        current_stage_index: 0,
        stage_started_at: '2024-01-01T00:00:00Z',
        start_date: '2024-01-01',
        medicine: { dosage_unit: 'mg' },
      }

      const result = calculateTitrationSteps(protocol)
      expect(result.steps[0].startDate.toISOString()).toContain('2024-01-01')
      expect(result.steps[1].startDate.toISOString()).toContain('2024-01-08')
    })

    it('should use mg as default unit', () => {
      const protocol = {
        titration_schedule: [{ dosage: 1, duration_days: 7, description: 'Etapa 1' }],
        current_stage_index: 0,
        stage_started_at: '2024-01-01T00:00:00Z',
        medicine: null,
      }

      const result = calculateTitrationSteps(protocol)
      expect(result.steps[0].unit).toBe('mg')
    })
  })

  describe('getDaysUntilNextStep', () => {
    it('should return 0 for last step', () => {
      const steps = [{ endDate: new Date('2024-01-07') }, { endDate: new Date('2024-01-14') }]
      const result = getDaysUntilNextStep(1, steps, new Date('2024-01-01'))
      expect(result).toBe(0)
    })

    it('should calculate days remaining for current step', () => {
      const today = new Date()
      const futureDate = new Date(today)
      futureDate.setDate(futureDate.getDate() + 5)

      const steps = [
        { endDate: futureDate },
        { endDate: new Date(today.getTime() + 86400000 * 10) },
      ]

      const result = getDaysUntilNextStep(0, steps, today)
      expect(result).toBeGreaterThanOrEqual(4)
      expect(result).toBeLessThanOrEqual(6)
    })

    it('should return 0 when no current step', () => {
      const result = getDaysUntilNextStep(0, [], new Date())
      expect(result).toBe(0)
    })
  })

  describe('getStepProgress', () => {
    it('should return 0 when step not started', () => {
      const futureDate = new Date()
      futureDate.setDate(futureDate.getDate() + 1)

      const steps = [
        {
          startDate: futureDate,
          endDate: new Date(futureDate.getTime() + 86400000 * 7),
          durationDays: 7,
        },
      ]

      const result = getStepProgress(0, steps, new Date())
      expect(result).toBe(0)
    })

    it('should return 100 when step completed', () => {
      const pastDate = new Date()
      pastDate.setDate(pastDate.getDate() - 10)

      const steps = [
        {
          startDate: pastDate,
          endDate: new Date(pastDate.getTime() + 86400000 * 7),
          durationDays: 7,
        },
      ]

      const result = getStepProgress(0, steps, pastDate)
      expect(result).toBe(100)
    })

    it('should calculate progress for ongoing step', () => {
      const startDate = new Date()
      startDate.setDate(startDate.getDate() - 3)
      const endDate = new Date(startDate.getTime() + 86400000 * 6)

      const steps = [{ startDate, endDate, durationDays: 7 }]

      const result = getStepProgress(0, steps, startDate)
      expect(result).toBeGreaterThan(0)
      expect(result).toBeLessThan(100)
    })
  })

  describe('formatDose', () => {
    it('should format dose with unit', () => {
      expect(formatDose(2, 'mg')).toBe('2 mg')
      expect(formatDose(1, 'comprimido')).toBe('1 comprimido')
    })

    it('should calculate total mg when dosagePerPill is provided', () => {
      expect(formatDose(2, 'mg', 500)).toBe('1000mg (2 comp.)')
    })

    it('should handle single unit', () => {
      expect(formatDose(1, 'cápsula')).toBe('1 cápsula')
    })
  })

  describe('formatDaysRemaining', () => {
    it('should return message for last step', () => {
      expect(formatDaysRemaining(0)).toBe('Última etapa')
    })

    it('should return singular for 1 day', () => {
      expect(formatDaysRemaining(1)).toBe('1 dia restante')
    })

    it('should return plural for multiple days', () => {
      expect(formatDaysRemaining(5)).toBe('5 dias restantes')
    })
  })

  describe('isTitrationActive', () => {
    it('should return true for active titration', () => {
      const protocol = {
        titration_status: 'titulando',
        titration_schedule: [{ dosage: 1, duration_days: 7 }],
      }
      expect(isTitrationActive(protocol)).toBe(true)
    })

    it('should return false when status is not titulando', () => {
      const protocol = {
        titration_status: 'estável',
        titration_schedule: [{ dosage: 1, duration_days: 7 }],
      }
      expect(isTitrationActive(protocol)).toBe(false)
    })

    it('should return false when no titration schedule', () => {
      const protocol = {
        titration_status: 'titulando',
        titration_schedule: [],
      }
      expect(isTitrationActive(protocol)).toBe(false)
    })

    it('should return false for null protocol', () => {
      expect(isTitrationActive(null)).toBe(false)
    })
  })

  describe('hasReachedTarget', () => {
    it('should return true when target reached', () => {
      const protocol = { titration_status: 'alvo_atingido' }
      expect(hasReachedTarget(protocol)).toBe(true)
    })

    it('should return false when not at target', () => {
      const protocol = { titration_status: 'titulando' }
      expect(hasReachedTarget(protocol)).toBe(false)
    })

    it('should return false for null protocol', () => {
      expect(hasReachedTarget(null)).toBe(false)
    })
  })

  describe('getTitrationSummary', () => {
    it('should return null when no active titration', () => {
      const protocol = {
        titration_status: 'estável',
        titration_schedule: [],
      }
      expect(getTitrationSummary(protocol)).toBeNull()
    })

    it('should return summary for active titration', () => {
      const protocol = {
        titration_status: 'titulando',
        titration_schedule: [{ dosage: 1, duration_days: 7, description: 'Etapa 1' }],
        current_stage_index: 0,
        stage_started_at: '2024-01-01T00:00:00Z',
        start_date: '2024-01-01',
        dosage_per_intake: 1,
        medicine: { dosage_unit: 'mg' },
      }

      const result = getTitrationSummary(protocol)
      expect(result).not.toBeNull()
      expect(result.currentStep).toBe(1)
      expect(result.totalSteps).toBe(1)
      expect(result.isComplete).toBe(false)
    })

    it('should return summary for completed titration', () => {
      const protocol = {
        titration_status: 'alvo_atingido',
        titration_schedule: [
          { dosage: 1, duration_days: 7, description: 'Etapa 1' },
          { dosage: 2, duration_days: 7, description: 'Etapa 2' },
        ],
        current_stage_index: 1,
        stage_started_at: '2024-01-08T00:00:00Z',
        start_date: '2024-01-01',
        dosage_per_intake: 2,
        medicine: { dosage_unit: 'mg' },
      }

      const result = getTitrationSummary(protocol)
      expect(result).not.toBeNull()
      expect(result.isComplete).toBe(true)
    })

    it('should include estimated end date', () => {
      const protocol = {
        titration_status: 'titulando',
        titration_schedule: [{ dosage: 1, duration_days: 7, description: 'Etapa 1' }],
        current_stage_index: 0,
        stage_started_at: '2024-01-01T00:00:00Z',
        start_date: '2024-01-01',
        dosage_per_intake: 1,
        medicine: { dosage_unit: 'mg' },
      }

      const result = getTitrationSummary(protocol)
      expect(result.estimatedEndDate).toBeInstanceOf(Date)
    })
  })
})

