describe('consultationPdfDataBuilder', () => {
  const now = new Date()
  const past = formatLocalDate(addDays(now, -20))
  const future = formatLocalDate(addDays(now, 20))

  const medicines = [
    {
      id: 'med-1',
      name: 'Losartana',
      dosage_per_pill: 50,
      dosage_unit: 'mg',
      notes: 'Tomar ao acordar',
    },
    {
      id: 'med-2',
      name: 'Ansitec',
      dosage_per_pill: 10,
      dosage_unit: 'mg',
    },
  ]

  const protocols = [
    {
      id: 'prot-1',
      name: 'Hipertensao',
      medicine_id: 'med-1',
      active: true,
      dosage_per_intake: 2,
      time_schedule: ['08:00', '20:00'],
      start_date: past,
      end_date: future,
    },
    {
      id: 'prot-2',
      name: 'Ansiedade',
      medicine_id: 'med-2',
      active: true,
      dosage_per_intake: 1,
      time_schedule: ['22:00'],
      titration_schedule: [{ dosage: 1, days: 3 }],
      start_date: past,
      end_date: future,
    },
