 * @fileoverview Monta os dados normalizados do PDF de consulta medica.
 * Converte o estado clinico da app em um modelo editorial pronto para renderizacao.
 * @module features/reports/services/consultationPdfDataBuilder
 */

import { addDays, formatLocalDate, parseLocalDate } from '@utils/dateUtils.js'
import { extractEmailHandle, formatPatientDisplayName } from '@shared/utils/patientUtils'
import { calculateDailyIntake, calculateDosesByDate } from '@utils/adherenceLogic'

/**
 * Formata um numero com fallback legivel.
 * @param {number|string|null|undefined} value - Valor a formatar.
 * @param {string} fallback - Texto exibido quando nao ha valor.
 * @returns {string} Texto formatado.
 */
function safeText(value, fallback = '-') {
  if (value === null || value === undefined || value === '') return fallback
  return String(value)
}

function getTrendLabel(days) {
  if (days >= 90) return '90 dias'
  if (days >= 30) return '30 dias'
  if (days >= 7) return '7 dias'
  return `${days} dias`
}

function summarizeTrend(trend = [], fallbackCurrentStreak = 0) {
  const totals = trend.reduce(
    (accumulator, row) => ({
      taken: accumulator.taken + Number(row.taken ?? 0),
      expected: accumulator.expected + Number(row.expected ?? 0),
    }),
    { taken: 0, expected: 0 }
  )

  const score = totals.expected > 0 ? Math.round((totals.taken / totals.expected) * 100) : 0

  return {
    score,
    taken: totals.taken,
    expected: totals.expected,
    punctuality: score,
    currentStreak: fallbackCurrentStreak,
  }
}

/**
 * Retorna o nome clinico do tratamento.
 * @param {Object} protocol - Protocolo ativo.
 * @param {Object} medicine - Medicamento associado.
 * @returns {string} Label no formato `[tratamento] - [medicacao]`.
 */
export function formatTreatmentLabel(protocol, medicine) {
  const treatmentName = protocol?.name || protocol?.treatment_name || protocol?.medicine_name
  const medicineName = medicine?.name || protocol?.medicine?.name || protocol?.medicine_name

  if (treatmentName && medicineName) {
    return `${treatmentName} - ${medicineName}`
  }

  return treatmentName || medicineName || 'Tratamento sem nome'
}

/**
 * Formata a apresentacao do medicamento.
 * @param {Object} medicine - Medicamento cadastrado.
 * @returns {string} Texto de apresentacao.
 */
export function formatMedicinePresentation(medicine) {
  const dosagePerPill = medicine?.dosage_per_pill
  const dosageUnit = medicine?.dosage_unit || 'mg'

  if (dosagePerPill === null || dosagePerPill === undefined) {
    return 'Apresentacao nao cadastrada'
  }

  return `${dosagePerPill} ${dosageUnit} por comprimido`
}

/**
 * Formata a dose por tomada.
 * @param {Object} protocol - Protocolo ativo.
 * @param {Object} medicine - Medicamento cadastrado.
 * @returns {string} Texto da dose por tomada.
 */
export function formatIntakeDose(protocol, medicine) {
  const pillsPerIntake = protocol?.dosage_per_intake ?? 1
  const dosagePerPill = medicine?.dosage_per_pill
  const dosageUnit = medicine?.dosage_unit || 'mg'
  const pillLabel = pillsPerIntake === 1 ? 'comprimido' : 'comprimidos'

  if (dosagePerPill === null || dosagePerPill === undefined) {
    return `${pillsPerIntake} ${pillLabel}`
  }

  const intakeAmount = pillsPerIntake * dosagePerPill
  return `${pillsPerIntake} ${pillLabel} (${intakeAmount} ${dosageUnit})`
}

/**
 * Formata a frequencia em linguagem clinica curta.
 * @param {Object} protocol - Protocolo ativo.
 * @returns {string} Texto da frequencia.
 */
export function formatFrequency(protocol) {
  const schedule = Array.isArray(protocol?.time_schedule) ? protocol.time_schedule : []
  if (schedule.length === 0) return '1x/dia'

  const schedulePreview = schedule.slice(0, 3).join(', ')
  const suffix = schedule.length > 3 ? '...' : ''
  return `${schedule.length}x/dia${schedulePreview ? ` • ${schedulePreview}${suffix}` : ''}`
}

/**
 * Formata a dose diaria total.
 * @param {Object} protocol - Protocolo ativo.
 * @param {Object} medicine - Medicamento cadastrado.
 * @returns {string} Texto da dose diaria.
 */
export function formatDailyDose(protocol, medicine) {
  const pillsPerIntake = protocol?.dosage_per_intake ?? 1
  const timesPerDay =
    Array.isArray(protocol?.time_schedule) && protocol.time_schedule.length > 0
      ? protocol.time_schedule.length
      : 1
  const dosagePerPill = medicine?.dosage_per_pill
  const dosageUnit = medicine?.dosage_unit || 'mg'

  if (dosagePerPill === null || dosagePerPill === undefined) {
    const pillsPerDay = pillsPerIntake * timesPerDay
    const pillLabel = pillsPerDay === 1 ? 'comprimido/dia' : 'comprimidos/dia'
    return `${pillsPerDay} ${pillLabel}`
  }

  const totalDosage = pillsPerIntake * timesPerDay * dosagePerPill
  return `${totalDosage} ${dosageUnit}/dia`
}

/**
 * Calcula a severidade de estoque.
 * @param {Object} stockItem - Resumo de estoque.
 * @returns {string} critical|warning|stable
 */
function getStockSeverity(stockItem) {
  if (!stockItem) return 'stable'
  if (stockItem.isZero || (stockItem.daysRemaining !== null && stockItem.daysRemaining <= 0)) {
    return 'critical'
  }
  if (stockItem.isLow || (stockItem.daysRemaining !== null && stockItem.daysRemaining < 7)) {
    return 'warning'
  }
  return 'stable'
}

/**
 * Gera rows de tratamentos para a tabela principal.
 * @param {Array<Object>} protocols - Protocolos do paciente.
 * @param {Array<Object>} medicines - Medicamentos do paciente.
 * @returns {Array<Object>} Rows prontos para renderizacao.
 */
function buildTreatmentRows(protocols = [], medicines = []) {
  return protocols
    .filter((protocol) => protocol?.active !== false)
    .map((protocol) => {
      const medicine =
        medicines.find((item) => item.id === protocol.medicine_id) || protocol.medicine || {}
      const timesPerDay =
        Array.isArray(protocol.time_schedule) && protocol.time_schedule.length > 0
          ? protocol.time_schedule.length
          : 1
      const dosagePerPill = medicine.dosage_per_pill ?? null
      const dosagePerIntake =
        dosagePerPill === null ? null : (protocol.dosage_per_intake ?? 1) * dosagePerPill

      return {
        id: protocol.id,
        label: formatTreatmentLabel(protocol, medicine),
        presentation: formatMedicinePresentation(medicine),
        dosePerIntake: formatIntakeDose(protocol, medicine),
        frequency: formatFrequency(protocol),
        dailyDose: formatDailyDose(protocol, medicine),
        status: 'Ativo',
        note: protocol.titration_schedule?.length
          ? 'Em titulacao'
          : safeText(medicine.notes, 'Sem observacoes'),
        timesPerDay,
        dosagePerIntake,
      }
    })
    .sort((a, b) => a.label.localeCompare(b.label, 'pt-BR'))
}

/**
 * Gera rows de estoque ordenados por urgencia.
 * @param {Array<Object>} stockSummary - Sumario de estoque vindo do dashboard.
 * @param {Array<Object>} protocols - Protocolos ativos.
 * @param {Array<Object>} medicines - Medicamentos cadastrados.
 * @returns {Array<Object>} Rows do estoque.
 */
function buildStockRows(stockSummary = [], protocols = [], medicines = []) {
  return stockSummary
    .map((stockItem) => {
      const medicine =
        medicines.find((item) => item.id === stockItem?.medicine?.id) || stockItem?.medicine || {}
      const protocol = protocols.find(
        (item) => item.medicine_id === medicine.id && item.active !== false
      )
      const dailyIntake = stockItem?.dailyIntake ?? calculateDailyIntake(medicine.id, protocols)
      const totalQuantity = stockItem?.total ?? 0
      const daysRemaining =
        stockItem?.daysRemaining ??
        (dailyIntake > 0 ? Math.floor(totalQuantity / dailyIntake) : null)
      const severity = getStockSeverity({ ...stockItem, daysRemaining })

      return {
        id: medicine.id || stockItem?.medicine?.id || stockItem?.medicine_id || crypto.randomUUID(),
        label: formatTreatmentLabel(protocol, medicine),
        medicineName: safeText(medicine.name, 'Desconhecido'),
        totalQuantity,
        dailyIntake,
        daysRemaining,
        severity,
        message: stockItem?.isZero
          ? 'Estoque esgotado'
          : stockItem?.isLow
            ? 'Estoque baixo'
            : 'Estoque monitorado',
      }
    })
    .sort((a, b) => {
      const severityOrder = { critical: 0, warning: 1, stable: 2 }
      const severityDiff = severityOrder[a.severity] - severityOrder[b.severity]
      if (severityDiff !== 0) return severityDiff
      const aDays = a.daysRemaining ?? Number.POSITIVE_INFINITY
      const bDays = b.daysRemaining ?? Number.POSITIVE_INFINITY
      return aDays - bDays
    })
}

/**
 * Gera rows de prescricao.
 * @param {Array<Object>} prescriptionStatus - Status das prescricoes.
 * @param {Array<Object>} protocols - Protocolos.
 * @param {Array<Object>} medicines - Medicamentos.
 * @returns {Array<Object>} Rows das prescricoes.
 */
function buildPrescriptionRows(prescriptionStatus = [], protocols = [], medicines = []) {
  return prescriptionStatus.map((prescription) => {
    const protocol = protocols.find((item) => item.id === prescription.protocolId)
    const medicine =
      medicines.find((item) => item.id === protocol?.medicine_id) || protocol?.medicine || {}

    return {
      id: prescription.protocolId,
      label: formatTreatmentLabel(protocol, medicine),
      status: prescription.status,
      statusLabel:
        prescription.status === 'vencida'
          ? 'Vencida'
          : prescription.status === 'vencendo'
            ? 'Vencendo'
            : 'Vigente',
      daysRemaining: prescription.daysRemaining,
      endDate: prescription.endDate || protocol?.end_date || null,
    }
  })
}

/**
 * Gera rows de titulacao.
 * @param {Array<Object>} activeTitrations - Titulacoes ativas.
 * @param {Array<Object>} protocols - Protocolos.
 * @param {Array<Object>} medicines - Medicamentos.
 * @returns {Array<Object>} Rows da titulacao.
 */
function buildTitrationRows(activeTitrations = [], protocols = [], medicines = []) {
  return activeTitrations.map((titration) => {
    const protocol = protocols.find((item) => item.id === titration.protocolId)
    const medicine =
      medicines.find((item) => item.id === titration.medicineId) || protocol?.medicine || {}

    return {
      id: titration.protocolId,
      label: formatTreatmentLabel(protocol, medicine),
      currentStep: titration.currentStep,
      totalSteps: titration.totalSteps,
      currentDosage: titration.currentDosage,
      progressPercent: titration.progressPercent,
      daysRemaining: titration.daysRemaining,
      isTransitionDue: titration.isTransitionDue,
      stageNote: safeText(titration.stageNote, 'Sem observacoes'),
    }
  })
}

/**
 * Gera uma trilha sintetica de adesao dos ultimos dias.
 * @param {Array<Object>} dailyAdherence - Série diária já consolidada pelo dashboard.
 * @param {Array<Object>} logs - Logs de dose.
 * @param {Array<Object>} protocols - Protocolos.
 * @param {number} days - Numero de dias a incluir.
 * @returns {Array<Object>} Rows com a adesao diaria.
 */
function buildAdherenceTrend(dailyAdherence = [], logs = [], protocols = [], days = 7) {
  if (Array.isArray(dailyAdherence) && dailyAdherence.length > 0) {
    return dailyAdherence.slice(-days).map((row) => {
      const taken = Number(row.taken ?? 0)
      const expected = Number(row.expected ?? 0)
      const score = expected > 0 ? Math.round((taken / expected) * 100) : null

      return {
        date: row.date,
        label: row.date
          ? parseLocalDate(row.date).toLocaleDateString('pt-BR', {
              day: '2-digit',
              month: '2-digit',
            })
          : row.label || '',
        taken,
        expected,
        score,
        status:
          expected === 0
            ? 'Sem doses'
            : score >= 90
              ? 'Excelente'
              : score >= 70
                ? 'Atenção'
                : 'Critico',
      }
    })
  }

  const activeProtocols = protocols.filter((protocol) => protocol?.active !== false)
  const trend = []

  for (let offset = days - 1; offset >= 0; offset -= 1) {
    const date = addDays(new Date(), -offset)
    const dateStr = formatLocalDate(date)
    const result = calculateDosesByDate(dateStr, logs, activeProtocols)
    const taken = result.takenDoses.length
    const missed = result.missedDoses.length
    const expected = taken + missed
    const score = expected > 0 ? Math.round((taken / expected) * 100) : null

    trend.push({
      date: dateStr,
      label: parseLocalDate(dateStr).toLocaleDateString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
      }),
      taken,
      expected,
      score,
      status:
        expected === 0
          ? 'Sem doses'
          : score >= 90
            ? 'Excelente'
            : score >= 70
              ? 'Atenção'
              : 'Critico',
    })
  }

  return trend
}

/**
 * Monta os dados normalizados para renderizacao do PDF.
 * @param {Object} params - Parametros agregados.
 * @param {Object} params.consultationData - Dados consolidados do modo consulta.
 * @param {Object} params.dashboardData - Dados brutos do dashboard.
 * @param {string} [params.period='30d'] - Periodo de cobertura.
 * @param {Date|string} [params.generatedAt=new Date()] - Momento de geracao.
 * @param {string} [params.title] - Titulo do documento.
 * @returns {Object} Modelo editorial pronto para o service de PDF.
 */
export function buildConsultationPdfData({
  consultationData,
  dashboardData = {},
  period = '30d',
  generatedAt = new Date(),
  title = 'Dosiq - Consulta Médica',
  patientEmail = '',
} = {}) {
  const medicines = dashboardData.medicines || []
  const protocols = dashboardData.protocols || []
  const logs = dashboardData.logs || []
  const dailyAdherence = dashboardData.dailyAdherence || []
  const stockSummary = dashboardData.stockSummary || []
  const patientInfo = consultationData?.patientInfo || {}
  const activeMedicines = consultationData?.activeMedicines || []
  const periodDays =
    period === 'all'
      ? Math.max(dailyAdherence.length || 0, 90)
      : Math.max(parseInt(period, 10) || 7, 1)
  const activeTreatments = buildTreatmentRows(protocols, medicines)
  const stockRows = buildStockRows(stockSummary, protocols, medicines)
  const prescriptionRows = buildPrescriptionRows(
    consultationData?.prescriptionStatus || [],
    protocols,
    medicines
  )
  const titrationRows = buildTitrationRows(
    consultationData?.activeTitrations || [],
    protocols,
    medicines
  )
  const adherenceTrend = buildAdherenceTrend(dailyAdherence, logs, protocols, periodDays)

  const adherence30d = consultationData?.adherenceSummary?.last30d || {
    score: 0,
    taken: 0,
    expected: 0,
    punctuality: 0,
  }
  const adherence90d = consultationData?.adherenceSummary?.last90d || {
    score: 0,
    taken: 0,
    expected: 0,
    punctuality: 0,
  }
  const selectedPeriodLabel = getTrendLabel(periodDays)
  const selectedPeriodSummary =
    periodDays === 30
      ? adherence30d
      : periodDays === 90
        ? adherence90d
        : summarizeTrend(
            adherenceTrend,
            consultationData?.adherenceSummary?.currentStreak ?? adherence30d.currentStreak ?? 0
          )

  const criticalStockCount = stockRows.filter((item) => item.severity === 'critical').length
  const warningStockCount = stockRows.filter((item) => item.severity === 'warning').length
  const expiringPrescriptionCount = prescriptionRows.filter(
    (item) => item.status === 'vencendo'
  ).length
  const expiredPrescriptionCount = prescriptionRows.filter(
    (item) => item.status === 'vencida'
  ).length
  const activeTitrationCount = titrationRows.length

  const summaryCards = [
    {
      label: `Adesao ${selectedPeriodLabel}`,
      value: `${selectedPeriodSummary.score ?? 0}%`,
      meta: `${selectedPeriodSummary.taken ?? 0}/${selectedPeriodSummary.expected ?? 0} doses`,
      tone:
        (selectedPeriodSummary.score ?? 0) >= 80
          ? 'success'
          : (selectedPeriodSummary.score ?? 0) >= 50
            ? 'warning'
            : 'danger',
    },
    {
      label: 'Adesao 30d',
      value: `${adherence30d.score ?? 0}%`,
      meta: `${adherence30d.taken ?? 0}/${adherence30d.expected ?? 0} doses`,
      tone:
        (adherence30d.score ?? 0) >= 80
          ? 'success'
          : (adherence30d.score ?? 0) >= 50
            ? 'warning'
            : 'danger',
    },
    {
      label: 'Adesao 90d',
      value: `${adherence90d.score ?? 0}%`,
      meta: `${adherence90d.taken ?? 0}/${adherence90d.expected ?? 0} doses`,
      tone:
        (adherence90d.score ?? 0) >= 80
          ? 'success'
          : (adherence90d.score ?? 0) >= 50
            ? 'warning'
            : 'danger',
    },
    {
      label: 'Pontualidade',
      value: `${selectedPeriodSummary.punctuality ?? 0}%`,
      meta: `Janela de tolerancia | ${selectedPeriodLabel}`,
      tone:
        (selectedPeriodSummary.punctuality ?? 0) >= 80
          ? 'success'
          : (selectedPeriodSummary.punctuality ?? 0) >= 50
            ? 'warning'
            : 'danger',
    },
    {
      label: 'Tratamentos ativos',
      value: String(activeTreatments.length),
      meta: `${activeMedicines.length} medicamentos`,
      tone: 'info',
    },
    {
      label: 'Alertas criticos',
      value: String(criticalStockCount + expiredPrescriptionCount),
      meta: `${warningStockCount + expiringPrescriptionCount} em atencao`,
      tone: criticalStockCount + expiredPrescriptionCount > 0 ? 'danger' : 'success',
    },
    {
      label: 'Titulações',
      value: String(activeTitrationCount),
      meta: `${titrationRows.filter((item) => item.isTransitionDue).length} pendentes`,
      tone: activeTitrationCount > 0 ? 'warning' : 'success',
    },
  ]

  const attentionItems = [
    ...stockRows
      .filter((item) => item.severity !== 'stable')
      .slice(0, 4)
      .map((item) => ({
        label: item.label,
        detail:
          item.severity === 'critical'
            ? 'Estoque esgotado'
            : `Estoque baixo: ${item.daysRemaining ?? '-'} dias`,
        tone: item.severity,
      })),
    ...prescriptionRows
      .filter((item) => item.status !== 'vigente')
      .slice(0, 4)
      .map((item) => ({
        label: item.label,
        detail:
          item.status === 'vencida'
            ? 'Prescricao vencida'
            : `${item.daysRemaining ?? '-'} dias para vencer`,
        tone: item.status === 'vencida' ? 'danger' : 'warning',
      })),
    ...titrationRows.slice(0, 3).map((item) => ({
      label: item.label,
      detail: item.isTransitionDue
        ? 'Transicao pendente'
        : `Etapa ${item.currentStep}/${item.totalSteps}`,
      tone: item.isTransitionDue ? 'warning' : 'info',
    })),
  ]

  return {
    title,
    period,
    generatedAt,
    generatedAtLabel: new Date(generatedAt).toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    }),
    patient: {
      name: formatPatientDisplayName(patientInfo.name, patientEmail),
      age: patientInfo.age ?? null,
      handle: extractEmailHandle(patientEmail) || null,
      emergencyCard: patientInfo.emergencyCard || null,
    },
    summaryCards,
    activeTreatments,
    adherence: {
      selectedPeriod: {
        ...selectedPeriodSummary,
        label: selectedPeriodLabel,
      },
      last30d: adherence30d,
      last90d: adherence90d,
      trend: adherenceTrend,
      trendLabel: selectedPeriodLabel,
      currentStreak:
        consultationData?.adherenceSummary?.currentStreak ?? adherence30d.currentStreak ?? 0,
    },
    stockRows,
    prescriptionRows,
    titrationRows,
    attentionItems,
    clinicalNotes: [
      patientInfo.emergencyCard?.allergies?.length
        ? `Alergias registradas: ${patientInfo.emergencyCard.allergies.join(', ')}`
        : 'Sem alergias registradas no cartao de emergencia',
      patientInfo.emergencyCard?.blood_type
        ? `Tipo sanguineo: ${patientInfo.emergencyCard.blood_type}`
        : 'Tipo sanguineo nao informado',
    ],
  }
}

export default {
  buildConsultationPdfData,
  formatTreatmentLabel,
  formatMedicinePresentation,
  formatIntakeDose,
  formatFrequency,
  formatDailyDose,
}

/**
 * @fileoverview Serviço de geração de relatórios PDF.
 * Gera relatórios completos em formato A4 com gráficos e tabelas.
 * @module features/reports/services/pdfGeneratorService
 */

import { parseLocalDate, formatLocalDate } from '@utils/dateUtils.js'

/**
 * Dimensões da página A4 em milímetros.
 * @constant {Object}
 */
const PAGE_DIMENSIONS = {
  width: 210,
  height: 297,
  margin: 10,
  contentWidth: 190, // 210 - 2*10
}

/**
 * Posições Y para elementos do PDF.
 * @constant {Object}
 */
const Y_POSITIONS = {
  headerStart: 20,
  headerTitle: 25,
  headerDate: 35,
  summaryStart: 45,
  chartStart: 80,
  chartHeight: 76, // Proporção 500x200 convertida para 190mm largura
  tableStart: 165,
  stockStart: 250,
  footer: 285,
}

/**
 * Cores do tema para o PDF.
 * @constant {Object}
 */
const PDF_COLORS = {
  primary: [16, 185, 129], // Verde
  warning: [245, 158, 11], // Âmbar
  danger: [239, 68, 68], // Vermelho
  text: [51, 51, 51], // Cinza escuro
  lightGray: [200, 200, 200],
  white: [255, 255, 255],
}

/**
 * Formata uma data para exibição no cabeçalho do relatório.
 * @param {Date} date - Data a ser formatada.
 * @returns {string} Data formatada em português.
 * @private
 */
function formatReportDate(date) {
  const options = {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  }
  return date.toLocaleDateString('pt-BR', options)
}

/**
 * Formata horários de doses para exibição.
 * @param {Array<string>} timeSchedule - Array de horários.
 * @returns {string} Horários formatados.
 * @private
 */
function formatTimeSchedule(timeSchedule) {
  if (!timeSchedule || timeSchedule.length === 0) return '1x/dia'
  return `${timeSchedule.length}x/dia`
}

/**
 * Traduz o status do protocolo para português.
 * @param {boolean} active - Se o protocolo está ativo.
 * @returns {string} Status traduzido.
 * @private
 */
function translateStatus(active) {
  return active ? 'Ativo' : 'Inativo'
}

/**
 * Calcula dias restantes de estoque para um medicamento.
 * @param {Object} stockSummary - Resumo do estoque.
 * @param {Object} protocol - Protocolo associado.
 * @returns {number} Dias restantes estimados.
 * @private
 */
function calculateDaysRemaining(stockSummary, protocol) {
  if (!stockSummary || stockSummary.total_quantity <= 0) return 0

  const dosesPerDay = protocol?.time_schedule?.length || 1
  return Math.floor(stockSummary.total_quantity / dosesPerDay)
}

/**
 * Log estruturado para o serviço de PDF (R-087).
 * @param {string} level - Nível do log (info, warn, error).
 * @param {string} message - Mensagem do log.
 * @param {Object} data - Dados adicionais.
 * @private
 */
function logPDF(level, message, data = {}) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    service: 'pdfGeneratorService',
    level,
    message,
    ...data,
  }
  console.log(JSON.stringify(logEntry))
}

/**
 * Desenha o cabeçalho do relatório.
 * @param {Object} doc - Instância do jsPDF.
 * @param {string} title - Título do relatório.
 * @param {Date} reportDate - Data do relatório.
 * @private
 */
function drawHeader(doc, title, reportDate) {
  // Título principal
  doc.setFontSize(20)
  doc.setTextColor(...PDF_COLORS.text)
  doc.text(title, PAGE_DIMENSIONS.width / 2, Y_POSITIONS.headerTitle, {
    align: 'center',
  })

  // Data do relatório
  doc.setFontSize(10)
  doc.setTextColor(...PDF_COLORS.lightGray)
  doc.text(formatReportDate(reportDate), PAGE_DIMENSIONS.width / 2, Y_POSITIONS.headerDate, {
    align: 'center',
  })

  // Linha separadora
  doc.setDrawColor(...PDF_COLORS.primary)
  doc.setLineWidth(0.5)
  doc.line(
    PAGE_DIMENSIONS.margin,
    Y_POSITIONS.headerDate + 5,
    PAGE_DIMENSIONS.width - PAGE_DIMENSIONS.margin,
    Y_POSITIONS.headerDate + 5
  )
}

/**
 * Desenha o resumo de adesão.
 * @param {Object} doc - Instância do jsPDF.
 * @param {Object} adherenceSummary - Dados de adesão.
 * @private
 */
function drawAdherenceSummary(doc, adherenceSummary) {
  const startY = Y_POSITIONS.summaryStart

  // Título da seção
  doc.setFontSize(14)
  doc.setTextColor(...PDF_COLORS.text)
  doc.text('Resumo de Adesão', PAGE_DIMENSIONS.margin, startY)

  // Estatísticas em caixas
  const stats = [
    {
      label: 'Score Geral',
      value: `${adherenceSummary.overallScore || 0}%`,
      color:
        adherenceSummary.overallScore >= 80
          ? PDF_COLORS.primary
          : adherenceSummary.overallScore >= 50
            ? PDF_COLORS.warning
            : PDF_COLORS.danger,
    },
    {
      label: 'Doses Tomadas',
      value: String(adherenceSummary.overallTaken || 0),
      color: PDF_COLORS.text,
    },
    {
      label: 'Doses Esperadas',
      value: String(adherenceSummary.overallExpected || 0),
      color: PDF_COLORS.text,
    },
    {
      label: 'Sequência Atual',
      value: `${adherenceSummary.currentStreak || 0} dias`,
      color: PDF_COLORS.primary,
    },
  ]

  const boxWidth = 45
  const boxHeight = 20
  const boxGap = 5
  const startX = PAGE_DIMENSIONS.margin

  stats.forEach((stat, index) => {
    const x = startX + index * (boxWidth + boxGap)

    // Caixa
    doc.setDrawColor(...PDF_COLORS.lightGray)
    doc.setLineWidth(0.2)
    doc.roundedRect(x, startY + 8, boxWidth, boxHeight, 2, 2, 'S')

    // Valor
    doc.setFontSize(14)
    doc.setTextColor(...stat.color)
    doc.text(stat.value, x + boxWidth / 2, startY + 18, { align: 'center' })

    // Label
    doc.setFontSize(8)
    doc.setTextColor(...PDF_COLORS.lightGray)
    doc.text(stat.label, x + boxWidth / 2, startY + 25, { align: 'center' })
  })
}

/**
 * Desenha o gráfico de adesão.
 * @param {Object} doc - Instância do jsPDF.
 * @param {string} chartImage - Imagem do gráfico em base64.
 * @param {number} startY - Posição Y inicial.
 * @returns {number} Posição Y após o gráfico.
 * @private
 */
function drawAdherenceChart(doc, chartImage, startY) {
  if (!chartImage) {
    // Mensagem de dados não disponíveis
    doc.setFontSize(10)
    doc.setTextColor(...PDF_COLORS.lightGray)
    doc.text(
      'Dados de adesão não disponíveis para o período',
      PAGE_DIMENSIONS.width / 2,
      startY + Y_POSITIONS.chartHeight / 2,
      { align: 'center' }
    )
    return startY + Y_POSITIONS.chartHeight + 10
  }

  // Título do gráfico
  doc.setFontSize(12)
  doc.setTextColor(...PDF_COLORS.text)
  doc.text('Tendência de Adesão (30 dias)', PAGE_DIMENSIONS.margin, startY)

  // Adiciona imagem do gráfico
  doc.addImage(
    chartImage,
    'PNG',
    PAGE_DIMENSIONS.margin,
    startY + 5,
    PAGE_DIMENSIONS.contentWidth,
    Y_POSITIONS.chartHeight
  )

  return startY + Y_POSITIONS.chartHeight + 15
}

/**
 * Desenha a tabela de protocolos.
 * @param {Object} doc - Instância do jsPDF.
 * @param {Array} protocols - Lista de protocolos.
 * @param {Function} autoTable - Função autoTable do jspdf-autotable.
 * @param {number} startY - Posição Y inicial.
 * @returns {number} Posição Y final após a tabela.
 * @private
 */
function drawProtocolsTable(doc, protocols, autoTable, startY) {
  if (!protocols || protocols.length === 0) {
    doc.setFontSize(10)
    doc.setTextColor(...PDF_COLORS.lightGray)
    doc.text('Nenhum protocolo cadastrado', PAGE_DIMENSIONS.margin, startY + 10)
    return startY + 20
  }

  // Prepara dados da tabela
  const tableData = protocols.map((protocol) => [
    protocol.medicine?.name || protocol.name || 'Medicamento',
    `${protocol.dosage || ''} ${protocol.dosage_unit || 'comprimido(s)'}`,
    formatTimeSchedule(protocol.time_schedule),
    translateStatus(protocol.active),
  ])

  // Usa autoTable para criar tabela formatada
  autoTable(doc, {
    startY: startY,
    head: [['Medicamento', 'Dosagem', 'Frequência', 'Status']],
    body: tableData,
    theme: 'striped',
    headStyles: {
      fillColor: PDF_COLORS.primary,
      textColor: PDF_COLORS.white,
      fontSize: 10,
      fontStyle: 'bold',
    },
    bodyStyles: {
      fontSize: 9,
      textColor: PDF_COLORS.text,
    },
    alternateRowStyles: {
      fillColor: [245, 245, 245],
    },
    margin: {
      left: PAGE_DIMENSIONS.margin,
      right: PAGE_DIMENSIONS.margin,
    },
    columnStyles: {
      0: { cellWidth: 60 },
      1: { cellWidth: 40 },
      2: { cellWidth: 40 },
      3: { cellWidth: 30 },
    },
  })

  // Retorna a posição Y final da tabela
  return doc.lastAutoTable.finalY + 10
}

/**
 * Desenha o resumo de estoque com gráfico.
 * @param {Object} doc - Instância do jsPDF.
 * @param {Array} stockData - Dados de estoque.
 * @param {string} stockChartImage - Imagem do gráfico de estoque.
 * @param {number} startY - Posição Y inicial.
 * @private
 */
function drawStockSummary(doc, stockData, stockChartImage, startY) {
  // Verifica se precisa de nova página
  if (startY > 240) {
    doc.addPage()
    startY = 20
  }

  // Título da seção
  doc.setFontSize(12)
  doc.setTextColor(...PDF_COLORS.text)
  doc.text('Resumo de Estoque', PAGE_DIMENSIONS.margin, startY)

  if (!stockData || stockData.length === 0) {
    doc.setFontSize(10)
    doc.setTextColor(...PDF_COLORS.lightGray)
    doc.text('Nenhum dado de estoque disponível', PAGE_DIMENSIONS.margin, startY + 10)
    return
  }

  // Alertas de estoque baixo
  const lowStock = stockData.filter((item) => item.daysRemaining < 7)
  if (lowStock.length > 0) {
    doc.setFontSize(9)
    doc.setTextColor(...PDF_COLORS.danger)
    doc.text(
      `Atenção: ${lowStock.length} medicamento(s) com estoque baixo`,
      PAGE_DIMENSIONS.margin,
      startY + 8
    )
  }

  // Gráfico de estoque
  if (stockChartImage) {
    doc.addImage(
      stockChartImage,
      'PNG',
      PAGE_DIMENSIONS.margin,
      startY + 12,
      PAGE_DIMENSIONS.contentWidth,
      50
    )
  }
}

/**
 * Cores RGB para nivel de risco (sem CSS vars — jsPDF usa RGB).
 * @constant {Object}
 */
const RISK_RGB_COLORS = {
  stable: [34, 197, 94], // #22c55e verde
  attention: [245, 158, 11], // #f59e0b amarelo
  critical: [239, 68, 68], // #ef4444 vermelho
}

/**
 * Desenha a tabela de risco por protocolo.
 * Só renderiza se houver protocolos com dados suficientes (hasEnoughData === true).
 * @param {Object} doc - Instância do jsPDF.
 * @param {Array} risks - Array retornado por calculateAllProtocolRisks.
 * @param {Array} protocols - Lista de protocolos (para buscar nome do medicamento).
 * @param {Function} autoTable - Função autoTable do jspdf-autotable.
 * @param {number} startY - Posição Y inicial.
 * @returns {number} Posição Y após a tabela.
 * @private
 */
function drawRiskTable(doc, risks, protocols, autoTable, startY) {
  const risksWithData = risks.filter((r) => r.hasEnoughData)
  if (risksWithData.length === 0) return startY

  // Verifica se precisa de nova página
  if (startY > 220) {
    doc.addPage()
    startY = 20
  }

  // Título da seção
  doc.setFontSize(12)
  doc.setTextColor(...PDF_COLORS.text)
  doc.text('Risco por Protocolo', PAGE_DIMENSIONS.margin, startY)

  const tableData = risksWithData.map((risk) => {
    const protocol = protocols.find((p) => p.id === risk.protocolId)
    const name = protocol?.medicine?.name || protocol?.name || 'Protocolo'
    const adherence = `${risk.adherence14d}%`
    const trend = risk.trend7d > 0 ? `+${risk.trend7d}%` : `${risk.trend7d}%`
    return [name, adherence, trend, risk.riskLabel]
  })

  autoTable(doc, {
    startY: startY + 5,
    head: [['Protocolo', 'Adesão 14d', 'Tendência', 'Classificação']],
    body: tableData,
    theme: 'striped',
    headStyles: {
      fillColor: PDF_COLORS.primary,
      textColor: PDF_COLORS.white,
      fontSize: 10,
      fontStyle: 'bold',
    },
    bodyStyles: {
      fontSize: 9,
      textColor: PDF_COLORS.text,
    },
    alternateRowStyles: {
      fillColor: [245, 245, 245],
    },
    margin: {
      left: PAGE_DIMENSIONS.margin,
      right: PAGE_DIMENSIONS.margin,
    },
    columnStyles: {
      0: { cellWidth: 70 },
      1: { cellWidth: 35 },
      2: { cellWidth: 35 },
      3: { cellWidth: 40 },
    },
    // Colorir células da coluna "Classificação" conforme nível de risco
    didParseCell(data) {
      if (data.section === 'body' && data.column.index === 3) {
        const risk = risksWithData[data.row.index]
        if (risk) {
          data.cell.styles.textColor = RISK_RGB_COLORS[risk.riskLevel] || PDF_COLORS.text
          data.cell.styles.fontStyle = 'bold'
        }
      }
    },
  })

  return doc.lastAutoTable.finalY + 10
}

/**
 * Desenha o rodapé do relatório.
 * @param {Object} doc - Instância do jsPDF.
 * @private
 */
function drawFooter(doc) {
  // Linha separadora
  doc.setDrawColor(...PDF_COLORS.lightGray)
  doc.setLineWidth(0.2)
  doc.line(
    PAGE_DIMENSIONS.margin,
    Y_POSITIONS.footer - 5,
    PAGE_DIMENSIONS.width - PAGE_DIMENSIONS.margin,
    Y_POSITIONS.footer - 5
  )

  // Disclaimer
  doc.setFontSize(8)
  doc.setTextColor(...PDF_COLORS.lightGray)
  doc.text(
    'Este relatório é apenas informativo e não substitui orientação médica. Consulte seu médico para decisões sobre tratamento.',
    PAGE_DIMENSIONS.width / 2,
    Y_POSITIONS.footer,
    { align: 'center', maxWidth: PAGE_DIMENSIONS.contentWidth }
  )
}

/**
 * Prepara dados de adesão para o gráfico.
 * @param {Array} dailyAdherence - Dados diários de adesão.
 * @returns {Object} Dados formatados para renderAdherenceChart.
 * @private
 */
function prepareAdherenceChartData(dailyAdherence) {
  if (!dailyAdherence || dailyAdherence.length === 0) {
    return null
  }

  return {
    labels: dailyAdherence.map((day) => {
      // Formata data para DD/MM
      const date = parseLocalDate(day.date)
      return date.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' })
    }),
    values: dailyAdherence.map((day) => day.adherence || 0),
    expected: dailyAdherence.map((day) => day.expected || 0),
    taken: dailyAdherence.map((day) => day.taken || 0),
  }
}

/**
 * Prepara dados de estoque para o gráfico.
 * @param {Array} protocols - Lista de protocolos.
 * @param {Array} stockSummaries - Resumos de estoque.
 * @returns {Array} Dados formatados para renderStockChart.
 * @private
 */
function prepareStockChartData(protocols, stockSummaries) {
  if (!protocols || protocols.length === 0) {
    return []
  }

  return protocols
    .filter((protocol) => protocol.active && protocol.medicine)
    .map((protocol) => {
      const stock = stockSummaries.find((s) => s.medicine_id === protocol.medicine_id)
      return {
        name: protocol.medicine?.name || protocol.name,
        daysRemaining: stock ? calculateDaysRemaining(stock, protocol) : 0,
      }
    })
    .filter((item) => item.daysRemaining > 0)
    .sort((a, b) => a.daysRemaining - b.daysRemaining)
    .slice(0, 10) // Limita a 10 medicamentos
}

/**
 * Gera um relatório PDF completo.
 *
 * @param {Object} options - Opções de geração do relatório.
 * @param {string} [options.title='Dosiq - Relatório'] - Título do relatório.
 * @param {string} [options.period='30d'] - Período do relatório ('7d', '30d', '90d').
 * @param {boolean} [options.includeCharts=true] - Se deve incluir gráficos.
 * @param {boolean} [options.includeProtocols=true] - Se deve incluir tabela de protocolos.
 * @param {boolean} [options.includeStock=true] - Se deve incluir resumo de estoque.
 * @param {boolean} [options.includeRiskTable=true] - Se deve incluir tabela de risco por protocolo.
 * @returns {Promise<Blob>} Blob do PDF gerado.
 *
 * @example
 * // Geração básica
 * const pdfBlob = await generatePDF()
 *
 * // Com opções personalizadas
 * const pdfBlob = await generatePDF({
 *   title: 'Relatório Mensal',
 *   period: '30d',
 *   includeCharts: true
 * })
 *
 * // Download do PDF
 * const url = URL.createObjectURL(pdfBlob)
 * const a = document.createElement('a')
 * a.href = url
 * a.download = 'relatorio-medicamentos.pdf'
 * a.click()
 * URL.revokeObjectURL(url)
 */
export async function generatePDF(options = {}) {
  const startTime = Date.now()
  const {
    title = 'Dosiq - Relatório',
    period = '30d',
    includeCharts = true,
    includeProtocols = true,
    includeStock = true,
    includeRiskTable = true,
  } = options

  logPDF('info', 'Iniciando geração do PDF', { title, period, options })

  try {
    // Lazy load TODOS os módulos pesados (jsPDF, services, chartRenderer)
    // Isso evita que o main bundle inclua vendor-pdf (589KB), feature-stock (139KB), etc.
    const [
      { jsPDF },
      { default: autoTable },
      { renderAdherenceChart, renderStockChart },
      { adherenceService },
      { protocolService },
      stockModule,
      riskModule,
      logModule,
    ] = await Promise.all([
      import('jspdf'),
      import('jspdf-autotable'),
      import('./chartRenderer.js'),
      import('@services/api/adherenceService.js'),
      import('@features/protocols/services/protocolService.js'),
      includeStock ? import('@features/stock/services/stockService.js') : Promise.resolve(null),
      includeRiskTable
        ? import('@adherence/services/protocolRiskService.js')
        : Promise.resolve(null),
      includeRiskTable ? import('@shared/services/api/logService.js') : Promise.resolve(null),
    ])

    const stockService = stockModule?.stockService
    const calculateAllProtocolRisks = riskModule?.calculateAllProtocolRisks
    const logService = logModule?.logService

    logPDF('info', 'Módulos carregados sob demanda', { library: 'jspdf + services + charts' })

    // Busca dados em paralelo
    const dataFetchStart = Date.now()
    const today = new Date()
    const thirtyDaysAgo = new Date(today)
    thirtyDaysAgo.setDate(today.getDate() - 30)
    const startDateStr = formatLocalDate(thirtyDaysAgo)
    const endDateStr = formatLocalDate(today)

    const [adherenceSummary, dailyAdherence, protocols, lowStock, recentLogs] = await Promise.all([
      adherenceService.getAdherenceSummary(period),
      adherenceService.getDailyAdherence(30),
      includeProtocols ? protocolService.getAll() : Promise.resolve([]),
      includeStock && stockService ? stockService.getLowStockMedicines(100) : Promise.resolve([]),
      includeRiskTable && logService
        ? logService.getByDateRange(startDateStr, endDateStr, 500).then((r) => r.data ?? [])
        : Promise.resolve([]),
    ])

    logPDF('info', 'Dados buscados', {
      duration: `${Date.now() - dataFetchStart}ms`,
      adherenceScore: adherenceSummary.overallScore,
      protocolsCount: protocols.length,
      lowStockCount: lowStock.length,
    })

    // Busca resumos de estoque para cada medicamento
    let stockSummaries = []
    if (includeStock && stockService && protocols.length > 0) {
      const medicineIds = [...new Set(protocols.map((p) => p.medicine_id).filter(Boolean))]
      stockSummaries = await Promise.all(medicineIds.map((id) => stockService.getStockSummary(id)))
    }

    // Cria documento PDF
    const doc = new jsPDF({
      orientation: 'portrait',
      unit: 'mm',
      format: 'a4',
    })

    // Desenha cabeçalho
    drawHeader(doc, title, new Date())

    // Desenha resumo de adesão
    drawAdherenceSummary(doc, adherenceSummary)

    // Prepara e desenha gráfico de adesão
    let currentY = Y_POSITIONS.chartStart
    if (includeCharts) {
      const chartData = prepareAdherenceChartData(dailyAdherence)
      const chartImage = chartData ? renderAdherenceChart(chartData, 500, 200) : null
      currentY = drawAdherenceChart(doc, chartImage, currentY)
    }

    // Desenha tabela de protocolos
    if (includeProtocols) {
      currentY = drawProtocolsTable(doc, protocols, autoTable, currentY)
    }

    // Desenha tabela de risco por protocolo
    if (includeRiskTable && calculateAllProtocolRisks && protocols.length > 0) {
      const risks = calculateAllProtocolRisks({ protocols, logs: recentLogs })
      currentY = drawRiskTable(doc, risks, protocols, autoTable, currentY)
      logPDF('info', 'Tabela de risco adicionada', {
        protocolsWithData: risks.filter((r) => r.hasEnoughData).length,
        totalProtocols: risks.length,
      })
    }

    // Desenha resumo de estoque
    if (includeStock) {
      const stockChartData = prepareStockChartData(protocols, stockSummaries)
      const stockChartImage =
        stockChartData.length > 0 ? renderStockChart(stockChartData, 500, 150) : null
      drawStockSummary(doc, stockChartData, stockChartImage, currentY)
    }

    // Desenha rodapé
    drawFooter(doc)

    // Gera Blob
    const pdfBlob = doc.output('blob')

    const totalDuration = Date.now() - startTime
    logPDF('info', 'PDF gerado com sucesso', {
      duration: `${totalDuration}ms`,
      blobSize: `${(pdfBlob.size / 1024).toFixed(2)}KB`,
      blobSizeMB: `${(pdfBlob.size / 1024 / 1024).toFixed(2)}MB`,
    })

    // Verifica tamanho do arquivo (<2MB)
    if (pdfBlob.size > 2 * 1024 * 1024) {
      logPDF('warn', 'PDF excede 2MB', {
        size: `${(pdfBlob.size / 1024 / 1024).toFixed(2)}MB`,
      })
    }

    return pdfBlob
  } catch (error) {
    logPDF('error', 'Erro ao gerar PDF', {
      error: error.message,
      stack: error.stack,
    })
    throw new Error(`Falha ao gerar relatório PDF: ${error.message}`)
  }
}

/**
 * Exporta todas as funções do módulo.
 */
export default {
  generatePDF,
}

/**
 * Service para compartilhamento de relatórios
 *
 * Fornece funções para upload de PDFs para compartilhamento temporário
 * e integração com Web Share API e Clipboard API.
 *
 * @module src/features/reports/services/shareService
 * @version 1.0.0
 */

import { supabase } from '@shared/utils/supabase'

// ============================================================================
// CONFIGURAÇÃO
// ============================================================================

const API_ENDPOINT = '/api/share'

/**
 * Níveis de log disponíveis
 * @readonly
 */
const LOG_LEVELS = {
  DEBUG: 'debug',
  INFO: 'info',
  WARN: 'warn',
  ERROR: 'error',
}

// ============================================================================
// LOGGER ESTRUTURADO (R-087)
// ============================================================================

/**
 * Log estruturado com timestamp e contexto
 * @param {string} level - Nível do log (debug, info, warn, error)
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais para o log
 */
function log(level, message, data = {}) {
  const timestamp = new Date().toISOString()
  const logEntry = {
    timestamp,
    service: 'shareService',
    level,
    message,
    ...data,
  }

  const formattedMessage = `[shareService] ${message}`

  if (level === LOG_LEVELS.ERROR) {
    console.error(formattedMessage, logEntry)
  } else if (level === LOG_LEVELS.WARN) {
    console.warn(formattedMessage, logEntry)
  } else {
    console.log(formattedMessage, logEntry)
  }
}

/**
 * Log de informação
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
function logInfo(message, data = {}) {
  log(LOG_LEVELS.INFO, message, data)
}

/**
 * Log de erro
 * @param {string} message - Mensagem descritiva
 * @param {Error|Object} error - Erro ocorrido
 * @param {Object} additionalData - Dados adicionais de contexto
 */
function logError(message, error, additionalData = {}) {
  const errorDetails =
    error instanceof Error
      ? { name: error.name, message: error.message, stack: error.stack }
      : { error: String(error) }

  log(LOG_LEVELS.ERROR, message, { ...errorDetails, ...additionalData })
}

/**
 * Log de warning
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
function logWarn(message, data = {}) {
  log(LOG_LEVELS.WARN, message, data)
}

// ============================================================================
// FUNÇÕES PÚBLICAS
// ============================================================================

/**
 * Obtém o token de acesso JWT do Supabase
 * @returns {Promise<string|null>} Token JWT ou null se não autenticado
 */
async function getAuthToken() {
  try {
    const {
      data: { session },
    } = await supabase.auth.getSession()
    return session?.access_token || null
  } catch (error) {
    logError('Erro ao obter token de autenticação', error)
    return null
  }
}

/**
 * Faz upload de um relatório PDF para compartilhamento temporário
 *
 * @param {Blob} blob - Arquivo PDF em formato Blob
 * @param {Object} options - Opções de compartilhamento
 * @param {string} options.filename - Nome do arquivo (deve terminar com .pdf)
 * @param {number} [options.expiresInHours=72] - Tempo de expiração em horas (1-168)
 * @returns {Promise<Object>} Resultado com { url, expiresAt }
 * @throws {Error} Se o upload falhar ou usuário não estiver autenticado
 *
 * @example
 * const pdfBlob = await generatePDF()
 * const { url, expiresAt } = await shareReport(pdfBlob, {
 *   filename: 'relatorio-medicamentos.pdf',
 *   expiresInHours: 48
 * })
 */
export async function shareReport(blob, options) {
  const { filename, expiresInHours = 72 } = options

  logInfo('Iniciando compartilhamento de relatório', { filename, size: blob.size, expiresInHours })

  // Validar parâmetros
  if (!blob || !(blob instanceof Blob)) {
    throw new Error('Arquivo inválido. Envie um Blob válido.')
  }

  if (!filename || !filename.endsWith('.pdf')) {
    throw new Error('Nome do arquivo deve terminar com .pdf')
  }

  if (expiresInHours < 1 || expiresInHours > 168) {
    throw new Error('Tempo de expiração deve estar entre 1 e 168 horas')
  }

  // Verificar tamanho máximo (5MB)
  const maxSize = 5 * 1024 * 1024
  if (blob.size > maxSize) {
    throw new Error('Arquivo muito grande. Máximo de 5MB.')
  }

  // Obter token de autenticação
  const token = await getAuthToken()
  if (!token) {
    throw new Error('Usuário não autenticado. Faça login para compartilhar.')
  }

  // Converter Blob para base64
  let base64Data
  try {
    base64Data = await blobToBase64(blob)
    logInfo('Blob convertido para base64', { size: base64Data.length })
  } catch (error) {
    logError('Erro ao converter blob para base64', error)
    throw new Error('Erro ao processar arquivo')
  }

  // Fazer requisição para API
  try {
    const response = await fetch(API_ENDPOINT, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({
        blob: base64Data,
        filename,
        expiresInHours,
      }),
    })

    const result = await response.json()

    if (!response.ok || !result.success) {
      const errorMessage = result.error || 'Erro ao compartilhar relatório'
      logWarn('Falha no compartilhamento', { status: response.status, error: errorMessage })
      throw new Error(errorMessage)
    }

    logInfo('Relatório compartilhado com sucesso', { url: result.data?.url?.split('?')[0] })

    return {
      url: result.data.url,
      expiresAt: result.data.expiresAt,
    }
  } catch (error) {
    if (error.message === 'Failed to fetch') {
      logError('Erro de conexão com servidor', error)
      throw new Error('Erro de conexão. Verifique sua internet.')
    }
    throw error
  }
}

/**
 * Compartilha uma URL usando Web Share API nativa
 * Fallback para clipboard se não suportado
 *
 * @param {string} url - URL a ser compartilhada
 * @param {string} [title='Relatório'] - Título do compartilhamento
 * @returns {Promise<boolean>} true se compartilhado com sucesso
 *
 * @example
 * const success = await shareNative(url, 'Meu Relatório de Medicamentos')
 * if (!success) {
 *   // Usuário cancelou ou não suportado
 * }
 */
export async function shareNative(url, title = 'Relatório') {
  logInfo('Tentando compartilhamento nativo', { url: url.split('?')[0], title })

  if (!url) {
    throw new Error('URL é obrigatória')
  }

  // Verificar se Web Share API é suportada
  if (navigator.share) {
    try {
      await navigator.share({
        title,
        text: `Confira meu ${title.toLowerCase()}`,
        url,
      })
      logInfo('Compartilhamento nativo bem-sucedido')
      return true
    } catch (error) {
      // Usuário cancelou ou erro
      if (error.name === 'AbortError') {
        logInfo('Usuário cancelou compartilhamento')
        return false
      }
      logWarn('Erro no compartilhamento nativo', { error: error.message })
      // Continuar para fallback
    }
  }

  // Fallback para clipboard
  logInfo('Usando fallback para clipboard')
  try {
    await copyToClipboard(url)
    return true
  } catch (error) {
    logError('Fallback de clipboard falhou', error)
    throw new Error('Não foi possível compartilhar. Copie a URL manualmente.')
  }
}

/**
 * Copia uma URL para o clipboard
 * Usa Clipboard API moderna com fallback para método legacy
 *
 * @param {string} url - URL a ser copiada
 * @returns {Promise<void>}
 * @throws {Error} Se não conseguir copiar
 *
 * @example
 * await copyToClipboard('https://example.com/relatorio.pdf')
 * // Mostrar toast: "Link copiado para a área de transferência!"
 */
export async function copyToClipboard(url) {
  logInfo('Copiando para clipboard', { url: url.split('?')[0] })

  if (!url) {
    throw new Error('URL é obrigatória')
  }

  // Tentar Clipboard API moderna
  if (navigator.clipboard && window.isSecureContext) {
    try {
      await navigator.clipboard.writeText(url)
      logInfo('URL copiada com Clipboard API')
      return
    } catch (error) {
      logWarn('Clipboard API falhou, tentando fallback', { error: error.message })
    }
  }

  // Fallback para método legacy
  const textArea = document.createElement('textarea')
  textArea.value = url
  textArea.style.position = 'fixed'
  textArea.style.left = '-999999px'
  textArea.style.top = '-999999px'
  document.body.appendChild(textArea)

  try {
    textArea.focus()
    textArea.select()

    const successful = document.execCommand('copy')
    document.body.removeChild(textArea)

    if (successful) {
      logInfo('URL copiada com método legacy')
    } else {
      throw new Error('execCommand retornou false')
    }
  } catch (error) {
    document.body.removeChild(textArea)
    logError('Fallback de clipboard falhou', error)
    throw new Error('Não foi possível copiar o link. Copie manualmente.')
  }
}

