import { describe, it, expect, vi, beforeEach, afterEach, beforeAll, afterAll } from 'vitest'
import { renderHook, act, waitFor } from '@testing-library/react'
import {
  useCachedQueries,
  clearCache,
  cancelGarbageCollection,
  restartGarbageCollection,
} from '@shared/hooks/useCachedQuery'

// Disable interval-based GC during tests to save memory
beforeAll(() => {
  cancelGarbageCollection()
})

afterAll(() => {
  restartGarbageCollection()
})

describe('useCachedQueries', () => {
  beforeEach(() => {
    clearCache()
    vi.clearAllMocks()
    vi.clearAllTimers()
  })

  afterEach(() => {
    clearCache()
    vi.clearAllMocks()
    vi.resetAllMocks()
    vi.clearAllTimers()
    if (global.gc) global.gc()
  })

  it('should fetch multiple queries in parallel', async () => {
    const fetcher1 = vi.fn().mockResolvedValue({ data: 'first' })
    const fetcher2 = vi.fn().mockResolvedValue({ data: 'second' })
    const fetcher3 = vi.fn().mockResolvedValue({ data: 'third' })

    const { result } = renderHook(() =>
      useCachedQueries([
        { key: 'key1', fetcher: fetcher1 },
        { key: 'key2', fetcher: fetcher2 },
        { key: 'key3', fetcher: fetcher3 },
      ])
    )

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })

    expect(result.current.results[0].data).toEqual({ data: 'first' })
    expect(result.current.results[1].data).toEqual({ data: 'second' })
    expect(result.current.results[2].data).toEqual({ data: 'third' })
    expect(fetcher1).toHaveBeenCalledTimes(1)
    expect(fetcher2).toHaveBeenCalledTimes(1)
    expect(fetcher3).toHaveBeenCalledTimes(1)
  })

  it('should handle errors in multiple queries', async () => {
    const fetcher1 = vi.fn().mockResolvedValue({ data: 'first' })
    const fetcher2 = vi.fn().mockRejectedValue(new Error('Error 2'))
    const fetcher3 = vi.fn().mockResolvedValue({ data: 'third' })

    const { result } = renderHook(() =>
      useCachedQueries([
        { key: 'key1', fetcher: fetcher1 },
        { key: 'key2', fetcher: fetcher2 },
        { key: 'key3', fetcher: fetcher3 },
      ])
    )

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })

    expect(result.current.results[0].data).toEqual({ data: 'first' })
    expect(result.current.results[1].error).toBeInstanceOf(Error)
    expect(result.current.results[2].data).toEqual({ data: 'third' })
    expect(result.current.hasError).toBe(true)
    expect(result.current.errors).toHaveLength(1)
  })

  it('should skip disabled queries', async () => {
    const fetcher1 = vi.fn().mockResolvedValue({ data: 'first' })
    const fetcher2 = vi.fn().mockResolvedValue({ data: 'second' })

    const { result } = renderHook(() =>
      useCachedQueries([
        { key: 'key1', fetcher: fetcher1 },
        { key: 'key2', fetcher: fetcher2, options: { enabled: false } },
      ])
    )

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })

    expect(result.current.results[0].data).toEqual({ data: 'first' })
    expect(result.current.results[1].data).toBe(undefined)
    expect(fetcher1).toHaveBeenCalledTimes(1)
    expect(fetcher2).not.toHaveBeenCalled()
  })

  it('should refetch all queries', async () => {
    const fetcher1 = vi
      .fn()
      .mockResolvedValueOnce({ data: 'first-1' })
      .mockResolvedValueOnce({ data: 'first-2' })
    const fetcher2 = vi
      .fn()
      .mockResolvedValueOnce({ data: 'second-1' })
      .mockResolvedValueOnce({ data: 'second-2' })

    const { result } = renderHook(() =>
      useCachedQueries([
        { key: 'key1', fetcher: fetcher1 },
        { key: 'key2', fetcher: fetcher2 },
      ])
    )

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })

    await act(async () => {
      await result.current.refetchAll()
    })

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })

    expect(result.current.results[0].data).toEqual({ data: 'first-2' })
    expect(result.current.results[1].data).toEqual({ data: 'second-2' })
    expect(fetcher1).toHaveBeenCalledTimes(2)
    expect(fetcher2).toHaveBeenCalledTimes(2)
  })
})

import { describe, it, expect, vi, beforeEach, afterEach, beforeAll, afterAll } from 'vitest'
import { renderHook, act, waitFor } from '@testing-library/react'
import {
  useCachedQuery,
  invalidateCache,
  clearCache,
  cancelGarbageCollection,
  restartGarbageCollection,
} from '@shared/hooks/useCachedQuery'

// Disable interval-based GC during tests to save memory
beforeAll(() => {
  cancelGarbageCollection()
})

afterAll(() => {
  restartGarbageCollection()
})

describe('useCachedQuery', () => {
  beforeEach(() => {
    clearCache()
    vi.clearAllMocks()
    vi.clearAllTimers()
  })

  afterEach(() => {
    clearCache()
    vi.clearAllMocks()
    vi.resetAllMocks()
    vi.clearAllTimers()
    if (global.gc) global.gc()
  })

  describe('basic functionality', () => {
    it('should fetch data successfully', async () => {
      const fetcher = vi.fn().mockResolvedValue({ data: 'test' })
      const { result } = renderHook(() => useCachedQuery('test-key', fetcher))

      await waitFor(() => {
        expect(result.current.isLoading).toBe(false)
      })

      expect(result.current.data).toEqual({ data: 'test' })
      expect(result.current.error).toBe(null)
      expect(fetcher).toHaveBeenCalledTimes(1)
    })

    it('should handle fetch errors', async () => {
      const error = new Error('Fetch failed')
      const fetcher = vi.fn().mockRejectedValue(error)
      const { result } = renderHook(() => useCachedQuery('error-key', fetcher))

      await waitFor(() => {
        expect(result.current.isLoading).toBe(false)
      })

      expect(result.current.error).toBe(error)
      expect(result.current.data).toBe(undefined)
    })

    it('should not fetch when key is null', async () => {
      const fetcher = vi.fn().mockResolvedValue({ data: 'test' })
      const { result } = renderHook(() => useCachedQuery(null, fetcher))

      await waitFor(() => {
        expect(result.current.isLoading).toBe(false)
      })

      expect(fetcher).not.toHaveBeenCalled()
      expect(result.current.data).toBe(undefined)
    })

    it('should not fetch when enabled is false', async () => {
      const fetcher = vi.fn().mockResolvedValue({ data: 'test' })
      const { result } = renderHook(() => useCachedQuery('test-key', fetcher, { enabled: false }))

      await waitFor(() => {
        expect(result.current.isLoading).toBe(false)
      })

      expect(fetcher).not.toHaveBeenCalled()
      expect(result.current.data).toBe(undefined)
    })
  })

  describe('refetch functionality', () => {
    it('should refetch data with force option', async () => {
      const fetcher = vi
        .fn()
        .mockResolvedValueOnce({ data: 'first' })
        .mockResolvedValueOnce({ data: 'second' })

      const { result } = renderHook(() => useCachedQuery('test-key', fetcher))

      await waitFor(() => {
        expect(result.current.data).toEqual({ data: 'first' })
      })

      await act(async () => {
        await result.current.refetch()
      })

      await waitFor(() => {
        expect(result.current.data).toEqual({ data: 'second' })
      })

      expect(fetcher).toHaveBeenCalledTimes(2)
    })

    it('should refresh data in background', async () => {
      const fetcher = vi
        .fn()
        .mockResolvedValueOnce({ data: 'first' })
        .mockResolvedValueOnce({ data: 'second' })

      const { result } = renderHook(() => useCachedQuery('test-key', fetcher))

      await waitFor(() => {
        expect(result.current.data).toEqual({ data: 'first' })
      })

      // Invalidate cache before refresh to ensure new data
      invalidateCache('test-key')

      // Refresh should not set isLoading to true
      await act(async () => {
        await result.current.refresh()
      })

      await waitFor(() => {
        expect(result.current.data).toEqual({ data: 'second' })
      })

      expect(fetcher).toHaveBeenCalledTimes(2)
    })
  })

  describe('initial data', () => {
    it('should use initial data', async () => {
      const fetcher = vi.fn().mockResolvedValue({ data: 'fetched' })
      const { result } = renderHook(() =>
        useCachedQuery('test-key', fetcher, { initialData: { data: 'initial' } })
      )

      // Initial data should be available immediately
      expect(result.current.data).toEqual({ data: 'initial' })

      await waitFor(() => {
        expect(result.current.data).toEqual({ data: 'fetched' })
      })
    })
  })

  describe('callbacks', () => {
    it('should call onSuccess callback', async () => {
      const onSuccess = vi.fn()
      const fetcher = vi.fn().mockResolvedValue({ data: 'test' })

      renderHook(() => useCachedQuery('test-key', fetcher, { onSuccess }))

      await waitFor(() => {
        expect(onSuccess).toHaveBeenCalledWith({ data: 'test' })
      })
    })

    it('should call onError callback', async () => {
      const onError = vi.fn()
      const error = new Error('Fetch failed')
      const fetcher = vi.fn().mockRejectedValue(error)

      renderHook(() => useCachedQuery('error-key', fetcher, { onError }))

      await waitFor(() => {
        expect(onError).toHaveBeenCalledWith(error)
      })
    })
  })

  describe('stale time', () => {
    it('should respect stale time option', async () => {
      const fetcher = vi.fn().mockResolvedValue({ data: 'test' })
      const { result, rerender } = renderHook(() =>
        useCachedQuery('test-key', fetcher, { staleTime: 5000 })
      )

      await waitFor(() => {
        expect(result.current.data).toEqual({ data: 'test' })
      })

      expect(fetcher).toHaveBeenCalledTimes(1)

      // Rerender should not refetch within stale time
      rerender()
      await waitFor(() => {
        expect(result.current.data).toEqual({ data: 'test' })
      })

      expect(fetcher).toHaveBeenCalledTimes(1)
    })
  })

  describe('cleanup', () => {
    it('should not update state after unmount', async () => {
      const fetcher = vi
        .fn()
        .mockImplementation(
          () => new Promise((resolve) => setTimeout(() => resolve({ data: 'test' }), 100))
        )

      const { result, unmount } = renderHook(() => useCachedQuery('test-key', fetcher))

      // Unmount immediately to prevent state updates
      unmount()

      // Wait longer than the fetcher to ensure it completes
      // Using a small delay to prevent hanging (safer than real timers in CI)
      await new Promise((resolve) => setTimeout(resolve, 5))

      // Should not throw error after unmount
      expect(result.current.data).toBe(undefined)
    })
  })

  describe('edge cases', () => {
    it('should handle null fetcher', async () => {
      const { result } = renderHook(() => useCachedQuery('test-key', null))

      await waitFor(() => {
        expect(result.current.isLoading).toBe(false)
      })

      expect(result.current.data).toBe(undefined)
    })
  })
})

/**
 * useCachedQuery - Hook React para uso do cache SWR
 *
 * Fornece uma interface React-friendly para o queryCache com:
 * - Estados de loading/error/data
 * - Revalidação automática
 * - Refetch manual
 * - Integração com ciclo de vida do componente
 *
 * @module useCachedQuery
 */

import { useState, useEffect, useCallback, useRef } from 'react'
import { webQueryCache } from '@shared/platform/query-cache/webQueryCache'

// Aliases locais para a engine — mantem chamadas internas compactas
const cachedQuery = (key, fetcher, opts) => webQueryCache.cachedQuery(key, fetcher, opts)
const invalidateCache = (pattern) => webQueryCache.invalidate(pattern)

/**
 * Hook para executar queries com cache SWR
 *
 * @param {string} key - Chave única da query (ou null para desabilitar)
 * @param {Function} fetcher - Função que retorna Promise com os dados
 * @param {Object} options - Opções do hook
 * @param {boolean} options.enabled - Se a query está habilitada (padrão: true)
 * @param {number} options.staleTime - Tempo de stale em ms
 * @param {*} options.initialData - Dados iniciais para SSR/hidratação
 * @param {Function} options.onSuccess - Callback quando dados são carregados
 * @param {Function} options.onError - Callback quando ocorre erro
 * @returns {Object} Estado e controles da query
 */
export function useCachedQuery(key, fetcher, options = {}) {
  const { enabled = true, staleTime, initialData, onSuccess, onError } = options

  const [data, setData] = useState(initialData)
  const [isLoading, setIsLoading] = useState(false)
  const [isFetching, setIsFetching] = useState(false)
  const [error, setError] = useState(null)

  // Refs para controle de cancelamento e duplicação
  const isMounted = useRef(true)
  const fetchCount = useRef(0)

  // Função principal de fetch
  const executeQuery = useCallback(
    async (options = {}) => {
      const { force = false, background = false } = options

      if (!key || !enabled || !fetcher) return

      const currentFetch = ++fetchCount.current

      try {
        if (!background) {
          setIsLoading(true)
        }
        setIsFetching(true)
        setError(null)

        // Se force=true, invalida o cache primeiro
        if (force) {
          invalidateCache(key)
        }

        const result = await cachedQuery(key, fetcher, { staleTime })

        // Só atualiza se for a fetch mais recente e componente montado
        if (isMounted.current && currentFetch === fetchCount.current) {
          setData(result)
          setIsLoading(false)
          setIsFetching(false)
          onSuccess?.(result)
        }

        return result
      } catch (err) {
        if (isMounted.current && currentFetch === fetchCount.current) {
          setError(err)
          setIsLoading(false)
          setIsFetching(false)
          onError?.(err)
        }
        throw err
      }
    },
    [key, fetcher, enabled, staleTime, onSuccess, onError]
  )

  // Fetch inicial
  useEffect(() => {
    isMounted.current = true

    if (enabled && key) {
      // Catch rejection to prevent unhandled promise warning
      // (error is already handled in executeQuery catch block and set in state)
      // eslint-disable-next-line react-hooks/set-state-in-effect
      executeQuery().catch(() => {})
    }

    return () => {
      isMounted.current = false
    }
  }, [key, enabled, executeQuery])

  // Refetch manual
  const refetch = useCallback(async () => {
    return executeQuery({ force: true })
  }, [executeQuery])

  // Refetch em background (silencioso)
  const refresh = useCallback(async () => {
    return executeQuery({ background: true })
  }, [executeQuery])

  return {
    data,
    isLoading,
    isFetching,
    error,
    refetch,
    refresh,
  }
}

/**
 * Utilitário para executar múltiplas queries em paralelo
 * Extraído para evitar duplicação entre fetchAll e refetchAll
 */
async function executeParallelQueries(queries) {
  const promises = queries.map(async (query, index) => {
    const { key, fetcher, options = {} } = query
    const { enabled = true, staleTime } = options

    if (!enabled || !key || !fetcher) {
      return { index, data: undefined, error: null }
    }

    try {
      const data = await cachedQuery(key, fetcher, { staleTime })
      return { index, data, error: null }
    } catch (error) {
      return { index, data: undefined, error }
    }
  })

  return Promise.all(promises)
}

/**
 * Hook para múltiplas queries em paralelo com cache SWR
 *
 * @param {Array} queries - Array de { key, fetcher, options }
 * @returns {Object} Estado combinado das queries
 */
export function useCachedQueries(queries) {
  const [results, setResults] = useState(() =>
    queries.map(() => ({
      data: undefined,
      isLoading: false,
      isFetching: false,
      error: null,
    }))
  )

  // Chave estável derivada das query keys (não muda com rerenders desnecessários)
  const queriesKey = queries.map((q) => q.key ?? 'null').join('|')

  // Ref para acessar queries atualizadas dentro do effect sem re-disparar o effect
  // (evita render loop causado por [queries] como dependência)
  const queriesRef = useRef(queries)

  const isMounted = useRef(true)

  // Note: Using [queriesKey] instead of [queries] to prevent infinite render loops.
  // We manually update queriesRef.current inside effect to access fresh query values.
  // This is intentional — queriesKey is a stable string derived from query keys.
  useEffect(() => {
    isMounted.current = true
    queriesRef.current = queries // Update ref inside effect (safe)

    const fetchAll = async () => {
      setResults((prev) => prev.map((r) => ({ ...r, isLoading: true })))

      const settled = await executeParallelQueries(queriesRef.current)

      if (isMounted.current) {
        setResults((prev) => {
          const next = [...prev]
          settled.forEach(({ index, data, error }) => {
            next[index] = {
              data,
              error,
              isLoading: false,
              isFetching: false,
            }
          })
          return next
        })
      }
    }

    fetchAll()

    return () => {
      isMounted.current = false
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [queriesKey]) // Estável: só muda quando as query keys mudam

  // Estados combinados
  const isLoading = results.some((r) => r.isLoading)
  const isFetching = results.some((r) => r.isFetching)
  const hasError = results.some((r) => r.error)
  const errors = results.map((r) => r.error).filter(Boolean)

  // Refetch todas as queries com invalidação
  const refetchAll = useCallback(async () => {
    queriesRef.current.forEach((query) => {
      const { key } = query
      if (key) invalidateCache(key)
    })

    setResults((prev) => prev.map((r) => ({ ...r, isLoading: true })))

    const settled = await executeParallelQueries(queriesRef.current)

    if (isMounted.current) {
      setResults((prev) => {
        const next = [...prev]
        settled.forEach(({ index, data, error }) => {
          next[index] = {
            data,
            error,
            isLoading: false,
            isFetching: false,
          }
        })
        return next
      })
    }
  }, []) // Sem dependências: sempre usa queriesRef.current (stale-safe)

  return {
    results,
    isLoading,
    isFetching,
    hasError,
    errors,
    refetchAll,
  }
}

/**
 * Hook para mutações que invalidam cache após sucesso
 *
 * @param {Function} mutationFn - Função de mutação
 * @param {Object} options - Opções
 * @param {string|Array} options.invalidateKeys - Chaves a invalidar após sucesso
 * @param {Function} options.onSuccess - Callback de sucesso
 * @param {Function} options.onError - Callback de erro
 * @returns {Object} Estado e função de mutação
 */
export function useCachedMutation(mutationFn, options = {}) {
  const { invalidateKeys = [], onSuccess, onError } = options

  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState(null)
  const [data, setData] = useState(null)

  const mutate = useCallback(
    async (variables) => {
      setIsLoading(true)
      setError(null)

      try {
        const result = await mutationFn(variables)
        setData(result)

        // Invalida as chaves especificadas
        const keysToInvalidate = Array.isArray(invalidateKeys) ? invalidateKeys : [invalidateKeys]

        keysToInvalidate.forEach((key) => {
          if (key) {
            invalidateCache(key)
            console.log(`[useCachedMutation] Cache invalidado: ${key}`)
          }
        })

        onSuccess?.(result)
        return result
      } catch (err) {
        setError(err)
        onError?.(err)
        throw err
      } finally {
        setIsLoading(false)
      }
    },
    [mutationFn, invalidateKeys, onSuccess, onError]
  )

  const reset = useCallback(() => {
    setData(null)
    setError(null)
    setIsLoading(false)
  }, [])

  return {
    mutate,
    reset,
    data,
    isLoading,
    error,
    isError: !!error,
  }
}

// Re-exporta funções úteis do query cache (via pacote centralizado — evita duplicação)
export { generateCacheKey } from '@dosiq/shared-data'

export { invalidateCache }

export function prefetchCache(key, data) {
  webQueryCache.prefetch(key, data)
}

export function getCacheStats() {
  return webQueryCache.getStats()
}

export function clearCache() {
  webQueryCache.clear()
}

export function cancelGarbageCollection() {
  webQueryCache.cancelGC()
}

export function restartGarbageCollection() {
  webQueryCache.restartGC()
}

/**
 * useHapticFeedback.js - Hook para feedback tátil (vibração)
 *
 * Funcionalidades:
 * - Vibration API para Android Chrome
 * - Fallback silencioso em iOS/desktop
 * - Tipos de haptic: success, warning, error, selection, impact
 * - Suporte a prefers-reduced-motion
 */

import { useCallback } from 'react'

/**
 * Tipos de feedback háptico pré-definidos
 */
const HAPTIC_PATTERNS = {
  // Feedback positivo (sucesso)
  success: {
    duration: 50,
    pattern: null,
  },
  // Feedback de atenção (aviso)
  warning: {
    duration: 100,
    pattern: null,
  },
  // Feedback negativo (erro)
  error: {
    duration: 200,
    pattern: null,
  },
  // Feedback de seleção
  selection: {
    duration: 10,
    pattern: null,
  },
  // Feedback de impacto leve
  impact: {
    duration: 20,
    pattern: null,
  },
  // Confete/celebração
  celebration: {
    duration: 15,
    pattern: [15, 10, 15, 10, 15, 10, 50],
  },
  // Pulso (para registro de dose)
  pulse: {
    duration: 30,
    pattern: null,
  },
  // Shake (erro de validação)
  shake: {
    duration: 500,
    pattern: [50, 30, 50, 30, 50],
  },
}

/**
 * Hook useHapticFeedback
 *
 * @returns {Object} { trigger, isSupported, vibrate }
 *
 * @example
 * const { trigger, vibrate } = useHapticFeedback()
 *
 * // Usar tipo pré-definido
 * trigger('success')
 *
 * // Vibração customizada
 * vibrate(100)
 */
export function useHapticFeedback() {
  // Verificar se Vibration API é suportada
  const isSupported =
    typeof navigator !== 'undefined' &&
    typeof navigator.vibrate === 'function' &&
    !navigator.userAgent.match(/iPhone|iPad|iPod/i)

  // Verificar prefers-reduced-motion
  const prefersReducedMotion =
    typeof window !== 'undefined' && window.matchMedia('(prefers-reduced-motion: reduce)').matches

  /**
   * Função principal de haptic feedback
   * @param {string} type - Tipo de haptic ('success', 'warning', 'error', 'selection', 'impact', 'celebration', 'pulse', 'shake')
   * @param {Object} options - Opções adicionais
   */
  const trigger = useCallback(
    (type, options = {}) => {
      // Se reduced-motion está ativo, não vibrate
      if (prefersReducedMotion) {
        return
      }

      // Se API não é suportada, retorna silenciosamente
      if (!isSupported) {
        return
      }

      const pattern = HAPTIC_PATTERNS[type] || HAPTIC_PATTERNS.selection

      // Se há pattern customizado via options, usa ele
      const patternToUse = options.pattern || pattern.pattern
      const duration = options.duration || pattern.duration

      try {
        if (patternToUse) {
          // Usar pattern de vibração
          navigator.vibrate(patternToUse)
        } else {
          // Usar duração simples
          navigator.vibrate(duration)
        }
      } catch (err) {
        // Silenciosamente ignora erros de vibration API
        console.debug('Haptic feedback error:', err)
      }
    },
    [isSupported, prefersReducedMotion]
  )

  /**
   * Função de vibração direta
   * @param {number|number[]} duration - Duração em ms ou array de pattern
   */
  const vibrate = useCallback(
    (duration) => {
      if (prefersReducedMotion || !isSupported) {
        return
      }

      try {
        navigator.vibrate(duration)
      } catch (err) {
        console.debug('Haptic vibration error:', err)
      }
    },
    [isSupported, prefersReducedMotion]
  )

  return {
    trigger,
    vibrate,
    isSupported,
  }
}

// Exportar padrões para uso externo se necessário
export { HAPTIC_PATTERNS }

export default useHapticFeedback

/**
 * useNotificationLog — Hook React para histórico de notificações (Web/PWA)
 *
 * Utiliza SWR via useCachedQuery para gerenciamento de cache e revalidação.
 *
 * @module useNotificationLog
 */

import { useMemo, useCallback } from 'react'
import { useCachedQuery, generateCacheKey } from '@shared/hooks/useCachedQuery'
import { createNotificationLogRepository, CACHE_KEYS } from '@dosiq/shared-data'
import { supabase } from '@shared/utils/supabase'

// Repositório singleton para a plataforma web
const repo = createNotificationLogRepository({ supabase })

/**
 * Enriquece logs agrupados com lista de medicamentos via join relacional.
 * Evita duplicar dados no notification_log — busca do estado atual dos protocolos.
 */
async function enrichWithDoses(logs) {
  const byPlanLogs      = logs.filter(l => l.notification_type === 'dose_reminder_by_plan' && l.treatment_plan_id)
  const miscLogs        = logs.filter(l => l.notification_type === 'dose_reminder_misc')
  const planIds         = [...new Set(byPlanLogs.map(l => l.treatment_plan_id))]
  const miscProtocolIds = [...new Set(miscLogs.flatMap(l => l.provider_metadata?.protocol_ids ?? []))]

  const [planProtoMap, miscProtoMap] = await Promise.all([
    planIds.length > 0
      ? supabase
          .from('protocols')
          .select('id, dosage_per_intake, treatment_plan_id, time_schedule, medicine:medicine_id(name)')
          .in('treatment_plan_id', planIds)
          .eq('active', true)
          .then(({ data }) => {
            const map = {}
            for (const p of data ?? []) {
              if (!map[p.treatment_plan_id]) map[p.treatment_plan_id] = []
              map[p.treatment_plan_id].push(p)
            }
            return map
          })
      : Promise.resolve({}),

    miscProtocolIds.length > 0
      ? supabase
          .from('protocols')
          .select('id, dosage_per_intake, medicine:medicine_id(name)')
          .in('id', miscProtocolIds)
          .then(({ data }) => Object.fromEntries((data ?? []).map(p => [p.id, p])))
      : Promise.resolve({}),
  ])

  return logs.map(log => {
    if (log.notification_type === 'dose_reminder_by_plan' && log.treatment_plan_id) {
      const d    = new Date(log.sent_at)
      const hhmm = `${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`
      const doses = (planProtoMap[log.treatment_plan_id] ?? [])
        .filter(p => (p.time_schedule ?? []).includes(hhmm))
        .map(p => ({ medicineName: p.medicine?.name ?? 'Medicamento', dosage: p.dosage_per_intake ?? 1 }))
      return { ...log, doses }
    }
    if (log.notification_type === 'dose_reminder_misc') {
      const doses = (log.provider_metadata?.protocol_ids ?? [])
        .map(pid => miscProtoMap[pid])
        .filter(Boolean)
        .map(p => ({ medicineName: p.medicine?.name ?? 'Medicamento', dosage: p.dosage_per_intake ?? 1 }))
      return { ...log, doses }
    }
    return log
  })
}

/**
 * Hook para buscar logs de notificações com cache SWR.
 *
 * @param {Object} options
 * @param {string} options.userId - ID do usuário (UUID)
 * @param {number} [options.limit=20] - Itens por página
 * @param {number} [options.offset=0] - Offset de paginação
 * @param {boolean} [options.enabled=true] - Se a query deve rodar
 * @returns {Object} { data, isLoading, isFetching, error, refetch, refresh }
 */
export function useNotificationLog(options = {}) {
  const { userId, limit = 20, offset = 0, enabled = true } = options

  // Chave de cache canônica e estável
  const cacheKey = useMemo(() => {
    if (!userId) return null
    return generateCacheKey(CACHE_KEYS.NOTIFICATIONS_PAGINATED, { userId, limit, offset })
  }, [userId, limit, offset])

  // Fetcher que utiliza o repositório compartilhado
  // High Priority: Memorizado para evitar loops de re-renderização
  const fetcher = useCallback(async () => {
    if (!userId) return []
    const raw = await repo.listByUserId(userId, { limit, offset })
    return enrichWithDoses(raw)
  }, [userId, limit, offset])

  return useCachedQuery(cacheKey, fetcher, {
    enabled: enabled && !!userId,
    staleTime: 60 * 1000, // 1 minuto (Notificações têm volatilidade média)
  })
}

/**
 * useUnreadNotificationCount — Conta notificações não lidas via localStorage (Web).
 *
 * Estratégia: compara sent_at dos logs com a última vez que o usuário abriu a inbox.
 * Zero roundtrip extra — tudo local.
 */
import { useMemo, useCallback } from 'react'

const STORAGE_KEY = 'dosiq:notif-last-seen'

/**
 * @param {Array|null} notifications - Lista retornada por useNotificationLog
 * @returns {{ unreadCount: number, markAllRead: () => void, lastSeen: string|null }}
 */
export function useUnreadNotificationCount(notifications) {
  const lastSeen = useMemo(() => {
    try {
      return localStorage.getItem(STORAGE_KEY)
    } catch (err) {
      if (process.env.NODE_ENV === 'development') {
        console.error('Failed to get notification last seen time from localStorage:', err)
      }
      return null
    }
  }, [])

  const unreadCount = useMemo(() => {
    if (!notifications?.length) return 0
    if (!lastSeen) return notifications.length
    const lastSeenTime = new Date(lastSeen).getTime()
    return notifications.filter(n => {
      if (!n.sent_at) return false
      return new Date(n.sent_at).getTime() > lastSeenTime
    }).length
  }, [notifications, lastSeen])

  const markAllRead = useCallback(() => {
    try {
      localStorage.setItem(STORAGE_KEY, new Date().toISOString())
    } catch (err) {
      if (process.env.NODE_ENV === 'development') {
        console.error('Failed to set notification last seen time in localStorage:', err)
      }
    }
  }, [])

  return { unreadCount, markAllRead, lastSeen }
}

/**
 * webQueryCache — Instancia do query cache para a plataforma web
 *
 * Criado via factory do shared-data com:
 * - webStorageAdapter: persistencia via localStorage (via contrato H3.1)
 * - logger: console do browser
 * - configuracoes padrao do projeto
 *
 * IMPORTANTE: init() e chamado aqui para hidratar o cache no bootstrap da web.
 * Em outras plataformas (mobile), o bootstrap chama init() explicitamente.
 *
 * Estrategia de coexistencia (H3.3):
 * - Este modulo cria a nova instancia de cache
 * - useCachedQuery.js importa daqui (nao mais de queryCache.js legado)
 * - queryCache.js legado removido apos validacao bem-sucedida
 */
import { createQueryCache } from '@dosiq/shared-data'
import { webStorageAdapter } from '@shared/platform/storage/webStorageAdapter'

const logger = {
  log: (msg) => {
    if (import.meta.env.DEV) console.debug(msg)
  },
  warn: (msg) => console.warn(msg),
  error: (msg) => console.error(msg),
}

export const webQueryCache = createQueryCache({
  storage: webStorageAdapter,
  logger,
  staleTime: 30_000,
  maxEntries: 200,
  persistKey: 'dosiq_query_cache',
})

// Hidratacao automatica no bootstrap web.
// init() e idempotente — chamadas multiplas sao seguras.
webQueryCache.init().catch((err) => {
  console.warn('[webQueryCache] Falha na inicializacao:', err)
})

import { z } from 'zod'
import { supabase, getUserId } from '@shared/utils/supabase'
import { stockService } from '@stock/services/stockService'
import { validateLogCreate, validateLogUpdate, validateLogBulkArray } from '@schemas/logSchema'
import { parseLocalDate } from '@utils/dateUtils'

// Schemas de validação para todos os métodos de leitura
const limitSchema = z.number().int().positive().max(5000).default(50)
const offsetSchema = z.number().int().min(0).default(0)

const paginationSchema = z.object({
  limit: limitSchema,
  offset: offsetSchema,
})

const protocolIdSchema = z.object({
  protocolId: z.string().uuid('protocolId deve ser UUID válido'),
  limit: limitSchema,
})

const dateRangeSchema = z.object({
  startDate: z.string().regex(/^\d{4}-\d{2}-\d{2}$/, 'startDate deve ser YYYY-MM-DD'),
  endDate: z.string().regex(/^\d{4}-\d{2}-\d{2}$/, 'endDate deve ser YYYY-MM-DD'),
  limit: limitSchema,
  offset: offsetSchema,
})

const monthSchema = z.object({
  year: z.number().int().min(2020).max(2100),
  month: z.number().int().min(0).max(11),
})

/**
 * Normaliza timestamps Supabase para formato Zod-compatível
 * Converte '+00:00' para 'Z' para passar validação z.string().datetime()
 */
function normalizeTimestamps(logs) {
  if (!logs) return logs
  if (!Array.isArray(logs)) return logs

  return logs.map((log) => ({
    ...log,
    taken_at: log.taken_at ? log.taken_at.replace(/\+00:00$/, 'Z') : log.taken_at,
  }))
}

/**
 * Log Service - Medicine intake logging
 *
 * VALIDAÇÃO ZOD:
 * - Todos os dados de entrada são validados antes de enviar ao Supabase
 * - Erros de validação retornam mensagens em português
 * - Nenhum payload inválido é enviado ao backend
 * - Timestamps Supabase são normalizados de '+00:00' para 'Z' (R-120)
 */
export const logService = {
  /**
   * Get all logs
   */
  async getAll(limit = 50) {
    const v = limitSchema.safeParse(limit)
    if (!v.success) {
      console.error('[logService.getAll] Validação falhou:', v.error.format())
      return []
    }

    const { data, error } = await supabase
      .from('medicine_logs')
      .select(
        `
        *,
        protocol:protocols(*),
        medicine:medicines(*)
      `
      )
      .eq('user_id', await getUserId())
      .order('taken_at', { ascending: false })
      .limit(limit)

    if (error) throw error
    return normalizeTimestamps(data)
  },

  /**
   * Get logs for a specific protocol
   */
  async getByProtocol(protocolId, limit = 50) {
    const v = protocolIdSchema.safeParse({ protocolId, limit })
    if (!v.success) {
      console.error('[logService.getByProtocol] Validação falhou:', v.error.format())
      return []
    }

    const { data, error } = await supabase
      .from('medicine_logs')
      .select(
        `
        *,
        protocol:protocols(*),
        medicine:medicines(*)
      `
      )
      .eq('protocol_id', protocolId)
      .eq('user_id', await getUserId())
      .order('taken_at', { ascending: false })
      .limit(limit)

    if (error) throw error
    return normalizeTimestamps(data)
  },

  /**
   * Log medicine taken
   * This also decrements the stock automatically
   *
   * VALIDAÇÃO: Dados são validados com Zod antes de enviar ao Supabase
   * @throws {Error} Se os dados forem inválidos
   */
  async create(log) {
    // Validação Zod
    const validation = validateLogCreate(log)
    if (!validation.success) {
      const errorMessages = validation.errors.map((e) => `${e.field}: ${e.message}`).join('; ')
      throw new Error(`Erro de validação: ${errorMessages}`)
    }

    const validatedLog = validation.data

    // First, create the log entry
    const { data, error } = await supabase
      .from('medicine_logs')
      .insert([{ ...validatedLog, user_id: await getUserId() }])
      .select(
        `
        *,
        protocol:protocols(*),
        medicine:medicines(*)
      `
      )
      .single()

    if (error) throw error

    // Then, decrease stock with exact log linkage for reversible FIFO.
    try {
      await stockService.decrease(validatedLog.medicine_id, validatedLog.quantity_taken, data.id)
    } catch (stockError) {
      console.error('Erro ao decrementar estoque:', stockError)
      await supabase
        .from('medicine_logs')
        .delete()
        .eq('id', data.id)
        .eq('user_id', await getUserId())
      throw new Error('Não foi possível consumir o estoque: ' + stockError.message)
    }

    return normalizeTimestamps([data])[0]
  },

  /**
   * Create multiple log entries at once
   *
   * VALIDAÇÃO: Dados são validados com Zod antes de enviar ao Supabase
   * @throws {Error} Se os dados forem inválidos
   */
  async createBulk(logs) {
    // Validação Zod em lote
    const validation = validateLogBulkArray(logs)
    if (!validation.success) {
      const errorMessages = validation.errors
        .map((e) =>
          e.index >= 0 ? `[${e.index + 1}] ${e.field}: ${e.message}` : `${e.field}: ${e.message}`
        )
        .join('; ')
      throw new Error(`Erro de validação em lote: ${errorMessages}`)
    }

    const validatedLogs = validation.data

    const createdLogs = []

    try {
      for (const log of validatedLogs) {
        const created = await this.create(log)
        createdLogs.push(created)
      }
    } catch (error) {
      console.error('Erro ao criar lote de logs:', error)
      throw error
    }

    return createdLogs
  },

  /**
   * Update a log entry and adjust stock
   *
   * VALIDAÇÃO: Dados são validados com Zod antes de enviar ao Supabase
   * @throws {Error} Se os dados forem inválidos
   */
  async update(id, updates) {
    // Validação Zod (parcial, pois é update)
    const validation = validateLogUpdate(updates)
    if (!validation.success) {
      const errorMessages = validation.errors.map((e) => `${e.field}: ${e.message}`).join('; ')
      throw new Error(`Erro de validação: ${errorMessages}`)
    }

    // 1. Get original log to calculate stock delta
    const { data: oldLog, error: fetchError } = await supabase
      .from('medicine_logs')
      .select('*')
      .eq('id', id)
      .single()

    if (fetchError) throw fetchError

    const nextLog = {
      ...oldLog,
      ...validation.data,
    }

    const stockAffectingChange =
      nextLog.quantity_taken !== oldLog.quantity_taken || nextLog.medicine_id !== oldLog.medicine_id

    if (!stockAffectingChange) {
      const { data, error } = await supabase
        .from('medicine_logs')
        .update(validation.data)
        .eq('id', id)
        .eq('user_id', await getUserId())
        .select(
          `
          *,
          protocol:protocols(*),
          medicine:medicines(*)
        `
        )
        .single()

      if (error) throw error
      return normalizeTimestamps([data])[0]
    }

    try {
      await stockService.increase(oldLog.medicine_id, oldLog.quantity_taken, {
        medicine_log_id: id,
        reason: 'dose_update_restore',
      })
    } catch (stockError) {
      console.error('Erro ao restaurar estoque no update:', stockError)
      throw new Error('Não foi possível restaurar o estoque antes da edição: ' + stockError.message)
    }

    const { data, error } = await supabase
      .from('medicine_logs')
      .update(validation.data)
      .eq('id', id)
      .eq('user_id', await getUserId())
      .select(
        `
        *,
        protocol:protocols(*),
        medicine:medicines(*)
      `
      )
      .single()

    if (error) {
      await stockService.decrease(oldLog.medicine_id, oldLog.quantity_taken, id)
      throw error
    }

    try {
      await stockService.decrease(nextLog.medicine_id, nextLog.quantity_taken, id)
    } catch (stockError) {
      console.error('Erro ao reconsumir estoque no update:', stockError)

      await supabase
        .from('medicine_logs')
        .update({
          protocol_id: oldLog.protocol_id,
          medicine_id: oldLog.medicine_id,
          taken_at: oldLog.taken_at,
          quantity_taken: oldLog.quantity_taken,
          notes: oldLog.notes,
        })
        .eq('id', id)
        .eq('user_id', await getUserId())

      await stockService.decrease(oldLog.medicine_id, oldLog.quantity_taken, id)

      throw new Error('Não foi possível reaplicar o consumo do estoque: ' + stockError.message)
    }

    return normalizeTimestamps([data])[0]
  },

  /**
   * Delete a log entry
   * Now restores stock!
   */
  async delete(id) {
    // 1. Get log info before deleting
    const { data: log, error: fetchError } = await supabase
      .from('medicine_logs')
      .select('*')
      .eq('id', id)
      .single()

    if (fetchError) throw fetchError

    try {
      await stockService.increase(log.medicine_id, log.quantity_taken, {
        medicine_log_id: id,
        reason: 'dose_deleted_restore',
      })
    } catch (stockError) {
      console.error('Erro ao restaurar estoque na exclusão:', stockError)
      throw new Error('Não foi possível devolver o remédio ao estoque: ' + stockError.message)
    }

    // 3. Delete log
    const { error } = await supabase
      .from('medicine_logs')
      .delete()
      .eq('id', id)
      .eq('user_id', await getUserId())

    if (error) throw error
  },

  /**
   * Get logs with pagination support
   * @param {number} limit - Items per page
   * @param {number} offset - Starting position
   * @returns {Promise} { data: [], total, hasMore }
   */
  getAllPaginated: async (limit = 50, offset = 0) => {
    const v = paginationSchema.safeParse({ limit, offset })
    if (!v.success) {
      console.error('[logService.getAllPaginated] Validação falhou:', v.error.format())
      return { data: [], total: 0, hasMore: false }
    }

    const { data, error, count } = await supabase
      .from('medicine_logs')
      .select(
        `
        *,
        protocol:protocols(*),
        medicine:medicines(*)
      `,
        { count: 'exact' }
      )
      .eq('user_id', await getUserId())
      .order('taken_at', { ascending: false })
      .range(offset, offset + limit - 1)

    if (error) throw error

    return {
      data: normalizeTimestamps(data) || [],
      total: count || 0,
      hasMore: offset + limit < (count || 0),
    }
  },

  /**
   * Timeline: dados mínimos para renderização (sem relações completas)
   * LogEntry usa: id, taken_at, quantity_taken, notes, medicine.name, protocol.name
   * LogForm (edição) usa: id, protocol_id, taken_at, quantity_taken, notes
   * ~120 bytes/log (vs ~500 bytes com select('*') + full relations)
   * @param {number} limit - Items per page
   * @param {number} offset - Starting position
   * @returns {Promise} { data: [], total, hasMore }
   */
  getAllPaginatedSlim: async (limit = 50, offset = 0) => {
    const v = paginationSchema.safeParse({ limit, offset })
    if (!v.success) {
      console.error('[logService.getAllPaginatedSlim] Validação falhou:', v.error.format())
      return { data: [], total: 0, hasMore: false }
    }

    const { data, error, count } = await supabase
      .from('medicine_logs')
      .select(
        `
        id, taken_at, quantity_taken, notes, medicine_id, protocol_id,
        protocol:protocols(id, name),
        medicine:medicines(id, name)
      `,
        { count: 'exact' }
      )
      .eq('user_id', await getUserId())
      .order('taken_at', { ascending: false })
      .range(offset, offset + limit - 1)

    if (error) throw error

    return {
      data: normalizeTimestamps(data) || [],
      total: count || 0,
      hasMore: offset + limit < (count || 0),
    }
  },

  /**
   * Get logs by date range
   * @param {string} startDate - ISO format YYYY-MM-DD (Brazil local date)
   * @param {string} endDate - ISO format YYYY-MM-DD (Brazil local date)
   * @returns {Promise}
   *
   * NOTE: Usa parseLocalDate() para conversão timezone-safe (R-020, AP-005).
   * parseLocalDate('YYYY-MM-DD') → Date local (meia-noite) → .toISOString() converte para UTC.
   */
  getByDateRange: async (startDate, endDate, limit = 50, offset = 0) => {
    const v = dateRangeSchema.safeParse({ startDate, endDate, limit, offset })
    if (!v.success) {
      console.error('[logService.getByDateRange] Validação falhou:', v.error.format())
      return { data: [], total: 0, hasMore: false }
    }

    // Converte datas locais (YYYY-MM-DD) para UTC via parseLocalDate (R-020, AP-005)
    const startUtc = parseLocalDate(startDate).toISOString()
    const endLocal = parseLocalDate(endDate)
    endLocal.setHours(23, 59, 59, 999)
    const endUtc = endLocal.toISOString()

    const { data, error, count } = await supabase
      .from('medicine_logs')
      .select(
        `
        *,
        protocol:protocols(*),
        medicine:medicines(*)
      `,
        { count: 'exact' }
      )
      .eq('user_id', await getUserId())
      .gte('taken_at', startUtc)
      .lte('taken_at', endUtc)
      .order('taken_at', { ascending: false })
      .range(offset, offset + limit - 1)

    if (error) throw error

    return {
      data: normalizeTimestamps(data) || [],
      total: count || 0,
      hasMore: offset + limit < (count || 0),
    }
  },

  /**
   * Get logs for a specific month
   * @param {number} year - Year (e.g., 2024)
   * @param {number} month - Month (0-11, where 0 is January)
   * @returns {Promise} { data: [], total }
   */
  getByMonth: async (year, month) => {
    const v = monthSchema.safeParse({ year, month })
    if (!v.success) {
      console.error('[logService.getByMonth] Validação falhou:', v.error.format())
      return { data: [], total: 0 }
    }

    // Converte datas locais para UTC via parseLocalDate (R-020)
    const startDateStr = `${year}-${String(month + 1).padStart(2, '0')}-01`
    const lastDay = new Date(Date.UTC(year, month + 1, 0)).getUTCDate()
    const endDateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`

    const startUtc = parseLocalDate(startDateStr).toISOString()
    const endLocal = parseLocalDate(endDateStr)
    endLocal.setHours(23, 59, 59, 999)
    const endUtc = endLocal.toISOString()

    const { data, error, count } = await supabase
      .from('medicine_logs')
      .select(
        `
        *,
        protocol:protocols(*),
        medicine:medicines(*)
      `,
        { count: 'exact' }
      )
      .eq('user_id', await getUserId())
      .gte('taken_at', startUtc)
      .lte('taken_at', endUtc)
      .order('taken_at', { ascending: false })

    if (error) throw error

    return {
      data: normalizeTimestamps(data) || [],
      total: count || 0,
    }
  },

  /**
   * Logs por período com select mínimo (sem relações completas).
   * Consumidores: calculateAdherenceStats, LastDosesWidget, DoseCalendar, useDoseZones
   * Campos: id, taken_at, quantity_taken, protocol_id, medicine_id
   * ~60 bytes/log (vs ~315 bytes com select('*') + full relations)
   * @param {string} startDate - ISO YYYY-MM-DD (data local Brasil)
   * @param {string} endDate - ISO YYYY-MM-DD (data local Brasil)
   * @param {number} limit - Máximo de registros
   * @param {number} offset - Posição inicial
   * @returns {Promise} { data: [], total, hasMore }
   */
  getByDateRangeSlim: async (startDate, endDate, limit = 50, offset = 0) => {
    const validation = dateRangeSchema.safeParse({ startDate, endDate, limit, offset })
    if (!validation.success) {
      console.error('[logService.getByDateRangeSlim] Validação falhou:', validation.error.format())
      return { data: [], total: 0, hasMore: false }
    }

    // Converte datas locais (YYYY-MM-DD) para UTC via parseLocalDate (R-020, AP-005)
    const startUtc = parseLocalDate(startDate).toISOString()
    const endLocal = parseLocalDate(endDate)
    endLocal.setHours(23, 59, 59, 999)
    const endUtc = endLocal.toISOString()

    const { data, error, count } = await supabase
      .from('medicine_logs')
      .select('id, taken_at, quantity_taken, protocol_id, medicine_id', { count: 'exact' })
      .eq('user_id', await getUserId())
      .gte('taken_at', startUtc)
      .lte('taken_at', endUtc)
      .order('taken_at', { ascending: false })
      .range(offset, offset + limit - 1)

    if (error) throw error

    return {
      data: normalizeTimestamps(data) || [],
      total: count || 0,
      hasMore: offset + limit < (count || 0),
    }
  },

  /**
   * Logs do mês com select mínimo para calendário.
   * Campos: id, taken_at, quantity_taken, medicine_id, medicine.name
   * ~80 bytes/log (vs ~315 bytes com select('*') + full relations)
   * @param {number} year - Ano (ex: 2026)
   * @param {number} month - Mês (0-11)
   * @returns {Promise} { data: [], total }
   */
  getByMonthSlim: async (year, month) => {
    const validation = monthSchema.safeParse({ year, month })
    if (!validation.success) {
      console.error('[logService.getByMonthSlim] Validação falhou:', validation.error.format())
      return { data: [], total: 0 }
    }

    const startDateStr = `${year}-${String(month + 1).padStart(2, '0')}-01`
    const lastDay = new Date(Date.UTC(year, month + 1, 0)).getUTCDate()
    const endDateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`

    // Converte datas locais para UTC via parseLocalDate (R-020)
    const startUtc = parseLocalDate(startDateStr).toISOString()
    const endLocal = parseLocalDate(endDateStr)
    endLocal.setHours(23, 59, 59, 999)
    const endUtc = endLocal.toISOString()

    const { data, error, count } = await supabase
      .from('medicine_logs')
      .select(
        `
        id, taken_at, quantity_taken, medicine_id, protocol_id,
        medicine:medicines(id, name, dosage_per_pill, dosage_unit),
        protocol:protocols(id, name)
      `,
        { count: 'exact' }
      )
      .eq('user_id', await getUserId())
      .gte('taken_at', startUtc)
      .lte('taken_at', endUtc)
      .order('taken_at', { ascending: false })

    if (error) throw error

    return {
      data: normalizeTimestamps(data) || [],
      total: count || 0,
    }
  },
}

/**
 * Cached Services - Wrappers com cache SWR para os services da API
 *
 * Este arquivo fornece versões cacheadas dos métodos de leitura dos services,
 * mantendo a API original intacta para compatibilidade.
 *
 * As mutations (create/update/delete) automaticamente invalidam o cache
 * relevante após sucesso.
 *
 * @module cachedServices
 */

import { CACHE_KEYS, generateCacheKey } from '@dosiq/shared-data'
import { invalidateCache } from '@shared/hooks/useCachedQuery'
import { webQueryCache } from '@shared/platform/query-cache/webQueryCache'
const cachedQuery = (key, fetcher, opts) => webQueryCache.cachedQuery(key, fetcher, opts)
import { medicineService } from '@medications/services/medicineService'
import { protocolService } from '@protocols/services/protocolService'
import { stockService } from '@stock/services/stockService'
import { purchaseService } from '@stock/services/purchaseService'
import { logService } from '@shared/services/api/logService'
import { treatmentPlanService } from '@protocols/services/treatmentPlanService'
import { adherenceService } from '@services/api/adherenceService'

// CACHE_KEYS importado de @dosiq/shared-data (fonte canônica)
// Re-exportado para compatibilidade com importadores existentes deste módulo
export { CACHE_KEYS } from '@dosiq/shared-data'

/**
 * Medicine Service com Cache
 */
export const cachedMedicineService = {
  // Métodos de leitura (com cache)
  async getAll() {
    return cachedQuery(CACHE_KEYS.MEDICINES, () => medicineService.getAll())
  },

  async getById(id) {
    const key = generateCacheKey(CACHE_KEYS.MEDICINE_BY_ID, { id })
    return cachedQuery(key, () => medicineService.getById(id))
  },

  // Métodos de escrita (com invalidação de cache)
  async create(medicine) {
    const result = await medicineService.create(medicine)
    // Invalida lista de medicamentos
    invalidateCache(CACHE_KEYS.MEDICINES)
    console.log('[cachedMedicineService] Cache invalidado após create')
    return result
  },

  async update(id, updates) {
    const result = await medicineService.update(id, updates)
    // Invalida lista e item específico
    invalidateCache(CACHE_KEYS.MEDICINES)
    invalidateCache(generateCacheKey(CACHE_KEYS.MEDICINE_BY_ID, { id }))
    // Também invalida estoque relacionado (preço pode ter mudado)
    invalidateCache(`${CACHE_KEYS.STOCK_BY_MEDICINE}:*`)
    invalidateCache(`${CACHE_KEYS.STOCK_SUMMARY}:*`)
    console.log('[cachedMedicineService] Cache invalidado após update')
    return result
  },

  async delete(id) {
    await medicineService.delete(id)
    // Invalida lista e item específico
    invalidateCache(CACHE_KEYS.MEDICINES)
    invalidateCache(generateCacheKey(CACHE_KEYS.MEDICINE_BY_ID, { id }))
    // Invalida estoque relacionado
    invalidateCache(`${CACHE_KEYS.STOCK_BY_MEDICINE}:*`)
    invalidateCache(`${CACHE_KEYS.STOCK_SUMMARY}:*`)
    invalidateCache(`${CACHE_KEYS.STOCK_TOTAL}:*`)
    console.log('[cachedMedicineService] Cache invalidado após delete')
  },
}

