    invalidateCache(`${CACHE_KEYS.STOCK_BY_MEDICINE}*`)
    invalidateCache(`${CACHE_KEYS.STOCK_TOTAL}*`)
    invalidateCache(`${CACHE_KEYS.STOCK_SUMMARY}*`)
    invalidateCache(`${CACHE_KEYS.STOCK_LOW}*`)
