/**
 * Logger com suporte a development mode
 * Reduz poluição de console em produção
 *
 * @module logger
 */

const isDev = typeof window !== 'undefined' && process.env.NODE_ENV === 'development'

/**
 * Log de debug (só em development)
 * @param {string} tag - Prefixo [tag] do log
 * @param {string} message - Mensagem principal
 * @param {...*} args - Dados adicionais (opcionais)
 */
export function debugLog(tag, message, ...args) {
  if (isDev) {
    console.log(`[${tag}] ${message}`, ...args)
  }
}

/**
 * Log de erro/warning (sempre, mas formatado)
 * @param {string} tag - Prefixo [tag]
 * @param {string} message - Mensagem
 * @param {...*} args - Erro opcional e outros dados
 */
export function errorLog(tag, message, ...args) {
  console.error(`[${tag}] ${message}`, ...args)
}

/**
 * Log condicional (quando expressão é true)
 * @param {boolean} condition - Condição
 * @param {string} tag - Prefixo
 * @param {string} message - Mensagem
 * @param {...*} args - Dados
 */
export function conditionalLog(condition, tag, message, ...args) {
  if (condition) {
    debugLog(tag, message, ...args)
  }
}

import { describe, it, expect } from 'vitest'
import { isDoseInToleranceWindow, calculateAdherenceStats } from '../adherenceLogic'

describe('Smoke: Adherence Logic', () => {
  it('detects dose within tolerance window', () => {
    const scheduledTime = '10:00'
    const takenTime = new Date().toISOString()

    const result = isDoseInToleranceWindow(scheduledTime, takenTime)
    expect(typeof result).toBe('boolean')
  })

  it('calculates adherence stats correctly', () => {
    const logs = [
      { taken_at: new Date().toISOString(), protocol_id: 'p1' },
      { taken_at: new Date().toISOString(), protocol_id: 'p1' },
    ]
    const protocols = [{ id: 'p1', time_schedule: ['08:00', '20:00'], frequency: 'diário' }]
    const result = calculateAdherenceStats(logs, protocols, 1)
    expect(typeof result).toBe('object')
    expect(typeof result.score).toBe('number')
    expect(result.score).toBeGreaterThanOrEqual(0)
    expect(result.score).toBeLessThanOrEqual(100)
  })
})

import { describe, it, expect } from 'vitest'
import { calculateDosesByDate } from '../adherenceLogic'

describe('calculateDosesByDate', () => {
  const baseDate = '2026-02-11'

  describe('daily frequency protocols', () => {
    it('should mark all doses as missed when no logs', () => {
      const protocols = [
        {
          id: 'proto-1',
          medicine_id: 'med-1',
          active: true,
          frequency: 'diário',
          time_schedule: ['08:00', '20:00'],
          dosage_per_intake: 1,
          medicine: { name: 'Paracetamol', type: 'comprimido' },
        },
      ]

      const result = calculateDosesByDate(baseDate, [], protocols)

      expect(result.takenDoses).toHaveLength(0)
      expect(result.missedDoses).toHaveLength(2)
      expect(result.missedDoses[0].scheduledTime).toBe('08:00')
      expect(result.missedDoses[1].scheduledTime).toBe('20:00')
    })

    it('should mark dose as taken when log within tolerance window', () => {
      const protocols = [
        {
          id: 'proto-1',
          medicine_id: 'med-1',
          active: true,
          frequency: 'diário',
          time_schedule: ['08:00'],
          dosage_per_intake: 1,
          medicine: { name: 'Paracetamol', type: 'comprimido' },
        },
      ]

      // Use local time string to avoid timezone issues in CI
      // 08:30 local time is within +/- 2h tolerance of 08:00 scheduled
      const baseDateObj = new Date(baseDate + 'T08:30:00')
      const localTimeString = baseDateObj.toISOString()

      const logs = [
        {
          id: 'log-1',
          protocol_id: 'proto-1',
          medicine_id: 'med-1',
          taken_at: localTimeString, // 08:30 local - dentro da janela de 08:00
          quantity_taken: 1,
          medicine: { name: 'Paracetamol', type: 'comprimido' },
          protocol: { name: 'Protocolo Manhã' },
        },
      ]

      const result = calculateDosesByDate(baseDate, logs, protocols)

      expect(result.takenDoses).toHaveLength(1)
      expect(result.missedDoses).toHaveLength(0)
      expect(result.takenDoses[0].scheduledTime).toBe('08:00')
    })

    it('should mark dose as missed when log outside tolerance window', () => {
      const protocols = [
        {
          id: 'proto-1',
          medicine_id: 'med-1',
          active: true,
          frequency: 'diário',
