          medicine_id: 'med-1',
          taken_at: eveningTime,
          quantity_taken: 1,
        },
      ]

      const result = calculateDosesByDate(baseDate, logs, protocols)

      expect(result.takenDoses).toHaveLength(2)
      expect(result.missedDoses).toHaveLength(0)
    })
