      }

      // Mock current date to be 1 day after start
      global.Date = class extends Date {
        constructor(...args) {
          if (args.length === 0) {
            super('2024-01-02')
          } else {
            super(...args)
          }
        }
      }

      const result = calculateTitrationData(protocol)

