    })

    it('should not indicate transition when within stage duration', () => {
      const protocol = {
        titration_schedule: [{ days: 7, dosage: 1 }],
        stage_started_at: baseDate,
      }

      // Mock current date to be within stage (day 5)
      global.Date = class extends Date {
