            super('2024-01-04')
          } else {
            super(...args)
          }
        }
      }

      const result = calculateTitrationData(protocol)

      // 10 - 3 = 7 days remaining
      expect(result.daysRemaining).toBe(7)
    })

    it('should calculate negative days remaining when past end', () => {
      const protocol = {
        titration_schedule: [{ days: 7, dosage: 1 }],
        stage_started_at: baseDate,
      }

      // Mock current date to be past stage end (day 10)
      global.Date = class extends Date {
        constructor(...args) {
          if (args.length === 0) {
            super('2024-01-11')
          } else {
            super(...args)
          }
        }
      }

      const result = calculateTitrationData(protocol)

      expect(result.daysRemaining).toBeLessThan(0)
    })
  })

  describe('stage note', () => {
    it('should return stage note from current stage', () => {
      const protocol = {
        titration_schedule: [{ days: 7, dosage: 1, note: 'Introdução gradual' }],
        stage_started_at: baseDate,
      }

      const result = calculateTitrationData(protocol)

      expect(result.stageNote).toBe('Introdução gradual')
    })

    it('should handle stage without note', () => {
      const protocol = {
        titration_schedule: [{ days: 7, dosage: 1 }],
        stage_started_at: baseDate,
      }

      const result = calculateTitrationData(protocol)

      expect(result.stageNote).toBeUndefined()
    })
  })

  describe('integration scenarios', () => {
    it('should handle multi-stage protocol correctly', () => {
      const protocol = {
        titration_schedule: [
          { days: 7, dosage: 0.5, note: 'Semana 1' },
          { days: 7, dosage: 1, note: 'Semana 2' },
          { days: 14, dosage: 2, note: 'Manutenção' },
        ],
        stage_started_at: baseDate,
        current_stage_index: 2,
      }

      // Mock current date to be 5 days into stage 3 (day 20 total)
      global.Date = class extends Date {
        constructor(...args) {
          if (args.length === 0) {
            super('2024-01-20') // Day 20, stage 3 starts day 15
          } else {
            super(...args)
          }
        }
      }

      const result = calculateTitrationData(protocol)

      expect(result.currentStep).toBe(3)
      expect(result.totalSteps).toBe(3)
      expect(result.totalDays).toBe(14)
      expect(result.stageNote).toBe('Manutenção')
    })
  })
})

export function calculateTitrationData(protocol) {
  if (!protocol.titration_schedule || protocol.titration_schedule.length === 0) return null
  if (!protocol.stage_started_at) return null

  const currentStageIndex = protocol.current_stage_index || 0
  const schedule = protocol.titration_schedule

  // Safety check
  if (currentStageIndex >= schedule.length) return null

  const currentStage = schedule[currentStageIndex]
  const startDate = new Date(protocol.stage_started_at)
  const today = new Date()

  // Calculate days elapsed (difference in time / milliseconds per day)
  const diffTime = Math.abs(today - startDate)
  const daysElapsed = Math.ceil(diffTime / (1000 * 60 * 60 * 24))

  // Clamp day to at least 1
  const currentDay = Math.max(1, daysElapsed)
  const totalDays = currentStage.days

  // Calculate progress percent (capped at 100)
  const progressPercent = Math.min(100, (currentDay / totalDays) * 100)

  const isTransitionDue = currentDay > totalDays // Or >= depending on logic. Let's say > implies finished yesterday.

  return {
    currentStep: currentStageIndex + 1,
    totalSteps: schedule.length,
    day: Math.min(currentDay, totalDays), // visual cap
    realDay: currentDay,
    totalDays: totalDays,
    progressPercent: progressPercent,
    isTransitionDue: isTransitionDue,
    stageNote: currentStage.note,
    daysRemaining: totalDays - currentDay,
  }
}

import { useState } from 'react'
import { X } from 'lucide-react'
import { signIn, signUp } from '@shared/utils/supabase'
import './Auth.css'

export default function Auth({ onAuthSuccess, onClose }) {
  const [isLogin, setIsLogin] = useState(true)
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState(null)
  const [message, setMessage] = useState(null)

  const handleSubmit = async (e) => {
    e.preventDefault()
    setIsLoading(true)
    setError(null)
    setMessage(null)

    try {
      if (isLogin) {
        await signIn(email, password)
        if (onAuthSuccess) onAuthSuccess()
      } else {
        await signUp(email, password)
        setMessage('Conta criada! Verifique seu email para confirmar o cadastro.')
        setIsLogin(true)
      }
    } catch (err) {
      console.error(err)
      let msg = 'Ocorreu um erro.'
      if (err.message.includes('Invalid login credentials')) {
        msg = 'Email ou senha incorretos.'
      } else if (err.message.includes('User already registered')) {
        msg = 'Usuário já cadastrado.'
      } else if (err.message.includes('Password should be at least')) {
        msg = 'A senha deve ter pelo menos 6 caracteres.'
      }
      setError(msg)
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div className="auth-container">
      <div className="auth-card">
        {onClose && (
          <button className="auth-close-btn" onClick={onClose} aria-label="Fechar">
            <X size={20} />
          </button>
        )}
        <div className="auth-header">
          <div className="logo-container">
            <img src="/logo-new.svg" alt="Dosiq" className="auth-logo" />
          </div>
          <h1>{isLogin ? 'Bem-vindo de volta' : 'Crie sua conta'}</h1>
          <p className="auth-subtitle">
            {isLogin ? 'Acesse sua agenda de medicamentos' : 'Comece a gerenciar sua saúde hoje'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="auth-form">
          <div className="form-group">
            <label htmlFor="email">Email</label>
            <input
              id="email"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="seu@email.com"
              required
              className="auth-input"
            />
          </div>

          <div className="form-group">
            <label htmlFor="password">Senha</label>
            <input
              id="password"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              required
              minLength={6}
              className="auth-input"
            />
          </div>

          {error && <div className="auth-error">{error}</div>}
          {message && <div className="auth-message">{message}</div>}

          <button type="submit" className="auth-submit-btn" disabled={isLoading}>
            {isLoading ? 'Carregando...' : isLogin ? 'Entrar' : 'Cadastrar'}
          </button>
        </form>

        <div className="auth-footer">
          <p>
            {isLogin ? 'Não tem uma conta?' : 'Já tem uma conta?'}
            <button
              className="toggle-auth-btn"
              onClick={() => {
                setIsLogin(!isLogin)
                setError(null)
                setMessage(null)
              }}
            >
              {isLogin ? 'Cadastre-se' : 'Entrar'}
            </button>
          </p>
        </div>
      </div>
    </div>
  )
}

import { useState, useEffect, useCallback } from 'react'
import { medicineService, protocolService, stockService } from '@shared/services' // Import protocolService and stockService
import Button from '@shared/components/ui/Button'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import EmptyState from '@shared/components/ui/EmptyState'
import MedicineForm from '@medications/components/MedicineForm'
import MedicineCard from '@medications/components/MedicineCard'
import './Medicines.css'

export default function Medicines({ onNavigateToProtocol }) {
  const [medicines, setMedicines] = useState([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [editingMedicine, setEditingMedicine] = useState(null)
  const [successMessage, setSuccessMessage] = useState('')
  const [filterType, setFilterType] = useState('all') // 'all', 'medicamento', 'suplemento'
  const [medicineDependencies, setMedicineDependencies] = useState({}) // { medicineId: { hasProtocols: boolean, hasStock: boolean } }

  const loadDependencies = useCallback(async (medicines) => {
    const dependencies = {}
    for (const medicine of medicines) {
      const [protocols, stock] = await Promise.all([
        protocolService.getByMedicineId(medicine.id),
        stockService.getByMedicine(medicine.id),
      ])
      dependencies[medicine.id] = {
        hasProtocols: protocols.length > 0,
        hasStock: stock.length > 0,
      }
    }
    setMedicineDependencies(dependencies)
  }, [])

  const loadMedicines = useCallback(async () => {
    try {
      setIsLoading(true)
      setError(null)
      const data = await medicineService.getAll()
      setMedicines(data)

      // Load dependencies
      await loadDependencies(data)
    } catch (err) {
      setError('Erro ao carregar medicamentos: ' + err.message)
      console.error(err)
    } finally {
      setIsLoading(false)
    }
  }, [loadDependencies])

  useEffect(() => {
    loadMedicines()
  }, [loadMedicines])

  const handleAdd = () => {
    setEditingMedicine(null)
    setIsModalOpen(true)
  }

  const handleEdit = (medicine) => {
    setEditingMedicine(medicine)
    setIsModalOpen(true)
  }

  const handleSave = async (medicineData) => {
    try {
      if (editingMedicine) {
        await medicineService.update(editingMedicine.id, medicineData)
        showSuccess('Medicamento atualizado com sucesso!')
      } else {
        const newMedicine = await medicineService.create(medicineData)
        showSuccess('Medicamento cadastrado com sucesso!')

        // UX: Offer to create a protocol immediately
        if (
          window.confirm('✨ Medicamento criado! Deseja criar um protocolo de uso para ele agora?')
        ) {
          if (onNavigateToProtocol) {
            onNavigateToProtocol(newMedicine.id)
            return // Exit early to avoid closing/reloading the current screen unnecessarily
          }
        }
      }

      setIsModalOpen(false)
      setEditingMedicine(null)
      await loadMedicines()
    } catch (err) {
      throw new Error('Erro ao salvar medicamento: ' + err.message)
    }
  }

  const handleDelete = async (medicine) => {
    const hasDependencies =
      medicineDependencies[medicine.id]?.hasProtocols || medicineDependencies[medicine.id]?.hasStock

    if (hasDependencies) {
      const confirmation = window.confirm(
        `Este medicamento possui${medicineDependencies[medicine.id].hasProtocols ? 'protocolos e' : ''} ${medicineDependencies[medicine.id].hasStock ? 'estoque' : ''} associado(s).\nTem certeza que deseja excluí-lo?`
      )
      if (!confirmation) {
        return
      }
    }
    if (!window.confirm(`Tem certeza que deseja excluir "${medicine.name}"?`)) {
      return
    }

    try {
      await medicineService.delete(medicine.id)
      showSuccess('Medicamento excluído com sucesso!')
      await loadMedicines()
    } catch (err) {
      setError('Erro ao excluir medicamento: ' + err.message)
      console.error(err)
    }
  }

  const showSuccess = (message) => {
    setSuccessMessage(message)
    setTimeout(() => setSuccessMessage(''), 3000)
  }

  if (isLoading) {
    return (
      <div className="medicines-view">
        <Loading text="Carregando medicamentos..." />
      </div>
    )
  }

  return (
    <div className="medicines-view">
      <div className="medicines-header">
        <div>
          <h2>💊 Medicamentos e Suplementos</h2>
          <p className="medicines-subtitle">Gerencie seus medicamentos cadastrados</p>
        </div>
        <Button variant="primary" onClick={handleAdd}>
          ➕ Adicionar
        </Button>
      </div>

      <div className="filter-tabs" style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
        <Button
          variant={filterType === 'all' ? 'primary' : 'outline'}
          onClick={() => setFilterType('all')}
          size="sm"
        >
          Todos
        </Button>
        <Button
          variant={filterType === 'medicamento' ? 'primary' : 'outline'}
          onClick={() => setFilterType('medicamento')}
          size="sm"
        >
          Medicamentos
        </Button>
        <Button
          variant={filterType === 'suplemento' ? 'primary' : 'outline'}
          onClick={() => setFilterType('suplemento')}
          size="sm"
        >
          Suplementos
        </Button>
      </div>

      {successMessage && <div className="success-banner fade-in">✅ {successMessage}</div>}

      {error && <div className="error-banner fade-in">❌ {error}</div>}

      {medicines.length === 0 ? (
        <EmptyState
          illustration="protocols"
          title="Nenhum medicamento cadastrado"
          description="Cadastre seus medicamentos para começar a controlar sua saúde"
          ctaLabel="Cadastrar Medicamento"
          onCtaClick={handleAdd}
        />
      ) : (
        <div className="medicines-grid">
          {medicines
            .filter((m) => filterType === 'all' || m.type === filterType)
            .map((medicine) => {
              const hasDependencies =
                medicineDependencies[medicine.id]?.hasProtocols ||
                medicineDependencies[medicine.id]?.hasStock
              return (
                <MedicineCard
                  key={medicine.id}
                  medicine={medicine}
                  onEdit={handleEdit}
                  onDelete={handleDelete}
                  hasDependencies={hasDependencies} // Pass this prop to MedicineCard
                />
              )
            })}
        </div>
      )}

      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setEditingMedicine(null)
        }}
      >
        <MedicineForm
          medicine={editingMedicine}
          onSave={handleSave}
          onCancel={() => {
            setIsModalOpen(false)
            setEditingMedicine(null)
          }}
        />
      </Modal>
    </div>
  )
}

