  const [protocols, setProtocols] = useState([])
  const [treatmentPlans, setTreatmentPlans] = useState([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [isPlanModalOpen, setIsPlanModalOpen] = useState(false)
  const [editingProtocol, setEditingProtocol] = useState(null)
  const [editingPlan, setEditingPlan] = useState(null)
  const [successMessage, setSuccessMessage] = useState('')

  const loadData = useCallback(async () => {
    try {
      setIsLoading(true)
      setError(null)

      const [medicinesData, protocolsData, plansData] = await Promise.all([
        medicineService.getAll(),
        protocolService.getAll(),
        treatmentPlanService.getAll(),
      ])

      // Enrich protocols with titration data
      const enrichedProtocols = protocolsData.map((p) => ({
        ...p,
        titration_scheduler_data: calculateTitrationData(p),
      }))

      setMedicines(medicinesData)
      setProtocols(enrichedProtocols)
      setTreatmentPlans(plansData)
    } catch (err) {
      setError('Erro ao carregar dados: ' + err.message)
      console.error(err)
    } finally {
      setIsLoading(false)
    }
  }, [])

  useEffect(() => {
    loadData()
  }, [loadData])

  useEffect(() => {
    if (initialParams?.medicineId && medicines.length > 0) {
      setIsModalOpen(true)
      setEditingProtocol(null)
    }
  }, [initialParams, medicines])

  const handleAdd = () => {
    if (medicines.length === 0) {
      setError('Cadastre um medicamento antes de criar protocolos')
      return
    }
    setEditingProtocol(null)
    setIsModalOpen(true)
  }

  const handleAddPlan = () => {
    setEditingPlan(null)
    setIsPlanModalOpen(true)
  }

  const handleEdit = (protocol) => {
    setEditingProtocol(protocol)
    setIsModalOpen(true)
  }

  const handleEditPlan = (plan) => {
    setEditingPlan(plan)
    setIsPlanModalOpen(true)
  }

  const handleSave = async (protocolData) => {
    try {
      if (editingProtocol) {
        await protocolService.update(editingProtocol.id, protocolData)
        showSuccess('Protocolo atualizado com sucesso!')
      } else {
        await protocolService.create(protocolData)
        showSuccess('Protocolo criado com sucesso!')

        if (
          window.confirm(
            'Protocolo criado! Deseja adicionar o estoque inicial deste medicamento agora?'
          )
        ) {
          onNavigateToStock(protocolData.medicine_id)
        }
      }

      setIsModalOpen(false)
      setEditingProtocol(null)
      if (onClearParams) onClearParams()
      await loadData()
    } catch (err) {
      throw new Error('Erro ao salvar protocolo: ' + err.message)
    }
  }

  const handleSavePlan = async (planData) => {
    try {
      if (editingPlan) {
        await treatmentPlanService.update(editingPlan.id, planData)
        showSuccess('Plano de tratamento atualizado!')
      } else {
        await treatmentPlanService.create(planData)
        showSuccess('Plano de tratamento criado!')
      }

      setIsPlanModalOpen(false)
      setEditingPlan(null)
      await loadData()
    } catch (err) {
      throw new Error('Erro ao salvar plano: ' + err.message)
    }
  }

  const handleToggleActive = async (protocol) => {
    try {
      await protocolService.update(protocol.id, { active: !protocol.active })
      showSuccess(`Protocolo ${!protocol.active ? 'ativado' : 'pausado'} com sucesso!`)
      await loadData()
    } catch (err) {
      setError('Erro ao atualizar protocolo: ' + err.message)
      console.error(err)
    }
  }

  const handleDelete = async (protocol) => {
    if (!window.confirm(`Tem certeza que deseja excluir o protocolo "${protocol.name}"?`)) {
      return
    }

    try {
      await protocolService.delete(protocol.id)
      showSuccess('Protocolo excluído com sucesso!')
      await loadData()
    } catch (err) {
      setError('Erro ao excluir protocolo: ' + err.message)
      console.error(err)
    }
  }

  const handleDeletePlan = async (plan) => {
    if (
      !window.confirm(
        `Tem certeza que deseja excluir o plano "${plan.name}" e desvincular seus remédios?`
      )
    ) {
      return
    }

    try {
      await treatmentPlanService.delete(plan.id)
      showSuccess('Plano excluído com sucesso!')
      await loadData()
    } catch (err) {
      setError('Erro ao excluir plano: ' + err.message)
      console.error(err)
    }
  }

  const showSuccess = (message) => {
    setSuccessMessage(message)
    setTimeout(() => setSuccessMessage(''), 3000)
  }

  // Separar protocolos ativos e inativos
  const activeProtocols = protocols.filter((p) => p.active)
  const inactiveProtocols = protocols.filter((p) => !p.active)

  if (isLoading) {
    return (
      <div className="protocols-view">
        <Loading text="Carregando tratamentos..." />
      </div>
    )
  }

  return (
    <div className="protocols-view">
      <div className="protocols-header">
        <div>
          <h2>📋 Protocolos</h2>
          <p className="protocols-subtitle">
            Gerencie seus protocolos e planos de tratamento agrupados
          </p>
        </div>
        <div style={{ display: 'flex', gap: 'var(--space-2)' }}>
          <Button variant="outline" onClick={handleAddPlan}>
            📁 Novo Plano (Grupo)
          </Button>
          <Button variant="primary" onClick={handleAdd}>
            ➕ Criar Protocolo
          </Button>
        </div>
      </div>

      {successMessage && <div className="success-banner fade-in">✅ {successMessage}</div>}

      {error && <div className="error-banner fade-in">❌ {error}</div>}

      {medicines.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">📋</div>
          <h3>Nenhum medicamento cadastrado</h3>
          <p>Cadastre medicamentos primeiro para criar protocolos</p>
        </div>
      ) : (
        <div className="protocols-content">
          {/* Planos de Tratamentos */}
          {treatmentPlans.length > 0 && (
            <div className="treatment-plans-section">
              <h3 className="section-title plans">📁 Planos de Tratamento</h3>
              <div className="plans-grid">
                {treatmentPlans.map((plan) => (
                  <Card key={plan.id} className="treatment-plan-card">
                    <div className="plan-header">
                      <div>
                        <h4>{plan.name}</h4>
                        <p className="plan-objective">{plan.objective}</p>
                      </div>
                      <div className="plan-actions">
                        <Button variant="ghost" size="sm" onClick={() => handleEditPlan(plan)}>
                          ✏️
                        </Button>
                        <Button variant="ghost" size="sm" onClick={() => handleDeletePlan(plan)}>
                          🗑️
                        </Button>
                      </div>
                    </div>
                    {plan.description && <p className="plan-desc">{plan.description}</p>}

                    <div className="plan-protocols-list">
                      {plan.protocols && plan.protocols.length > 0 ? (
                        plan.protocols.map((p) => (
                          <div key={p.id} className="plan-protocol-row">
                            <span>💊 {p.name}</span>
                            <span className={`titration-status-mini ${p.titration_status}`}>
                              {p.titration_status === 'titulando' ? '📈 Titulando' : '✅'}
                            </span>
                          </div>
                        ))
                      ) : (
                        <p className="empty-plan">Nenhum remédio vinculado ainda.</p>
                      )}
                    </div>
                  </Card>
                ))}
              </div>
            </div>
          )}

          {/* Protocolos ativos */}
          {activeProtocols.length > 0 && (
            <div className="protocols-section">
              <h3 className="section-title active">
                {treatmentPlans.length > 0
                  ? '🔍 Todos os Protocolos Ativos'
                  : '✅ Protocolos Ativos'}{' '}
                ({activeProtocols.length})
              </h3>
              <div className="protocols-grid">
                {activeProtocols.map((protocol) => (
                  <ProtocolCard
                    key={protocol.id}
                    protocol={protocol}
                    onEdit={handleEdit}
                    onToggleActive={handleToggleActive}
                    onDelete={handleDelete}
                  />
                ))}
              </div>
            </div>
          )}

          {/* Protocolos inativos */}
          {inactiveProtocols.length > 0 && (
            <div className="protocols-section">
              <h3 className="section-title inactive">
                ⏸️ Protocolos Pausados ({inactiveProtocols.length})
              </h3>
              <div className="protocols-grid">
                {inactiveProtocols.map((protocol) => (
                  <ProtocolCard
                    key={protocol.id}
                    protocol={protocol}
                    onEdit={handleEdit}
                    onToggleActive={handleToggleActive}
                    onDelete={handleDelete}
                  />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Modal para Protocolos */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setEditingProtocol(null)
          if (onClearParams) onClearParams()
        }}
      >
        <ProtocolForm
          medicines={medicines}
          treatmentPlans={treatmentPlans}
          protocol={editingProtocol}
          initialValues={initialParams ? { medicine_id: initialParams.medicineId } : null}
          onSave={handleSave}
          onCancel={() => {
            setIsModalOpen(false)
            setEditingProtocol(null)
            if (onClearParams) onClearParams()
          }}
        />
      </Modal>

      {/* Modal para Planos de Tratamento */}
      <Modal
        isOpen={isPlanModalOpen}
        onClose={() => {
          setIsPlanModalOpen(false)
          setEditingPlan(null)
        }}
      >
        <TreatmentPlanForm
          plan={editingPlan}
          onSave={handleSavePlan}
          onCancel={() => {
            setIsPlanModalOpen(false)
            setEditingPlan(null)
          }}
        />
      </Modal>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { supabase, signOut, updatePassword } from '@shared/utils/supabase'
import Button from '@shared/components/ui/Button'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import ExportDialog from '@features/export/components/ExportDialog'
import ReportGenerator from '@features/reports/components/ReportGenerator'
import styles from './Settings.module.css'
import './Settings.css'

export default function Settings({ onNavigate }) {
  const [user, setUser] = useState(null)
  const [settings, setSettings] = useState(null)
  const [isLoading, setIsLoading] = useState(true)
  const [telegramToken, setTelegramToken] = useState(null)
  const [newPassword, setNewPassword] = useState('')
  const [message, setMessage] = useState(null)
  const [error, setError] = useState(null)
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false)
  const [isReportModalOpen, setIsReportModalOpen] = useState(false)

  useEffect(() => {
    loadProfile()
  }, [])

  const loadProfile = async () => {
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()
      setUser(user)

      const { data, error } = await supabase
        .from('user_settings')
        .select('*')
        .eq('user_id', user.id)
        .single() // Might fail if no settings exist yet

      if (!error && data) {
        setSettings(data)
      } else if (error && error.code !== 'PGRST116') {
        // Ignore "not found"
        console.error(error)
      }
    } catch (err) {
      console.error(err)
    } finally {
      setIsLoading(false)
    }
  }

  const handleLogout = async () => {
    try {
      await signOut()
      // App.jsx will handle redirect due to auth state change
    } catch (err) {
      console.error(err)
    }
  }

  const handleUpdatePassword = async (e) => {
    e.preventDefault()
    if (newPassword.length < 6) {
      setError('Senha deve ter no mínimo 6 caracteres')
      return
    }

    try {
      await updatePassword(newPassword)
      setMessage('Senha atualizada com sucesso!')
      setNewPassword('')
      setTimeout(() => setMessage(null), 3000)
    } catch (err) {
      setError('Erro ao atualizar senha: ' + err.message)
    }
  }

  const generateTelegramToken = async () => {
    const token = Math.random().toString(36).substring(2, 8).toUpperCase()

    try {
      const { error } = await supabase.from('user_settings').upsert(
        {
          user_id: user.id,
          verification_token: token,
          updated_at: new Date(),
        },
        { onConflict: 'user_id' }
      )

      if (error) throw error

      setTelegramToken(token)
    } catch (err) {
      console.error(err)
      setError('Erro ao gerar token. Tente novamente.')
    }
  }

  const handleDisconnectTelegram = async () => {
    if (
      !window.confirm(
        'Deseja realmente desconectar o Telegram? Você parará de receber notificações.'
      )
    )
      return

    try {
      const { error } = await supabase
        .from('user_settings')
        .update({
          telegram_chat_id: null,
          verification_token: null,
          updated_at: new Date(),
        })
        .eq('user_id', user.id)

      if (error) throw error

      setSettings((prev) => ({ ...prev, telegram_chat_id: null }))
      setTelegramToken(null)
      setMessage('Telegram desconectado com sucesso!')
      setTimeout(() => setMessage(null), 3000)
    } catch (err) {
      console.error(err)
      setError('Erro ao desconectar Telegram.')
    }
  }

  if (isLoading) return <Loading />

  return (
    <div className="settings-container">
      <h2 className="page-title">Configurações</h2>

      <div className="settings-section">
        <h3>Minha Conta</h3>
        <div className="profile-info">
          <div className="info-row">
            <span className="label">Email</span>
            <span className="value">{user?.email}</span>
          </div>
          <div className="info-row">
            <span className="label">ID</span>
            <span className="value mono">{user?.id?.slice(0, 8)}...</span>
          </div>
        </div>

        <form onSubmit={handleUpdatePassword} className="password-form">
          <h4>Alterar Senha</h4>
          <div className="input-group">
            <input
              type="password"
              placeholder="Nova senha"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              className="settings-input"
            />
            <Button type="submit" disabled={!newPassword}>
              Atualizar
            </Button>
          </div>
        </form>
      </div>

      <div className="settings-section">
        <h3>Integração Telegram</h3>
        <p className="section-desc">Receba notificações e gerencie seus remédios pelo Telegram.</p>

        <div className="telegram-status">
          Status:
          <span
            className={`status-badge ${settings?.telegram_chat_id ? 'connected' : 'disconnected'}`}
          >
            {settings?.telegram_chat_id ? 'Conectado' : 'Não Conectado'}
          </span>
        </div>

        {settings?.telegram_chat_id ? (
          <div className="connected-actions">
            <p className="section-desc success-text">Bot vinculado com sucesso!</p>
            <Button variant="outline" className="btn-disconnect" onClick={handleDisconnectTelegram}>
              Desconectar Telegram
            </Button>
          </div>
        ) : (
          <div className="connect-telegram">
            {!telegramToken ? (
              <Button onClick={generateTelegramToken}>Gerar Código de Vínculo</Button>
            ) : (
              <div className="token-display">
                <p>Envie este comando para o bot:</p>
                <div className="code-box">/start {telegramToken}</div>
                <a
                  href={`https://t.me/dosiq_bot?start=${telegramToken}`}
                  target="_blank"
                  rel="noreferrer"
                  className="telegram-link"
                >
                  Abrir Bot no Telegram
                </a>
                <Button
                  variant="ghost"
                  className="btn-cancel-token"
                  onClick={() => setTelegramToken(null)}
                >
                  Cancelar
                </Button>
              </div>
            )}
          </div>
        )}
      </div>

      <div className="settings-section">
        <h3>Saúde e Emergência</h3>
        <p className="section-desc">Informações médicas críticas para situações de emergência.</p>

        <div className="emergency-actions">
          <Button variant="outline" onClick={() => onNavigate('emergency')}>
            Cartão de Emergência
          </Button>
          <Button
            variant="outline"
            onClick={() => onNavigate('consultation')}
            className={styles.consultationButton}
          >
            Modo Consulta Médica
          </Button>
        </div>
      </div>

      <div className="settings-section">
        <h3>Exportar Dados</h3>
        <p className="section-desc">
          Exporte seus dados em formato CSV ou JSON para backup ou análise.
        </p>

        <div className="export-actions">
          <Button variant="outline" onClick={() => setIsExportDialogOpen(true)}>
            Exportar Dados
          </Button>
        </div>
      </div>

      <div className="settings-section">
        <h3>Relatórios</h3>
        <p className="section-desc">
          Gere relatórios em PDF com seu histórico de medicamentos e adesão.
        </p>

        <div className="report-actions">
          <Button variant="outline" onClick={() => setIsReportModalOpen(true)}>
            Gerar Relatório PDF
          </Button>
        </div>
      </div>

      <div className="settings-section">
        <h3>Administração</h3>
        <p className="section-desc">Ferramentas administrativas do sistema.</p>

        <div className="admin-actions">
          <Button variant="outline" onClick={() => onNavigate('admin-dlq')}>
            Gerenciar Notificações Falhadas (DLQ)
          </Button>
        </div>
      </div>

      {message && <div className="settings-message success">{message}</div>}
      {error && <div className="settings-message error">{error}</div>}

      <div className="logout-section">
        <Button variant="outline" className="logout-btn" onClick={handleLogout}>
          Sair da Conta
        </Button>
      </div>

      <ExportDialog isOpen={isExportDialogOpen} onClose={() => setIsExportDialogOpen(false)} />

      {/* Modal de Geração de Relatórios */}
      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)}>
        <ReportGenerator onClose={() => setIsReportModalOpen(false)} />
      </Modal>
    </div>
  )
}

