// src/views/admin/DLQAdmin.jsx
// Dead Letter Queue Admin Interface
import { useState, useEffect, useCallback } from 'react'
import { dlqService } from '@services/api/dlqService'
import Button from '@shared/components/ui/Button'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import './DLQAdmin.css'

// Constantes de formatação
const USER_ID_TRUNCATE_LENGTH = 8
const ERROR_MESSAGE_TRUNCATE_LENGTH = 50

/**
 * DLQAdmin - Interface de administração da Dead Letter Queue
 *
 * Funcionalidades:
 * - Lista notificações falhadas com paginação
 * - Filtra por status
 * - Permite retentar ou descartar notificações
 * - Exibe detalhes de cada notificação
 */
export default function DLQAdmin() {
  // Estados principais
  const [entries, setEntries] = useState([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)

  // Estados de paginação
  const [total, setTotal] = useState(0)
  const [page, setPage] = useState(1)
  const [pageSize] = useState(20)
  const [totalPages, setTotalPages] = useState(0)

  // Estados de filtro
  const [statusFilter, setStatusFilter] = useState('')

  // Estados de ação
  const [selectedEntry, setSelectedEntry] = useState(null)
  const [showDetails, setShowDetails] = useState(false)
  const [actionLoading, setActionLoading] = useState(null)
  const [actionMessage, setActionMessage] = useState(null)

  // Estados de confirmação
  const [confirmAction, setConfirmAction] = useState(null)
  const [showConfirmModal, setShowConfirmModal] = useState(false)

  // Carregar dados
  const loadEntries = useCallback(async () => {
    setIsLoading(true)
    setError(null)

    try {
      const offset = (page - 1) * pageSize
      const result = await dlqService.getAll({
        limit: pageSize,
        offset,
        status: statusFilter || null,
      })

      setEntries(result.data)
      setTotal(result.total)
      setTotalPages(result.totalPages)
    } catch (err) {
      console.error('[DLQAdmin] Erro ao carregar:', err)
      setError(err.message)
    } finally {
      setIsLoading(false)
    }
  }, [page, pageSize, statusFilter])

  useEffect(() => {
    loadEntries()
  }, [loadEntries])

  // Handlers de ação com Modal de confirmação
  const handleRetry = async (id) => {
    setConfirmAction({
      type: 'retry',
      id,
      message: 'Deseja retentar esta notificação?',
      onConfirm: async () => {
        setActionLoading(id)
        setActionMessage(null)

        try {
          const result = await dlqService.retry(id)
          setActionMessage({
            type: 'success',
            text: result.message || 'Notificação reenviada com sucesso!',
          })
          loadEntries() // Recarregar lista
        } catch (err) {
          setActionMessage({ type: 'error', text: err.message })
        } finally {
          setActionLoading(null)
        }
      },
    })
    setShowConfirmModal(true)
  }

  const handleDiscard = async (id) => {
    setConfirmAction({
      type: 'discard',
      id,
      message: 'Deseja descartar esta notificação? Esta ação não pode ser desfeita.',
      onConfirm: async () => {
        setActionLoading(id)
        setActionMessage(null)

        try {
          const result = await dlqService.discard(id)
          setActionMessage({ type: 'success', text: result.message || 'Notificação descartada.' })
          loadEntries() // Recarregar lista
        } catch (err) {
          setActionMessage({ type: 'error', text: err.message })
        } finally {
          setActionLoading(null)
        }
      },
    })
    setShowConfirmModal(true)
  }

  // Handler de confirmação
  const handleConfirmAction = async () => {
    if (confirmAction?.onConfirm) {
      await confirmAction.onConfirm()
    }
    setShowConfirmModal(false)
    setConfirmAction(null)
  }

  const handleCancelConfirm = () => {
    setShowConfirmModal(false)
    setConfirmAction(null)
  }

  const handleViewDetails = (entry) => {
    setSelectedEntry(entry)
    setShowDetails(true)
  }

  // Handlers de paginação
  const handlePrevPage = () => {
    if (page > 1) setPage(page - 1)
  }

  const handleNextPage = () => {
    if (page < totalPages) setPage(page + 1)
  }

  // Handler de filtro
  const handleStatusChange = (e) => {
    setStatusFilter(e.target.value)
    setPage(1) // Resetar para primeira página
  }

  // Limpar mensagem após 5 segundos
  useEffect(() => {
    if (actionMessage) {
      const timer = setTimeout(() => setActionMessage(null), 5000)
      return () => clearTimeout(timer)
    }
  }, [actionMessage])

  return (
    <div className="dlq-admin">
      <header className="dlq-admin__header">
        <h1>Dead Letter Queue</h1>
        <p className="dlq-admin__subtitle">Gerenciamento de notificações falhadas</p>
      </header>

      {/* Filtros e estatísticas */}
      <div className="dlq-admin__controls">
        <div className="dlq-admin__filter">
          <label htmlFor="status-filter">Filtrar por status:</label>
          <select
            id="status-filter"
            value={statusFilter}
            onChange={handleStatusChange}
            className="dlq-admin__select"
          >
            <option value="">Todos</option>
            <option value="pending">Pendente</option>
            <option value="retrying">Retentando</option>
            <option value="resolved">Resolvido</option>
            <option value="discarded">Descartado</option>
          </select>
        </div>

        <div className="dlq-admin__stats">
          <span className="dlq-admin__stat">
            <strong>{total}</strong> notificações
          </span>
        </div>
      </div>

      {/* Mensagem de ação */}
      {actionMessage && (
        <div className={`dlq-admin__message dlq-admin__message--${actionMessage.type}`}>
          {actionMessage.text}
        </div>
      )}

      {/* Erro */}
      {error && (
        <div className="dlq-admin__error">
          <p>Erro ao carregar dados: {error}</p>
          <Button onClick={loadEntries} variant="secondary">
            Tentar novamente
          </Button>
        </div>
      )}

      {/* Loading */}
      {isLoading && (
        <div className="dlq-admin__loading">
          <Loading text="Carregando notificações..." />
        </div>
      )}

      {/* Tabela */}
      {!isLoading && !error && (
        <>
          <div className="dlq-admin__table-container">
            <table className="dlq-admin__table">
              <thead>
                <tr>
                  <th>Data/Hora</th>
                  <th>Usuário</th>
                  <th>Tipo</th>
                  <th>Status</th>
                  <th>Erro</th>
                  <th>Tentativas</th>
                  <th>Ações</th>
                </tr>
              </thead>
              <tbody>
                {entries.length === 0 ? (
                  <tr>
                    <td colSpan="7" className="dlq-admin__empty">
                      Nenhuma notificação encontrada
                    </td>
                  </tr>
                ) : (
                  entries.map((entry) => (
                    <tr key={entry.id} className="dlq-admin__row">
                      <td className="dlq-admin__cell dlq-admin__cell--date">
                        {dlqService.formatDate(entry.created_at)}
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--user">
                        <span className="dlq-admin__user-id">
                          {entry.user_id
                            ? entry.user_id.substring(0, USER_ID_TRUNCATE_LENGTH) + '...'
                            : '-'}
                        </span>
                      </td>
                      <td className="dlq-admin__cell">
                        {dlqService.formatNotificationType(entry.notification_type)}
                      </td>
                      <td className="dlq-admin__cell">
                        <span
                          className="dlq-admin__status"
                          style={{ color: dlqService.getStatusColor(entry.status) }}
                        >
                          {dlqService.formatStatus(entry.status)}
                        </span>
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--error">
                        <span className="dlq-admin__error-text" title={entry.error_message}>
                          {entry.error_message
                            ? entry.error_message.length > ERROR_MESSAGE_TRUNCATE_LENGTH
                              ? entry.error_message.substring(0, ERROR_MESSAGE_TRUNCATE_LENGTH) +
                                '...'
                              : entry.error_message
                            : '-'}
                        </span>
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--attempts">
                        {entry.retry_count || 0}
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--actions">
                        <div className="dlq-admin__actions">
                          <button
                            className="dlq-admin__action-btn dlq-admin__action-btn--view"
                            onClick={() => handleViewDetails(entry)}
                            title="Ver detalhes"
                          >
                            Ver
                          </button>
                          {(entry.status === 'pending' || entry.status === 'retrying') && (
                            <>
                              <button
                                className="dlq-admin__action-btn dlq-admin__action-btn--retry"
                                onClick={() => handleRetry(entry.id)}
                                disabled={actionLoading === entry.id}
                                title="Retentar"
                              >
                                {actionLoading === entry.id ? '...' : 'Retentar'}
                              </button>
                              <button
                                className="dlq-admin__action-btn dlq-admin__action-btn--discard"
                                onClick={() => handleDiscard(entry.id)}
                                disabled={actionLoading === entry.id}
                                title="Descartar"
                              >
                                Descartar
                              </button>
                            </>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Paginação */}
          {totalPages > 1 && (
            <div className="dlq-admin__pagination">
              <button
                className="dlq-admin__page-btn"
                onClick={handlePrevPage}
                disabled={page === 1}
              >
                Anterior
              </button>
              <span className="dlq-admin__page-info">
                Página {page} de {totalPages}
              </span>
              <button
                className="dlq-admin__page-btn"
                onClick={handleNextPage}
                disabled={page === totalPages}
              >
                Próxima
              </button>
            </div>
          )}
        </>
      )}

      {/* Modal de detalhes */}
      {showDetails && selectedEntry && (
        <Modal isOpen={showDetails} onClose={() => setShowDetails(false)}>
          <div className="dlq-admin__details">
            <h2>Detalhes da Notificação</h2>

            <div className="dlq-admin__detail-grid">
              <div className="dlq-admin__detail-item">
                <label>ID:</label>
                <span className="dlq-admin__detail-value dlq-admin__detail-value--mono">
                  {selectedEntry.id}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Correlation ID:</label>
                <span className="dlq-admin__detail-value dlq-admin__detail-value--mono">
                  {selectedEntry.correlation_id || '-'}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>User ID:</label>
                <span className="dlq-admin__detail-value dlq-admin__detail-value--mono">
                  {selectedEntry.user_id || '-'}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Protocol ID:</label>
                <span className="dlq-admin__detail-value dlq-admin__detail-value--mono">
                  {selectedEntry.protocol_id || '-'}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Tipo:</label>
                <span className="dlq-admin__detail-value">
                  {dlqService.formatNotificationType(selectedEntry.notification_type)}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Status:</label>
                <span
                  className="dlq-admin__detail-value"
                  style={{ color: dlqService.getStatusColor(selectedEntry.status) }}
                >
                  {dlqService.formatStatus(selectedEntry.status)}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Categoria de Erro:</label>
                <span className="dlq-admin__detail-value">
                  {dlqService.formatErrorCategory(selectedEntry.error_category)}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Código de Erro:</label>
                <span className="dlq-admin__detail-value">{selectedEntry.error_code || '-'}</span>
              </div>

              <div className="dlq-admin__detail-item dlq-admin__detail-item--full">
                <label>Mensagem de Erro:</label>
                <span className="dlq-admin__detail-value dlq-admin__detail-value--error">
                  {selectedEntry.error_message || '-'}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Tentativas:</label>
                <span className="dlq-admin__detail-value">{selectedEntry.retry_count || 0}</span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Criado em:</label>
                <span className="dlq-admin__detail-value">
                  {dlqService.formatDate(selectedEntry.created_at)}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Atualizado em:</label>
                <span className="dlq-admin__detail-value">
                  {dlqService.formatDate(selectedEntry.updated_at)}
                </span>
              </div>

              {selectedEntry.resolved_at && (
                <div className="dlq-admin__detail-item">
                  <label>Resolvido em:</label>
                  <span className="dlq-admin__detail-value">
                    {dlqService.formatDate(selectedEntry.resolved_at)}
                  </span>
                </div>
              )}

              {selectedEntry.resolution_notes && (
                <div className="dlq-admin__detail-item dlq-admin__detail-item--full">
                  <label>Notas de Resolução:</label>
                  <span className="dlq-admin__detail-value">{selectedEntry.resolution_notes}</span>
                </div>
              )}

              {selectedEntry.notification_payload && (
                <div className="dlq-admin__detail-item dlq-admin__detail-item--full">
                  <label>Payload:</label>
                  <pre className="dlq-admin__detail-value dlq-admin__detail-value--code">
                    {JSON.stringify(selectedEntry.notification_payload, null, 2)}
                  </pre>
                </div>
              )}
            </div>

            <div className="dlq-admin__detail-actions">
              {(selectedEntry.status === 'pending' || selectedEntry.status === 'retrying') && (
                <>
                  <Button
                    onClick={() => {
                      handleRetry(selectedEntry.id)
                      setShowDetails(false)
                    }}
                    disabled={actionLoading === selectedEntry.id}
                  >
                    Retentar
                  </Button>
                  <Button
                    variant="secondary"
                    onClick={() => {
                      handleDiscard(selectedEntry.id)
                      setShowDetails(false)
                    }}
                    disabled={actionLoading === selectedEntry.id}
                  >
                    Descartar
                  </Button>
                </>
              )}
              <Button variant="ghost" onClick={() => setShowDetails(false)}>
                Fechar
              </Button>
            </div>
          </div>
        </Modal>
      )}

      {/* Modal de confirmação */}
      {showConfirmModal && confirmAction && (
        <Modal isOpen={showConfirmModal} onClose={handleCancelConfirm}>
          <div className="dlq-admin__confirm">
            <h2>Confirmar Ação</h2>
            <p>{confirmAction.message}</p>
            <div className="dlq-admin__confirm-actions">
              <Button onClick={handleConfirmAction} disabled={actionLoading === confirmAction.id}>
                Confirmar
              </Button>
              <Button variant="secondary" onClick={handleCancelConfirm}>
                Cancelar
              </Button>
            </div>
          </div>
        </Modal>
      )}
    </div>
  )
}

/**
 * ConsultationRedesign — Container view do Modo Consulta (Santuário Terapêutico).
 * Reutiliza 100% da lógica de dados do Consultation.jsx original.
 * Apenas o presenter muda (ConsultationViewRedesign).
 */

import { useState, useEffect, useMemo, useCallback } from 'react'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import { getCurrentUser } from '@shared/utils/supabase'
import { cachedAdherenceService } from '@shared/services/cachedServices'
import { getConsultationData } from '@features/consultation/services/consultationDataService'
import ConsultationViewRedesign from '@features/consultation/components/redesign/ConsultationViewRedesign'
import Loading from '@shared/components/ui/Loading'
import { analyticsService } from '@dashboard/services/analyticsService'
import { generateConsultationPDF } from '@features/reports/services/consultationPdfService'
import { formatLocalDate } from '@utils/dateUtils.js'
import './Consultation.css'

export default function Consultation({ onBack }) {
  const [isLoading, setIsLoading] = useState(true)
  const [consultationData, setConsultationData] = useState(null)
  const [error, setError] = useState(null)

  const { medicines, protocols, logs, stockSummary, stats, dailyAdherence } = useDashboard()

  const dashboardData = useMemo(
    () => ({ medicines, protocols, logs, stockSummary, stats, dailyAdherence }),
    [medicines, protocols, logs, stockSummary, stats, dailyAdherence]
  )

  // Create single 'now' instance for temporal consistency across PDF export, share, and filename generation
  const now = useMemo(() => new Date(), [])

  useEffect(() => {
    let isMounted = true

    const loadConsultationData = async () => {
      try {
        setIsLoading(true)
        setError(null)
        const user = await getCurrentUser()
        const resolvedName = user?.user_metadata?.name || user?.user_metadata?.full_name || ''
        const resolvedEmail = user?.email || ''
        if (!isMounted) return
        if (!dashboardData.medicines || !dashboardData.protocols) {
          if (isMounted) {
            setConsultationData(null)
            setIsLoading(false)
          }
          return
        }
        const data = getConsultationData(dashboardData, resolvedName, null, resolvedEmail)
        setConsultationData(data)
      } catch {
        if (!isMounted) return
        setError('Não foi possível carregar os dados para consulta.')
      } finally {
        if (isMounted) setIsLoading(false)
      }
    }

    loadConsultationData()
    return () => {
      isMounted = false
    }
  }, [dashboardData])

  const handleGeneratePDF = useCallback(async () => {
    try {
      analyticsService.track('consultation_pdf_generated', { timestamp: Date.now() })
      const resolvedDailyAdherence = await cachedAdherenceService.getDailyAdherenceFromView(30)
      const pdfBlob = await generateConsultationPDF({
        consultationData,
        dashboardData: { ...dashboardData, dailyAdherence: resolvedDailyAdherence },
        period: '30d',
      })
      const url = URL.createObjectURL(pdfBlob)
      const link = document.createElement('a')
      link.href = url
      link.download = `consulta-medica-${formatLocalDate(now)}.pdf`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)
    } catch (error) {
      console.error('Erro ao gerar PDF:', error)
      alert('Erro ao gerar PDF. Tente novamente.')
    }
  }, [consultationData, dashboardData, now])

  const handleShare = useCallback(async () => {
    try {
      analyticsService.track('consultation_share_initiated', { timestamp: Date.now() })
      const resolvedDailyAdherence = await cachedAdherenceService.getDailyAdherenceFromView(30)
      const pdfBlob = await generateConsultationPDF({
        consultationData,
        dashboardData: { ...dashboardData, dailyAdherence: resolvedDailyAdherence },
        period: '30d',
      })
      const fileName = `consulta-medica-${formatLocalDate(now)}.pdf`

      // 1. Tentar Web Share API (mobile nativo)
      if (navigator.share && navigator.canShare) {
        try {
          const file = new File([pdfBlob], fileName, { type: 'application/pdf' })
          if (navigator.canShare({ files: [file] })) {
            await navigator.share({
              title: 'Dados da Consulta Médica',
              text: 'Relatório de tratamento e adesão aos medicamentos',
              files: [file],
            })
            analyticsService.track('consultation_shared', { method: 'web_share_api' })
            return
          }
        } catch (shareErr) {
          // Se usuário cancelou a share sheet, trata como no-op
          if (shareErr.name === 'AbortError') {
            return
          }
          // Caso contrário, fallback para download
          console.warn('Web Share API failed, falling back to download:', shareErr)
        }
      }

      // 2. Fallback: Download direto do PDF
      const url = URL.createObjectURL(pdfBlob)
      const link = document.createElement('a')
      link.href = url
      link.download = fileName
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)

      alert('PDF baixado com sucesso! Você pode compartilhá-lo manualmente.')
      analyticsService.track('consultation_shared', { method: 'download' })
    } catch (error) {
      if (error.name !== 'AbortError') {
        console.error('Share error:', error)
        alert('Erro ao compartilhar. Tente novamente.')
      }
    }
  }, [consultationData, dashboardData, now])

  const handleBack = useCallback(() => {
    analyticsService.track('consultation_mode_closed', { timestamp: Date.now() })
    onBack?.()
  }, [onBack])

  if (isLoading) {
    return (
      <div className="cr-loading">
        <Loading text="Carregando dados da consulta..." />
      </div>
    )
  }

  if (error || !consultationData) {
    return (
      <div className="cr-error">
        <h2 className="cr-error__title">{error ? 'Erro ao carregar' : 'Nenhum dado disponível'}</h2>
        <p className="cr-error__message">
          {error || 'Cadastre medicamentos e tratamentos para visualizar dados na consulta.'}
        </p>
        <button className="btn-primary" onClick={handleBack}>
          Voltar
        </button>
      </div>
    )
  }

  return (
    <ConsultationViewRedesign
      data={consultationData}
      onGeneratePDF={handleGeneratePDF}
      onShare={handleShare}
      onBack={handleBack}
    />
  )
}

import { useState, useEffect, useMemo, useCallback, useRef } from 'react'
import { cachedLogService as logService } from '@shared/services'
import { analyticsService } from '@dashboard/services/analyticsService'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import {
  useDoseZones,
  expandProtocolsToDoses,
  filterTodayLogs,
} from '@dashboard/hooks/useDoseZones'
import { useComplexityMode } from '@dashboard/hooks/useComplexityMode'
import { getCurrentUser, supabase } from '@shared/utils/supabase'
import { getTodayLocal } from '@utils/dateUtils'
import Loading from '@shared/components/ui/Loading'
import './Dashboard.css'
import RingGaugeRedesign from '@dashboard/components/RingGaugeRedesign'
import PriorityDoseCard from '@dashboard/components/PriorityDoseCard'
import CronogramaPeriodo from '@dashboard/components/CronogramaPeriodo'
import StockAlertInline from '@dashboard/components/StockAlertInline'
import SmartAlertsRedesign from '@dashboard/components/SmartAlertsRedesign'
import InsightCardRedesign from '@dashboard/components/InsightCardRedesign'
import ReminderSuggestionRedesign from '@features/protocols/components/ReminderSuggestionRedesign'
import {
  analyzeReminderTiming,
  isSuggestionDismissed,
  dismissSuggestion,
} from '@features/protocols/services/reminderOptimizerService'
import insightService from '@dashboard/services/insightService'
import { protocolService } from '@features/protocols/services/protocolService'

/**
 * getMotivationalMessage — Mensagem contextual baseada em adesão e doses restantes
 *
 * @param {number} adherenceScore — Score de 0-100
 * @param {number} remainingDoses — Doses não registradas hoje
 * @returns {string} Mensagem motivacional
 */
function getMotivationalMessage(adherenceScore, remainingDoses) {
  if (remainingDoses === 0) {
    return '✅ Perfeito!'
  }
  if (adherenceScore >= 80) {
    return '🌟 Excelente!'
  }
  if (adherenceScore >= 50) {
    return '💪 Quase lá!'
  }
  return '🎯 Vamos retomar'
}

/**
 * DashboardRedesign — View principal do Santuário Terapêutico.
 *
 * Compartilha TODA a lógica de dados com Dashboard.jsx.
 * Diferença: apenas a camada de apresentação.
 *
 * @param {Function} onNavigate — Callback de navegação (view, params?) => void
 */
export default function Dashboard({ onNavigate }) {
  // ── Dados compartilhados (NÃO duplicar) ──
  const {
    stats,
    stockSummary,
    protocols,
    logs,
    refresh,
    isLoading: contextLoading,
  } = useDashboard()
  const { zones, totals, now } = useDoseZones()
  const { mode: complexityMode } = useComplexityMode()

  // ── Estado local ──
  const [userName, setUserName] = useState('')
  const [isLoading, setIsLoading] = useState(true)
  const currentDateRef = useRef(getTodayLocal())
  const [dismissedSuggestionId, setDismissedSuggestionId] = useState(null)
  const [snoozedAlerts, setSnoozedAlerts] = useState({})

  // ── Computadas ──
  // Enriquecer doses com dados de estoque
  const stockByMedicineId = useMemo(() => {
    const map = new Map()
    stockSummary?.items?.forEach((item) => map.set(item.medicineId, item))
    return map
  }, [stockSummary])

  // scheduleAllDoses: fonte separada para CronogramaPeriodo — todos os protocolos expandidos (sem filtro classifyDose)
  const scheduleAllDoses = useMemo(() => {
    if (!protocols?.length) return []
    const todayLogs = filterTodayLogs(logs || [])
    return expandProtocolsToDoses(protocols, todayLogs).map((dose) => ({
      ...dose,
      stockDays: stockByMedicineId.get(dose.medicineId)?.daysRemaining ?? null,
      stockStatus: stockByMedicineId.get(dose.medicineId)?.stockStatus ?? null,
    }))
  }, [protocols, logs, stockByMedicineId])

  // urgentDoses: fonte separada para PriorityDoseCard — zonas late/now filtradas
  const urgentDoses = useMemo(
    () => [
      ...(zones.late || []).filter((d) => !d.isRegistered),
      ...(zones.now || []).filter((d) => !d.isRegistered),
    ],
    [zones]
  )

  const criticalStockItems = useMemo(() => {
    if (!stockSummary?.items) return []
    return stockSummary.items.filter(
      (item) => item.stockStatus === 'critical' || item.stockStatus === 'low'
    )
  }, [stockSummary])

  // ── smartAlerts: alertas inteligentes (estoque + dose atrasada + prescrição) ──
  const smartAlerts = useMemo(() => {
    const alerts = []

    // 1. Stock alerts
    stockSummary?.items?.forEach((item) => {
      if (snoozedAlerts[`stock-${item.medicineId}`]) return
      if (item.stockStatus === 'critical' || item.stockStatus === 'low') {
        const severity = item.stockStatus === 'critical' ? 'critical' : 'warning'
        alerts.push({
          id: `stock-${item.medicineId}`,
          severity,
          title:
            severity === 'critical'
              ? `Estoque crítico — ${item.medicineName}`
              : `Estoque baixo — ${item.medicineName}`,
          message:
            severity === 'critical'
              ? `${item.quantity ?? 0} unidades restantes. Reposição urgente.`
              : `${item.daysRemaining} dias restantes. Programe a compra.`,
          actions: [{ label: 'Registrar Compra', type: 'primary' }],
        })
      }
    })

    // 2. Doses atrasadas (zones.late)
    const lateDoses = (zones.late || []).filter((d) => !d.isRegistered)
    if (lateDoses.length > 0 && !snoozedAlerts['late-doses']) {
      const names = lateDoses
        .slice(0, 2)
        .map((d) => d.medicineName)
        .join(', ')
      const extra = lateDoses.length > 2 ? ` +${lateDoses.length - 2}` : ''
      alerts.push({
        id: 'late-doses',
        severity: 'warning',
        title: `${lateDoses.length} dose${lateDoses.length > 1 ? 's' : ''} atrasada${lateDoses.length > 1 ? 's' : ''}`,
        message: `${names}${extra} — registre agora para manter sua adesão.`,
        actions: [{ label: 'Registrar Agora', type: 'primary' }],
      })
    }

    return alerts.sort((a, b) => {
      const order = { critical: 0, warning: 1, info: 2 }
      return (order[a.severity] ?? 2) - (order[b.severity] ?? 2)
    })
  }, [stockSummary, zones, snoozedAlerts])

  // ── currentInsight: insight rotativo do insightService ──
  const currentInsight = useMemo(() => {
    if (!stats) return null
    const insight = insightService.selectBestInsight({
      stats: {
        score: stats.score ?? 0,
        currentStreak: stats.currentStreak ?? 0,
        longestStreak: stats.longestStreak ?? 0,
        adherence: stats.adherence ?? 0,
        activeProtocols: protocols?.filter((p) => p.active)?.length ?? 0,
      },
      dailyAdherence: [],
      stockSummary: stockSummary?.items ?? [],
      logs: logs ?? [],
      onNavigate,
    })
    return insight
  }, [stats, stockSummary, logs, protocols, onNavigate])

  // ── Carregar nome do usuário ──
  useEffect(() => {
    getCurrentUser()
      .then(async (user) => {
        if (!user) return

        // 1. Prioridade: display_name do perfil (user_settings)
        const { data: settings } = await supabase
          .from('user_settings')
          .select('display_name')
          .eq('user_id', user.id)
          .single()

        if (settings?.display_name) {
          setUserName(settings.display_name.split(' ')[0])
        } else if (user?.user_metadata?.full_name) {
          // 2. Fallback: nome do auth metadata
          setUserName(user.user_metadata.full_name.split(' ')[0])
        } else if (user?.email) {
          // 3. Fallback: prefixo do email
          setUserName(user.email.split('@')[0])
        }
      })
      .catch(() => {})
      .finally(() => setIsLoading(false))
  }, [])

  // ── Refresh automático ao virar o dia (timezone local) ──
  useEffect(() => {
    const interval = setInterval(() => {
      const currentDate = getTodayLocal()
      if (currentDate !== currentDateRef.current) {
        currentDateRef.current = currentDate
        refresh()
      }
    }, 60_000)
    return () => clearInterval(interval)
  }, [refresh])

  // ── Sugestão de lembrete calculada (sem setState em effect) ──
  // isSuggestionDismissed e analyzeReminderTiming são funções estáveis importadas (não reativas)
  const reminderSuggestionData = (() => {
    if (!protocols?.length || !logs?.length) return null
    for (const protocol of protocols) {
      if (!protocol.active) continue
      if (protocol.id === dismissedSuggestionId) continue
      if (isSuggestionDismissed(protocol.id)) continue
      const suggestion = analyzeReminderTiming({ protocol, logs })
      if (suggestion?.shouldSuggest) {
        return {
          suggestion,
          protocolId: protocol.id,
          protocolName: protocol.medicine?.name || protocol.name || '',
        }
      }
    }
    return null
  })()

  // ── Handlers ──
  // Registra dose DIRETAMENTE sem modal (1-click experience)
  const handleRegisterDoseQuick = useCallback(
    async (medicineId, protocolId, dosagePerIntake) => {
      try {
        await logService.create({
          medicine_id: medicineId,
          protocol_id: protocolId,
          quantity_taken: dosagePerIntake,
          taken_at: new Date().toISOString(),
        })
        analyticsService.track('dose_registered_quick', {
          timestamp: Date.now(),
          method: 'priority-card',
        })
        refresh()
      } catch (err) {
        console.error('Erro ao registrar dose:', err)
        alert('Erro ao registrar dose. Tente novamente.')
      }
    },
    [refresh]
  )

  // Registra múltiplas doses em batch (PriorityDoseCard com 2+ doses)
  const handleRegisterDosesAll = useCallback(
    async (doses) => {
      if (!doses || doses.length === 0) return
      try {
        for (const dose of doses) {
          await logService.create({
            medicine_id: dose.medicineId,
            protocol_id: dose.protocolId,
            quantity_taken: dose.dosagePerIntake,
            taken_at: new Date().toISOString(),
          })
        }
        analyticsService.track('doses_registered_batch', {
          timestamp: Date.now(),
          method: 'priority-card',
          count: doses.length,
        })
        refresh()
      } catch (err) {
        console.error('Erro ao registrar doses:', err)
        alert('Erro ao registrar doses. Tente novamente.')
      }
    },
    [refresh]
  )

  const handleSnoozeAlert = useCallback((alertId) => {
    setSnoozedAlerts((prev) => ({ ...prev, [alertId]: true }))
  }, [])

  const handleReminderAccept = useCallback(
    async (newTime) => {
      const protocolId = reminderSuggestionData?.protocolId
      const currentTime = reminderSuggestionData?.suggestion?.currentTime
      if (protocolId && newTime && currentTime) {
        // Atualiza time_schedule: substitui horário antigo pelo sugerido
        const protocol = protocols?.find((p) => p.id === protocolId)
        const currentSchedule = protocol?.time_schedule ?? []
        const updatedSchedule = currentSchedule.map((t) => (t === currentTime ? newTime : t))
        // Se o horário antigo não estava no array (edge case), adiciona o novo
        const finalSchedule = updatedSchedule.includes(newTime)
          ? updatedSchedule
          : [...updatedSchedule, newTime]
        try {
          await protocolService.update(protocolId, { time_schedule: finalSchedule })
        } catch (err) {
          console.error('[DashboardRedesign] Erro ao atualizar horário do protocolo:', err)
        }
      }
      if (protocolId) {
        // Persiste dispensa no localStorage (30 dias) para sobreviver ao reload
        dismissSuggestion(protocolId, false)
        setDismissedSuggestionId(protocolId)
      }
      refresh()
    },
    [refresh, reminderSuggestionData, protocols]
  )

  // ── Loading state ──
  if (isLoading || contextLoading) {
    return (
      <div
        style={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          minHeight: '50vh',
        }}
      >
        <Loading text="Carregando..." />
      </div>
    )
  }

  const adherenceScore = stats?.score ?? 0
  const streak = stats?.currentStreak ?? 0
  const today = new Date().toLocaleDateString('pt-BR', {
    weekday: 'long',
    day: 'numeric',
    month: 'long',
  })

  return (
    <div
      className="page-container"
      style={{ paddingTop: '1.5rem', paddingBottom: '2rem' }}
      aria-label="Dashboard — Dosiq"
    >
      {/* ─── Smart Alerts (substitui StockAlertInline no topo) ─── */}
      {smartAlerts.length > 0 && (
        <section style={{ marginBottom: '1.25rem' }} aria-label="Alertas inteligentes">
          <SmartAlertsRedesign
            alerts={smartAlerts}
            onAction={(alert, action) => {
              if (action.label === 'Registrar Compra') onNavigate?.('stock')
              if (action.label === 'Registrar Agora') onNavigate?.('dashboard')
            }}
            isComplex={complexityMode !== 'simple'}
            onSnooze={handleSnoozeAlert}
          />
        </section>
      )}

      {/* ─── 2-Column Grid: Left (Ring + Greeting + Priority) | Right (Schedule + Stock + Empty) ─── */}
      <div className="grid-dashboard">
        {/* ═══ LEFT COLUMN (1fr) ═══ */}
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            gap: '1.5rem',
            alignItems: 'center',
          }}
        >
          {/* Header + Ring de Adesão */}
          <div className="dr-badge">
            <div className="dr-badge__text">
              <h1
                style={{
                  margin: 0,
                  fontFamily: 'var(--font-display, Public Sans, sans-serif)',
                  fontSize: 'var(--text-headline-md, 1.75rem)',
                  fontWeight: '700',
                  color: 'var(--color-on-surface, #191c1d)',
                  lineHeight: 1.2,
                }}
              >
                {userName ? `Olá, ${userName} 👋` : 'Olá! 👋'}
              </h1>

              <p
                style={{
                  margin: '0.25rem 0 0',
                  fontFamily: 'var(--font-body, Lexend, sans-serif)',
                  fontSize: 'var(--text-label-md, 0.75rem)',
                  color: 'var(--color-outline, #6d7a76)',
                  textTransform: 'uppercase',
                  letterSpacing: '0.1em',
                  fontWeight: '600',
                }}
              >
                ADESÃO DIÁRIA
              </p>

              <p
                style={{
                  margin: '0.5rem 0 0',
                  fontFamily: 'var(--font-body, Lexend, sans-serif)',
                  fontSize: 'var(--text-body-lg, 1rem)',
                  color: 'var(--color-on-surface-variant, #3e4946)',
                }}
              >
                {getMotivationalMessage(adherenceScore, totals.remaining)}
              </p>
            </div>

            <RingGaugeRedesign score={adherenceScore} streak={streak} size="large" />
          </div>

          {/* Priority Dose Card — 1-Click Registration */}
          {urgentDoses.length > 0 && (
            <div style={{ width: '100%' }}>
              <PriorityDoseCard
                doses={urgentDoses}
                onRegister={(dose) =>
                  handleRegisterDoseQuick(dose.medicineId, dose.protocolId, dose.dosagePerIntake)
                }
                onRegisterAll={handleRegisterDosesAll}
                variant="priority"
              />
            </div>
          )}

          {/* 🆕 Insight Card — coluna esquerda, sob o PriorityDoseCard */}
          {currentInsight && (
            <div style={{ width: '100%' }}>
              <InsightCardRedesign
                insight={currentInsight}
                onAction={(insight) => {
                  if (insight.action?.navigate) onNavigate?.(insight.action.navigate)
                }}
                onDismiss={() => {}}
              />
            </div>
          )}

          {/* 🆕 Reminder Suggestion — coluna esquerda, sob o InsightCard */}
          {reminderSuggestionData && (
            <div style={{ width: '100%' }}>
              <ReminderSuggestionRedesign
                suggestion={reminderSuggestionData.suggestion}
                protocolId={reminderSuggestionData.protocolId}
                protocolName={reminderSuggestionData.protocolName}
                onAccept={handleReminderAccept}
                onDismiss={() => setDismissedSuggestionId(reminderSuggestionData.protocolId)}
              />
            </div>
          )}
        </div>

        {/* ═══ RIGHT COLUMN (2fr) ═══ */}
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            gap: '1.5rem',
          }}
        >
          {/* Cronograma do Dia */}
          {scheduleAllDoses.length > 0 && (
            <section aria-label="Cronograma de hoje">
              <div style={{ marginBottom: '1rem' }}>
                <h2
                  style={{
                    margin: 0,
                    fontFamily: 'var(--font-display, Public Sans, sans-serif)',
                    fontSize: 'var(--text-title-lg, 1.125rem)',
                    fontWeight: '600',
                    color: 'var(--color-on-surface, #191c1d)',
                  }}
                >
                  Cronograma de Hoje
                </h2>
                <p
                  style={{
                    margin: '0.25rem 0 0',
                    fontFamily: 'var(--font-body, Lexend, sans-serif)',
                    fontSize: 'var(--text-label-md, 0.75rem)',
                    color: 'var(--color-outline, #6d7a76)',
                    textTransform: 'uppercase',
                    letterSpacing: '0.1em',
                    fontWeight: '600',
                  }}
                >
                  {today}
                </p>
              </div>
              <CronogramaPeriodo
                allDoses={scheduleAllDoses}
                onRegister={(dose) =>
                  handleRegisterDoseQuick(dose.medicineId, dose.protocolId, dose.dosagePerIntake)
                }
                variant={complexityMode === 'simple' ? 'simple' : 'complex'}
                now={now}
              />
            </section>
          )}

          {/* Empty State */}
          {scheduleAllDoses.length === 0 && !contextLoading && (
            <div
              style={{
                textAlign: 'center',
                padding: '3rem 1rem',
                color: 'var(--color-outline, #6d7a76)',
              }}
              role="status"
            >
              <p style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>💊</p>
              <p
                style={{
                  fontFamily: 'var(--font-body, Lexend, sans-serif)',
                  fontSize: 'var(--text-body-lg, 1rem)',
                }}
              >
                Nenhuma dose agendada para hoje.
              </p>
              <button
                onClick={() => onNavigate?.('medicines')}
                style={{
                  marginTop: '1rem',
                  padding: '0.625rem 1.125rem',
                  minHeight: '3.5rem',
                  background: 'var(--gradient-primary, linear-gradient(135deg, #006a5e, #008577))',
                  color: '#ffffff',
                  border: 'none',
                  borderRadius: 'var(--radius-button, 1.25rem)',
                  fontFamily: 'var(--font-body, Lexend, sans-serif)',
                  fontWeight: '600',
                  cursor: 'pointer',
                }}
              >
                Adicionar Medicamento
              </button>
            </div>
          )}

          {/* Stock Alert (Simple Mode: Bottom) */}
          {complexityMode !== 'complex' && criticalStockItems.length > 0 && (
            <section style={{ marginTop: 'auto' }} aria-label="Alertas de estoque">
              <StockAlertInline
                criticalItems={criticalStockItems}
                onNavigateToStock={() => onNavigate?.('stock')}
              />
            </section>
          )}
        </div>
      </div>
    </div>
  )
}

// src/views/redesign/HealthHistoryRedesign.jsx
// Wave 10C — Rewrite completo: componente independente calendar-driven (sem Virtuoso, sem wrapper)

import { useState, useEffect, useCallback, useMemo, useRef, lazy, Suspense } from 'react'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import { useComplexityMode } from '@dashboard/hooks/useComplexityMode'
import { cachedLogService as logService } from '@shared/services'
import { cachedAdherenceService as adherenceService } from '@shared/services'
import { formatLocalDate, parseLocalDate } from '@utils/dateUtils'
import Calendar from '@shared/components/ui/Calendar'
import Modal from '@shared/components/ui/Modal'
import LogForm from '@shared/components/log/LogForm'
import HistoryKPICards from './history/HistoryKPICards'
import HistoryDayPanel from './history/HistoryDayPanel'
import './history/HistoryRedesign.css'

// Lazy: só carrega em modo complex
const SparklineAdesao = lazy(() => import('@dashboard/components/SparklineAdesao'))
const AdherenceHeatmap = lazy(() => import('@adherence/components/AdherenceHeatmap'))

/**
 * Histórico de Doses — Calendar-Driven.
 *
 * Paradigma: calendário é o controle principal de navegação.
 * Fluxo: Selecionar mês → Clicar dia → Ver doses → Editar/Deletar.
 *
 * Performance: 1 query por mês (getByMonthSlim), dados carregados on-demand.
 * SEM Virtuoso, SEM scroll infinito, SEM paginação global.
 *
 * @param {Object} props
 * @param {Function} props.onNavigate - Callback de navegação (para 'profile', etc.)
 */
export default function HealthHistory({ onNavigate }) {
  // ═══ States ═══
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)
  const [successMessage, setSuccessMessage] = useState('')
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [editingLog, setEditingLog] = useState(null)
  const [selectedDate, setSelectedDate] = useState(new Date())
  const [currentMonthLogs, setCurrentMonthLogs] = useState([])
  const [, setTotalLogs] = useState(0)

  // Dados para modo complex (sparkline + heatmap)
  const [dailyAdherence, setDailyAdherence] = useState([])
  const [adherencePattern, setAdherencePattern] = useState(null)

  // ═══ Context ═══
  const { protocols, stats, refresh } = useDashboard()
  const { mode: complexityMode } = useComplexityMode()
  const isComplex = complexityMode === 'complex'

  // ═══ Refs ═══
  const patternLoadedRef = useRef(false)

  // ═══ Memos ═══

  // Planos de tratamento (para LogForm)
  const treatmentPlans = useMemo(() => {
    const planMap = new Map()
    protocols.forEach((p) => {
      if (p.treatment_plan_id) {
        planMap.set(p.treatment_plan_id, true)
      }
    })
    return Array.from(planMap.keys())
  }, [protocols])

  // Doses do dia selecionado — filtra dos logs do mês carregado, ordenados ascendente
  const dayLogs = useMemo(() => {
    const d = selectedDate || new Date()
    return currentMonthLogs
      .filter((log) => {
        const logDate = new Date(log.taken_at)
        return (
          logDate.getFullYear() === d.getFullYear() &&
          logDate.getMonth() === d.getMonth() &&
          logDate.getDate() === d.getDate()
        )
      })
      .sort((a, b) => new Date(a.taken_at) - new Date(b.taken_at))
  }, [currentMonthLogs, selectedDate])

  // Datas marcadas no calendário (array de strings 'YYYY-MM-DD')
  const markedDates = useMemo(
    () => currentMonthLogs.map((log) => formatLocalDate(new Date(log.taken_at))),
    [currentMonthLogs]
  )

  // Contadores do mês (para KPI "Doses este Mês")
  const dosesThisMonth = useMemo(() => currentMonthLogs.length, [currentMonthLogs])

  // ═══ Effects ═══

  const loadData = useCallback(async () => {
    try {
      setIsLoading(true)
      setError(null)
      const now = new Date()

      // Phase 1: UI-critical — logs do mês atual (calendário + day panel)
      const logsResult = await logService.getByMonthSlim(now.getFullYear(), now.getMonth())
      setCurrentMonthLogs(logsResult.data || [])
      setTotalLogs(logsResult.total || 0)

      // Selecionar dia mais recente com dose (ou hoje)
      if (logsResult.data?.length > 0) {
        setSelectedDate(new Date(logsResult.data[0].taken_at))
      }

      // UI fica interativa AQUI
      setIsLoading(false)

      // Phase 2: Dados deferidos (só se complex)
      if (isComplex) {
        const scheduleIdle = window.requestIdleCallback || ((cb) => setTimeout(cb, 100))
        scheduleIdle(async () => {
          try {
            const daily = await adherenceService.getDailyAdherenceFromView(90)
            setDailyAdherence(daily)
          } catch (err) {
            console.error('[HistoryRedesign] Erro daily adherence:', err.message)
          }

          // Heatmap: carregar direto (sem IntersectionObserver)
          if (!patternLoadedRef.current) {
            try {
              const pattern = await adherenceService.getAdherencePatternFromView()
              setAdherencePattern(pattern)
              patternLoadedRef.current = true
            } catch (err) {
              console.error('[HistoryRedesign] Erro pattern:', err.message)
            }
          }
        })
      }
    } catch (err) {
      setError('Erro ao carregar dados: ' + err.message)
      setIsLoading(false)
    }
  }, [isComplex])

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    loadData()
  }, [loadData])

  // Escuta evento global de dose salva (GlobalDoseModal) para recarregar
  useEffect(() => {
    const handleDoseSaved = () => loadData()
    window.addEventListener('mr:dose-saved', handleDoseSaved)
    return () => window.removeEventListener('mr:dose-saved', handleDoseSaved)
  }, [loadData])

  // ═══ Handlers ═══

  const showSuccess = useCallback((msg) => {
    setSuccessMessage(msg)
    setTimeout(() => setSuccessMessage(''), 3000)
  }, [])

  const handleCalendarLoadMonth = useCallback(async (year, month) => {
    try {
      const result = await logService.getByMonthSlim(year, month)
      setCurrentMonthLogs(result.data || [])
      setTotalLogs(result.total || 0)
      // Selecionar primeiro dia com dose no novo mês, ou dia 1
      if (result.data?.length > 0) {
        setSelectedDate(new Date(result.data[0].taken_at))
      } else {
        setSelectedDate(parseLocalDate(`${year}-${String(month + 1).padStart(2, '0')}-01`))
      }
      return result
    } catch (err) {
      console.error('[HistoryRedesign] Erro ao carregar mês:', err)
      return { data: [], total: 0 }
    }
  }, [])

  const handleDayClick = useCallback((date) => {
    setSelectedDate(date)
  }, [])

  const handleLogMedicine = useCallback(
    async (logData) => {
      try {
        if (logData.id) {
          await logService.update(logData.id, logData)
          showSuccess('Registro atualizado!')
        } else if (Array.isArray(logData)) {
          await logService.createBulk(logData)
          showSuccess('Plano registrado!')
        } else {
          await logService.create(logData)
          showSuccess('Dose registrada!')
        }
        setIsModalOpen(false)
        setEditingLog(null)
        await loadData()
        refresh()
      } catch (err) {
        console.error('[HistoryRedesign] Erro ao salvar/atualizar log:', err)
        throw new Error(err.message)
      }
    },
    [loadData, refresh, showSuccess]
  )

  const handleDeleteLog = useCallback(
    async (id) => {
      try {
        await logService.delete(id)
        showSuccess('Registro removido!')
        // Remover do state local (otimismo) — evita reload completo
        setCurrentMonthLogs((prev) => prev.filter((log) => log.id !== id))
        setTotalLogs((prev) => Math.max(0, prev - 1))
        refresh()
      } catch (err) {
        setError('Erro ao remover: ' + err.message)
      }
    },
    [refresh, showSuccess]
  )

  const handleEditClick = useCallback((log) => {
    setEditingLog(log)
    setIsModalOpen(true)
  }, [])

  // ═══ Render ═══

  if (isLoading) {
    return (
      <div className="hhr-view">
        <div className="hhr-loading">
          <div className="hhr-loading__spinner" />
          <span>Carregando histórico...</span>
        </div>
      </div>
    )
  }

  return (
    <div className="hhr-view">
      {/* ── Header ── */}
      <div className="hhr-header">
        {onNavigate && (
          <button
            className="hhr-back-btn"
            onClick={() => onNavigate('profile')}
            aria-label="Voltar"
          >
            ← Voltar
          </button>
        )}
        <h1 className="hhr-header__title">Histórico de Doses</h1>
        <p className="hhr-header__subtitle">
          Acompanhe sua jornada de saúde e adesão ao tratamento.
        </p>
      </div>

      {/* ── Feedback messages ── */}
      {successMessage && <div className="hhr-banner hhr-banner--success">{successMessage}</div>}
      {error && <div className="hhr-banner hhr-banner--error">{error}</div>}

      {/* ── KPI Cards ── */}
      <HistoryKPICards
        adherenceScore={stats?.score ?? 0}
        currentStreak={stats?.currentStreak ?? 0}
        dosesThisMonth={dosesThisMonth}
      />

      {/* ── Calendar + Day Panel ── */}
      <div className="hhr-calendar-section">
        <div className="hhr-calendar-card">
          <Calendar
            selectedDate={selectedDate}
            onDayClick={handleDayClick}
            onLoadMonth={handleCalendarLoadMonth}
            markedDates={markedDates}
            enableLazyLoad={true}
            enableSwipe={true}
            enableMonthPicker={true}
          />
        </div>

        <HistoryDayPanel
          selectedDate={selectedDate}
          dayLogs={dayLogs}
          onEditLog={handleEditClick}
          onDeleteLog={handleDeleteLog}
        />
      </div>

      {/* ── Sparkline 30d (complex only) ── */}
      {isComplex && dailyAdherence.length > 0 && (
        <div className="hhr-chart-card">
          <h3 className="hhr-section-title">Adesão 30 Dias</h3>
          <Suspense fallback={<div className="hhr-chart-skeleton" aria-busy="true" />}>
            <SparklineAdesao adherenceByDay={dailyAdherence} size="expanded" />
          </Suspense>
        </div>
      )}

      {/* ── Adherence Heatmap (complex only) ── */}
      {isComplex && adherencePattern && (
        <div className="hhr-chart-card">
          <h3 className="hhr-section-title">Padrão por Período</h3>
          <Suspense fallback={<div className="hhr-chart-skeleton" aria-busy="true" />}>
            <AdherenceHeatmap pattern={adherencePattern} />
          </Suspense>
        </div>
      )}

      {/* ── Modal de edição ── */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setEditingLog(null)
        }}
      >
        <LogForm
          protocols={protocols}
          treatmentPlans={treatmentPlans}
          initialValues={editingLog}
          onSave={handleLogMedicine}
          onCancel={() => {
            setIsModalOpen(false)
            setEditingLog(null)
          }}
        />
      </Modal>
    </div>
  )
}

import { useState, useMemo, useCallback } from 'react'
import { Pill, Plus, CheckCircle2, AlertCircle } from 'lucide-react'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import { medicineService } from '@shared/services'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import EmptyState from '@shared/components/ui/EmptyState'
import MedicineForm from '@medications/components/MedicineForm'
import MedicineCardRedesign from '@medications/components/redesign/MedicineCardRedesign'
import ConfirmDialog from '@shared/components/ui/ConfirmDialog'
import './Medicines.css'

export default function Medicines({ onNavigateToProtocol }) {
  // 1. Context & Memos
  const {
    medicines: contextMedicines,
    protocols,
    stockSummary,
    isLoading,
    refresh,
  } = useDashboard()

  // 2. States
  const [error, setError] = useState(null)
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [editingMedicine, setEditingMedicine] = useState(null)
  const [successMessage, setSuccessMessage] = useState('')
  const [filterType, setFilterType] = useState('all')
  const [deleteTarget, setDeleteTarget] = useState(null)
  const [showProtocolPrompt, setShowProtocolPrompt] = useState(false)
  const [newMedicineId, setNewMedicineId] = useState(null)

  // 3. Calculate dependencies from dashboard context in-memory
  const medicineDependencies = useMemo(() => {
    const deps = {}
    if (!contextMedicines || !protocols || !stockSummary) return deps

    contextMedicines.forEach((med) => {
      const hasProtocols = protocols.some((p) => p.medicine_id === med.id)
      const hasStock = stockSummary.some((s) => s.medicine_id === med.id)
      deps[med.id] = { hasProtocols, hasStock }
    })
    return deps
  }, [contextMedicines, protocols, stockSummary])

  // 3. Feedback handlers
  const showSuccess = (msg) => {
    setSuccessMessage(msg)
    setTimeout(() => setSuccessMessage(''), 3000)
  }

  // 4. Action handlers
  const handleAdd = () => {
    setEditingMedicine(null)
    setIsModalOpen(true)
  }

  const handleEdit = (medicine) => {
    setEditingMedicine(medicine)
    setIsModalOpen(true)
  }

  const handleSave = useCallback(
    async (medicineData) => {
      try {
        if (editingMedicine) {
          await medicineService.update(editingMedicine.id, medicineData)
          showSuccess('Medicamento atualizado com sucesso!')
        } else {
          const newMedicine = await medicineService.create(medicineData)
          showSuccess('Medicamento cadastrado com sucesso!')
          // Show protocol prompt instead of window.confirm()
          setNewMedicineId(newMedicine.id)
          setShowProtocolPrompt(true)
          setIsModalOpen(false)
          setEditingMedicine(null)
          refresh({ force: true })
          return // Don't close modal yet after refetch
        }
        setIsModalOpen(false)
        setEditingMedicine(null)
        refresh({ force: true })
      } catch (err) {
        setError('Erro ao salvar medicamento: ' + err.message)
      }
    },
    [editingMedicine, refresh]
  )

  const handleDeleteRequest = useCallback((medicine) => {
    setDeleteTarget(medicine)
  }, [])

  const handleDeleteConfirm = useCallback(async () => {
    if (!deleteTarget) return
    try {
      await medicineService.delete(deleteTarget.id)
      showSuccess('Medicamento excluído com sucesso!')
      refresh({ force: true })
    } catch (err) {
      setError('Erro ao excluir medicamento: ' + err.message)
    } finally {
      setDeleteTarget(null)
    }
  }, [deleteTarget, refresh])

  const handleProtocolPromptConfirm = () => {
    setShowProtocolPrompt(false)
    if (onNavigateToProtocol && newMedicineId) {
      onNavigateToProtocol(newMedicineId)
    }
    setNewMedicineId(null)
  }

  const handleProtocolPromptCancel = useCallback(() => {
    setShowProtocolPrompt(false)
    setNewMedicineId(null)
    setIsModalOpen(false)
    setEditingMedicine(null)
  }, [])

  // 5. Derived state
  const filteredMedicines = useMemo(
    () => contextMedicines?.filter((m) => filterType === 'all' || m.type === filterType) || [],
    [contextMedicines, filterType]
  )

  if (isLoading) {
    return (
      <div className="sr-medicines">
        <Loading text="Carregando medicamentos..." />
      </div>
    )
  }

  return (
    <div className="sr-medicines">
      {/* Header */}
      <div className="sr-medicines__header">
        <div>
          <div className="sr-medicines__title-group">
            <div className="sr-medicines__title-icon">
              <Pill size={22} />
            </div>
            <h2 className="sr-medicines__title">Medicamentos</h2>
          </div>
          <p className="sr-medicines__subtitle">Gerencie seus medicamentos cadastrados</p>
        </div>
        <button className="btn-primary" onClick={handleAdd}>
          <Plus size={18} /> Adicionar
        </button>
      </div>

      {/* Filter Chips */}
      <div className="sr-medicines__filters">
        {[
          { key: 'all', label: 'Todos' },
          { key: 'medicamento', label: 'Medicamentos' },
          { key: 'suplemento', label: 'Suplementos' },
        ].map(({ key, label }) => (
          <button
            key={key}
            className={`sr-filter-chip ${filterType === key ? 'sr-filter-chip--active' : ''}`}
            onClick={() => setFilterType(key)}
          >
            {label}
          </button>
        ))}
      </div>

      {/* Feedback Banners */}
      {successMessage && (
        <div className="sr-medicines__success">
          <CheckCircle2 size={18} /> {successMessage}
        </div>
      )}
      {error && (
        <div className="sr-medicines__error">
          <AlertCircle size={18} /> {error}
        </div>
      )}

      {/* Content */}
      {contextMedicines?.length === 0 ? (
        <EmptyState
          illustration="protocols"
          title="Nenhum medicamento cadastrado"
          description="Cadastre seus medicamentos para começar a controlar sua saúde"
          ctaLabel="Cadastrar Medicamento"
          onCtaClick={handleAdd}
        />
      ) : (
        <div className="sr-medicines__grid">
          {filteredMedicines.map((medicine) => (
            <MedicineCardRedesign
              key={medicine.id}
              medicine={medicine}
              onEdit={handleEdit}
              onDelete={handleDeleteRequest}
              hasDependencies={
                medicineDependencies[medicine.id]?.hasProtocols ||
                medicineDependencies[medicine.id]?.hasStock
              }
            />
          ))}
        </div>
      )}

      {/* Modal: Edit/Create */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setEditingMedicine(null)
        }}
      >
        <MedicineForm
          medicine={editingMedicine}
          onSave={handleSave}
          onCancel={() => {
            setIsModalOpen(false)
            setEditingMedicine(null)
          }}
        />
      </Modal>

      {/* ConfirmDialog: Delete */}
      <ConfirmDialog
        isOpen={!!deleteTarget}
        title={`Excluir "${deleteTarget?.name}"?`}
        message={
          medicineDependencies[deleteTarget?.id]?.hasProtocols ||
          medicineDependencies[deleteTarget?.id]?.hasStock
            ? 'Este medicamento possui tratamentos e/ou estoque associados. Esta ação não pode ser desfeita.'
            : 'Esta ação não pode ser desfeita.'
        }
        confirmLabel="Excluir"
        variant="danger"
        onConfirm={handleDeleteConfirm}
        onCancel={() => setDeleteTarget(null)}
      />

      {/* ConfirmDialog: Create Protocol Prompt */}
      <ConfirmDialog
        isOpen={showProtocolPrompt}
        title="Medicamento criado!"
        message="Deseja criar um tratamento para ele agora?"
        confirmLabel="Criar Tratamento"
        cancelLabel="Depois"
        variant="default"
        onConfirm={handleProtocolPromptConfirm}
        onCancel={handleProtocolPromptCancel}
      />
    </div>
  )
}

// src/views/redesign/ProfileRedesign.jsx
// Wave 10B — Profile Hub (rewrite completo)
// View centralizada: identidade + dados críticos + ferramentas de gestão

import { useState, useEffect, useCallback, useMemo } from 'react'
import {
  Settings,
  MapPinHouse,
  Phone,
  BriefcaseMedical,
  ClipboardPlus,
  History,
  CloudDownload,
} from 'lucide-react'
import QRCode from 'qrcode'
import { supabase } from '@shared/utils/supabase'
import { parseLocalDate } from '@utils/dateUtils'
import { validateUserProfile, BRAZILIAN_STATES } from '@schemas/userProfileSchema'
import { emergencyCardService } from '@features/emergency/services/emergencyCardService'
import Button from '@shared/components/ui/Button'
import Modal from '@shared/components/ui/Modal'
import Loading from '@shared/components/ui/Loading'
import ExportDialog from '@features/export/components/ExportDialog'
import ReportGenerator from '@features/reports/components/ReportGenerator'
import './profile/ProfileRedesign.css'

/**
 * Converte string JSON para base64 sem usar unescape() (deprecated)
 * @param {string} jsonString - JSON string a codificar
 * @returns {string} Base64 encoded string
 */
function jsonToBase64(jsonString) {
  return btoa(
    encodeURIComponent(jsonString).replace(/%([0-9A-F]{2})/g, (match, p1) =>
      String.fromCharCode(parseInt(p1, 16))
    )
  )
}

/**
 * ProfileRedesign — Hub centralizado do Perfil
 * @param {Object} props
 * @param {Function} props.onNavigate - Callback para navegação
 */
export default function Profile({ onNavigate }) {
  // ═══ States ═══
  // User & data
  const [user, setUser] = useState(null)
  const [settings, setSettings] = useState(null)
  const [emergencyCard, setEmergencyCard] = useState(null)
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)
  const [qrMiniatureUrl, setQrMiniatureUrl] = useState(null)

  // Edit profile
  const [isEditingProfile, setIsEditingProfile] = useState(false)
  const [profileForm, setProfileForm] = useState({
    display_name: '',
    birth_date: '',
    city: '',
    state: '',
  })
  const [isSaving, setIsSaving] = useState(false)
  const [message, setMessage] = useState(null)

  // Modais de ferramentas
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false)
  const [isReportModalOpen, setIsReportModalOpen] = useState(false)

  // ═══ Helper Functions ═══
  const showFeedback = useCallback((msg) => {
    setMessage(msg)
    setTimeout(() => setMessage(null), 3000)
  }, [])

  // ═══ Data Loading ═══
  const loadProfile = useCallback(async () => {
    try {
      setIsLoading(true)

      // 1. Fetch auth user
      const {
        data: { user },
      } = await supabase.auth.getUser()
      if (!user) throw new Error('Usuário não autenticado')

      // 2. Fetch user_settings (inclui novas colunas de perfil)
      const { data: settingsData } = await supabase
        .from('user_settings')
        .select('*')
        .eq('user_id', user.id)
        .single()

      let settings = settingsData ?? {}

      // 3. Migrate display_name if null (one-time)
      // Copia de auth.user_metadata.name se existir
      if (settings && !settings.display_name && user.user_metadata?.name) {
        const { error: updateError } = await supabase
          .from('user_settings')
          .update({
            display_name: user.user_metadata.name,
            updated_at: new Date().toISOString(),
          })
          .eq('user_id', user.id)

        if (!updateError) {
          settings.display_name = user.user_metadata.name
        }
      }

      // 4. Load emergency card data (offline-first via localStorage)
      const cardResult = await emergencyCardService.load()
      const cardData = cardResult.success ? cardResult.data : null

      // 5. One-time sync: localStorage → Supabase (corrige dívida técnica)
      // Se dados vieram de localStorage mas não existem em Supabase,
      // re-salva para ativar write-through que agora funciona (coluna recém-criada)
      if (cardData && cardResult.source === 'local' && settings && !settings.emergency_card) {
        // Fire and forget — não bloqueia o carregamento
        emergencyCardService.save(cardData)
      }

      setUser(user)
      setSettings(settings)
      setEmergencyCard(cardData)

      // 6. Initialize form with current data
      setProfileForm({
        display_name: settings?.display_name || user.user_metadata?.name || '',
        birth_date: settings?.birth_date || '',
        city: settings?.city || '',
        state: settings?.state || '',
      })
    } catch (err) {
      console.error('[ProfileRedesign] Error loading profile:', err)
      setError('Erro ao carregar perfil: ' + err.message)
    } finally {
      setIsLoading(false)
    }
  }, [])

  // ═══ Derived Data ═══
  // Nome de exibição
  const displayName = useMemo(
    () => settings?.display_name || user?.user_metadata?.name || user?.email || 'Paciente',
    [settings?.display_name, user]
  )

  // Iniciais para avatar
  const initials = useMemo(
    () =>
      displayName
        .split(' ')
        .filter(Boolean)
        .slice(0, 2)
        .map((w) => w[0].toUpperCase())
        .join(''),
    [displayName]
  )

  // Idade calculada
  const age = useMemo(() => {
    if (!settings?.birth_date) return null
    try {
      const birth = parseLocalDate(settings.birth_date)
      const today = new Date()
      let years = today.getFullYear() - birth.getFullYear()
      const monthDiff = today.getMonth() - birth.getMonth()
      if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birth.getDate())) {
        years--
      }
      return years >= 0 ? years : null
    } catch (err) {
      console.error('[ProfileRedesign] Falha ao calcular idade:', err)
      return null
    }
  }, [settings?.birth_date])

  // Tipo sanguíneo
  const bloodType = useMemo(() => emergencyCard?.blood_type, [emergencyCard])

  // Localização
  const location = useMemo(() => {
    const parts = [settings?.city, settings?.state].filter(Boolean)
    return parts.length > 0 ? parts.join(', ') : null
  }, [settings])

  // ═══ Effects ═══
  useEffect(() => {
    loadProfile()
  }, [loadProfile])

  // Gerar QR code miniatura quando emergencyCard mudar
  useEffect(() => {
    if (!emergencyCard) {
      setQrMiniatureUrl(null)
      return
    }

    const generateMiniatureQR = async () => {
      try {
        // Formato compacto para QR code (mesma estrutura do EmergencyQRCode)
        const payload = {
          v: '1',
          n: displayName,
          bt: emergencyCard.blood_type || '',
          a: emergencyCard.allergies?.join(', ') || '',
          c: emergencyCard.emergency_contacts?.[0]
            ? `${emergencyCard.emergency_contacts[0].name} - ${emergencyCard.emergency_contacts[0].phone}`
            : '',
        }
        const qrString = jsonToBase64(JSON.stringify(payload))
        const miniatureUrl = await QRCode.toDataURL(qrString, {
          width: 100,
          margin: 1,
          color: { dark: '#000000', light: '#FFFFFF' },
          errorCorrectionLevel: 'L',
          type: 'image/png',
        })
        setQrMiniatureUrl(miniatureUrl)
      } catch (err) {
        console.error('[ProfileRedesign] Erro ao gerar QR miniatura:', err)
        setQrMiniatureUrl(null)
      }
    }

    generateMiniatureQR()
  }, [emergencyCard, displayName])

  // ═══ Handlers ═══
  const handleSaveProfile = useCallback(
    async (e) => {
      e.preventDefault()

      const validation = validateUserProfile(profileForm)
      if (!validation.success) {
        setError(validation.errors[0]?.message || 'Erro de validação')
        return
      }

      setIsSaving(true)
      setError(null)

      try {
        const { error: upsertError } = await supabase.from('user_settings').upsert(
          {
            user_id: user.id,
            ...validation.data,
            updated_at: new Date().toISOString(),
          },
          { onConflict: 'user_id' }
        )

        if (upsertError) throw upsertError

        // Update local state
        setSettings((prev) => ({ ...prev, ...validation.data }))
        setIsEditingProfile(false)
        showFeedback('Perfil atualizado com sucesso!')
      } catch (err) {
        console.error('[ProfileRedesign] Error saving profile:', err)
        setError('Erro ao salvar perfil: ' + err.message)
      } finally {
        setIsSaving(false)
      }
    },
    [profileForm, user?.id, showFeedback]
  )

  // ═══ Render Loading ═══
  if (isLoading) {
    return <Loading />
  }

  // ═══ Render Main ═══
  return (
    <div className="ph-view">
      {/* ── Header com gear (Profile é view mestra, sem back) ── */}
      <div className="ph-mobile-header">
        <h1 className="ph-mobile-header__title">Perfil</h1>
        <button
          className="ph-mobile-header__settings"
          onClick={() => onNavigate('settings')}
          aria-label="Configurações"
          type="button"
        >
          <Settings size={24} />
        </button>
      </div>

      {/* ── Feedback messages ── */}
      {message && <div className="ph-message ph-message--success">{message}</div>}
      {error && <div className="ph-message ph-message--error">{error}</div>}

      {/* ── Header do Perfil ── */}
      <ProfileHeader
        initials={initials}
        displayName={displayName}
        age={age}
        bloodType={bloodType}
        location={location}
        onEditClick={() => setIsEditingProfile(true)}
      />

      {/* ── Cards principais (Emergency + Consulta) ── */}
      <div className="ph-cards-row">
        <EmergencyCard
          emergencyCard={emergencyCard}
          qrMiniatureUrl={qrMiniatureUrl}
          onNavigate={onNavigate}
        />
        <ConsultationCard onNavigate={onNavigate} />
      </div>

      {/* ── Ferramentas de Gestão ── */}
      <section className="ph-tools">
        <h2 className="ph-tools__title">Ferramentas de Gestão</h2>
        <div className="ph-tools__grid">
          <ToolCard
            icon={ClipboardPlus}
            label="Relatório PDF"
            description="Gerar relatório completo dos últimos 30 dias"
            onClick={() => setIsReportModalOpen(true)}
          />
          <ToolCard
            icon={History}
            label="Histórico de Doses"
            description="Calendário, adesão e heatmap"
            onClick={() => onNavigate('health-history')}
          />
          <ToolCard
            icon={CloudDownload}
            label="Exportar Dados"
            description="Formato CSV ou JSON para outros sistemas"
            onClick={() => setIsExportDialogOpen(true)}
          />
        </div>
      </section>

      {/* ── Modais ── */}
      <EditProfileModal
        isOpen={isEditingProfile}
        onClose={() => setIsEditingProfile(false)}
        profileForm={profileForm}
        setProfileForm={setProfileForm}
        handleSaveProfile={handleSaveProfile}
        isSaving={isSaving}
      />
      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)}>
        <ReportGenerator onClose={() => setIsReportModalOpen(false)} />
      </Modal>
      <ExportDialog isOpen={isExportDialogOpen} onClose={() => setIsExportDialogOpen(false)} />
    </div>
  )
}

