      ],
      scheduledDoses: [
        { id: '4', scheduledTime: '13:00', name: 'Remédio D' }, // Em 1h (PROXIMA)
        { id: '5', scheduledTime: '15:00', name: 'Remédio E' }, // Em 3h (PLANEJADA)
      ],
    }

    const result = evaluateDoseTimelineState(date, dosesObj, now)

