/**
 * Formata uma data ISO em texto relativo legível (pt-BR).
 *
 * @param {string} isoString - Data ISO do campo sent_at
 * @returns {string}
 */
export function formatRelativeTime(isoString) {
  if (!isoString) return ''
  const now = Date.now()
  const then = new Date(isoString).getTime()
  const diff = now - then

  const minute = 60 * 1000
  const hour   = 60 * minute
  const day    = 24 * hour
  const week   = 7 * day

  if (diff < minute)    return 'agora'
  if (diff < hour)      return `há ${Math.floor(diff / minute)}min`
  if (diff < 2 * hour)  return 'há 1h'
  if (diff < day)       return `há ${Math.floor(diff / hour)}h`
  if (diff < 2 * day)   return 'ontem'
  if (diff < week)      return `há ${Math.floor(diff / day)} dias`

  return new Date(isoString).toLocaleDateString('pt-BR', {
    day: 'numeric',
    month: 'short',
  })
}

export function calculateTitrationData(protocol) {
  if (!protocol.titration_schedule || protocol.titration_schedule.length === 0) return null
  if (!protocol.stage_started_at) return null

  const currentStageIndex = protocol.current_stage_index || 0
  const schedule = protocol.titration_schedule

  // Safety check
  if (currentStageIndex >= schedule.length) return null

  const currentStage = schedule[currentStageIndex]
  const startDate = new Date(protocol.stage_started_at)
  const today = new Date()

  // Calculate days elapsed (difference in time / milliseconds per day)
  const diffTime = Math.abs(today - startDate)
  const daysElapsed = Math.ceil(diffTime / (1000 * 60 * 60 * 24))

  // Clamp day to at least 1
  const currentDay = Math.max(1, daysElapsed)
  const totalDays = currentStage.days

  // Calculate progress percent (capped at 100)
  const progressPercent = Math.min(100, (currentDay / totalDays) * 100)

  const isTransitionDue = currentDay > totalDays // Or >= depending on logic. Let's say > implies finished yesterday.

  return {
    currentStep: currentStageIndex + 1,
    totalSteps: schedule.length,
    day: Math.min(currentDay, totalDays), // visual cap
    realDay: currentDay,
    totalDays: totalDays,
    progressPercent: progressPercent,
    isTransitionDue: isTransitionDue,
    stageNote: currentStage.note,
    daysRemaining: totalDays - currentDay,
  }
}

/**
 * createQueryCache — Engine de cache SWR compartilhada (platform-agnostic)
 *
 * Design:
 * - Factory function: sem singleton global, sem inicializacao em import
 * - Storage injetado: funciona com web localStorage, AsyncStorage, memoryStorage
 * - Logger injetado: sem dependencia de console/debugLog especifico da plataforma
 * - React-free: a engine nao importa React — hooks ficam na plataforma
 * - Async-first: persiste/hidrata via storage adapter async (contratos H3.1)
 *
 * Regra: NUNCA chamar `init()` fora do bootstrap da plataforma.
 *
 * @module createQueryCache
 */

import { setJSON, getJSON } from '@dosiq/storage'

/**
 * Cria uma instancia de query cache com dependencias injetadas.
 *
 * @param {Object} options
 * @param {import('@dosiq/storage').StorageAdapter} options.storage - Adapter de storage async
 * @param {Object} [options.logger] - Logger opcional com metodo log/warn/error
 * @param {number} [options.staleTime=30000] - Tempo (ms) antes de um entry ficar stale
 * @param {number} [options.maxEntries=200] - Maximo de entradas no cache (LRU eviction)
 * @param {string} [options.persistKey='dosiq_query_cache'] - Chave de persistencia
 * @returns {QueryCache} Instancia do cache
 */
export function createQueryCache({
  storage,
  logger = null,
  staleTime = 30_000,
  maxEntries = 200,
  persistKey = 'dosiq_query_cache',
} = {}) {
  if (!storage) throw new Error('createQueryCache: storage adapter is required')

  // --- estado privado da instancia ---
  /** @type {Map<string, {data: *, timestamp: number, isRevalidating: boolean}>} */
  const cache = new Map()
  /** @type {Map<string, Promise>} */
  const pendingRequests = new Map()
  /** @type {Map<string, number>} */
  const accessCount = new Map()
  let accessCounter = 0
  let cacheGeneration = 0
  let gcInterval = null
  let persistTimer = null
  let initialized = false

  const GC_INTERVAL = 60_000

  // --- helpers privados ---

  function log(level, msg) {
    if (!logger) return
    const fn = logger[level] ?? logger.log
    if (fn) fn(`[QueryCache] ${msg}`)
  }

  function isStale(timestamp, customStaleTime) {
    return Date.now() - timestamp > (customStaleTime ?? staleTime)
  }

  function updateAccess(key) {
    accessCounter++
    accessCount.set(key, accessCounter)
  }

  /**
   * Persiste o cache no storage adapter (debounced 500ms).
   * Nunca bloqueia — falhas sao logadas e ignoradas.
   */
  function schedulePersist() {
    if (persistTimer) clearTimeout(persistTimer)
    persistTimer = setTimeout(async () => {
      try {
        const entries = Array.from(cache.entries())
          .filter(([, v]) => !v.isRevalidating)
          .slice(0, maxEntries)
        await setJSON(storage, persistKey, entries)
      } catch (err) {
        log('warn', `Falha ao persistir cache: ${err.message}`)
      }
      persistTimer = null
    }, 500)
  }

  function garbageCollect() {
    const now = Date.now()
    const ttlThreshold = staleTime * 2
    let removed = 0

    for (const [key, value] of cache.entries()) {
      if (now - value.timestamp > ttlThreshold) {
        cache.delete(key)
        accessCount.delete(key)
        pendingRequests.delete(key)
        removed++
      }
    }

    if (removed > 0) log('log', `GC TTL: ${removed} entradas removidas`)

    if (cache.size <= maxEntries) return

    const sorted = Array.from(accessCount.entries()).sort((a, b) => a[1] - b[1])
    const toEvict = sorted.slice(0, cache.size - maxEntries)
    toEvict.forEach(([key]) => {
      cache.delete(key)
      accessCount.delete(key)
      pendingRequests.delete(key)
    })

    if (toEvict.length > 0) {
      log('log', `GC LRU: ${toEvict.length} entradas evictadas. Tamanho: ${cache.size}`)
      schedulePersist()
    }
  }

  // --- API publica ---

  /**
   * Inicializa o cache: hidrata do storage e inicia GC.
   * DEVE ser chamado explicitamente no bootstrap da plataforma.
   * Nao e chamado automaticamente no import.
   *
   * @returns {Promise<void>}
   */
  async function init() {
    if (initialized) return

    try {
      const persisted = await getJSON(storage, persistKey, null)
      if (Array.isArray(persisted)) {
        persisted.forEach(([key, value]) => {
          cache.set(key, { ...value, isRevalidating: false })
        })
        log('log', `Hidracao: ${persisted.length} entradas carregadas`)
      }
    } catch (err) {
      log('warn', `Falha ao hidratar cache: ${err.message}`)
    }

    gcInterval = setInterval(garbageCollect, GC_INTERVAL)
    initialized = true
  }

  /**
   * Executa uma query com semantica SWR (Stale-While-Revalidate):
   * 1. Cache valido (fresh) → retorna imediatamente
   * 2. Cache stale → retorna stale + revalida em background
   * 3. Cache MISS → executa fetcher e armazena
   *
   * @param {string} key - Chave unica
   * @param {Function} fetcher - Funcao que retorna Promise com os dados
   * @param {Object} [options]
   * @param {number} [options.staleTime] - Override de staleTime para esta query
   * @param {boolean} [options.dedupe=true] - Deduplica requests em voo
   * @returns {Promise<*>}
   */
  async function cachedQuery(key, fetcher, options = {}) {
    const { dedupe = true, staleTime: customStaleTime } = options
    const cached = cache.get(key)

    if (dedupe && pendingRequests.has(key)) {
      log('log', `Deduplica: ${key}`)
      return pendingRequests.get(key)
    }

    if (cached && !isStale(cached.timestamp, customStaleTime)) {
      updateAccess(key)
      log('log', `HIT (fresh): ${key}`)
      return cached.data
    }

    if (cached) {
      log('log', `HIT (stale): ${key} — revalidando em background`)
      const capturedGen = cacheGeneration
      const revalPromise = (async () => {
        try {
          const data = await fetcher()
          if (capturedGen === cacheGeneration) {
            cache.set(key, { data, timestamp: Date.now(), isRevalidating: false })
            updateAccess(key)
            garbageCollect()
            schedulePersist()
          }
          return data
        } catch (err) {
          log('warn', `Revalidacao falhou: ${key} — ${err.message}`)
          cached.isRevalidating = false
          throw err
        }
      })()
      cached.isRevalidating = true
      revalPromise.catch(() => {})
      updateAccess(key)
      return cached.data
    }

    log('log', `MISS: ${key}`)
    const capturedGen = cacheGeneration
    const fetchPromise = (async () => {
      try {
        const data = await fetcher()
        if (capturedGen === cacheGeneration) {
          cache.set(key, { data, timestamp: Date.now(), isRevalidating: false })
          updateAccess(key)
          garbageCollect()
          schedulePersist()
        }
        return data
      } catch (err) {
        log('warn', `Fetch falhou: ${key} — ${err.message}`)
        throw err
      } finally {
        pendingRequests.delete(key)
      }
    })()

    if (dedupe) pendingRequests.set(key, fetchPromise)
    return fetchPromise
  }

  /**
   * Invalida entradas do cache por chave exata, prefixo (*) ou regex.
   *
   * @param {string|RegExp} pattern
   * @returns {number} Numero de entradas invalidadas
   */
  function invalidate(pattern) {
    let count = 0

    if (typeof pattern === 'string') {
      if (pattern.endsWith('*')) {
        const prefix = pattern.slice(0, -1)
        for (const key of cache.keys()) {
          if (key.startsWith(prefix)) {
            cache.delete(key)
            accessCount.delete(key)
            pendingRequests.delete(key)
            count++
          }
        }
      } else if (cache.has(pattern)) {
        cache.delete(pattern)
        accessCount.delete(pattern)
        pendingRequests.delete(pattern)
        count = 1
      }
    } else if (pattern instanceof RegExp) {
      for (const key of cache.keys()) {
        if (pattern.test(key)) {
          cache.delete(key)
          accessCount.delete(key)
          pendingRequests.delete(key)
          count++
        }
      }
    }

    if (count > 0) {
      schedulePersist()
      log('log', `Invalidadas ${count} entradas para: ${pattern}`)
    }

    return count
  }

  /**
   * Limpa todo o cache e cancela persist pendente.
   * Incrementa cacheGeneration para invalidar fetches em voo.
   */
  function clear() {
    if (persistTimer) {
      clearTimeout(persistTimer)
      persistTimer = null
    }
    cacheGeneration++
    const size = cache.size
    cache.clear()
    accessCount.clear()
    pendingRequests.clear()
    accessCounter = 0
    log('log', `Cache limpo: ${size} entradas removidas`)
  }

  /**
   * Preenche o cache com dados (util para pre-carregamento ou testes).
   *
   * @param {string} key
   * @param {*} data
   */
  function prefetch(key, data) {
    cache.set(key, { data, timestamp: Date.now(), isRevalidating: false })
    updateAccess(key)
    garbageCollect()
    schedulePersist()
  }

  /**
   * Retorna estatisticas do cache (debug).
   * @returns {Object}
   */
  function getStats() {
    const entries = Array.from(cache.entries())
    const staleCount = entries.filter(([, v]) => isStale(v.timestamp)).length
    return {
      size: cache.size,
      staleEntries: staleCount,
      freshEntries: cache.size - staleCount,
      pendingRequests: pendingRequests.size,
      maxEntries,
      initialized,
    }
  }

  /**
   * Cancela GC interval (para testes).
   * @internal
   */
  function cancelGC() {
    if (gcInterval) {
      clearInterval(gcInterval)
      gcInterval = null
    }
  }

  /**
   * Reinicia GC interval (para testes).
   * @internal
   */
  function restartGC() {
    if (!gcInterval) {
      gcInterval = setInterval(garbageCollect, GC_INTERVAL)
    }
  }

  return {
    init,
    cachedQuery,
    invalidate,
    clear,
    prefetch,
    getStats,
    // internals para testes
    cancelGC,
    restartGC,
  }
}

import { test, describe } from 'node:test';
import assert from 'node:assert/strict';
import { partitionDoses } from '../utils/partitionDoses.js';

/**
 * Helper para criar uma dose fixture para testes.
 * @param {string|number} id - Identificador único
 * @param {string} medicineName - Nome do medicamento
 * @param {string|null} treatmentPlanId - ID do plano de tratamento (opcional)
 * @param {string|null} treatmentPlanName - Nome do plano de tratamento (opcional)
 * @returns {Object} DoseEntry
 */
function makeDose(id, medicineName, treatmentPlanId = null, treatmentPlanName = null) {
  return {
    protocolId: `proto-${id}`,
    protocolName: `Protocol-${id}`,
    medicineName,
    treatmentPlanId,
    treatmentPlanName,
    dosagePerIntake: 1,
    medicineId: `med-${id}`,
  };
}

describe('partitionDoses', () => {
  test('Caso vazio — array vazio retorna array vazio', () => {
    const result = partitionDoses([]);
    assert.strictEqual(result.length, 0);
  });

  test('Cenário A — 8 doses sem plano → 1 bloco misc', () => {
    const doses = [
      makeDose(1, 'Medicamento 1'),
      makeDose(2, 'Medicamento 2'),
      makeDose(3, 'Medicamento 3'),
      makeDose(4, 'Medicamento 4'),
      makeDose(5, 'Medicamento 5'),
      makeDose(6, 'Medicamento 6'),
      makeDose(7, 'Medicamento 7'),
      makeDose(8, 'Medicamento 8'),
    ];

    const result = partitionDoses(doses);

    assert.strictEqual(result.length, 1);
    assert.strictEqual(result[0].kind, 'misc');
    assert.strictEqual(result[0].planId, null);
    assert.strictEqual(result[0].planName, null);
    assert.strictEqual(result[0].doses.length, 8);
  });

  test('Cenário B — 4 doses do mesmo plano → 1 bloco by_plan', () => {
    const doses = [
      makeDose(1, 'Medicamento 1', 'plan-A', 'Plano A'),
      makeDose(2, 'Medicamento 2', 'plan-A', 'Plano A'),
      makeDose(3, 'Medicamento 3', 'plan-A', 'Plano A'),
      makeDose(4, 'Medicamento 4', 'plan-A', 'Plano A'),
    ];

    const result = partitionDoses(doses);

    assert.strictEqual(result.length, 1);
    assert.strictEqual(result[0].kind, 'by_plan');
    assert.strictEqual(result[0].planId, 'plan-A');
    assert.strictEqual(result[0].planName, 'Plano A');
    assert.strictEqual(result[0].doses.length, 4);
  });

  test('Cenário C — 4 doses plano A + 2 avulsas → 2 blocos: by_plan + misc', () => {
    const doses = [
      makeDose(1, 'Medicamento 1', 'plan-A', 'Plano A'),
      makeDose(2, 'Medicamento 2', 'plan-A', 'Plano A'),
      makeDose(3, 'Medicamento 3', 'plan-A', 'Plano A'),
      makeDose(4, 'Medicamento 4', 'plan-A', 'Plano A'),
      makeDose(5, 'Medicamento 5'),
      makeDose(6, 'Medicamento 6'),
    ];

    const result = partitionDoses(doses);

    assert.strictEqual(result.length, 2);

    const byPlanBlock = result.find(b => b.kind === 'by_plan');
    assert.ok(byPlanBlock);
    assert.strictEqual(byPlanBlock.planId, 'plan-A');
    assert.strictEqual(byPlanBlock.doses.length, 4);

    const miscBlock = result.find(b => b.kind === 'misc');
    assert.ok(miscBlock);
    assert.strictEqual(miscBlock.doses.length, 2);
  });

  test('Cenário D — 4 doses plano A + 3 doses plano B → 2 blocos by_plan', () => {
    const doses = [
      makeDose(1, 'Medicamento 1', 'plan-A', 'Plano A'),
      makeDose(2, 'Medicamento 2', 'plan-A', 'Plano A'),
      makeDose(3, 'Medicamento 3', 'plan-A', 'Plano A'),
      makeDose(4, 'Medicamento 4', 'plan-A', 'Plano A'),
      makeDose(5, 'Medicamento 5', 'plan-B', 'Plano B'),
      makeDose(6, 'Medicamento 6', 'plan-B', 'Plano B'),
      makeDose(7, 'Medicamento 7', 'plan-B', 'Plano B'),
    ];

    const result = partitionDoses(doses);

    assert.strictEqual(result.length, 2);

    const blockA = result.find(b => b.planId === 'plan-A');
    assert.ok(blockA);
    assert.strictEqual(blockA.kind, 'by_plan');
    assert.strictEqual(blockA.doses.length, 4);

    const blockB = result.find(b => b.planId === 'plan-B');
    assert.ok(blockB);
    assert.strictEqual(blockB.kind, 'by_plan');
    assert.strictEqual(blockB.doses.length, 3);
  });

  test('Cenário E — 4 plano A + 3 plano B + 2 avulsas → 3 blocos: 2 by_plan + 1 misc', () => {
    const doses = [
      makeDose(1, 'Medicamento 1', 'plan-A', 'Plano A'),
      makeDose(2, 'Medicamento 2', 'plan-A', 'Plano A'),
      makeDose(3, 'Medicamento 3', 'plan-A', 'Plano A'),
      makeDose(4, 'Medicamento 4', 'plan-A', 'Plano A'),
      makeDose(5, 'Medicamento 5', 'plan-B', 'Plano B'),
      makeDose(6, 'Medicamento 6', 'plan-B', 'Plano B'),
      makeDose(7, 'Medicamento 7', 'plan-B', 'Plano B'),
      makeDose(8, 'Medicamento 8'),
      makeDose(9, 'Medicamento 9'),
    ];

    const result = partitionDoses(doses);

    assert.strictEqual(result.length, 3);

    const byPlanBlocks = result.filter(b => b.kind === 'by_plan');
    assert.strictEqual(byPlanBlocks.length, 2);

    const miscBlock = result.find(b => b.kind === 'misc');
    assert.ok(miscBlock);
    assert.strictEqual(miscBlock.doses.length, 2);
  });

  test('Cenário F — 4 plano A + 3 plano B + 1 avulsa → 3 blocos: 2 by_plan + 1 individual', () => {
    const doses = [
      makeDose(1, 'Medicamento 1', 'plan-A', 'Plano A'),
      makeDose(2, 'Medicamento 2', 'plan-A', 'Plano A'),
      makeDose(3, 'Medicamento 3', 'plan-A', 'Plano A'),
      makeDose(4, 'Medicamento 4', 'plan-A', 'Plano A'),
      makeDose(5, 'Medicamento 5', 'plan-B', 'Plano B'),
      makeDose(6, 'Medicamento 6', 'plan-B', 'Plano B'),
      makeDose(7, 'Medicamento 7', 'plan-B', 'Plano B'),
      makeDose(8, 'Medicamento 8'),
    ];

    const result = partitionDoses(doses);

    assert.strictEqual(result.length, 3);

    const byPlanBlocks = result.filter(b => b.kind === 'by_plan');
    assert.strictEqual(byPlanBlocks.length, 2);

    const individualBlock = result.find(b => b.kind === 'individual');
    assert.ok(individualBlock);
    assert.strictEqual(individualBlock.doses.length, 1);
  });

  test('Cenário G — 1 dose plano A + 1 dose plano B (cada com 1 dose) → 2 individuais', () => {
    const doses = [
      makeDose(1, 'Medicamento 1', 'plan-A', 'Plano A'),
      makeDose(2, 'Medicamento 2', 'plan-B', 'Plano B'),
    ];

    const result = partitionDoses(doses);

    assert.strictEqual(result.length, 2);

    const allIndividuals = result.every(b => b.kind === 'individual');
    assert.ok(allIndividuals, 'Todos os blocos devem ser individual');

    const planABlock = result.find(b => b.planId === 'plan-A');
    assert.ok(planABlock);
    assert.strictEqual(planABlock.planName, 'Plano A');
    assert.strictEqual(planABlock.doses.length, 1);

    const planBBlock = result.find(b => b.planId === 'plan-B');
    assert.ok(planBBlock);
    assert.strictEqual(planBBlock.planName, 'Plano B');
    assert.strictEqual(planBBlock.doses.length, 1);
  });

  test('Cenário H — 1 dose única com plano → 1 individual', () => {
    const doses = [makeDose(1, 'Medicamento 1', 'plan-A', 'Plano A')];

    const result = partitionDoses(doses);

    assert.strictEqual(result.length, 1);
    assert.strictEqual(result[0].kind, 'individual');
    assert.strictEqual(result[0].doses.length, 1);
  });

  test('Cenário I — 1 dose única sem plano → 1 individual', () => {
    const doses = [makeDose(1, 'Medicamento 1')];

    const result = partitionDoses(doses);

    assert.strictEqual(result.length, 1);
    assert.strictEqual(result[0].kind, 'individual');
    assert.strictEqual(result[0].planId, null);
    assert.strictEqual(result[0].planName, null);
    assert.strictEqual(result[0].doses.length, 1);
  });
});

import cron from 'node-cron';
import { createLogger } from './logger.js';
import {
  checkStockAlerts,
  checkAdherenceReports,
  checkTitrationAlerts,
  checkMonthlyReport
} from './tasks.js';

const logger = createLogger('Alerts');

/**
 * Wrapper para cron jobs com tratamento de erro padronizado
 * @param {string} name - Nome do job para logging
 * @param {string} schedule - Expressão cron
 * @param {Function} task - Função async a ser executada
 */
function scheduleTask(name, schedule, task) {
  cron.schedule(schedule, async () => {
    try {
      logger.debug(`Starting scheduled task: ${name}`);
      await task();
      logger.debug(`Completed scheduled task: ${name}`);
    } catch (error) {
      logger.error(`Scheduled task failed: ${name}`, error);
    }
  });
  logger.info(`Scheduled task registered: ${name}`, { schedule });
}

export function startStockAlerts(bot, options = {}) {
  // Run daily at 9:00 AM
  scheduleTask('checkStockAlerts', '0 9 * * *', () => checkStockAlerts(bot, options));
  console.log('✅ Alertas de estoque configurados (diariamente às 9h)');
}

