import { supabase } from '../../services/supabase.js';
import { getUserIdByChatId } from '../../services/userService.js';
import { medicineLogService } from '../../services/medicineLogService.js';
import { calculateDaysRemaining, calculateStreak, escapeMarkdownV2 } from '../../utils/formatters.js';
import { setState, getState, clearState } from '../state.js';
import { partitionDoses } from '../utils/partitionDoses.js';

const SKIP_CONFIRMATION_TIMEOUT_MS = 30000; // 30 seconds

export async function handleCallbacks(bot) {
  bot.on('callback_query', async (callbackQuery) => {
    const { data } = callbackQuery;

    if (data.startsWith('take_')) {
      await handleTakeDose(bot, callbackQuery);
    } else if (data.startsWith('skip_')) {
      await handleSkipDose(bot, callbackQuery);
    } else if (data.startsWith('confirm_skip_')) {
      await handleConfirmSkipDose(bot, callbackQuery);
    } else if (data.startsWith('cancel_skip_')) {
      await handleCancelSkipDose(bot, callbackQuery);
    } else if (data.startsWith('takeplan:')) {
      await handleTakePlan(bot, callbackQuery);
    } else if (data.startsWith('takelist:')) {
      await handleTakeList(bot, callbackQuery);
    }
  });
}

async function handleTakeDose(bot, callbackQuery) {
  const { data, message, id } = callbackQuery;
  const chatId = message.chat.id;

  // New format: take_:{protocolId}:{quantity}
  const [_, protocolId, quantity] = data.split(':');

  try {
    // Get actual user ID from chat ID
    const userId = await getUserIdByChatId(chatId);

    // 1. Fetch medicine_id from protocol
    const { data: protocol, error: protocolError } = await supabase
      .from('protocols')
      .select('medicine_id, medicine:medicines(name, dosage_unit)')
      .eq('id', protocolId)
      .single();

    if (protocolError || !protocol) throw new Error('Protocolo não encontrado');

    const medicineId = protocol.medicine_id;
    const medicineName = protocol.medicine.name;

    // 2. Criar Log
    const { data: createdLogs, error: logError } = await supabase
      .from('medicine_logs')
      .insert([{
        user_id: userId,
        protocol_id: protocolId,
        medicine_id: medicineId,
        quantity_taken: parseFloat(quantity),
        taken_at: new Date().toISOString()
      }])
      .select('id')
      .single();

    if (logError) throw logError;

    // 3. Decrementar Estoque via RPC FIFO (overload server-side com p_user_id explícito)
    // Bot usa service_role → auth.uid() = NULL → usar overload de 4 parâmetros
    const { error: consumeError } = await supabase.rpc('consume_stock_fifo', {
      p_user_id: userId,
      p_medicine_id: medicineId,
      p_quantity: parseFloat(quantity),
      p_medicine_log_id: createdLogs.id
    });

    if (consumeError) {
      await supabase
        .from('medicine_logs')
        .delete()
        .eq('id', createdLogs.id)
        .eq('user_id', userId);

      throw consumeError;
    }

    // 4. Check stock levels and warn if low
    const { data: updatedStock } = await supabase
      .from('stock')
      .select('quantity')
      .eq('medicine_id', medicineId)
      .eq('user_id', userId)
      .gt('quantity', 0);

    const totalQuantity = updatedStock?.reduce((sum, s) => sum + s.quantity, 0) || 0;

    // Get daily usage for this medicine
    const { data: activeProtocols } = await supabase
      .from('protocols')
      .select('time_schedule, dosage_per_intake')
      .eq('medicine_id', medicineId)
      .eq('user_id', userId)
      .eq('active', true);

    const dailyUsage = activeProtocols?.reduce((sum, p) => {
      const timesPerDay = p.time_schedule?.length || 0;
      const dosagePerIntake = p.dosage_per_intake || 0;
      return sum + (timesPerDay * dosagePerIntake);
    }, 0) || 0;

    const daysRemaining = calculateDaysRemaining(totalQuantity, dailyUsage);

    // Get all logs to calculate streak
    const { data: allLogs } = await supabase
      .from('medicine_logs')
      .select('taken_at')
      .eq('user_id', userId);

    const streak = calculateStreak(allLogs);

    // Update the message
    let confirmMsg = `✅ Dose de *${escapeMarkdownV2(medicineName)}* registrada\\!`;

    if (streak > 1) {
      confirmMsg += `\n🔥 *${streak} dias seguidos\\!*`;
    }

    if (daysRemaining !== null && daysRemaining <= 7) {
      if (daysRemaining <= 0) {
        confirmMsg += `\n\n⚠️ *ATENÇÃO:* Estoque zerado\\!`;
      } else {
        confirmMsg += `\n\n⚠️ Estoque baixo: \\~${daysRemaining} dias restantes`;
      }
    }

    // Add quick action buttons
    const quickActions = {
      inline_keyboard: [
        [
          { text: '📊 Ver Hoje', callback_data: 'cmd:hoje' },
          { text: '📦 Ver Estoque', callback_data: 'quick_stock' }
        ],
        [{ text: '📝 Registrar Outra', callback_data: 'quick_register' }]
      ]
    };

    await bot.editMessageText(confirmMsg, {
      chat_id: chatId,
      message_id: message.message_id,
      parse_mode: 'MarkdownV2',
      reply_markup: quickActions
    });

    await bot.answerCallbackQuery(id, { text: 'Dose registrada!' });
  } catch (err) {
    console.error('Erro ao registrar dose:', err);

    // Handle unlinked user case
    if (err.message === 'User not linked') {
      try {
        await bot.answerCallbackQuery(id, {
          text: 'Conta não vinculada. Use /start para vincular.',
          show_alert: true
        });
      } catch { /* ignore */ }
      return;
    }

    try {
      await bot.answerCallbackQuery(id, { text: 'Erro ao registrar dose.', show_alert: true });
    } catch { /* ignore */ }
  }
}

async function handleSkipDose(bot, callbackQuery) {
  const { data, message, id } = callbackQuery;
  const chatId = message.chat.id;

  // Parse skip data: skip_:{protocolId}
  const [_, protocolId] = data.split(':');

  try {
    // Get medicine name for the confirmation message
    const { data: protocol, error: protocolError } = await supabase
      .from('protocols')
      .select('medicine:medicines(name)')
      .eq('id', protocolId)
      .single();

    if (protocolError || !protocol) {
      await bot.answerCallbackQuery(id, { 
        text: 'Erro: Protocolo não encontrado.', 
        show_alert: true 
      });
      return;
    }

    const medicineName = protocol.medicine?.name || 'Medicamento';

    // Store original message state for potential restoration
    const originalState = {
      action: 'skip_confirmation',
      protocolId,
      medicineName,
      originalText: message.text,
      originalReplyMarkup: message.reply_markup,
      timestamp: Date.now()
    };

    await setState(chatId, originalState);

    // Set up timeout to restore original UI after 30 seconds
    setTimeout(async () => {
      await handleSkipTimeout(bot, chatId, message.message_id);
    }, SKIP_CONFIRMATION_TIMEOUT_MS);

    // Show confirmation keyboard
    const confirmKeyboard = {
      inline_keyboard: [
        [
          { text: '✅ Confirmar pular', callback_data: `confirm_skip_:${protocolId}` },
          { text: '❌ Cancelar', callback_data: `cancel_skip_:${protocolId}` }
        ]
      ]
    };

    const confirmText = `⚠️ *Confirmar ação*\n\n` +
      `Você está prestes a *pular* a dose de *${escapeMarkdownV2(medicineName)}*\\.\n\n` +
      `Esta ação não poderá ser desfeita\\.\n\n` +
      `_Confirme em 30 segundos\\.\\.\\._`;

    await bot.editMessageText(confirmText, {
      chat_id: chatId,
      message_id: message.message_id,
      parse_mode: 'MarkdownV2',
      reply_markup: confirmKeyboard
    });

    await bot.answerCallbackQuery(id, { text: 'Confirme para pular a dose' });

  } catch (err) {
    console.error('Erro ao iniciar confirmação de skip:', err);
    await bot.answerCallbackQuery(id, { 
      text: 'Erro ao processar. Tente novamente.', 
      show_alert: true 
    });
  }
}

async function handleConfirmSkipDose(bot, callbackQuery) {
  const { data, message, id } = callbackQuery;
  const chatId = message.chat.id;

  // Parse: confirm_skip_:{protocolId}
  const [_, protocolId] = data.split(':');

  try {
    // Verify we have a pending confirmation state
    const state = await getState(chatId);

    if (!state || state.action !== 'skip_confirmation' || state.protocolId !== protocolId) {
      await bot.answerCallbackQuery(id, { 
        text: 'Confirmação expirada ou inválida.', 
        show_alert: true 
      });
      return;
    }

    // Check if timeout expired
    const elapsed = Date.now() - state.timestamp;
    if (elapsed > SKIP_CONFIRMATION_TIMEOUT_MS) {
      await clearState(chatId);
      await bot.answerCallbackQuery(id, { 
        text: 'Tempo de confirmação expirado.', 
        show_alert: true 
      });
      return;
    }

    // Clear the state
    await clearState(chatId);

    const medicineName = state.medicineName || 'Medicamento';

    // Confirm the skip
    await bot.editMessageText(
      `❌ Dose de *${escapeMarkdownV2(medicineName)}* pulada\\.`,
      {
        chat_id: chatId,
        message_id: message.message_id,
        parse_mode: 'MarkdownV2'
      }
    );

    await bot.answerCallbackQuery(id, { text: 'Dose pulada.' });

  } catch (err) {
    console.error('Erro ao confirmar skip:', err);
    await bot.answerCallbackQuery(id, { 
      text: 'Erro ao pular dose.', 
      show_alert: true 
    });
  }
}

async function handleCancelSkipDose(bot, callbackQuery) {
  const { data, message, id } = callbackQuery;
  const chatId = message.chat.id;

  // Parse: cancel_skip_:{protocolId}
  // eslint-disable-next-line no-unused-vars
  const [_, protocolId] = data.split(':');

  try {
    // Get state to restore original UI if possible
    const state = await getState(chatId);

    // Clear the state
    await clearState(chatId);

    // Restore original message or show cancellation message
    if (state && state.originalText && state.originalReplyMarkup) {
      // Restore original UI
      await bot.editMessageText(state.originalText, {
        chat_id: chatId,
        message_id: message.message_id,
        parse_mode: 'MarkdownV2',
        reply_markup: state.originalReplyMarkup
      });
    } else {
      // Show cancellation message
      await bot.editMessageText(
        `✅ Ação cancelada\\. Nenhuma dose foi pulada\\.`,
        {
          chat_id: chatId,
          message_id: message.message_id,
          parse_mode: 'MarkdownV2'
        }
      );
    }

    await bot.answerCallbackQuery(id, { text: 'Ação cancelada.' });

  } catch (err) {
    console.error('Erro ao cancelar skip:', err);
    await bot.answerCallbackQuery(id, { 
      text: 'Ação cancelada.', 
      show_alert: true 
    });
  }
}

async function handleSkipTimeout(bot, chatId, messageId) {
  try {
    // Check if state still exists (confirmation still pending)
    const state = await getState(chatId);

    if (!state || state.action !== 'skip_confirmation') {
      // Already confirmed, cancelled, or handled
      return;
    }

    // Clear the state
    await clearState(chatId);

    // Restore original UI or show timeout message
    if (state.originalText) {
      try {
        await bot.editMessageText(
          state.originalText + '\n\n_⏱️ Confirmação expirada\\._',
          {
            chat_id: chatId,
            message_id: messageId,
            parse_mode: 'MarkdownV2',
            reply_markup: state.originalReplyMarkup
          }
        );
      } catch {
        // Message may have been deleted, ignore
      }
    }

    console.log(`[SkipConfirmation] Timeout expired for chat ${chatId}`);

  } catch (err) {
    console.error('Erro no timeout de skip:', err);
  }
}

async function handleTakePlan(bot, callbackQuery) {
  const { data, message, id } = callbackQuery;
  const chatId = message.chat.id;

  const parts = data.split(':');
  const planIdShort = parts[1];
  const hhmm = parts.slice(2).join(':'); // '23:15' contém ':', split produz 4 partes

  try {
    const userId = await getUserIdByChatId(chatId);

    const { data: allActive, error: protocolsError } = await supabase
      .from('protocols')
      .select('id, medicine_id, dosage_per_intake, treatment_plan_id, time_schedule, medicine:medicines(name), treatment_plan:treatment_plans(id, name)')
      .eq('user_id', userId)
      .eq('active', true)
      .not('treatment_plan_id', 'is', null);

    if (protocolsError) {
      console.error('[handleTakePlan] Supabase error:', protocolsError);
      throw protocolsError;
    }

    // Filter: horário matches + planId starts with
    const validProtocols = (allActive || []).filter(p =>
      (p.time_schedule || []).includes(hhmm) &&
      p.treatment_plan_id?.startsWith(planIdShort)
    );
    console.log(`[handleTakePlan] validProtocols: ${validProtocols.length}`);


    if (!validProtocols.length) {
      await bot.answerCallbackQuery(id, { text: 'Nenhuma dose pendente encontrada para este plano e horário.', show_alert: true });
      return;
    }

    const planName = validProtocols[0].treatment_plan?.name || 'Plano';

    const logsToSave = validProtocols.map((p) => ({
      protocol_id: p.id,
      medicine_id: p.medicine_id,
      quantity_taken: p.dosage_per_intake,
      taken_at: new Date().toISOString(),
      notes: `[Plano: ${planName}] Registrar agora (Telegram)`
    }));

    const result = await medicineLogService.createMany(userId, logsToSave);
    console.log(`[handleTakePlan] success: ${result.count} doses registered for user ${userId}`);

    if (!result.success) throw new Error('Falha ao registrar doses do plano');

    const confirmMsg = `✅ *${result.count} doses* do plano *${escapeMarkdownV2(planName)}* registradas\\!`;

    await bot.editMessageText(confirmMsg, {
      chat_id: chatId,
      message_id: message.message_id,
      parse_mode: 'MarkdownV2',
      reply_markup: { inline_keyboard: [] }
    });

    await bot.answerCallbackQuery(id, { text: `✅ ${validProtocols.length} doses registradas!` });
  } catch (err) {
    console.error('Erro ao registrar takeplan:', err);
    try {
      await bot.answerCallbackQuery(id, { text: 'Erro ao registrar doses.', show_alert: true });
    } catch { /* ignore */ }
  }
}

async function handleTakeList(bot, callbackQuery) {
  const { data, message, id } = callbackQuery;
  const chatId = message.chat.id;

  const [_, _type, hhmm] = data.split(':');

  try {
    const userId = await getUserIdByChatId(chatId);

    const { data: allActive, error: protocolsError } = await supabase
      .from('protocols')
      .select('id, user_id, name, time_schedule, medicine_id, dosage_per_intake, treatment_plan_id, medicine:medicines(name), treatment_plan:treatment_plans(id, name)')
      .eq('user_id', userId)
      .eq('active', true);

    if (protocolsError) throw protocolsError;

    const dosesNow = (allActive || [])
      .filter(p => (p.time_schedule || []).includes(hhmm))
      .map(p => ({
        protocolId: p.id,
        protocolName: p.name,
        medicineName: p.medicine?.name || 'Medicamento',
        treatmentPlanId: p.treatment_plan_id ?? null,
        treatmentPlanName: p.treatment_plan?.name ?? null,
        dosagePerIntake: p.dosage_per_intake ?? 1,
        medicineId: p.medicine_id,
      }));

    const blocks = partitionDoses(dosesNow);
    const miscBlock = blocks.find(b => b.kind === 'misc');

    if (!miscBlock || !miscBlock.doses.length) {
      await bot.answerCallbackQuery(id, { text: 'Nenhuma dose pendente encontrada para esta lista.', show_alert: true });
      return;
    }

    const logsToSave = miscBlock.doses.map((p) => ({
      protocol_id: p.protocolId,
      medicine_id: p.medicineId,
      quantity_taken: p.dosagePerIntake,
      taken_at: new Date().toISOString(),
      notes: 'Doses avulsas registradas via Telegram'
    }));

    const result = await medicineLogService.createMany(userId, logsToSave);
    console.log(`[handleTakeList] success: ${result.count} doses registradas para user ${userId}`);

    if (!result.success) throw new Error('Falha ao registrar doses avulsas');

    const confirmMsg = `✅ *${result.count} doses* avulsas registradas\\!`;

    await bot.editMessageText(confirmMsg, {
      chat_id: chatId,
      message_id: message.message_id,
      parse_mode: 'MarkdownV2',
      reply_markup: { inline_keyboard: [] }
    });

    await bot.answerCallbackQuery(id, { text: `✅ ${miscBlock.doses.length} doses registradas!` });
  } catch (err) {
    console.error('Erro ao registrar takelist:', err);
    try {
      await bot.answerCallbackQuery(id, { text: 'Erro ao registrar doses.', show_alert: true });
    } catch { /* ignore */ }
  }
}

/**
 * Handler para mensagens de texto não-comando no Telegram.
 *
 * Intercepta mensagens que NÃO começam com '/' e as encaminha
 * para o chatbot IA (Groq) com contexto personalizado do paciente.
 *
 * Requer: GROQ_API_KEY no env
 *
 * @module commands/chatbot
 */

import { getUserIdByChatId } from '../../services/userService.js'
import { sendTelegramChatMessage } from '../services/chatbotServerService.js'
import { createLogger } from '../logger.js'

const logger = createLogger('ChatbotCommand')

/**
 * Processa mensagem de texto do usuário e responde com chatbot IA.
 *
 * @param {import('node-telegram-bot-api')} bot
 * @param {import('node-telegram-bot-api').Message} msg
 */
export async function handleChatbotMessage(bot, msg) {
  const chatId = msg.chat.id
  const message = msg.text?.trim()

  // Log de entrada
  logger.info('📨 Mensagem de chat recebida', {
    chatId,
    msgPreview: message?.substring(0, 50) || '(vazio)',
    msgLen: message?.length || 0,
  })

  // Ignorar mensagens vazias ou comandos (tratados por outros handlers)
  if (!message || message.startsWith('/')) {
    logger.debug('⏭️ Ignorando (vazio ou comando)', { chatId })
    return
  }

  // Verificar API key antes de processar
  if (!process.env.GROQ_API_KEY) {
    logger.warn('❌ GROQ_API_KEY não configurada — chatbot desabilitado')
    return
  }

  let userId
  try {
    userId = await getUserIdByChatId(chatId)
    logger.info('✅ userId obtido', { chatId, userId })
  } catch (err) {
    // Usuário não vinculado: ignorar silenciosamente (sem mensagem de erro)
    // (o /start vai orientá-los a vincular a conta)
    logger.warn('❌ Usuário não vinculado', { chatId, error: err.message })
    return
  }

  try {
    // Mostrar indicador de digitação enquanto processa
    logger.debug('🕐 Enviando ação "typing" ao Telegram', { chatId })
    await bot.sendChatAction(chatId, 'typing')

    logger.debug('🤖 Chamando sendTelegramChatMessage', { chatId, userId, msgLen: message.length })
    const result = await sendTelegramChatMessage({ message, userId })

    logger.info('✅ Resultado do chatbot recebido', {
      chatId,
      userId,
      blocked: result.blocked,
      rateLimited: result.rateLimited,
      responseLen: result.response?.length || 0,
      responsePreview: result.response?.substring(0, 80) || '(vazio)',
    })

    logger.debug('📤 Enviando resposta ao Telegram', { chatId, respLen: result.response?.length })
    const prefixedResponse = `🤖 IA: ${result.response}`
    await bot.sendMessage(chatId, prefixedResponse)
    logger.info('✅ Mensagem enviada com sucesso', { chatId, respLen: prefixedResponse?.length })
  } catch (error) {
    logger.error('❌ Erro no handler do chatbot', error, {
      chatId,
      userId,
      errorMessage: error.message,
      errorStatus: error.response?.statusCode,
    })
    try {
      await bot.sendMessage(chatId, '🤖 IA: Desculpe, tive um problema. Tente novamente.')
    } catch (sendError) {
      logger.error('❌ Erro ao enviar mensagem de erro', sendError, {
        chatId,
        errorMessage: sendError.message,
        errorStatus: sendError.response?.statusCode,
      })
    }
  }
}

import { supabase } from '../../services/supabase.js';
import { getUserIdByChatId } from '../../services/userService.js';
import { escapeMarkdownV2 } from '../../utils/formatters.js';

export async function handleHistorico(bot, msg) {
  const chatId = msg.chat.id;

  try {
    const userId = await getUserIdByChatId(chatId);

    const { data: logs, error } = await supabase
      .from('medicine_logs')
      .select(`
        *,
        medicine:medicines(name),
        protocol:protocols(*)
      `)
      .eq('user_id', userId)
      .order('taken_at', { ascending: false })
      .limit(10);

    if (error) throw error;

    if (!logs || logs.length === 0) {
      return await bot.sendMessage(chatId, 'Nenhuma dose registrada ainda\\.');
    }

    let message = '📜 *Histórico Recente:*\n\n';

    logs.forEach(log => {
      const date = new Date(log.taken_at);
      const dateStr = date.toLocaleDateString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        timeZone: 'America/Sao_Paulo'
      });
      const timeStr = date.toLocaleTimeString('pt-BR', {
        hour: '2-digit',
        minute: '2-digit',
        timeZone: 'America/Sao_Paulo'
      });
      const medicineName = escapeMarkdownV2(log.medicine?.name || 'Medicamento');
      const quantity = escapeMarkdownV2(String(log.quantity_taken ?? 0));

      message += `📅 ${dateStr} às ${timeStr}\n`;
      message += `💊 ${medicineName} \\- ${quantity}x\n\n`;
    });

    await bot.sendMessage(chatId, message, { parse_mode: 'MarkdownV2' });
  } catch (err) {
    if (err.message === 'User not linked') {
      return bot.sendMessage(chatId, '❌ Conta não vinculada\\. Use /start para vincular\\.');
    }
    console.error('Erro ao buscar histórico:', err);
    await bot.sendMessage(chatId, 'Erro ao buscar histórico\\.');
  }
}

import { supabase } from '../../services/supabase.js';
import { getUserIdByChatId } from '../../services/userService.js';
import { getCurrentTime, escapeMarkdownV2 } from '../../utils/formatters.js';

export async function handleHoje(bot, msg) {
  const chatId = msg.chat.id;

  try {
    let userId;
    try {
      userId = await getUserIdByChatId(chatId);
    } catch {
      return await bot.sendMessage(chatId, '⚠️ Você precisa vincular sua conta primeiro\\. Use /start para instruções\\.');
    }

    const { data: protocols, error } = await supabase
      .from('protocols')
      .select('*, medicine:medicines(*)')
      .eq('user_id', userId)
      .eq('active', true);

    if (error) throw error;

    if (!protocols || protocols.length === 0) {
      return await bot.sendMessage(chatId, 'Você não possui protocolos ativos\\.');
    }

    // Get today's date in SP timezone
    const timezone = 'America/Sao_Paulo';
    const now = new Date();
    const todayStr = new Intl.DateTimeFormat('en-CA', { timeZone: timezone }).format(now);

    // Fetch logs from last 24h to ensure we don't miss anything due to UTC shift
    // Then filter accurately in memory
    const { data: allLogs } = await supabase
      .from('medicine_logs')
      .select('protocol_id, taken_at')
      .eq('user_id', userId)
      .gte('taken_at', new Date(now.getTime() - 36 * 60 * 60 * 1000).toISOString());

    const todayLogs = allLogs?.filter(log => {
      const logDate = new Intl.DateTimeFormat('en-CA', { timeZone: timezone }).format(new Date(log.taken_at));
      return logDate === todayStr;
    }) || [];

    // Helper to convert HH:MM to minutes
    const toMin = (t) => {
      const [h, m] = t.split(':').map(Number);
      return h * 60 + m;
    };

    // Build schedule for today
    const schedule = [];
    protocols.forEach(protocol => {
      const protocolLogs = todayLogs.filter(l => l.protocol_id === protocol.id);

      protocol.time_schedule.forEach(time => {
        const scheduledMin = toMin(time);

        // Find if any log matches this slot (within 3h window)
        const wasTaken = protocolLogs.some(log => {
          const logTime = new Date(log.taken_at).toLocaleTimeString('pt-BR', {
            hour: '2-digit',
            minute: '2-digit',
            hour12: false,
            timeZone: timezone
          }).replace(/^24/, '00');

          const actualMin = toMin(logTime);
          return Math.abs(scheduledMin - actualMin) < 180; // 3 hour window
        });

        schedule.push({
          time,
          medicine: protocol.medicine.name,
          dosage: protocol.dosage_per_intake,
          taken: wasTaken
        });
      });
    });

    // Sort by time
    schedule.sort((a, b) => a.time.localeCompare(b.time));

    const currentTime = getCurrentTime();
    const todayFormatted = new Intl.DateTimeFormat('pt-BR', { timeZone: 'America/Sao_Paulo' }).format(new Date());
    let message = `📅 *Doses de Hoje* \\(${escapeMarkdownV2(todayFormatted)}\\)\n\n`;

    schedule.forEach(item => {
      const status = item.taken ? '✅' : (item.time <= currentTime ? '⏰' : '⏱️');
      const medicineName = escapeMarkdownV2(item.medicine || 'Medicamento');
      const time = escapeMarkdownV2(item.time);
      const dosage = escapeMarkdownV2(String(item.dosage ?? 1));
      message += `${status} ${time} \\- ${medicineName} \\(${dosage}x\\)\n`;
    });

    const taken = schedule.filter(s => s.taken).length;
    const total = schedule.length;
    message += `\n📊 Progresso: ${taken}/${total} doses`;

    await bot.sendMessage(chatId, message, { parse_mode: 'MarkdownV2' });
  } catch (err) {
    console.error('Erro ao buscar agenda:', err);
    await bot.sendMessage(chatId, 'Erro ao buscar agenda de hoje\\.');
  }
}

import { supabase } from '../../services/supabase.js';

export async function handleStart(bot, msg) {
  const chatId = msg.chat.id;
  const token = msg.text.split(' ')[1]?.trim();

  try {
    if (!token) {
      // Check if already linked
      const { data: existing } = await supabase
        .from('user_settings')
        .select('user_id')
        .eq('telegram_chat_id', chatId.toString())
        .single();

      if (existing) {
        await bot.sendMessage(chatId, '✅ Você já está conectado! Use /ajuda para ver os comandos.');
      } else {
        await bot.sendMessage(chatId, 
          'Olá! 👋 Para conectar o bot à sua conta:\n\n' +
          '1. Abra o app Dosiq\n' +
          '2. Vá em **Configurações > Integração Telegram**\n' +
          '3. Clique em "Gerar Código"\n' +
          '4. Envie o código aqui: `/start SEU_CODIGO`',
          { parse_mode: 'Markdown' }
        );
      }
      return;
    }

    // Try to link using token
    const { data: linked, error } = await supabase
      .from('user_settings')
      .update({ 
        telegram_chat_id: chatId.toString(),
        verification_token: null, // Consume token
        updated_at: new Date().toISOString()
      })
      .eq('verification_token', token)
      .select()
      .single();

    if (error) {
      console.error('Database error during linking:', error);
      // Check if it's an RLS issue or missing column
      if (error.code === '42703') {
        await bot.sendMessage(chatId, '❌ Erro técnico: Coluna de verificação não encontrada no banco. Execute o SQL de migração.');
      } else {
        await bot.sendMessage(chatId, '❌ Ops! Ocorreu um erro no banco de dados. Contate o suporte.');
      }
      return;
    }

    if (!linked) {
      await bot.sendMessage(chatId, '❌ Código inválido ou expirado. Por favor, gere um novo código no app.');
      return;
    }

    await bot.sendMessage(chatId, 
      `🎉 *Conta vinculada com sucesso!*\n\n` +
      `Agora você receberá notificações e poderá gerenciar seus remédios por aqui.\n\n` +
      `*Comandos úteis:*\n` +
      `/hoje - O que tomar hoje\n` +
      `/status - Status dos tratamentos\n` +
      `/estoque - Compras necessárias`,
      { parse_mode: 'Markdown' }
    );
  } catch (err) {
    console.error('Erro ao salvar chat_id:', err);
    await bot.sendMessage(chatId, 'Ops, tive um erro ao configurar seu perfil. Tente novamente mais tarde.');
  }
}

// server/bot/correlationLogger.js
import { createLogger } from './logger.js';
import crypto from 'crypto';

const logger = createLogger('Correlation');

// AsyncLocalStorage para contexto implícito (Node 14.8+)
let asyncLocalStorage = null;
try {
  const { AsyncLocalStorage } = await import('async_hooks');
  asyncLocalStorage = new AsyncLocalStorage();
} catch {
  logger.warn('AsyncLocalStorage não disponível, usando contexto explícito');
}

/**
 * Gera um UUID v4 usando crypto nativo do Node.js
 * @returns {string} Novo correlation ID
 */
export function generateCorrelationId() {
  return crypto.randomUUID();
}

/**
 * Obtém o correlation ID atual ou gera um novo
 * @returns {string} Correlation ID (existente ou novo)
 */
export function getOrGenerateCorrelationId() {
  return getCurrentCorrelationId() || generateCorrelationId();
}

/**
 * Executa uma função com contexto de correlação
 * @param {Function} fn - Função a ser executada
 * @param {object} context - Contexto com correlationId e outros dados
 * @returns {Promise<any>} Resultado da função
 */
export async function withCorrelation(fn, context = {}) {
  const correlationId = context.correlationId || generateCorrelationId();
  const fullContext = {
    correlationId,
    timestamp: new Date().toISOString(),
    ...context
  };

  logger.debug('Iniciando operação com correlação', {
    correlationId,
    operation: fn.name || 'anonymous',
    ...context
  });

  if (asyncLocalStorage) {
    return asyncLocalStorage.run(fullContext, async () => {
      try {
        const result = await fn(fullContext);
        return result;
      } finally {
        logger.debug('Operação com correlação finalizada', {
          correlationId,
          operation: fn.name || 'anonymous'
        });
      }
    });
  } else {
    // Fallback: passar contexto explicitamente
    try {
      const result = await fn(fullContext);
      return result;
    } finally {
      logger.debug('Operação com correlação finalizada', {
        correlationId,
        operation: fn.name || 'anonymous'
      });
    }
  }
}

/**
 * Obtém o correlation ID atual do contexto
 * @returns {string|null} Correlation ID ou null
 */
export function getCurrentCorrelationId() {
  if (asyncLocalStorage) {
    const store = asyncLocalStorage.getStore();
    return store?.correlationId || null;
  }
  return null;
}

/**
 * Obtém o contexto atual completo
 * @returns {object|null} Contexto ou null
 */
export function getCurrentContext() {
  if (asyncLocalStorage) {
    return asyncLocalStorage.getStore() || null;
  }
  return null;
}

/**
 * Wrapper para logging com correlation ID
 * @param {string} context - Nome do contexto/componente
 * @param {string} correlationId - ID de correlação
 * @returns {object} Logger com contexto
 */
export function createCorrelationLogger(context, correlationId) {
  const baseLogger = createLogger(context);

  return {
    error: (message, error, data = {}) => {
      baseLogger.error(message, error, { correlationId, ...data });
    },
    warn: (message, data = {}) => {
      baseLogger.warn(message, { correlationId, ...data });
    },
    info: (message, data = {}) => {
      baseLogger.info(message, { correlationId, ...data });
    },
    debug: (message, data = {}) => {
      baseLogger.debug(message, { correlationId, ...data });
    },
    trace: (message, data = {}) => {
      baseLogger.trace(message, { correlationId, ...data });
    }
  };
}

/**
 * Middleware para Vercel API handlers
 * Adiciona correlation ID a todas as requisições
 * @param {Function} handler - Handler da API
 * @returns {Function} Handler com correlation
 */
export function withCorrelationMiddleware(handler) {
  return async (req, res) => {
    const correlationId = req.headers['x-correlation-id'] || generateCorrelationId();

    // Adicionar correlation ID à resposta
    res.setHeader('X-Correlation-Id', correlationId);

    const context = {
      correlationId,
      method: req.method,
      url: req.url,
      userAgent: req.headers['user-agent']
    };

    return withCorrelation(async () => {
      return handler(req, res, context);
    }, context);
  };
}

import { createLogger } from './logger.js';

const logger = createLogger('HealthCheck');

export class HealthCheck {
  constructor() {
    this.checks = new Map();
    this.lastCheck = null;
  }

  register(name, checkFn) {
    this.checks.set(name, checkFn);
    logger.info(`Health check registered: ${name}`);
  }

  async runAll() {
    const results = {
      timestamp: new Date().toISOString(),
      overall: 'healthy',
      checks: {}
    };

    for (const [name, checkFn] of this.checks) {
      try {
        const result = await checkFn();
        results.checks[name] = {
          status: result.ok ? 'healthy' : 'unhealthy',
          ...result
        };
        if (!result.ok) {
          results.overall = 'unhealthy';
        }
      } catch (error) {
        results.checks[name] = {
          status: 'error',
          error: error.message
        };
        results.overall = 'unhealthy';
        logger.error(`Health check failed: ${name}`, error);
      }
    }

    this.lastCheck = results;
    return results;
  }

  getStatus() {
    return this.lastCheck || { status: 'unknown', timestamp: null };
  }
}

// Singleton instance
export const healthCheck = new HealthCheck();

// Checks predefinidos
export function registerDefaultChecks(bot, supabase) {
  // Check Telegram API
  healthCheck.register('telegram-api', async () => {
    try {
      const me = await bot.getMe();
      return { ok: true, username: me.username, id: me.id };
    } catch (error) {
      return { ok: false, error: error.message };
    }
  });

  // Check Supabase Connection
  healthCheck.register('supabase', async () => {
    try {
      const { error } = await supabase.from('user_settings').select('count').limit(1);
      if (error) throw error;
      return { ok: true, connected: true };
    } catch (error) {
      return { ok: false, error: error.message };
    }
  });

  // Check Environment
  healthCheck.register('environment', async () => {
    const required = ['TELEGRAM_BOT_TOKEN', 'VITE_SUPABASE_URL'];
    const missing = required.filter(key => !process.env[key]);
    return {
      ok: missing.length === 0,
      missing: missing.length > 0 ? missing : undefined
    };
  });
}

// Logger estruturado com níveis de log
export const LOG_LEVELS = {
  ERROR: 0,
  WARN: 1,
  INFO: 2,
  DEBUG: 3,
  TRACE: 4
};

const CURRENT_LEVEL = LOG_LEVELS[process.env.LOG_LEVEL?.toUpperCase()] ?? LOG_LEVELS.INFO;

class Logger {
  constructor(context) {
    this.context = context;
  }

  formatMessage(level, message, data = null) {
    const timestamp = new Date().toISOString();
    const dataStr = data ? ` ${JSON.stringify(data)}` : '';
    return `[${timestamp}] [${level}] [${this.context}] ${message}${dataStr}`;
  }

  error(message, error = null, data = null) {
    if (CURRENT_LEVEL >= LOG_LEVELS.ERROR) {
      console.error(this.formatMessage('ERROR', message, data));
      if (error) {
        console.error('  Error:', error.message);
        console.error('  Stack:', error.stack);
      }
    }
  }

  warn(message, data = null) {
    if (CURRENT_LEVEL >= LOG_LEVELS.WARN) {
      console.warn(this.formatMessage('WARN', message, data));
    }
  }

  info(message, data = null) {
    if (CURRENT_LEVEL >= LOG_LEVELS.INFO) {
      console.log(this.formatMessage('INFO', message, data));
    }
  }

  debug(message, data = null) {
    if (CURRENT_LEVEL >= LOG_LEVELS.DEBUG) {
      console.log(this.formatMessage('DEBUG', message, data));
    }
  }

  trace(message, data = null) {
    if (CURRENT_LEVEL >= LOG_LEVELS.TRACE) {
      console.log(this.formatMessage('TRACE', message, data));
    }
  }
}

export function createLogger(context) {
  return new Logger(context);
}

import cron from 'node-cron';
import { createLogger } from './logger.js';
import { checkReminders, runDailyDigest, checkPrescriptionAlerts } from './tasks.js';

const logger = createLogger('Scheduler');

/**
 * Wrapper para cron jobs com tratamento de erro padronizado
 * @param {string} name - Nome do job para logging
 * @param {string} schedule - Expressão cron
 * @param {Function} task - Função async a ser executada
 */
function scheduleTask(name, schedule, task) {
  cron.schedule(schedule, async () => {
    try {
      logger.debug(`Starting scheduled task: ${name}`);
      await task();
      logger.debug(`Completed scheduled task: ${name}`);
    } catch (error) {
      logger.error(`Scheduled task failed: ${name}`, error);
    }
  });
  logger.info(`Scheduled task registered: ${name}`, { schedule });
}

export function startScheduler(bot, options = {}) {
  // Main notification scheduler - runs every minute
  scheduleTask('checkReminders', '* * * * *', () => checkReminders(bot, options));
  console.log('✅ Notificador de lembretes iniciado');
}

export function startDailyDigest(bot, options = {}) {
  // Bug B-cron: digest precisa rodar a cada minuto para honrar o digest_time por usuário
