}

/**
 * Serviço de chatbot IA para o Telegram Bot (server-side).
 *
 * Equivalente server-side do chatbotService.js do cliente web.
 * Diferenças principais:
 * - Busca dados do paciente via Supabase diretamente (sem DashboardContext)
 * - Rate limiting via Map em memória (sem localStorage)
 * - Chama Groq SDK diretamente (sem fetch para /api/chatbot)
 * - Mantém histórico de conversa por userId em memória
 *
 * Configurações centralizadas em:
 * src/features/chatbot/config/chatbotConfig.js
 *
 * @module chatbotServerService
 */

import Groq from 'groq-sdk'
import { supabase } from '../../services/supabase.js'
import { createLogger } from '../logger.js'
import {
  CHATBOT_MAX_TOKENS,
  CHATBOT_TEMPERATURE,
  CHATBOT_TOP_P,
  CHATBOT_MAX_HISTORY,
  CHATBOT_RATE_LIMIT_MAX,
  CHATBOT_RATE_LIMIT_WINDOW,
  CHATBOT_BLOCKED_PATTERNS,
  CHATBOT_DISCLAIMER,
  CHATBOT_HEALTH_KEYWORDS,
} from '../../../apps/web/src/features/chatbot/config/chatbotConfig.js'

const logger = createLogger('ChatbotServerService')

const MODEL = process.env.GROQ_MODEL || 'groq/compound'
const rateLimitMap = new Map()
const historyMap = new Map()

// -- Segurança --

/**
 * Valida mensagem do usuário antes de enviar ao LLM.
 * @param {string} message
 * @returns {{ blocked: boolean, reason?: string }}
 */
export function validateServerMessage(message) {
  for (const pattern of CHATBOT_BLOCKED_PATTERNS) {
    if (pattern.test(message)) {
      return {
        blocked: true,
        reason: 'Não posso recomendar dosagens, diagnósticos ou mudanças no tratamento. Consulte seu médico.',
      }
    }
  }

  if (!message || message.length > 500) {
    return {
      blocked: true,
      reason: 'Mensagem muito longa. Tente ser mais conciso (máx 500 caracteres).',
    }
  }

  return { blocked: false }
}

/**
 * Adiciona disclaimer médico à resposta do LLM se necessário.
 * @param {string} response
 * @returns {string}
 */
export function addServerDisclaimer(response) {
  const hasHealthContent = CHATBOT_HEALTH_KEYWORDS.some(kw => response.toLowerCase().includes(kw))

  if (hasHealthContent && !response.includes('Não substituo')) {
    return `${response}\n\n_${CHATBOT_DISCLAIMER}_`
  }

  return response
}

// -- Rate limiting --

/**
 * Verifica se o usuário atingiu o limite de mensagens.
 * @param {string} userId
 * @returns {boolean}
 */
export function isServerRateLimited(userId) {
  const data = rateLimitMap.get(userId)
  if (!data) return false
  if (Date.now() - data.windowStart > CHATBOT_RATE_LIMIT_WINDOW) return false
  return data.count >= CHATBOT_RATE_LIMIT_MAX
}

function incrementServerRateCounter(userId) {
  const data = rateLimitMap.get(userId)
  const now = Date.now()

  if (!data || now - data.windowStart > CHATBOT_RATE_LIMIT_WINDOW) {
    rateLimitMap.set(userId, { windowStart: now, count: 1 })
  } else {
    rateLimitMap.set(userId, { windowStart: data.windowStart, count: data.count + 1 })
  }
}

// -- Busca de dados do paciente --

/**
 * Busca dados do paciente no Supabase para construção de contexto.
 * @param {string} userId
 * @returns {Promise<{ medicines, protocols, logs, stockSummary, stats }>}
 */
export async function fetchPatientData(userId) {
  logger.debug('📊 fetchPatientData: iniciando', { userId })

  const today = new Date()
  const yesterday = new Date(today.getTime() - 36 * 60 * 60 * 1000).toISOString()

  logger.debug('📅 Intervalo de tempo', {
    userId,
    today: today.toISOString(),
    yesterday,
  })

  logger.debug('🔄 Executando 4 queries em paralelo (Supabase)', { userId })

  const [medicinesResult, protocolsResult, logsResult, stockResult] = await Promise.all([
    supabase
      .from('medicines')
      .select('id, name, dosage_per_pill, dosage_unit, active_ingredient, therapeutic_class')
      .eq('user_id', userId),

    supabase
      .from('protocols')
      .select('id, medicine_id, frequency, time_schedule, dosage_per_intake')
      .eq('user_id', userId)
      .eq('active', true),

    supabase
      .from('medicine_logs')
      .select('protocol_id, taken_at')
      .eq('user_id', userId)
      .gte('taken_at', yesterday),

    supabase
      .from('stock')
      .select('medicine_id, quantity')
      .eq('user_id', userId)
      .gt('quantity', 0),
  ])

  logger.debug('✅ Queries Supabase completadas', {
    userId,
    medicinesCount: medicinesResult.data?.length || 0,
    medicinesError: medicinesResult.error?.message,
    protocolsCount: protocolsResult.data?.length || 0,
    protocolsError: protocolsResult.error?.message,
    logsCount: logsResult.data?.length || 0,
    logsError: logsResult.error?.message,
    stockCount: stockResult.data?.length || 0,
    stockError: stockResult.error?.message,
  })

  if (medicinesResult.error) {
    const { code, details, hint } = medicinesResult.error
    logger.error('❌ Erro ao buscar medicamentos', medicinesResult.error, {
      userId,
      errorCode: code,
      errorDetails: details,
      errorHint: hint,
    })
    throw medicinesResult.error
  }

  const timezone = 'America/Sao_Paulo'
  const todayLocal = new Intl.DateTimeFormat('en-CA', { timeZone: timezone }).format(today)

  // Filtrar logs de hoje (com timezone correto)
  const todayLogs = (logsResult.data || []).filter(log => {
    const logDate = new Intl.DateTimeFormat('en-CA', { timeZone: timezone }).format(new Date(log.taken_at))
    return logDate === todayLocal
  })

  // Agregar estoque por medicamento
  const stockByMedicine = {}
  for (const entry of (stockResult.data || [])) {
    stockByMedicine[entry.medicine_id] = (stockByMedicine[entry.medicine_id] || 0) + entry.quantity
  }

  const stockSummary = Object.entries(stockByMedicine).map(([medicine_id, quantity]) => ({
    medicine_id,
    quantity,
  }))

  // Calcular adesão simples dos últimos 7 dias
  const stats = await calculateSimpleAdherence(userId, protocolsResult.data || [])

  return {
    medicines: medicinesResult.data || [],
    protocols: protocolsResult.data || [],
    logs: todayLogs,
    stockSummary,
    stats,
  }
}

/**
 * Calcula adesão simples nos últimos 7 dias.
 * Versão simplificada sem protocolo completo.
 * @param {string} userId
 * @param {Array} protocols
 * @returns {Promise<{ adherence: number|null }>}
 */
async function calculateSimpleAdherence(userId, protocols) {
  if (!protocols.length) return { adherence: null }

  const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString()
  const { data: logs } = await supabase
    .from('medicine_logs')
    .select('id')
    .eq('user_id', userId)
    .gte('taken_at', sevenDaysAgo)

  // Estimativa simples: doses registradas / doses esperadas
  const totalDosesPerDay = protocols.reduce(
    (sum, p) => sum + (p.time_schedule?.length || 1),
    0
  )
  const expectedDoses = totalDosesPerDay * 7
  const actualDoses = logs?.length || 0

  return {
    adherence: expectedDoses > 0 ? Math.min(actualDoses / expectedDoses, 1) : null,
  }
}

// -- Construção de contexto (adaptado de contextBuilder.js) --

/**
 * Monta contexto compacto do paciente para o LLM.
 * Mesmo formato do contextBuilder.js do cliente web.
 * @param {{ medicines, protocols, logs, stockSummary, stats }} patientData
 * @returns {string}
 */
export function buildServerContext({ medicines, protocols, logs, stockSummary, stats }) {
  const today = new Date()
  const todayStr = today.toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' })

  const medsContext = (medicines || []).map(med => {
    const protocol = (protocols || []).find(p => p.medicine_id === med.id)
    const stockEntry = (stockSummary || []).find(s => s.medicine_id === med.id)
    const totalStock = stockEntry?.quantity ?? 0

    return {
      nome: med.name,
      principioAtivo: med.active_ingredient,
      classeTerapeutica: med.therapeutic_class,
      dosagem: `${med.dosage_per_pill ?? ''}${med.dosage_unit ?? ''}`.trim(),
      frequencia: protocol?.frequency ?? 'sem protocolo',
      horarios: protocol?.time_schedule ?? [],
      estoque: totalStock,
    }
  })

  const adherence7d = stats?.adherence != null ? Math.round(stats.adherence * 100) : null

  return [
    `Data: ${todayStr}`,
    `Medicamentos ativos: ${medsContext.length}`,
    ...medsContext.map(m => {
      const infos = [m.principioAtivo, m.classeTerapeutica].filter(Boolean).join(', ')
      const detalhe = infos ? ` [${infos}]` : ''
      return `- ${m.nome}${detalhe} (${m.dosagem}): ${m.frequencia}, horarios ${m.horarios.join(', ') || 'nao definidos'}, estoque ${m.estoque} un.`
    }),
    `Doses registradas hoje: ${logs?.length ?? 0}`,
    adherence7d != null ? `Adesao ultimos 7 dias: ${adherence7d}%` : '',
  ]
    .filter(Boolean)
    .join('\n')
}

/**
 * Constrói a PARTE ESTÁTICA do system prompt (regras, instruções).
 * Esta seção é cacheable porque não muda entre requisições.
 * Ref: Groq Prompt Caching docs — colocar conteúdo estático PRIMEIRO.
 *
 * @returns {string}
 */
export function buildStaticSystemRules() {
  return [
    'Você é um assistente virtual do app Dosiq no Telegram.',
    'Você ajuda o paciente a gerenciar seus medicamentos de forma amigavel.',
    'REGRAS ABSOLUTAS:',
    '- NUNCA recomende dosagens, diagnosticos ou substituicoes de medicamentos.',
    '- NUNCA sugira parar ou alterar tratamento sem consultar o medico.',
    '- Se sua resposta menciona medicamentos ou saúde, SEMPRE termine com uma linha em branco seguida de: "Não substituo orientação médica."',
    '- Responda em portugues brasileiro, de forma concisa (max 3 frases).',
    '- Responda em texto simples, sem Markdown (o Telegram usa formatacao diferente).',
    '- Use os dados do paciente abaixo para contextualizar respostas.',
  ].join('\n')
}

/**
 * System prompt para o LLM (mesmo do contextBuilder.js web).
 * Combina regras estáticas (cacheable) + contexto dinâmico do paciente.
 *
 * NOTA: Para otimizar Groq Prompt Caching:
 * - Conteúdo estático (buildStaticSystemRules) deve vir PRIMEIRO
 * - Conteúdo dinâmico (patientContext) vem DEPOIS
 * - Isso permite cache hit em conversas multi-turn onde o contexto é reutilizado
 *
 * @param {string} patientContext
 * @returns {string}
 */
export function buildServerSystemPrompt(patientContext) {
  const staticRules = buildStaticSystemRules()
  return [
    staticRules,
    '',
    'DADOS DO PACIENTE:',
    patientContext,
  ].join('\n')
}

// -- Histórico de conversa --

/**
 * Obtém histórico de conversa de um usuário.
 * @param {string} userId
 * @returns {Array<{role: string, content: string}>}
 */
export function getConversationHistory(userId) {
  return historyMap.get(userId) || []
}

/**
 * Atualiza histórico de conversa de um usuário.
 * @param {string} userId
 * @param {string} userMessage
 * @param {string} assistantResponse
 */
export function updateConversationHistory(userId, userMessage, assistantResponse) {
  const history = historyMap.get(userId) || []
  const newHistory = [
    ...history,
    { role: 'user', content: userMessage },
    { role: 'assistant', content: assistantResponse },
  ].slice(-CHATBOT_MAX_HISTORY)
  historyMap.set(userId, newHistory)
}

// -- Função principal --

/**
 * Envia mensagem ao chatbot IA via Groq e retorna resposta.
 *
 * @param {Object} params
 * @param {string} params.message - Mensagem do usuário
 * @param {string} params.userId - UUID do usuário (para buscar dados e rate limit)
 * @returns {Promise<{
 *   response: string,
 *   blocked: boolean,
 *   reason?: string,
 *   rateLimited: boolean
 * }>}
 */
export async function sendTelegramChatMessage({ message, userId }) {
  logger.info('🤖 sendTelegramChatMessage entrada', {
    userId,
    msgLen: message.length,
    msgPreview: message.substring(0, 50),
  })

  // 1. Validar mensagem
  logger.debug('🔍 Validando mensagem', { userId })
  const validation = validateServerMessage(message)
  if (validation.blocked) {
    logger.info('⛔ Mensagem bloqueada pela validação', {
      userId,
      reason: validation.reason,
    })
    return { response: validation.reason, blocked: true, rateLimited: false }
  }
  logger.debug('✅ Validação passou', { userId })

  // 2. Rate limiting
  if (isServerRateLimited(userId)) {
    logger.warn('⏱️ Rate limit atingido para usuário', { userId })
    return {
      response: '⏱️ Muitas perguntas! Aguarde alguns minutos e tente novamente.',
      blocked: false,
      rateLimited: true,
    }
  }
  logger.debug('✅ Rate limit OK', { userId })

  // 3. Verificar API key
  if (!process.env.GROQ_API_KEY) {
    logger.error('❌ GROQ_API_KEY não configurada')
    return {
      response: '🤖 Assistente IA temporariamente indisponível.',
      blocked: false,
      rateLimited: false,
    }
  }

  // 4. Buscar dados do paciente
  let patientData
  try {
    logger.info('📊 Buscando dados do paciente no Supabase', { userId })
    patientData = await fetchPatientData(userId)
    logger.info('✅ Dados do paciente obtidos com sucesso', {
      userId,
      medicinesCount: patientData.medicines?.length || 0,
      protocolsCount: patientData.protocols?.length || 0,
      logsCount: patientData.logs?.length || 0,
      stockCount: patientData.stockSummary?.length || 0,
      adherencePercent: patientData.stats?.adherence
        ? Math.round(patientData.stats.adherence * 100)
        : null,
    })
  } catch (error) {
    logger.error('❌ Erro ao buscar dados do paciente', error, { userId })
    return {
      response: 'Desculpe, tive um problema ao carregar seus dados. Tente novamente.',
      blocked: false,
      rateLimited: false,
    }
  }

  // 5. Construir contexto e system prompt
  logger.debug('🔨 Construindo contexto do paciente', { userId })
  const context = buildServerContext(patientData)
  const systemPrompt = buildServerSystemPrompt(context)
  const history = getConversationHistory(userId)
  logger.debug('✅ Contexto construído', {
    userId,
    contextLen: context.length,
    systemPromptLen: systemPrompt.length,
    historyLen: history.length,
  })

  // 6. Chamar Groq API
  try {
    const groq = new Groq({ apiKey: process.env.GROQ_API_KEY })
    const messages = [
      { role: 'system', content: systemPrompt },
      ...history,
      { role: 'user', content: message },
    ]

    logger.info('🔵 Chamando Groq API', {
      userId,
      model: MODEL,
      messagesCount: messages.length,
      maxTokens: CHATBOT_MAX_TOKENS,
      temperature: CHATBOT_TEMPERATURE,
      topP: CHATBOT_TOP_P,
    })

    const completion = await groq.chat.completions.create({
      model: MODEL,
      messages,
      max_tokens: CHATBOT_MAX_TOKENS,
      temperature: CHATBOT_TEMPERATURE,
      top_p: CHATBOT_TOP_P,
    })

    const rawResponse =
      completion.choices[0]?.message?.content || 'Desculpe, não consegui responder.'

    const promptTokens = completion.usage?.prompt_tokens || 0
    const cachedTokens = completion.usage?.cached_prompt_tokens || 0
    const cacheHitRate = promptTokens > 0 ? Math.round((cachedTokens / promptTokens) * 100) : 0
    const estimatedSavings = Math.round(cachedTokens * 0.5) // 50% desconto em cached_tokens

    logger.info('✅ Groq respondeu com sucesso', {
      userId,
      rawResponseLen: rawResponse.length,
      promptTokens,
      cachedTokens,
      cacheHitRate: `${cacheHitRate}%`,
      estimatedTokenSavings: estimatedSavings,
      completionTokens: completion.usage?.completion_tokens,
      totalTokens: completion.usage?.total_tokens,
    })

    // 7. Adicionar disclaimer se necessário
    const response = addServerDisclaimer(rawResponse)
    logger.debug('📝 Disclaimer adicionado (se necessário)', {
      userId,
      finalLen: response.length,
      disclaimerAdded: response.length > rawResponse.length,
    })

    // 8. Incrementar rate counter e atualizar histórico
    incrementServerRateCounter(userId)
    updateConversationHistory(userId, message, response)
    logger.info('✅ Taxa incrementada e histórico atualizado', { userId })

    logger.info('✅ Resposta final pronta para envio', {
      userId,
      finalResponseLen: response.length,
    })

    return { response, blocked: false, rateLimited: false }
  } catch (error) {
    logger.error('❌ Erro ao chamar Groq API', error, {
      userId,
      errorStatus: error.status,
      errorMessage: error.message,
      errorType: error.constructor.name,
    })

    if (error.status === 429) {
      logger.warn('⚠️ Rate limit na Groq API', { userId })
      return {
        response: '⏱️ Serviço de IA sobrecarregado. Tente novamente em alguns segundos.',
        blocked: false,
        rateLimited: false,
      }
    }

    return {
      response: 'Desculpe, estou com dificuldades técnicas. Tente novamente em instantes.',
      blocked: false,
      rateLimited: false,
    }
  }
}

import { supabase } from '../services/supabase.js';
import { createLogger } from '../bot/logger.js';
import { ErrorCategories } from '../services/deadLetterQueue.js';
import { getCurrentCorrelationId } from './correlationLogger.js';
import {
  getActiveProtocols
} from '../services/protocolCache.js';
import { shouldSendNotification, shouldSendGroupedNotification } from '../services/notificationDeduplicator.js';
import {
  getCurrentTimeInTimezone,
  getCurrentDateInTimezone
} from '../utils/timezone.js';
import { partitionDoses } from './utils/partitionDoses.js';
import { parseLocalDate, formatLocalDate } from '../utils/dateUtils.js';
import { 
  formatMedicineWithStrength, 
  formatIntakeQuantity 
} from './utils/notificationHelpers.js';


const logger = createLogger('Tasks');

// Horário fixo para o relatório diário de adesão (fechamento do dia)
const ADHERENCE_REPORT_TIME = '23:00';

// Helpers removidos (migrados para ./utils/notificationHelpers.js)

/**
 * Função genérica para enviar alertas de estoque
 * Consolida lógica compartilhada: deduplicação, envio, logging e enfileiramento em DLQ
 *
 * @param {object} params - Parâmetros da função
 * @param {string} params.userId - ID do usuário
 * @param {string} params.chatId - ID do chat Telegram
 * @param {string} params.notificationType - Tipo de notificação ('stock_alert', 'proactive_stock_alert')
 * @param {function} params.formatMessage - Função que retorna a mensagem formatada
 * @param {object} params.bot - Instância do bot Telegram
 * @param {object} params.dlqPayload - Dados para enfileiramento em DLQ em caso de erro
 * @param {object} params.logContext - Contexto adicional para logging
 */

// --- Helper Functions ---



/**
 * Check reminders via dispatcher com agrupamento por treatment_plan (Wave N1).
 *
 * Substitui o loop "1 dispatch por protocolo" por partição semântica:
 *   - 1 dispatch por plano com ≥2 doses (dose_reminder_by_plan)
 *   - 1 dispatch consolidado para sobra ≥2 sem plano (dose_reminder_misc)
 *   - 1 dispatch individual para dose única (dose_reminder)
 *
 * ADR-029, ADR-030. R-031 (escapeMarkdownV2). R-030 (callback_data <64 bytes).
 */
async function checkRemindersViaDispatcher(dispatcher, correlationId) {
  try {
    // R-111: Buscar apenas usuários ativos (evita queries em massa na auth.users)
    const { data: users, error: userError } = await supabase
      .from('user_settings')
      .select('user_id, timezone, notification_mode, quiet_hours_start, quiet_hours_end');

    if (userError) throw userError;

    // WAVE 11: Filtrar usuários que não estão no modo realtime
    // Silent: sem notificações
    // Digest: notificações individuais suprimidas (recebe apenas o resumo matinal)
    const realtimeUsers = (users || []).filter(u => u.notification_mode === 'realtime');

    if (realtimeUsers.length === 0) {
      logger.info('Nenhum usuário em modo realtime encontrado para dispatch de lembretes unitários', { correlationId });
      return;
    }

    logger.info(`Iniciando verificação de lembretes para ${realtimeUsers.length} usuários em modo realtime`, { correlationId });

    // Otimização Wave 12: Agrupar usuários por HHMM local para busca otimizada via JSONB (@>)
    // R-020: Usamos Map para garantir consistência de tempo por usuário (evita minute-flip race)
    const userTimes = new Map();
    const userIdsByHHMM = {};

    for (const user of realtimeUsers) {

      const timezone = user.timezone || 'America/Sao_Paulo';
      // Sanitização: remove caracteres de controle do Intl (ex: \u202f no Node 18+) que quebram JSONB
      const currentHHMM = getCurrentTimeInTimezone(timezone).replace(/[^\d:]/g, ''); 
      userTimes.set(user.user_id, currentHHMM);

      if (!userIdsByHHMM[currentHHMM]) userIdsByHHMM[currentHHMM] = [];
      userIdsByHHMM[currentHHMM].push(user.user_id);
    }

    const allProtocols = [];
    for (const [hhmm, ids] of Object.entries(userIdsByHHMM)) {
      // Otimização: Batching de IDs (lotes de 50) para evitar limites de URL (414 Request-URI Too Large)
      for (let i = 0; i < ids.length; i += 50) {
        const chunk = ids.slice(i, i + 50);
        const { data, error } = await supabase
          .from('protocols')
          .select(`
            id,
            user_id,
            name,
            time_schedule,
            medicine_id,
            dosage_per_intake,
            treatment_plan_id,
            medicine:medicines(name, dosage_unit, dosage_per_pill),
            treatment_plan:treatment_plans(id, name)
          `)
          .in('user_id', chunk)
          .eq('active', true)
          // Fix Wave 12: JSON.stringify garante sintaxe correta para JSONB @> no PostgREST
          .contains('time_schedule', JSON.stringify([hhmm])); 

        if (error) {
          logger.error(`Erro ao buscar protocolos para HHMM ${hhmm} (Batch ${Math.floor(i/50) + 1})`, error, { correlationId });
          continue;
        }
        if (data) allProtocols.push(...data);
      }
    }

    // Agrupar por user_id em memória (para facilitar o loop de dispatch por usuário)
    const protocolsByUser = {};
    for (const p of allProtocols) {
      if (!protocolsByUser[p.user_id]) protocolsByUser[p.user_id] = [];
      protocolsByUser[p.user_id].push(p);
    }

    for (const user of realtimeUsers) {
      const userId = user.user_id;

      try {
        // Recupera o tempo calculado no início para manter consistência com a query
        const currentHHMM = userTimes.get(userId);
        const currentHour = parseInt(currentHHMM.split(':')[0], 10);
        const protocols = protocolsByUser[userId] || [];
        if (protocols.length === 0) continue;

        // Coletar doses ativas neste minuto
        const dosesNow = protocols
          .filter(p => (p.time_schedule || []).includes(currentHHMM))
          .map(p => ({
            protocolId: p.id,
            protocolName: p.name,
            medicineName: formatMedicineWithStrength(
              p.medicine?.name || p.name, 
              p.medicine?.dosage_per_pill, 
              p.medicine?.dosage_unit
            ),
            treatmentPlanId: p.treatment_plan_id ?? null,
            treatmentPlanName: p.treatment_plan?.name ?? null,
            dosagePerIntake: p.dosage_per_intake ?? 1,
            dosageString: formatIntakeQuantity(p.dosage_per_intake || 1, p.medicine?.dosage_unit),
            medicineId: p.medicine_id,
          }));

        if (dosesNow.length === 0) continue;

        // Particionar em blocos semânticos (cenários A–I)
        const blocks = partitionDoses(dosesNow);

        logger.info(`${dosesNow.length} dose(s) → ${blocks.length} bloco(s) para userId=${userId} às ${currentHHMM}`, {
          correlationId,
          userId,
          blockKinds: blocks.map(b => b.kind),
        });

        for (const block of blocks) {
          // Verificar deduplicação para blocos agrupados
          const normalizedKind = block.kind?.toLowerCase();
          if (['by_plan', 'misc'].includes(normalizedKind)) {
            const notificationType = 'dose_reminder_' + normalizedKind;
            const options = normalizedKind === 'by_plan' ? { planId: block.planId } : {};
            const shouldSend = await shouldSendGroupedNotification(userId, notificationType, options);
            if (!shouldSend) {
              const logContext = { userId, correlationId };
              if (block.planId) {
                logContext.planId = block.planId;
              }
              logger.debug('Dose reminder ' + normalizedKind + ' suprimido por deduplicação', logContext);
              continue;
            }
          }

          let kind, data;

          if (block.kind === 'by_plan') {
            kind = 'dose_reminder_by_plan';
            data = {
              planId: block.planId,
              planName: block.planName,
              scheduledTime: currentHHMM,
              hour: currentHour,
              doses: block.doses,
              protocolIds: block.doses.map(d => d.protocolId),
            };
          } else if (block.kind === 'misc') {
            kind = 'dose_reminder_misc';
            data = {
              scheduledTime: currentHHMM,
              hour: currentHour,
              doses: block.doses,
              protocolIds: block.doses.map(d => d.protocolId),
            };
          } else {
            // individual
            const dose = block.doses[0];
            kind = 'dose_reminder';
            data = {
              medicineName: dose.medicineName,
              protocolId: dose.protocolId,
              medicineId: dose.medicineId,
              time: currentHHMM,
              dosage: dose.dosageString || dose.dosagePerIntake,
            };
          }

          const result = await dispatcher.dispatch({
            userId,
            kind,
            data,
            context: { correlationId, jobType: 'dose_reminder_dispatcher' },
          });

          if (!result.success) {
            logger.error('Falha no dispatch do bloco de dose', null, {
              userId,
              kind,
              planId: block.planId,
              errors: result.errors,
              correlationId,
            });
          }
        }
      } catch (err) {
        logger.error('Erro ao processar lembretes do usuário via dispatcher', err, { userId, correlationId });
      }
    }

    logger.info('CheckReminders (Dispatcher) concluído', { correlationId });
  } catch (err) {
    logger.error('Erro crítico em checkRemindersViaDispatcher', err, { correlationId });
  }
}



/**
 * Check reminders for ALL users (cron job)
 * @param {object} bot - Bot adapter
 * @param {object} options - Opções adicionais (correlationId, etc)
 */
export async function checkReminders(bot, options = {}) {
  const correlationId = options.correlationId || getCurrentCorrelationId();
  const notificationDispatcher = options.notificationDispatcher;

  if (!notificationDispatcher) {
    logger.warn('NotificationDispatcher não fornecido para checkReminders. Skipping.', { correlationId });
    return;
  }

  logger.info('Iniciando verificação de lembretes via Dispatcher (ADR-030)', { correlationId });
  return checkRemindersViaDispatcher(notificationDispatcher, correlationId);
}

/**
 * Run daily digest via dispatcher (Sprint 6.4 — ADR-029, ADR-030)
 */
async function runDailyDigestViaDispatcher(dispatcher, correlationId) {
  try {
    // Bug B7: auth.users não é acessível pelo client JS — usar user_settings
    // Aproveitar para pré-carregar settings e evitar N+1 de getUserSettings()
    const { data: usersRaw } = await supabase
      .from('user_settings')
      .select('user_id, notification_mode, digest_time, timezone, display_name')
      .eq('notification_mode', 'digest_morning');

    const users = usersRaw ?? [];
    if (users.length === 0) {
      logger.debug('Daily digest: nenhum usuário em modo digest_morning', { correlationId });
      return;
    }

    logger.info(`Running daily digest via dispatcher for ${users.length} users`, { correlationId });

    // Fase 1: filtrar usuários cujo digest_time bate com o horário atual
    const eligibleEntries = [];
    for (const user of users) {
      const userId = user.user_id;
      try {
        const timezone = user.timezone || 'America/Sao_Paulo';
        // Bug B-formato: Postgres TIME retorna '14:00:00' (com segundos)
        // getCurrentTimeInTimezone retorna 'HH:MM' — fatiar para comparar
        const digestTime = (user.digest_time || '07:00').slice(0, 5);
        const currentHHMM = getCurrentTimeInTimezone(timezone);

        logger.debug(`Evaluating user ${userId} (${user.display_name})`, { 
          timezone, 
          digestTime, 
          currentHHMM, 
          match: currentHHMM === digestTime,
          correlationId 
        });

        if (currentHHMM !== digestTime) continue;

        const shouldSend = await shouldSendNotification(userId, null, 'daily_digest');
        if (!shouldSend) {
          logger.debug(`Daily digest suppressed by deduplication`, { userId, correlationId });
          continue;
        }

        eligibleEntries.push({ 
          userId, 
          timezone, 
          displayName: user.display_name,
          digestTime 
        });
      } catch (err) {
        logger.error(`Error evaluating daily digest eligibility for user`, err, { userId, correlationId });
      }
    }

    if (eligibleEntries.length === 0) {
      logger.info('Daily digest: no eligible users at this time', { correlationId });
      return;
    }

    // Fase 2: bulk-fetch de protocolos para todos os usuários elegíveis (evita N+1)
    const eligibleIds = eligibleEntries.map(e => e.userId);
    const { data: allProtocols } = await supabase
      .from('protocols')
      .select('*, medicine:medicines(name, dosage_unit, dosage_per_pill)')
      .in('user_id', eligibleIds)
      .eq('active', true);

    const protocolsByUser = {};
    for (const p of allProtocols ?? []) {
      if (!protocolsByUser[p.user_id]) protocolsByUser[p.user_id] = [];
      protocolsByUser[p.user_id].push(p);
    }

    // Fase 3: dispatch por usuário com dados já em memória
    for (const { userId, displayName, digestTime } of eligibleEntries) {
      try {
        const protocols = protocolsByUser[userId] || [];


        // Agenda de Hoje
        const todaySchedule = [];
        protocols.forEach(p => {
          (p.time_schedule || []).forEach(time => {
            todaySchedule.push({
              time,
              medicineName: formatMedicineWithStrength(
                p.medicine?.name || p.name,
                p.medicine?.dosage_per_pill,
                p.medicine?.dosage_unit
              ),
              dosageString: formatIntakeQuantity(p.dosage_per_intake || 1, p.medicine?.dosage_unit)
            });
          });
        });
        todaySchedule.sort((a, b) => a.time.localeCompare(b.time));

        const currentHour = parseInt(digestTime.split(':')[0], 10);

        // Dados para a Presentation Layer (L2) - Gate L1 -> L2
        const data = {
          firstName: displayName || 'Paciente',
          hour: currentHour,
          pendingCount: todaySchedule.length,
          medicines: todaySchedule.map(s => ({
            name: s.medicineName,
            time: s.time,
            dosage: s.dosageString
          }))
        };

        await dispatcher.dispatch({
          userId,
          kind: 'daily_digest',
          data,
          context: { correlationId, jobType: 'daily_digest' }
        });

      } catch (err) {
        logger.error(`Error processing daily digest for user`, err, { userId, correlationId });
      }
    }
  } catch (error) {
    logger.error('Error in runDailyDigestViaDispatcher', error, { correlationId });
  }
}

/**
 * Relatório Diário de Adesão (Fase 12)
 * Disparado às 23:00 para todos os usuários (estratégia Inbox-First).
 * Foca em analytics e reforço positivo.
 */
async function runDailyAdherenceReportViaDispatcher(dispatcher, correlationId) {
  try {
    const { data: users } = await supabase
      .from('user_settings')
      .select('user_id, timezone, display_name, digest_time, notification_mode')
      .neq('notification_mode', 'silent');


    if (!users || users.length === 0) return;

    const eligibleUsers = [];
    for (const user of users) {
      try {
        const timezone = user.timezone || 'America/Sao_Paulo';
        const currentHHMM = getCurrentTimeInTimezone(timezone).replace(/[^\d:]/g, ''); 

        // Relatório de adesão é fixo às 23:00 (ADHERENCE_REPORT_TIME)
        // Desacoplado do digest_time (que é matinal)
        if (currentHHMM !== ADHERENCE_REPORT_TIME) continue;

        const shouldSend = await shouldSendNotification(user.user_id, null, 'adherence_report');
        if (!shouldSend) continue;

        eligibleUsers.push(user);
      } catch (err) {
        logger.error(`Error evaluating adherence report eligibility for user`, err, { userId: user.user_id, correlationId });
      }
    }

    if (eligibleUsers.length === 0) return;

    logger.info(`Running daily adherence report for ${eligibleUsers.length} users`, { correlationId });

    const userIds = eligibleUsers.map(u => u.user_id);
    const { data: allProtocols } = await supabase
      .from('protocols')
      .select('*, medicine:medicines(name)')
      .in('user_id', userIds)
      .eq('active', true);

    const protocolsByUser = {};
    for (const p of allProtocols ?? []) {
      if (!protocolsByUser[p.user_id]) protocolsByUser[p.user_id] = [];
      protocolsByUser[p.user_id].push(p);
    }

    for (const user of eligibleUsers) {
      const { user_id: userId, timezone, display_name: displayName } = user;
      try {
        const dateToday = getCurrentDateInTimezone(timezone || 'America/Sao_Paulo');
        const startOfDay = parseLocalDate(dateToday);
        const dateYesterdayDate = new Date(startOfDay);
        dateYesterdayDate.setDate(dateYesterdayDate.getDate() - 1);
        const startOfYesterday = formatLocalDate(dateYesterdayDate);

        const { data: logs } = await supabase
          .from('medicine_logs')
          .select('*')
          .eq('user_id', userId)
          .gte('taken_at', dateYesterdayDate.toISOString());

        const todayLogs = logs?.filter(l => l.taken_at >= startOfDay.toISOString()) || [];
        const yesterdayLogs = logs?.filter(l => l.taken_at < startOfDay.toISOString() && l.taken_at >= dateYesterdayDate.toISOString()) || [];

        const protocols = protocolsByUser[userId] || [];
        if (protocols.length === 0) continue;

        const expectedDoses = protocols.reduce((sum, p) => sum + (p.time_schedule?.length || 0), 0);
        const takenDoses = todayLogs.length;
        const percentage = expectedDoses > 0 ? Math.min(100, Math.round((takenDoses / expectedDoses) * 100)) : 0;

        const expectedYesterday = protocols.reduce((sum, p) => {
          if (p.start_date && p.start_date > startOfYesterday) return sum;
          return sum + (p.time_schedule?.length || 0);
        }, 0);
        const percentageYesterday = expectedYesterday > 0 ? Math.min(100, Math.round((yesterdayLogs.length / expectedYesterday) * 100)) : 0;

        // Storytelling logic
        let storytelling = '';
        if (percentage > percentageYesterday) {
          storytelling = `📈 Melhora de ${percentage - percentageYesterday}% em relação a ontem!`;
        } else if (percentage < percentageYesterday && percentage > 0) {
          storytelling = `📉 Hoje foi um pouco mais difícil que ontem (${percentage}% vs ${percentageYesterday}%).`;
        } else if (percentage === 100 && percentageYesterday === 100) {
          storytelling = `🌟 Segundo dia seguido com 100%!`;
        } else if (percentage === 0 && expectedDoses > 0) {
          storytelling = `🧘 Amanhã é uma nova oportunidade para cuidar de você.`;
        } else {
          storytelling = `⚖️ Mantendo a constância de ontem.`;
        }

        // Dados para a Presentation Layer (L2) - Gate L1 -> L2
        const data = {
          firstName: displayName || 'Paciente',
          period: 'hoje',
          percentage,
          taken: takenDoses,
          total: expectedDoses,
          storytelling
        };

        await dispatcher.dispatch({
          userId,
          kind: 'adherence_report',
          data,
          context: { correlationId, jobType: 'adherence_report' }
        });

      } catch (err) {
        logger.error(`Error processing daily adherence for user`, err, { userId, correlationId });
      }
    }
  } catch (error) {
    logger.error('Error in runDailyAdherenceReportViaDispatcher', error, { correlationId });
  }
}

