import { handleEstoque } from './bot/commands/estoque.js';
import { handleHoje } from './bot/commands/hoje.js';
import { handleProxima } from './bot/commands/proxima.js';
import { handleHistorico } from './bot/commands/historico.js';
import { handleAjuda } from './bot/commands/ajuda.js';
import { handleRegistrar } from './bot/commands/registrar.js';
import { handleAdicionarEstoque, handleReporShortcut } from './bot/commands/adicionar_estoque.js';
import { handlePausar, handleRetomar } from './bot/commands/protocols.js';
import { handleChatbotMessage } from './bot/commands/chatbot.js';
import { handleCallbacks } from './bot/callbacks/doseActions.js';
import { handleConversationalCallbacks } from './bot/callbacks/conversational.js';
import { handleInlineQueries } from './bot/inlineQuery.js';
import { startScheduler, startDailyDigest } from './bot/scheduler.js';
import { startStockAlerts, startAdherenceReports, startTitrationAlerts, startMonthlyReport } from './bot/alerts.js';
import { startAutoCleanup } from './services/sessionManager.js';
import { BotFactory } from './bot/bot-factory.js';
import { createLogger } from './bot/logger.js';
import { healthCheck, registerDefaultChecks } from './bot/health-check.js';
import { supabase } from './services/supabase.js';
import { getNotificationDispatcher } from './bot/utils/dispatcherFactory.js';

const logger = createLogger('BotApp');

// Validate environment
const token = process.env.TELEGRAM_BOT_TOKEN;
if (!token) {
  logger.error('TELEGRAM_BOT_TOKEN não definido no .env');
  process.exit(1);
}

// Validate token before creating bot
logger.info('Validating Telegram token...');
const validation = await BotFactory.validateToken(token);
if (!validation.valid) {
  logger.error('Token validation failed', null, { error: validation.error });
  process.exit(1);
}
logger.info('Token validated', { username: validation.botInfo.username });

// Initialize bot with factory
const bot = BotFactory.createPollingBot(token);

// Initialize Notification Dispatcher (Sprint Wave N2)
const notificationDispatcher = getNotificationDispatcher(bot);
const schedulerOptions = { notificationDispatcher };

// Register health checks
registerDefaultChecks(bot, supabase);

// Run initial health check
const initialHealth = await healthCheck.runAll();
logger.info('Initial health check', { results: initialHealth });

logger.info('Bot de Remédios iniciado com sucesso!');
logger.info('Comandos disponíveis: /start, /status, /estoque, /hoje, /proxima, /historico, /ajuda, /registrar, /adicionar_estoque, /repor, /pausar, /retomar');

// Register command handlers
bot.onText(/\/start/, (msg) => handleStart(bot, msg));
bot.onText(/\/status/, (msg) => handleStatus(bot, msg));
bot.onText(/\/estoque/, (msg) => handleEstoque(bot, msg));
bot.onText(/\/hoje/, (msg) => handleHoje(bot, msg));
bot.onText(/\/proxima/, (msg) => handleProxima(bot, msg));
bot.onText(/\/historico/, (msg) => handleHistorico(bot, msg));
bot.onText(/\/ajuda/, (msg) => handleAjuda(bot, msg));
bot.onText(/\/registrar/, (msg) => handleRegistrar(bot, msg));
bot.onText(/\/adicionar_estoque/, (msg) => handleAdicionarEstoque(bot, msg));
bot.onText(/\/repor\s+(.+)\s+(\d+[.,]?\d*)/, (msg, match) => handleReporShortcut(bot, msg, match));
bot.onText(/\/pausar(?:\s+(.+))?/, (msg, match) => handlePausar(bot, msg, match));
bot.onText(/\/retomar(?:\s+(.+))?/, (msg, match) => handleRetomar(bot, msg, match));

// Register callback handlers
handleCallbacks(bot);
handleConversationalCallbacks(bot);

// Register inline query handler (Phase 2.2)
handleInlineQueries(bot);

// Chatbot IA: mensagens de texto não-comando encaminhadas para Groq (Sprint 8.3.2)
bot.on('message', (msg) => handleChatbotMessage(bot, msg));

// Start scheduler
startScheduler(bot, schedulerOptions);
startDailyDigest(bot, schedulerOptions);

// Start intelligent alerts (Phase 4)
startStockAlerts(bot, schedulerOptions);
startAdherenceReports(bot, schedulerOptions);
startTitrationAlerts(bot, schedulerOptions);
startMonthlyReport(bot, schedulerOptions);

// Start session cleanup for persistent sessions
startAutoCleanup();

// Graceful shutdown
process.on('SIGTERM', async () => {
  logger.info('SIGTERM received, shutting down gracefully...');
  bot.stopPolling();
  process.exit(0);
});

process.on('SIGINT', async () => {
  logger.info('SIGINT received, shutting down gracefully...');
  bot.stopPolling();
  process.exit(0);
});

// Canal de notificação Telegram
// Encapsula o adapter Telegram existente (server/bot/)
// Recebe payload canônico e converte para texto MarkdownV2
// bot é injetado para facilitar testes sem chamadas HTTP reais

import { supabase } from '../../services/supabase.js'
import { escapeMarkdownV2 } from '../../utils/formatters.js'
import {
  formatDoseGroupedByPlanMessage,
  formatDoseGroupedMiscMessage,
} from '../../bot/utils/doseFormatters.js'
// Retorna telegram_chat_id do usuário ou null se não configurado
async function getTelegramChatId(userId) {
  const { data, error } = await supabase
    .from('user_settings')
    .select('telegram_chat_id')
    .eq('user_id', userId)
    .single()

  if (error) {
    console.error('[telegramChannel.getTelegramChatId]', { userId, error: error.message })
    return null
  }

  return data?.telegram_chat_id || null
}

const SYSTEM_USER_ID = '00000000-0000-0000-0000-000000000000'

/**
 * Converte payload canônico em texto MarkdownV2 para Telegram.
 * Kinds by_plan e misc usam formatters ricos com lista de doses.
 * @param {object} payload - Payload normalizado por buildNotificationPayload
 * @returns {string} Mensagem MarkdownV2
 */
function formatMessage(payload) {
  const { metadata } = payload

  if (payload.kind === 'dose_reminder_by_plan' && metadata?.doses) {
    return formatDoseGroupedByPlanMessage(
      metadata.planName,
      metadata.doses,
      metadata.scheduledTime,
      metadata.hour,
    )
  }

  if (payload.kind === 'dose_reminder_misc' && metadata?.doses) {
    return formatDoseGroupedMiscMessage(
      metadata.doses,
      metadata.scheduledTime,
      metadata.hour,
    )
  }

  const title = escapeMarkdownV2(payload.title)
  // body já vem formatado do L2 (buildNotificationPayload)
  const body = payload.body
  return `*${title}*\n${body}`
}

// Shape padronizado de retorno de canal
const EMPTY_RESULT = {
  channel: 'telegram',
  success: true,
  attempted: 0,
  delivered: 0,
  failed: 0,
  deactivatedTokens: [],
  errors: [],
}

export async function sendTelegramNotification({ userId, payload, context, bot }) {
  const correlationId = context?.correlationId || 'unknown'

  const chatId = userId === SYSTEM_USER_ID 
    ? process.env.ADMIN_CHAT_ID 
    : await getTelegramChatId(userId)

  if (!chatId) {
    console.info('[telegramChannel] sem telegram_chat_id', { correlationId, userId })
    return EMPTY_RESULT
  }

  // Inferir kind via metadata (explícito do dispatcher) ou deeplink como fallback
  const kind = payload.metadata?.kind ?? (payload.deeplink?.includes('plan=') ? 'dose_reminder_by_plan' :
                                          payload.deeplink?.includes('misc=1') ? 'dose_reminder_misc' :
                                          'dose_reminder')

  const message = formatMessage({ ...payload, kind })

  // Botões interativos por kind (R-030: callback_data < 64 bytes)
  const options = { parse_mode: 'MarkdownV2' }

  if (kind === 'dose_reminder_by_plan' && payload.metadata?.planId) {
    // Sprint 1.2: planIdx será adicionado quando callbacks forem implementados
    // Por ora, usar planId truncado para manter < 64 bytes
    const planIdShort = String(payload.metadata.planId).slice(0, 8)
    const hhmm = payload.metadata.scheduledTime ?? '00:00'
    options.reply_markup = {
      inline_keyboard: [[
        { text: '✅ Registrar este plano', callback_data: `takeplan:${planIdShort}:${hhmm}` },
        { text: '📋 Detalhes', callback_data: `details:plan:${planIdShort}` },
      ]]
    }
  } else if (kind === 'dose_reminder_misc' && payload.metadata?.protocolIds?.length) {
    const hhmm = payload.metadata.scheduledTime ?? '00:00'
    options.reply_markup = {
      inline_keyboard: [[
        { text: '✅ Registrar todos', callback_data: `takelist:misc:${hhmm}` },
        { text: '📋 Detalhes', callback_data: `details:misc:${hhmm}` },
      ]]
    }
  } else if (payload.metadata?.protocolId) {
    const { protocolId, dosage } = payload.metadata
    options.reply_markup = {
      inline_keyboard: [[
        { text: '✅ Tomar', callback_data: `take_:${protocolId}:${dosage ?? 1}` },
        { text: '⏰ Adiar', callback_data: `snooze_:${protocolId}` },
        { text: '⏭️ Pular', callback_data: `skip_:${protocolId}` }
      ]]
    }
  }

  try {
    const sentMessage = await bot.sendMessage(chatId, message, options)

    console.info('[telegramChannel] entregue', { 
      correlationId, 
      userId, 
      chatId,
      withButtons: !!options.reply_markup 
    })

    const messageId = sentMessage?.messageId ?? sentMessage?.message_id;
    if (!messageId) {
      console.error('[telegramChannel] Resposta do bot sem message_id', { correlationId, userId, result: sentMessage });
    }

    return {
      channel: 'telegram',
      success: true,
      attempted: 1,
      delivered: 1,
      failed: 0,
      deactivatedTokens: [],
      errors: [],
      messageId,
      providerMetadata: { telegram_message_id: messageId }
    }
  } catch (error) {
    console.error('[telegramChannel] falha no envio', { correlationId, userId, chatId, error: error.message })

    return {
      channel: 'telegram',
      success: false,
      attempted: 1,
      delivered: 0,
      failed: 1,
      deactivatedTokens: [],
      errors: [{ message: error.message }],
    }
  }
}

// Dispatcher central de notificações multicanal (ADR-029)
// Recebe lista de canais resolvidos por resolveChannelsForUser e delega a cada canal
// Falha de um canal não cancela os demais (Promise.allSettled por canal)
// correlationId é obrigatório em todos os logs (R-087)

import { z } from 'zod'
import { buildNotificationPayload, kindSchema } from '../payloads/buildNotificationPayload.js'
import { resolveChannelsForUser } from '../policies/resolveChannelsForUser.js'
import { sendTelegramNotification } from '../channels/telegramChannel.js'
import { sendExpoPushNotification } from '../channels/expoPushChannel.js'
import { shouldSendNow } from '../utils/notificationGate.js'
import { normalizeChannelResults } from '../utils/normalizeChannelResults.js'
import { notificationLogRepository } from '../repositories/notificationLogRepository.js'
import { createLogger } from '../../bot/logger.js'

const logger = createLogger('Dispatcher')

const dispatchInputSchema = z.object({
  userId: z.string().min(1),
  kind: kindSchema,
  channels: z.array(z.string()).default([]),
})

async function dispatchChannel({ channel, userId, payload, context, repositories, bot, expoClient }) {
  const correlationId = context.correlationId
  try {
    if (channel === 'telegram') {
      return await sendTelegramNotification({ userId, payload, context, bot })
    } else if (channel === 'mobile_push') {
      return await sendExpoPushNotification({ userId, payload, context, repositories, expoClient })
    } else {
      logger.warn('canal desconhecido ignorado', { correlationId, channel })
      return null
    }
  } catch (error) {
    logger.error('canal falhou', error, { correlationId, userId, channel })
    return {
      channel,
      success: false,
      attempted: 0,
      delivered: 0,
      failed: 0,
      deactivatedTokens: [],
      errors: [{ message: error.message }],
    }
  }
}

export async function dispatchNotification({ userId, kind, payload, data, channels, context, repositories, bot, expoClient }) {
  const parsed = dispatchInputSchema.safeParse({ userId, kind, channels })
  if (!parsed.success) {
    throw new Error(`[dispatchNotification] Entrada inválida: ${parsed.error.message}`)
  }

  const correlationId = context?.correlationId || `dispatch_${Date.now()}`
  const ctx = { ...context, correlationId }

  // Resolve channels if not provided
  let validChannels = parsed.data.channels
  if (validChannels.length === 0) {
    validChannels = await resolveChannelsForUser({ userId, repositories })
  }

  // Se payload não veio, tentamos construir a partir de data usando o builder canônico
  // Isso unifica as chamadas vindas de tasks legadas que ainda usam "data"
  const finalPayload = payload || (typeof buildNotificationPayload === 'function' ? buildNotificationPayload({ kind, data }) : (data || {}))

  // --- Wave N2: Centralized Gate Policy ---
  let isSuppressed = false
  // Relatórios e digests não são "alertas" e ignoram quiet_hours e modo digest (só param no silent)
  const isAlert = !['daily_digest', 'weekly_adherence', 'monthly_report', 'adherence_report'].includes(kind)

  if (isAlert) {
    const settings = await repositories.preferences.getSettingsByUserId(userId)
    const now = new Date()
    const currentHHMM = now.toLocaleTimeString('pt-BR', { 
      hour: '2-digit', 
      minute: '2-digit', 
      hour12: false,
      timeZone: settings.timezone || 'America/Sao_Paulo'
    })

    const isQuietEnabled = settings.quiet_hours_enabled ?? false

    const shouldSend = shouldSendNow({
      mode: settings.notification_mode || 'realtime',
      quietHoursStart: isQuietEnabled ? settings.quiet_hours_start : null,
      quietHoursEnd: isQuietEnabled ? settings.quiet_hours_end : null,
      currentHHMM
    })

    if (!shouldSend) {
      isSuppressed = true
      console.info('[dispatchNotification] suprimida pelo gate', { 
        correlationId, 
        userId, 
        kind, 
        mode: settings.notification_mode,
        quietHours: isQuietEnabled ? `${settings.quiet_hours_start}-${settings.quiet_hours_end}` : 'disabled'
      })
    }
  }

  if (validChannels.length === 0 && !isSuppressed) {
    console.info('[dispatchNotification] nenhum canal físico ativo — prosseguindo apenas com log (Inbox-First)', { correlationId, userId, kind })
  }

  logger.info('Iniciando dispatch de notificação', { 
    correlationId, 
    userId, 
    kind, 
    channels: validChannels,
    suppressed: isSuppressed 
  })

  let results = []
  if (!isSuppressed && validChannels.length > 0) {
    const settledResults = await Promise.allSettled(
      validChannels.map((channel) => dispatchChannel({ channel, userId, payload: finalPayload, context: ctx, repositories, bot, expoClient }))
    )

    results = settledResults
      .map((r, i) => {
        if (r.status === 'rejected') {
          console.error('[dispatchNotification] canal rejeitou promise', { correlationId, channel: validChannels[i], reason: r.reason?.message })
          return { channel: validChannels[i], success: false, attempted: 0, delivered: 0, failed: 0, deactivatedTokens: [], errors: [{ message: r.reason?.message }] }
        }
        return r.value
      })
      .filter(Boolean)
  }

  const normalized = normalizeChannelResults(results);

  // Sprint 8.4: Um único log por evento (não por canal) — evita duplicatas na inbox
  ;(async () => {
    try {
      // Wave 12: Sempre logar se houver payload, mesmo sem canais físicos, para alimentar a Inbox
      if (!finalPayload) return;

      const isGroupedKind = kind === 'dose_reminder_by_plan' || kind === 'dose_reminder_misc'
      const protocolId = isGroupedKind ? null : (finalPayload?.metadata?.protocolId ?? null)

      const activeResults = results.filter(r => r.attempted > 0 || r.errors.length > 0)

      const logChannels = activeResults.map((res) => ({
        channel:    res.channel,
        status:     res.success ? 'enviada' : 'falhou',
        message_id: res.channel === 'telegram' ? (res.messageId ?? null) : null,
        tickets:    res.channel === 'mobile_push' ? (res.tickets ?? null) : null,
      }))

      let overallStatus = 'falhou'
      if (isSuppressed) {
        overallStatus = 'silenciada'
      } else if (activeResults.some(r => r.success) || (validChannels.length === 0 && !isSuppressed)) {
        overallStatus = 'enviada'
      }

      const firstError = activeResults.find(r => !r.success)?.errors?.[0]?.message ?? null

      try {
        await notificationLogRepository.create({
          user_id:              userId,
          protocol_id:          protocolId,
          notification_type:    kind,
          title:                finalPayload.title ?? null,
          body:                 finalPayload.body ?? null,
          medicine_name:        finalPayload.metadata?.medicineName ?? null,
          protocol_name:        finalPayload.metadata?.protocolName ?? null,
          treatment_plan_id:    finalPayload.metadata?.planId ?? null,
          treatment_plan_name:  finalPayload.metadata?.planName ?? null,
          status:               overallStatus,
          channels:             logChannels,
          telegram_message_id:  logChannels.find(c => c.channel === 'telegram')?.message_id ?? null,
          mensagem_erro:        firstError,
          provider_metadata: {
            ...(finalPayload.metadata?.protocolIds ? { protocol_ids: finalPayload.metadata.protocolIds } : {}),
            ...(finalPayload.metadata?.planId ? { treatment_plan_id: finalPayload.metadata.planId } : {}),
            ...(finalPayload.metadata?.percentage !== undefined ? { percentage: finalPayload.metadata.percentage } : {}),
            ...(finalPayload.metadata?.expected_doses !== undefined ? { expected_doses: finalPayload.metadata.expected_doses } : {}),
            ...(finalPayload.metadata?.taken_doses !== undefined ? { taken_doses: finalPayload.metadata.taken_doses } : {}),
            ...(finalPayload.metadata?.nudge ? { nudge: finalPayload.metadata.nudge } : {}),
            ...(finalPayload.metadata?.storytelling ? { storytelling: finalPayload.metadata.storytelling } : {}),
            ...(finalPayload.metadata?.details ? { details: finalPayload.metadata.details } : {}),
          },
        })
      } catch (logErr) {
        console.error('[dispatchNotification] Falha ao persistir log no DB', {
          correlationId,
          userId,
          error: logErr.message,
        })
      }
    } catch (err) {
      console.error('[dispatchNotification] Erro inesperado na rotina de log', {
        correlationId,
        error: err.message,
      })
    }
  })()


  logger.info('Notificação concluída', {
    correlationId,
    userId,
    kind,
    channels: validChannels,
    totalDelivered: normalized.totalDelivered,
    totalFailed: normalized.totalFailed,
  })

  // --- DLQ Integration (Gate 3.5) ---
  // Se houver falhas e o repositório estiver presente, enfileiramos para o Admin (DLQ)
  // Evitamos re-enfileirar retentativas manuais (que já estão na DLQ e são tratadas pelo handler de retry)
  if (normalized.totalFailed > 0 && repositories?.dlq && !context?.isRetry) {
    const firstError = results.find(r => !r.success)?.errors?.[0];
    const isGroupedKind = kind === 'dose_reminder_by_plan' || kind === 'dose_reminder_misc';
    const protocolId = isGroupedKind ? null : (finalPayload?.metadata?.protocolId ?? null);

    // Enfileira de forma assíncrona (não bloqueia o retorno do dispatch)
    ;(async () => {
      try {
        await repositories.dlq.enqueue({
          userId,
          protocolId,
          type: kind,
          ...(data || {}) // L1 payload original para futura retentativa
        }, firstError, 1, correlationId);
        logger.info('Notificação falha enfileirada na DLQ', { correlationId, userId, kind });
      } catch (dlqErr) {
        logger.error('Falha ao enfileirar na DLQ', dlqErr, { correlationId, userId, kind });
      }
    })();
  }

  return normalized
}

// Constrói payload canônico de notificação a partir de evento de domínio
// Todos os canais (Telegram, Expo) consomem este shape normalizado

import { z } from 'zod';
import { escapeMarkdownV2 } from '../../utils/formatters.js';
import { getGreeting, getMotivationalNudge, getTimeOfDayGreeting } from '../../bot/utils/notificationHelpers.js';

/**
 * Schemas de contrato para os dados de entrada (Layer 1 -> Layer 2)
 */
export const dailyDigestDataSchema = z.object({
  firstName: z.string(),
  hour: z.number().min(0).max(23),
  pendingCount: z.number(),
  medicines: z.array(z.object({
    name: z.string(),
    time: z.string(),
    dosage: z.string().optional()
  }))
});

export const adherenceReportDataSchema = z.object({
  firstName: z.string(),
  period: z.string(), // ex: "hoje", "esta semana"
  percentage: z.number().min(0).max(100),
  taken: z.number(),
  total: z.number(),
  storytelling: z.string().optional() // Insights comparativos vindos da L1
});

export const stockAlertDataSchema = z.object({
  medicineName: z.string(),
  remaining: z.number(),
  daysRemaining: z.number().optional()
});

export const titrationAlertDataSchema = z.object({
  medicineName: z.string(),
  currentStage: z.number(),
  totalStages: z.number(),
  status: z.enum(['alvo_atingido', 'titulando']),
  nextStage: z.object({
    dosage: z.string(),
    unit: z.string(),
    date: z.string().optional()
  }).optional()
});

export const prescriptionAlertDataSchema = z.object({
  medicineName: z.string(),
  endDate: z.string(),
  daysRemaining: z.number()
});

export const dlqDigestDataSchema = z.object({
  failedCount: z.number(),
  failures: z.array(z.object({
    id: z.string(),
    type: z.string(),
    error_message: z.string().optional(),
    created_at: z.string()
  }))
});

export const kindSchema = z.enum([
  'dose_reminder',
  'dose_reminder_by_plan',
  'dose_reminder_misc',
  'stock_alert',
  'daily_digest',
  'adherence_report',
  'monthly_report',
  'titration_alert',
  'prescription_alert',
  'dlq_digest'
]);

// Contrato de saída da Presentation Layer (L2) para a Delivery Layer (L3)
export const notificationPayloadSchema = z.object({
  title: z.string(),
  body: z.string(),
  pushBody: z.string(), // Texto puro sem escapes para Push/Alerts (R-205)
  deeplink: z.string().startsWith('dosiq://'), // Garante padrão de deep linking do app
  metadata: z.object({
    kind: kindSchema,
  }).passthrough()
});

/**
 * Centralizador de construção de payloads de notificação.
 * Garante que todas as mensagens sigam o mesmo padrão visual e de escape.
 * 
 * @param {object} params - Parâmetros da notificação
 * @param {string} params.kind - Tipo da notificação
 * @param {object} params.data - Dados específicos para o tipo
 * @returns {object} Payload formatado { title, body, deeplink, metadata }
 */
export function buildNotificationPayload({ kind, data }) {
  // 1. Validar Kind
  const validatedKind = kindSchema.parse(kind);

  let title = '';
  let body = '';
  let pushBody = '';
  let metadata = { ...data, kind: validatedKind };

  switch (validatedKind) {
    case 'daily_digest': {
      const { firstName, hour, pendingCount, medicines } = dailyDigestDataSchema.parse(data);
      const greeting = getGreeting(hour);
      title = '📅 Resumo do Dia';

      const safeName = escapeMarkdownV2(firstName);

      // Versão Rich (Telegram/Inbox)
      let richMsg = `${greeting}, *${safeName}*\\!

`;
      // Versão Plain (Push)
      let plainMsg = `${greeting}, ${firstName}! `;

      if (pendingCount > 0) {
        const text = pendingCount === 1 ? 'dose pendente' : 'doses pendentes';
        richMsg += `Você tem *${pendingCount}* ${text} para hoje:

`;
        plainMsg += `Você tem ${pendingCount} ${text} para hoje:
`;

        medicines.forEach(m => {
          richMsg += `💊 *${escapeMarkdownV2(m.name)}*
`;
          richMsg += `⏰ ${escapeMarkdownV2(m.time)}${m.dosage ? ` \\(${escapeMarkdownV2(m.dosage)}\\)` : ''}

`;

          plainMsg += `⏰ ${m.name} - ${m.time}${m.dosage ? ` (${m.dosage})` : ''}
`;
        });
        richMsg += `Não se esqueça de registrar no app\\!`;
        plainMsg += `Não se esqueça de registrar no app!`;
      } else {
        const success = `Você está em dia com todos os seus medicamentos de hoje\\! 🎉`;
        richMsg += success;
        plainMsg += success.replace(/\\/g, '');
      }

      body = richMsg;
      pushBody = plainMsg;
      break;
    }

    case 'adherence_report': {
      const { firstName, period, percentage, taken, total, storytelling } = adherenceReportDataSchema.parse(data);
      const nudge = getMotivationalNudge(percentage);
      title = '📈 Relatório diário';

      const safeName = escapeMarkdownV2(firstName);
      const safePeriod = escapeMarkdownV2(period);

      // Versão Rich
      let richMsg = `Olá, *${safeName}*\\!

`;
