import { supabase } from '../../services/supabase.js';
import { notificationLogCreateSchema } from '../../../packages/core/src/schemas/notificationLogSchema.js';

export const notificationLogRepository = {
  /**
   * Registra uma nova entrada no log de notificações
   * @param {Object} data - Dados da notificação (userId, protocolId, kind, status, etc)
   */
  async create(data) {
    const parsed = notificationLogCreateSchema.safeParse(data);

    if (!parsed.success) {
      throw new Error(`Dados de log inválidos: ${JSON.stringify(parsed.error?.format())}`);
    }

    const { error, data: insertedData } = await supabase
      .from('notification_log')
      .insert({
        user_id: parsed.data.user_id,
        title: parsed.data.title ?? null,
        body: parsed.data.body ?? null,
        medicine_name: parsed.data.medicine_name ?? null,
        protocol_name: parsed.data.protocol_name ?? null,
        channels: parsed.data.channels ?? [],
        protocol_id: parsed.data.protocol_id,
        treatment_plan_id:   parsed.data.treatment_plan_id ?? null,
        treatment_plan_name: parsed.data.treatment_plan_name ?? null,
        notification_type: parsed.data.notification_type,
        status: parsed.data.status,
        sent_at: parsed.data.sent_at || new Date().toISOString(),
        telegram_message_id: parsed.data.telegram_message_id,
        mensagem_erro: parsed.data.mensagem_erro,
        provider_metadata: parsed.data.provider_metadata || {},
      })
      .select()
      .single();

    if (error) {
      console.error('[notificationLogRepository.create] Erro ao inserir log no Supabase:', {
        userId: parsed.data.user_id,
        error: error.message
      });
      throw new Error(`Erro ao persistir log: ${error.message}`);
    }

    return insertedData;
  },

  /**
   * Lista notificações de um usuário de forma paginada para a Inbox
   * (Será usado principalmente na v8.2/8.3, mas deixamos pronto o backend)
   */
  async listByUserId(userId, { limit = 20, offset = 0 } = {}) {
    const { data, error } = await supabase
      .from('notification_log')
      .select(`
        *,
        protocols:protocol_id (
          name,
          medicine_id (
            name
          )
        )
      `)
      .eq('user_id', userId)
      .order('sent_at', { ascending: false })
      .range(offset, offset + limit - 1);

    if (error) {
      console.error('[notificationLogRepository.listByUserId] Erro ao listar logs:', {
        userId,
        error: error.message
      });
      return [];
    }

    return data || [];
  }
};

// server/services/deadLetterQueue.js
import { supabase } from './supabase.js';
import { createLogger } from '../bot/logger.js';
import { updateDlqSize } from './notificationMetrics.js';

const logger = createLogger('DeadLetterQueue');

/**
 * Error categories for DLQ
 * @readonly
 * @enum {string}
 */
export const ErrorCategories = {
  NETWORK_ERROR: 'network_error',           // Network error, retryable
  RATE_LIMIT: 'rate_limit',                 // 429 Too Many Requests
  INVALID_CHAT: 'invalid_chat',             // User blocked the bot
  MESSAGE_TOO_LONG: 'message_too_long',     // Message exceeds limit
  TELEGRAM_API_ERROR: 'telegram_api_error', // Telegram API errors
  TELEGRAM_400: 'telegram_400',             // Bad Request
  TELEGRAM_401: 'telegram_401',             // Unauthorized
  TELEGRAM_403: 'telegram_403',             // Forbidden
  TELEGRAM_404: 'telegram_404',             // Not Found
  UNKNOWN: 'unknown'                        // Unknown error
};

/**
 * Possible statuses in DLQ
 * @readonly
 * @enum {string}
 */
export const DLQStatus = {
  FAILED: 'failed',             // Failed after all attempts
  PENDING: 'pending',           // Awaiting retry
  RETRYING: 'retrying',         // Retry in progress
  RESOLVED: 'resolved',         // Successfully resolved
  DISCARDED: 'discarded'        // Discarded (too old or invalid)
};

/**
 * Categorizes a notification error
 * @param {Error|object} error - Error that occurred
 * @returns {string} Error category
 */
function categorizeError(error) {
  if (!error) return ErrorCategories.UNKNOWN;

  const code = error.code || error.error_code;
  const message = (error.message || '').toLowerCase();

  // Telegram HTTP codes
  if (code) {
    switch (Number(code)) {
      case 400:
        if (message.includes('too long') || message.includes('message is too long')) {
          return ErrorCategories.MESSAGE_TOO_LONG;
        }
        return ErrorCategories.TELEGRAM_400;
      case 401:
        return ErrorCategories.TELEGRAM_401;
      case 403:
        if (message.includes('bot was blocked') || message.includes('user is deactivated')) {
          return ErrorCategories.INVALID_CHAT;
        }
        return ErrorCategories.TELEGRAM_403;
      case 404:
        return ErrorCategories.TELEGRAM_404;
      case 429:
        return ErrorCategories.RATE_LIMIT;
      default:
        return ErrorCategories.TELEGRAM_API_ERROR;
    }
  }

  // Message patterns
  if (message.includes('etimedout') || message.includes('econnreset') || 
      message.includes('enotfound') || message.includes('network error')) {
    return ErrorCategories.NETWORK_ERROR;
  }

  return ErrorCategories.UNKNOWN;
}

/**
 * Adds a failed notification to the DLQ
 * @param {object} notificationData - Notification data
 * @param {Error|object} error - Error that occurred
 * @param {number} retryCount - Number of attempts made
 * @param {string} correlationId - Correlation ID
 * @returns {Promise<{success: boolean, id?: string, error?: string}>}
 */
export async function enqueue(notificationData, error, retryCount, correlationId) {
  try {
    const errorCategory = categorizeError(error);

    // Usar upsert para evitar race condition
    // O índice único parcial garante atomicidade
    const { data, error: upsertError } = await supabase
      .from('failed_notification_queue')
      .upsert({
        user_id: notificationData.userId,
        protocol_id: notificationData.protocolId,
        notification_type: notificationData.type,
        notification_payload: notificationData,
        error_code: error?.code || error?.error_code,
        error_message: error?.message || 'Unknown error',
        error_category: errorCategory,
        retry_count: retryCount,
        correlation_id: correlationId,
        status: DLQStatus.PENDING
      }, {
        onConflict: 'correlation_id',
        ignoreDuplicates: false
      })
      .select('id')
      .single();

    if (upsertError) throw upsertError;

    logger.info('Notification enqueued to DLQ', {
      id: data.id,
      correlationId,
      userId: notificationData.userId,
      errorCategory
    });

    // Atualizar métrica de tamanho da DLQ
    const stats = await getDLQStats();
    updateDlqSize(stats.pending + stats.retrying);

    return { success: true, id: data.id };

  } catch (err) {
    logger.error('Failed to add to DLQ', err, {
      correlationId,
      userId: notificationData.userId
    });
    return { success: false, error: err.message };
  }
}

/**
 * Marks a notification for retry
 * @param {string} id - Notification ID in DLQ
 * @returns {Promise<{success: boolean, error?: string}>}
 */
export async function markForRetry(id) {
  try {
    const { error } = await supabase
      .from('failed_notification_queue')
      .update({
        status: DLQStatus.RETRYING,
        updated_at: new Date().toISOString()
      })
      .eq('id', id)
      .eq('status', DLQStatus.PENDING); // Only if pending

    if (error) throw error;

    logger.info('Notification marked for retry', { id });

    return { success: true };

  } catch (err) {
    logger.error('Failed to mark for retry', err, { id });
    return { success: false, error: err.message };
  }
}

/**
 * Marks a notification as resolved
 * @param {string} id - Notification ID in DLQ
 * @param {string} resolution - Resolution type ('success' | 'discarded' | 'manual')
 * @param {string} notes - Notes about the resolution
 * @returns {Promise<{success: boolean, error?: string}>}
 */
export async function markAsResolved(id, resolution, notes = '') {
  const statusMap = {
    success: DLQStatus.RESOLVED,
    discarded: DLQStatus.DISCARDED,
    manual: DLQStatus.RESOLVED
  };

  const status = statusMap[resolution] || DLQStatus.RESOLVED;

  try {
    const { error } = await supabase
      .from('failed_notification_queue')
      .update({
        status,
        resolution_notes: notes,
        resolved_at: new Date().toISOString()
      })
      .eq('id', id);

    if (error) throw error;

    logger.info('Notification resolved', { id, resolution, notes });

    // Atualizar métrica de tamanho da DLQ
    const stats = await getDLQStats();
    updateDlqSize(stats.pending + stats.retrying);

    return { success: true };

  } catch (err) {
    logger.error('Failed to resolve notification', err, { id });
    return { success: false, error: err.message };
  }
}

/**
 * Gets failed notifications for a user
 * @param {string} userId - User UUID
 * @param {number} limit - Result limit
 * @param {string} status - Filter by status (optional)
 * @returns {Promise<Array>} List of failed notifications
 */
export async function getFailedForUser(userId, limit = 10, status = null) {
  try {
    let query = supabase
      .from('failed_notification_queue')
      .select('*')
      .eq('user_id', userId)
      .order('created_at', { ascending: false })
      .limit(limit);

    if (status) {
      query = query.eq('status', status);
    }

    const { data, error } = await query;

    if (error) throw error;
    return data || [];

  } catch (err) {
    logger.error('Failed to fetch failed notifications', err, { userId });
    return [];
  }
}

/**
 * Gets DLQ statistics
 * @returns {Promise<object>} Statistics
 */
export async function getDLQStats() {
  try {
    // Usa função PostgreSQL para agregação eficiente (não carrega todas as linhas)
    const { data, error } = await supabase
      .rpc('get_dlq_stats');

    if (error) throw error;

    const stats = {
      total: 0,
      failed: 0,
      pending: 0,
      retrying: 0,
      resolved: 0,
      discarded: 0,
      byCategory: {},
      oldestFailure: null
    };

    data.forEach(item => {
      const count = parseInt(item.count, 10) || 0;
      stats[item.status] = count;
      stats.total += count;

      // Agrega por categoria de erro
      const cat = item.error_category || 'unknown';
      stats.byCategory[cat] = (stats.byCategory[cat] || 0) + count;

      // Rastreia a falha mais antiga
      if (item.oldest_failure) {
        const oldestDate = new Date(item.oldest_failure);
        if (!stats.oldestFailure || oldestDate < new Date(stats.oldestFailure)) {
          stats.oldestFailure = item.oldest_failure;
        }
      }
    });

    return stats;

  } catch (err) {
    logger.error('Failed to get DLQ statistics', err);
    return {
      total: 0,
      failed: 0,
      pending: 0,
      retrying: 0,
      resolved: 0,
      discarded: 0,
      byCategory: {},
      oldestFailure: null,
      error: err.message
    };
  }
}

/**
 * Gets pending notifications for automatic retry
 * @param {number} limit - Notification limit
 * @returns {Promise<Array>} Pending notifications
 */
export async function getPendingForRetry(limit = 50) {
  try {
    const { data, error } = await supabase
      .from('failed_notification_queue')
      .select('*')
      .eq('status', DLQStatus.PENDING)
      .lte('retry_count', 5) // Maximum 5 automatic retries
      .order('created_at', { ascending: true }) // Oldest first
      .limit(limit);

    if (error) throw error;
    return data || [];

  } catch (err) {
    logger.error('Failed to fetch pending for retry', err);
    return [];
  }
}

/**
 * Cleans up old resolved notifications
 * @param {number} daysToKeep - Days to keep (default: 30)
 * @returns {Promise<{success: boolean, deleted?: number, error?: string}>}
 */
export async function cleanupResolved(daysToKeep = 30) {
  try {
    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - daysToKeep);

    const { error, count } = await supabase
      .from('failed_notification_queue')
      .delete()
      .in('status', [DLQStatus.RESOLVED, DLQStatus.DISCARDED])
      .lt('resolved_at', cutoffDate.toISOString());

    if (error) throw error;

    logger.info('DLQ cleanup completed', { deleted: count, olderThan: cutoffDate.toISOString() });
    return { success: true, deleted: count };

  } catch (err) {
    logger.error('DLQ cleanup failed', err);
    return { success: false, error: err.message };
  }
}

export default {
  enqueue,
  markForRetry,
  markAsResolved,
  getFailedForUser,
  getDLQStats,
  getPendingForRetry,
  cleanupResolved,
  ErrorCategories,
  DLQStatus
};

import { supabase } from './supabase.js';

const DEDUP_WINDOW_MINUTES = 5; // Don't send same notification twice within 5 minutes

/**
 * Verifica se a notificação deve ser enviada (sem duplicatas)
 * NÃO mais loga automaticamente - o log deve ser feito APÓS envio confirmado
 * @param {string} userId - UUID do usuário (obrigatório)
 * @param {string|null} protocolId - UUID do protocolo (opcional)
 * @param {string} notificationType - Tipo: 'dose_reminder', 'daily_digest', etc.
 * @returns {Promise<boolean>} true se deve enviar, false se duplicado
 */
export async function shouldSendNotification(userId, protocolId, notificationType) {
  if (!userId) {
    console.error('[Deduplicator] shouldSendNotification chamado sem userId');
    return true; // Fail open
  }

  const cutoffTime = new Date(Date.now() - DEDUP_WINDOW_MINUTES * 60 * 1000).toISOString();

  try {
    // Build query based on notification type
    let query = supabase
      .from('notification_log')
      .select('id')
      .eq('user_id', userId)
      .eq('notification_type', notificationType)
      .gte('sent_at', cutoffTime)
      .limit(1);

    // Add protocol filter only for protocol-level notifications
    if (protocolId) {
      query = query.eq('protocol_id', protocolId);
    } else {
      query = query.is('protocol_id', null);
    }

    const { data, error } = await query.single();

    if (error && error.code !== 'PGRST116') {
      console.error('[Deduplicator] Erro ao verificar log de notificação:', error);
      return true; // Fail open on error
    }

    // If we found a recent notification, this is a duplicate
    if (data) {
      console.log(`[Deduplicator] Ignorando duplicata ${notificationType} para usuário ${userId}`);
      return false;
    }

    // Not a duplicate - return true (but DON'T log yet)
    return true;
  } catch (err) {
    console.error('[Deduplicator] Erro inesperado:', err);
    return true; // Fail open
  }
}

/**
 * Loga uma notificação (função legada - usar logSuccessfulNotification)
 * @deprecated Use logSuccessfulNotification após envio confirmado
 */
export async function logNotification(userId, protocolId, notificationType, status = 'enviada') {
  if (!userId) {
    console.error('[Deduplicator] logNotification chamado sem userId');
    return false;
  }

  try {
    const { error } = await supabase
      .from('notification_log')
      .insert({
        user_id: userId,
        protocol_id: protocolId,  // Can be null for user-level alerts
        notification_type: notificationType,
        status: status
      });

    if (error) {
      console.error('[Deduplicator] Erro ao logar notificação:', error);
      return false;
    }

    return true;
  } catch (err) {
    console.error('[Deduplicator] Erro inesperado em logNotification:', err);
    return false;
  }
}

/**
 * Loga uma notificação como enviada com sucesso
 * Deve ser chamado APÓS confirmação de envio pelo Telegram
 * @param {string} userId - UUID do usuário (obrigatório)
 * @param {string|null} protocolId - UUID do protocolo (opcional)
 * @param {string} notificationType - Tipo de notificação
 * @param {object} metadata - Metadados adicionais (messageId, etc)
 * @returns {Promise<boolean>} true se logado com sucesso
 */
export async function logSuccessfulNotification(userId, protocolId, notificationType, metadata = {}) {
  if (!userId) {
    console.error('[Deduplicator] logSuccessfulNotification chamado sem userId');
    return false;
  }

  try {
    const { error } = await supabase
      .from('notification_log')
      .insert({
        user_id: userId,
        protocol_id: protocolId,
        notification_type: notificationType,
        status: 'enviada',
        telegram_message_id: metadata.messageId || null
      });

    if (error) {
      console.error('[Deduplicator] Erro ao logar notificação:', error);
      return false;
    }

    return true;
  } catch (err) {
    console.error('[Deduplicator] Erro inesperado em logSuccessfulNotification:', err);
    return false;
  }
}

/**
 * Limpa logs de notificação antigos (mais de 7 dias)
 */
export async function cleanupOldNotificationLogs() {
  const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();

  const { error } = await supabase
    .from('notification_log')
    .delete()
    .lt('created_at', sevenDaysAgo);

  if (error) {
    console.error('[Deduplicator] Erro ao limpar logs:', error);
  } else {
    console.log('[Deduplicator] Limpeza concluída');
  }
}

/**
 * Verifica deduplicação para notificações agrupadas (dose_reminder_by_plan / dose_reminder_misc).
 * Para by_plan: discrimina por treatment_plan_id no provider_metadata.
 * Para misc: só verifica tipo + user + janela de 5min.
 * @param {string} userId - UUID do usuário
 * @param {string} notificationType - 'dose_reminder_by_plan' | 'dose_reminder_misc'
 * @param {object} [options] - { planId?: string }
 * @returns {Promise<boolean>} true se deve enviar, false se duplicado
 */
export async function shouldSendGroupedNotification(userId, notificationType, { planId } = {}) {
  if (!userId) {
    console.error('[Deduplicator] shouldSendGroupedNotification chamado sem userId');
    return true; // Fail open
  }

  const cutoffTime = new Date(Date.now() - DEDUP_WINDOW_MINUTES * 60 * 1000).toISOString();

  try {
    let query = supabase
      .from('notification_log')
      .select('id')
      .eq('user_id', userId)
      .eq('notification_type', notificationType)
      .gte('sent_at', cutoffTime)
      .limit(1);

    if (planId) {
      query = query.filter('provider_metadata->>treatment_plan_id', 'eq', planId);
    }

    const { data, error } = await query.single();

    if (error && error.code !== 'PGRST116') {
      console.error('[Deduplicator] Erro ao verificar grouped notification:', error);
      return true; // Fail open
    }

    if (data) {
      console.log(`[Deduplicator] Ignorando duplicata grouped ${notificationType} para userId ${userId}${planId ? ` planId ${planId}` : ''}`);
      return false;
    }

    return true;
  } catch (err) {
    console.error('[Deduplicator] Erro inesperado em shouldSendGroupedNotification:', err);
    return true; // Fail open
  }
}

// server/services/notificationMetrics.js
import { createLogger } from '../bot/logger.js';

const logger = createLogger('NotificationMetrics');

/**
 * Janela de retenção de métricas em memória (em minutos)
 */
const METRICS_RETENTION_MINUTES = 60;

/**
 * Estrutura de métricas em memória
 */
class MetricsStore {
  constructor() {
    this.successCount = new Map();      // key: "YYYY-MM-DDTHH:mm", value: count
    this.failureCount = new Map();      // key: "YYYY-MM-DDTHH:mm", value: count
    this.retryCount = new Map();        // key: "YYYY-MM-DDTHH:mm", value: count
    this.deliveryTimes = new Map();     // key: "YYYY-MM-DDTHH:mm", value: number[]
    this.errorBreakdown = new Map();    // key: errorCategory, value: count
    this.rateLimitHits = new Map();     // key: "YYYY-MM-DDTHH:mm", value: count
    this.lastSuccessfulSend = null;
    this.lastFailure = null;
    this.dlqSize = 0;
    this.lastDlqCheck = null;
  }

  /**
   * Gera chave de minuto atual
   * @returns {string} Formato: "YYYY-MM-DDTHH:mm"
   */
  getCurrentMinuteKey() {
    const now = new Date();
    return now.toISOString().slice(0, 16); // YYYY-MM-DDTHH:mm
  }

  /**
   * Incrementa contador em um Map
   * @param {Map} map - Mapa de contadores
   * @param {string} key - Chave
   */
  increment(map, key) {
    const current = map.get(key) || 0;
    map.set(key, current + 1);
  }

  /**
   * Limpa dados antigos (mais de METRICS_RETENTION_MINUTES)
   */
  cleanup() {
    const cutoff = new Date();
    cutoff.setMinutes(cutoff.getMinutes() - METRICS_RETENTION_MINUTES);
    const cutoffKey = cutoff.toISOString().slice(0, 16);

    const cleanMap = (map) => {
      for (const key of map.keys()) {
        if (key < cutoffKey) {
          map.delete(key);
        }
      }
    };

    cleanMap(this.successCount);
    cleanMap(this.failureCount);
    cleanMap(this.retryCount);
    cleanMap(this.deliveryTimes);
    cleanMap(this.rateLimitHits);
    this.errorBreakdown.clear();

    logger.debug('Métricas limpas', { cutoffKey });
  }
}

// Instância singleton
const metricsStore = new MetricsStore();

/**
 * Registra uma notificação bem-sucedida
 * @param {number} deliveryTimeMs - Tempo de entrega em ms (opcional)
 * @param {object} metadata - Metadados adicionais
 */
export function recordSuccess(deliveryTimeMs = null, metadata = {}) {
  const key = metricsStore.getCurrentMinuteKey();
  metricsStore.increment(metricsStore.successCount, key);

  if (deliveryTimeMs) {
    if (!metricsStore.deliveryTimes.has(key)) {
      metricsStore.deliveryTimes.set(key, []);
    }
    metricsStore.deliveryTimes.get(key).push(deliveryTimeMs);
  }

  metricsStore.lastSuccessfulSend = new Date().toISOString();

  logger.debug('Métrica: sucesso registrado', {
    minute: key,
    deliveryTimeMs,
    ...metadata
  });
}

/**
 * Registra uma notificação falha
 * @param {string} errorCategory - Categoria do erro
 * @param {boolean} wasRetryable - Se o erro era retryable
 * @param {object} metadata - Metadados adicionais
 */
export function recordFailure(errorCategory = 'unknown', wasRetryable = false, metadata = {}) {
  const key = metricsStore.getCurrentMinuteKey();
  metricsStore.increment(metricsStore.failureCount, key);

  // Error breakdown
  const catKey = `${errorCategory}_${wasRetryable ? 'retryable' : 'final'}`;
  metricsStore.increment(metricsStore.errorBreakdown, catKey);

  metricsStore.lastFailure = {
    timestamp: new Date().toISOString(),
    category: errorCategory,
    retryable: wasRetryable
  };

  logger.debug('Métrica: falha registrada', {
    minute: key,
    errorCategory,
    wasRetryable,
    ...metadata
  });
}

/**
 * Registra uma tentativa de retry
 * @param {number} attemptNumber - Número da tentativa (1-based)
 * @param {object} metadata - Metadados adicionais
 */
export function recordRetry(attemptNumber, metadata = {}) {
  const key = metricsStore.getCurrentMinuteKey();
  metricsStore.increment(metricsStore.retryCount, key);

  // Track retry distribution
  const retryKey = `attempt_${attemptNumber}`;
  metricsStore.increment(metricsStore.errorBreakdown, retryKey);

  logger.debug('Métrica: retry registrado', {
    minute: key,
    attemptNumber,
    ...metadata
  });
}

/**
 * Registra hit de rate limit
 * @param {object} metadata - Metadados adicionais
 */
export function recordRateLimitHit(metadata = {}) {
  const key = metricsStore.getCurrentMinuteKey();
  metricsStore.increment(metricsStore.rateLimitHits, key);

  logger.debug('Métrica: rate limit hit', {
    minute: key,
    ...metadata
  });
}

/**
 * Atualiza tamanho da DLQ
 * @param {number} size - Tamanho atual da DLQ
 */
export function updateDlqSize(size) {
  metricsStore.dlqSize = size;
  metricsStore.lastDlqCheck = new Date().toISOString();
}

/**
 * Calcula percentil de um array de números
 * @param {number[]} arr - Array de números
 * @param {number} p - Percentil (0-100)
 * @returns {number} Valor do percentil
 */
function percentile(arr, p) {
  if (arr.length === 0) return 0;
  const sorted = [...arr].sort((a, b) => a - b);
  const index = Math.ceil((p / 100) * sorted.length) - 1;
  return sorted[Math.max(0, index)];
}

/**
 * Obtém métricas agregadas para um período
 * @param {number} windowMinutes - Janela de tempo em minutos (padrão: 5)
 * @returns {object} Métricas agregadas
 */
export function getMetrics(windowMinutes = 5) {
  const now = new Date();
  const keys = [];

  // Gerar chaves dos últimos N minutos
  for (let i = 0; i < windowMinutes; i++) {
    const d = new Date(now);
    d.setMinutes(d.getMinutes() - i);
    keys.push(d.toISOString().slice(0, 16));
  }

  // Agregar contagens
  let totalSuccess = 0;
  let totalFailure = 0;
  let totalRetry = 0;
  let totalRateLimitHits = 0;
  const allDeliveryTimes = [];

  keys.forEach(key => {
    totalSuccess += metricsStore.successCount.get(key) || 0;
    totalFailure += metricsStore.failureCount.get(key) || 0;
    totalRetry += metricsStore.retryCount.get(key) || 0;
    totalRateLimitHits += metricsStore.rateLimitHits.get(key) || 0;

    const times = metricsStore.deliveryTimes.get(key) || [];
    allDeliveryTimes.push(...times);
  });

  const totalAttempts = totalSuccess + totalFailure;
  const errorRate = totalAttempts > 0 ? (totalFailure / totalAttempts) * 100 : 0;

  // Calcular percentis de tempo de entrega
  const deliveryTimeStats = {
    count: allDeliveryTimes.length,
    avg: allDeliveryTimes.length > 0 
      ? Math.round(allDeliveryTimes.reduce((a, b) => a + b, 0) / allDeliveryTimes.length)
      : 0,
    p50: percentile(allDeliveryTimes, 50),
    p95: percentile(allDeliveryTimes, 95),
    p99: percentile(allDeliveryTimes, 99)
  };

  // Error breakdown
  const errorBreakdown = {};
  for (const [key, count] of metricsStore.errorBreakdown.entries()) {
    errorBreakdown[key] = count;
  }

  return {
    window: {
      start: keys[keys.length - 1],
      end: keys[0],
      minutes: windowMinutes
    },
    summary: {
      totalAttempts,
      successful: totalSuccess,
      failed: totalFailure,
      retried: totalRetry,
      errorRate: Math.round(errorRate * 100) / 100, // 2 decimals
      rateLimitHits: totalRateLimitHits
    },
    deliveryTime: deliveryTimeStats,
    errorBreakdown,
    dlq: {
      currentSize: metricsStore.dlqSize,
      lastCheck: metricsStore.lastDlqCheck
    },
    timestamps: {
      lastSuccessfulSend: metricsStore.lastSuccessfulSend,
      lastFailure: metricsStore.lastFailure
    }
  };
}

/**
 * Obtém métricas para dashboard
 * @returns {object} Métricas simplificadas
 */
export function getDashboardMetrics() {
  const metrics = getMetrics(60); // Última hora

  return {
    sentToday: metrics.summary.successful,
    failed: metrics.summary.failed,
    errorRate: metrics.summary.errorRate,
    inDlq: metrics.dlq.currentSize,
    avgDeliveryTime: metrics.deliveryTime.avg,
    lastSuccessfulSend: metrics.timestamps.lastSuccessfulSend
  };
}

/**
 * Reseta todas as métricas (útil para testes)
 */
export function resetMetrics() {
  metricsStore.successCount.clear();
  metricsStore.failureCount.clear();
  metricsStore.retryCount.clear();
  metricsStore.deliveryTimes.clear();
  metricsStore.errorBreakdown.clear();
