// Import after mocks (use dynamic import to support ESM)
let DEFAULT_RETRY_CONFIG
let sendWithRetry
let isRetryableError
let calculateDelay
let sleep

beforeAll(async () => {
  const mod = await import('../../../../server/utils/retryManager.js')
  DEFAULT_RETRY_CONFIG = mod.DEFAULT_RETRY_CONFIG
  sendWithRetry = mod.sendWithRetry
  isRetryableError = mod.isRetryableError
  calculateDelay = mod.calculateDelay
  sleep = mod.sleep
})

describe('RetryManager', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  describe('DEFAULT_RETRY_CONFIG', () => {
    it('deve ter configuração padrão definida', () => {
      expect(DEFAULT_RETRY_CONFIG).toBeDefined()
      expect(DEFAULT_RETRY_CONFIG.maxRetries).toBe(3)
      expect(DEFAULT_RETRY_CONFIG.baseDelay).toBe(1000)
      expect(DEFAULT_RETRY_CONFIG.maxDelay).toBe(10000)
      expect(DEFAULT_RETRY_CONFIG.jitter).toBe(true)
    })
  })

  describe('isRetryableError', () => {
    it('deve identificar erros de rede como retryable', () => {
      const networkError = new Error('ETIMEDOUT')
      expect(isRetryableError(networkError)).toBe(true)
    })

    it('deve identificar erro 429 como retryable', () => {
      const rateLimitError = new Error('Rate limited')
      rateLimitError.response = { status: 429 }
      expect(isRetryableError(rateLimitError)).toBe(true)
    })

    it('deve identificar erro 5xx como retryable', () => {
      const serverError = new Error('Internal server error')
      serverError.response = { status: 500 }
      expect(isRetryableError(serverError)).toBe(true)
    })

    it('não deve identificar erros de cliente como retryable', () => {
      const clientError = new Error('Bad request')
      clientError.response = { status: 400 }
      expect(isRetryableError(clientError)).toBe(false)
    })
  })

  describe('sleep', () => {
    it('deve aguardar o tempo especificado', async () => {
      const start = Date.now()
      await sleep(100)
      const elapsed = Date.now() - start
      expect(elapsed).toBeGreaterThanOrEqual(90) // Allow some margin
    })
  })

  describe('calculateDelay', () => {
    it('deve calcular delay com backoff exponencial', () => {
      const delay1 = calculateDelay(1, { baseDelay: 1000, maxDelay: 10000, jitter: false })
      const delay2 = calculateDelay(2, { baseDelay: 1000, maxDelay: 10000, jitter: false })
      const delay3 = calculateDelay(3, { baseDelay: 1000, maxDelay: 10000, jitter: false })

      expect(delay1).toBe(1000)
      expect(delay2).toBe(2000)
      expect(delay3).toBe(4000)
    })

    it('deve respeitar maxDelay', () => {
      const delay = calculateDelay(10, { baseDelay: 1000, maxDelay: 5000, jitter: false })
      expect(delay).toBe(5000)
    })
  })

  describe('sendWithRetry', () => {
    it('deve retornar sucesso na primeira tentativa', async () => {
      const mockOperation = vi.fn().mockResolvedValue({ success: true, messageId: '123' })

      const result = await sendWithRetry(mockOperation, DEFAULT_RETRY_CONFIG, {
        operation: 'test',
      })

      expect(result.success).toBe(true)
      expect(result.attempts).toBe(1)
      expect(mockOperation).toHaveBeenCalledTimes(1)
    })

    it('deve fazer retry em erro de rede', async () => {
      const networkError = new Error('ETIMEDOUT')
      const mockOperation = vi
        .fn()
        .mockRejectedValueOnce(networkError)
        .mockResolvedValue({ success: true, messageId: '123' })

      const result = await sendWithRetry(
        mockOperation,
        { ...DEFAULT_RETRY_CONFIG, jitter: false },
        {
          operation: 'test',
        }
      )

      expect(result.success).toBe(true)
      expect(result.attempts).toBe(2)
    })

    it('deve falhar após todas as tentativas', async () => {
      const networkError = new Error('ETIMEDOUT')
      const mockOperation = vi.fn().mockRejectedValue(networkError)

      const result = await sendWithRetry(
        mockOperation,
        { ...DEFAULT_RETRY_CONFIG, jitter: false },
        {
          operation: 'test',
        }
      )

      expect(result.success).toBe(false)
      expect(result.attempts).toBe(3)
      expect(result.error).toBeDefined()
    })

    it('deve não fazer retry para erros não recuperáveis', async () => {
      const clientError = new Error('Bad request')
      clientError.response = { status: 400 }
      const mockOperation = vi.fn().mockRejectedValue(clientError)

      const result = await sendWithRetry(mockOperation, DEFAULT_RETRY_CONFIG, {
        operation: 'test',
      })

      expect(result.success).toBe(false)
      expect(result.attempts).toBe(1)
    })

    it('deve aceitar configuração customizada', async () => {
      const customConfig = { maxRetries: 1, baseDelay: 100, maxDelay: 1000, jitter: false }
      const mockOperation = vi.fn().mockResolvedValue({ success: true, messageId: '123' })

      const result = await sendWithRetry(mockOperation, customConfig, { operation: 'test' })

      expect(result.success).toBe(true)
      expect(result.attempts).toBe(1)
    })
  })
})

/**
 * Date Utilities - Funções utilitárias para manipulação de datas no Servidor
 */

/**
 * Converte string de data (YYYY-MM-DD) para Date em timezone local
 * @param {string} dateStr - Data no formato YYYY-MM-DD
 * @returns {Date} Date object em timezone local (meia-noite local)
 */
export function parseLocalDate(dateStr) {
  return new Date(dateStr + 'T00:00:00')
}

/**
 * Formata Date para string YYYY-MM-DD em timezone local
 * @param {Date} date - Date object
 * @returns {string} Data no formato YYYY-MM-DD
 */
export function formatLocalDate(date) {
  const year = date.getFullYear()
  const month = String(date.getMonth() + 1).padStart(2, '0')
  const day = String(date.getDate()).padStart(2, '0')
  return `${year}-${month}-${day}`
}

import { getCurrentTimeInTimezone } from './timezone.js';

/**
 * Format time in HH:MM format for Brazil timezone (legacy)
 * @deprecated Use getCurrentTimeInTimezone from timezone.js instead
 */
export function getCurrentTime() {
  return getCurrentTimeInTimezone('America/Sao_Paulo');
}

/**
 * Calculate days remaining based on stock and daily usage
 */
export function calculateDaysRemaining(totalQuantity, dailyUsage) {
  if (!dailyUsage || dailyUsage <= 0) return null;
  return Math.floor(totalQuantity / dailyUsage);
}

/**
 * Formata mensagem de status do estoque.
 * @param {object} medicine - Objeto do medicamento com name e dosage_unit
 * @param {number} totalQuantity - Quantidade total em estoque
 * @param {number|null} daysRemaining - Dias restantes de estoque
 * @returns {string} Mensagem formatada com escape MarkdownV2
 */
export function formatStockStatus(medicine, totalQuantity, daysRemaining) {
  const unit = escapeMarkdownV2(medicine.dosage_unit || 'unidades');
  const name = escapeMarkdownV2(medicine.name || 'Medicamento');
  let status = `💊 *${name}*\n`;
  status += `📦 Estoque: ${totalQuantity} ${unit}\n`;

  if (daysRemaining !== null) {
    if (daysRemaining <= 0) {
      status += `⚠️ *SEM ESTOQUE*\n`;
    } else if (daysRemaining <= 7) {
      status += `⚠️ Acaba em ${daysRemaining} dias\n`;
    } else {
      status += `✅ Acaba em ${daysRemaining} dias\n`;
    }
  }

  return status;
}

/**
 * Formata informações do protocolo.
 * @param {object} protocol - Objeto do protocolo com medicine, time_schedule, etc.
 * @returns {string} Mensagem formatada com escape MarkdownV2
 */
export function formatProtocol(protocol) {
  const name = escapeMarkdownV2(protocol.medicine?.name || 'Medicamento');
  const times = escapeMarkdownV2(protocol.time_schedule?.join(', ') || '');
  const dosage = escapeMarkdownV2(String(protocol.dosage_per_intake ?? 1));

  let msg = `💊 *${name}*\n`;
  msg += `⏰ Horários: ${times}\n`;
  msg += `📏 Dose: ${dosage}x\n`;

  if (protocol.titration_schedule && protocol.titration_schedule.length > 0) {
    const currentStage = protocol.current_stage_index || 0;
    msg += `🎯 Titulação: Etapa ${currentStage + 1}/${protocol.titration_schedule.length}\n`;
  }

  if (protocol.notes) {
    const notes = escapeMarkdownV2(protocol.notes);
    msg += `📝 _${notes}_\n`;
  }

  return msg;
}

/**
 * Calculate adherence streak (days in a row with at least one dose) 
 * in a specific timezone.
 */
export function calculateStreak(logs, timezone = 'America/Sao_Paulo') {
  if (!logs || logs.length === 0) return 0;

  // Get unique local dates (YYYY-MM-DD) in the target timezone
  const localDates = logs
    .map(l => new Intl.DateTimeFormat('en-CA', { timeZone: timezone }).format(new Date(l.taken_at)))
    .filter((v, i, a) => a.indexOf(v) === i)
    .sort((a, b) => b.localeCompare(a)); // Descending "2026-01-21", "2026-01-20"...

  const today = new Intl.DateTimeFormat('en-CA', { timeZone: timezone }).format(new Date());

  // If no logs at all for today OR yesterday, streak is broken
  // (We allow today to be empty if it's still early, as long as yesterday has a log)
  const firstLogDate = localDates[0];
  const d1 = new Date(today);
  const d2 = new Date(firstLogDate);
  const diffDays = Math.round(Math.abs((d1 - d2) / (1000 * 60 * 60 * 24)));

  if (diffDays > 1) return 0;

  let streak = 0;
  let currentRef = new Date(firstLogDate);

  for (let i = 0; i < localDates.length; i++) {
    const dateStr = localDates[i];
    const dateObj = new Date(dateStr);

    // Check if this date is 'currentRef'
    const diff = Math.round((currentRef - dateObj) / (1000 * 60 * 60 * 24));

    if (diff === 0) {
      streak++;
      // Move reference to yesterday
      currentRef.setDate(currentRef.getDate() - 1);
    } else {
      // Gap found
      break;
    }
  }

  return streak;
}

/**
 * Escapa caracteres especiais para o formato Telegram MarkdownV2.
 * Conforme: https://core.telegram.org/bots/api#markdownv2-style
 * 
 * @param {string} text - Texto a ser escapado
 * @returns {string} Texto seguro para MarkdownV2
 * 
 * @example
 * escapeMarkdownV2("Omega 3!") // Retorna "Omega 3\!"
 * escapeMarkdownV2("Vitamina D (1000UI)") // Retorna "Vitamina D \(1000UI\)"
 */
export function escapeMarkdownV2(text) {
  if (!text || typeof text !== 'string') return '';

  // Uma única regex com callback para melhor performance
  // Ordem importa: primeiro escaping de backslash para evitar double-escaping
  // Nota: dentro de [], apenas ] e \ precisam de escape, não _ ou [

  return text.replace(/([\\*()`>#+\-=|{}.!_[\]~])/g, (match) => {
    const escapeMap = {
      '\\': '\\\\',
      '_': '\\_',
      '*': '\\*',
      '[': '\\[',
      ']': '\\]',
      '(': '\\(',
      ')': '\\)',
      '~': '\\~',
      '`': '\\`',
      '>': '\\>',
      '#': '\\#',
      '+': '\\+',
      '-': '\\-',
      '=': '\\=',
      '|': '\\|',
      '{': '\\{',
      '}': '\\}',
      '.': '\\.',
      '!': '\\!'
    };
    return escapeMap[match] || match;
  });
}

/**
 * Retry Manager para Bot Telegram
 *
 * Fornece funções helper para retry com backoff exponencial e jitter.
 * Usado pelo bot adapter para resiliência no envio de mensagens.
 */

import { createLogger } from '../bot/logger.js';
import { generateCorrelationId } from '../bot/correlationLogger.js';
import {
  recordSuccess,
  recordFailure,
  recordRetry,
  recordRateLimitHit
} from '../services/notificationMetrics.js';

const logger = createLogger('RetryManager');

/**
 * Configuração padrão de retry
 */
export const DEFAULT_RETRY_CONFIG = {
  maxRetries: 3,
  baseDelay: 1000,    // 1 segundo
  maxDelay: 10000,    // 10 segundos
  jitter: true        // Adiciona aleatoriedade ao delay
};

/**
 * Verifica se um erro é passível de retry (transitório)
 * @param {Error} error - Objeto de erro
 * @returns {boolean} true se o erro é transitório e pode ser retentado
 */
export function isRetryableError(error) {
  // Network errors (connection issues)
  const retryableCodes = [
    'ETIMEDOUT',
    'ECONNRESET',
    'ENOTFOUND',
    'ECONNREFUSED',
    'Socket hang up',
    'ECONNABORTED',
    'Network Error'
  ];

  if (retryableCodes.some(code =>
    error.message?.includes(code) ||
    error.code === code
  )) {
    return true;
  }

  // Telegram API rate limiting (429 Too Many Requests)
  if (error.response?.status === 429 || error.statusCode === 429) {
    return true;
  }

  // Telegram API internal errors (5xx)
  if ((error.response?.status >= 500) || (error.statusCode >= 500)) {
    return true;
  }

  return false;
}

/**
 * Calcula o delay para a próxima tentativa com backoff exponencial e jitter
 * @param {number} attempt - Número da tentativa atual (1-based)
 * @param {object} config - Configuração de retry
 * @returns {number} Delay em milissegundos
 */
export function calculateDelay(attempt, config = DEFAULT_RETRY_CONFIG) {
  const { baseDelay, maxDelay, jitter } = config;

  // Backoff exponencial: baseDelay * 2^(attempt-1)
  let delay = baseDelay * Math.pow(2, attempt - 1);

  // Aplicar limite máximo
  delay = Math.min(delay, maxDelay);

  // Aplicar jitter (aleatoriedade) para evitar thundering herd
  if (jitter) {
    // Jitter decorrelacionado: delay = random(0, delay)
    delay = Math.random() * delay;
  }

  return Math.floor(delay);
}

/**
 * Helper para aguardar um período de tempo
 * @param {number} ms - Tempo em milissegundos
 * @returns {Promise<void>}
 */
export function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

/**
 * Executa uma função com retry automático
 * @param {Function} fn - Função a ser executada
 * @param {object} config - Configuração de retry
 * @param {object} context - Contexto para logging
 * @returns {Promise<{success: boolean, result?: any, error?: Error, attempts: number}>}
 */
export async function sendWithRetry(fn, config = DEFAULT_RETRY_CONFIG, context = {}) {
  const { maxRetries } = config;
  const correlationId = context.correlationId || generateCorrelationId();

  let lastError;

  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const result = await fn();

      // Sucesso - registrar métrica e retornar
      recordSuccess(context.operation || 'unknown');

      if (attempt > 1) {
        logger.info(`Operação bem-sucedida após retry`, {
          correlationId,
          attempt,
          ...context
        });
      }

      return {
        success: true,
        result,
        attempts: attempt
      };
    } catch (err) {
      lastError = err;

      // Verificar se é erro de rate limiting
      if (err.response?.status === 429 || err.statusCode === 429) {
        recordRateLimitHit(context.operation || 'unknown');
      }

      // Verificar se deve retry
      if (!isRetryableError(err) || attempt === maxRetries) {
        break;
      }

      // Registrar retry
      recordRetry(context.operation || 'unknown');

      // Calcular delay
      const delay = calculateDelay(attempt, config);

      logger.warn(`Retry ${attempt}/${maxRetries} após ${delay}ms`, {
        correlationId,
        error: err.message,
        ...context
      });

      // Aguardar antes da próxima tentativa
      await sleep(delay);
    }
  }

  // Falha após todas as tentativas
  recordFailure(context.operation || 'unknown');

  const actualAttempts = isRetryableError(lastError) ? maxRetries : 1;

  logger.error(`Falha após ${actualAttempts} tentativas`, lastError, {
    correlationId,
    ...context
  });

  return {
    success: false,
    error: lastError,
    attempts: actualAttempts
  };
}

export default {
  DEFAULT_RETRY_CONFIG,
  isRetryableError,
  calculateDelay,
  sleep,
  sendWithRetry
};

/**
 * Get current time in HH:MM format for a specific timezone
 * @param {string} timezone - IANA timezone (e.g., 'America/Sao_Paulo')
 * @returns {string} HH:MM format
 */
export function getCurrentTimeInTimezone(timezone = 'America/Sao_Paulo') {
  const now = new Date();
  return new Intl.DateTimeFormat('pt-BR', {
    timeZone: timezone,
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  }).format(now).replace(/^24/, '00');
}

/**
 * Get current date in YYYY-MM-DD format for a specific timezone
 * @param {string} timezone - IANA timezone
 * @returns {string} YYYY-MM-DD format
 */
export function getCurrentDateInTimezone(timezone = 'America/Sao_Paulo') {
  const now = new Date();
  return new Intl.DateTimeFormat('en-CA', {
    timeZone: timezone
  }).format(now);
}

/**
 * Get current hour and minute separately
 * @param {string} timezone - IANA timezone
 * @returns {{hour: number, minute: number, date: string}}
 */
export function getCurrentTimeComponents(timezone = 'America/Sao_Paulo') {
  const now = new Date();
  const formatter = new Intl.DateTimeFormat('en-GB', {
    timeZone: timezone,
    hour: '2-digit',
    minute: '2-digit',
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour12: false
  });

  const parts = formatter.formatToParts(now);
  const values = {};
  parts.forEach(({ type, value }) => {
    values[type] = value;
  });

  return {
    hour: parseInt(values.hour, 10),
    minute: parseInt(values.minute, 10),
    day: parseInt(values.day, 10),
    weekDay: now.toLocaleString('en-US', { timeZone: timezone, weekday: 'numeric' })
  };
}

/**
 * Convert ISO string to timezone-aware date string
 * @param {string} isoString - ISO 8601 datetime
 * @param {string} timezone - IANA timezone
 * @returns {string} Formatted time HH:MM
 */
export function formatTimeInTimezone(isoString, timezone = 'America/Sao_Paulo') {
  const date = new Date(isoString);
  return new Intl.DateTimeFormat('pt-BR', {
    timeZone: timezone,
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  }).format(date).replace(/^24/, '00');
}
